window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]=window.__LIBQ["pham-nhan-tu-tien"]["q06"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]["techniques"]={"updatedAt":"2026-07-16","count":532,"techniques":[{"id":"that-tinh-quyet","name":"Thất Tình Quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Đại Diễn Thần Quân"],"blurb":"Công pháp tâm thuật có thể khống chế hỉ nộ ái ố của đối thủ nhưng không khống chế được thần thức. Đại Diễn Thần Quân từng dùng để tấn công Hàn Lập, liên kết cảm xúc với đệ nhị nguyên anh của hắn.","detail":"Thất Tình Quyết không khống chế được thần thức tu sĩ nhưng khống chế được các loại hỉ nộ ái ố, khiến đối thủ sống không bằng chết. Đại Diễn Thần Quân từng thi triển nhằm khống chế chủ nguyên thần Hàn Lập nhưng thất bại vì Hàn Lập có đệ nhị nguyên anh. Đã liên kết hỉ nộ ái ố của Hàn Lập với đệ nhị nguyên anh, khiến tâm tư hắn bị xao động khi lão cố ý khuấy động.","thuocTinh":"Tâm thuật, khống chế cảm xúc","nguonGoc":"Không rõ, Đại Diễn Thần Quân nắm giữ","congNang":["Khống chế hỉ nộ ái ố của đối thủ, khiến đối thủ sống không bằng chết @c0795","Liên kết cảm xúc với đệ nhị nguyên anh @c0795"],"nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0795","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0795","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ diện lần đầu","text":"Đại Diễn Thần Quân từng thi triển Thất Tình Quyết nhằm khống chế chủ nguyên thần Hàn Lập nhưng thất bại vì đệ nhị nguyên anh. Đã liên kết hỉ nộ ái ố của Hàn Lập với đệ nhị nguyên anh.","anchor":"Thất tình quyết không cách nào không chế được thần thức của tu sĩ nhưng lại có thể không chế được các loại hỉ nộ ái ố của con người"}]},"capNhatToi":"@c0795","nguon":["@c0795"]},{"id":"ky-than-thuat","name":"Ký Thần Thuật","cn":"寄神术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thiên Trúc Giáo","soHuu":["Đại Diễn Thần Quân"],"blurb":"Bí thuật do Đại Diễn Thần Quân sáng lập, lấy Đại Diễn Quyết làm trụ cột, nhằm bảo trì thần trí/nguyên thần sau khi chết. Chỉ hoàn thành một nửa, kết quả không như ý.","detail":"Đại Diễn Thần Quân dùng hai trăm năm cuối đời khổ tâm sáng lập, sau vô số thất bại, lấy Đại Diễn Quyết làm trụ cột mà tạo ra. Mục đích là bảo trì thần trí sau chuyển sinh hoặc trường sinh, nhưng chỉ hoàn thành một nửa khi hết thời gian. Bất đắc dĩ sử dụng, kết quả buông bỏ đại bộ phận tu vi, đem thần thức nhập vào Khôi Lỗi đặc chế, chỉ còn thần thông dùng bằng thần thức, nguyên thần không thể xuất khiếu.","thuocTinh":"Thần thức","nguonGoc":"Đại Diễn Thần Quân sáng lập, lấy Đại Diễn Quyết làm trụ cột","dacDiem":"Chưa hoàn chỉnh, chỉ xong một nửa. Sử dụng sẽ mất tu vi, thần thức nhập vào vật chứa (Khôi Lỗi đặc chế).","congNang":["Bảo trì thần trí/nguyên thần sau khi chết, dạng phụ thể thần thức vào Khôi Lỗi","Duy trì thần hồn trên khôi lỗi trong tình trạng kéo dài tàn mệnh @c0908","Ký phụ thần hồn vào khôi lỗi, nhưng từng khiến Đại Diễn Thần Quân bị vây trong thân khôi lỗi @c0964"],"trangThai":"Chưa hoàn chỉnh","nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0796","tangDatToi":"đã sử dụng","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0796","loai":"xuất hiện","importance":"major","giaiDoan":"Lai lịch được tiết lộ","text":"Đại Diễn Thần Quân kể lại quá trình sáng lập Ký Thần Thuật: dùng hai trăm năm cuối đời, lấy Đại Diễn Quyết làm trụ cột, nhưng chỉ hoàn thành một nửa, bất đắc dĩ sử dụng dẫn đến mất tu vi và bị nhốt trong Khôi Lỗi vạn năm.","anchor":"rốt cuộc lấy Đại Diễn Quyết làm trụ cột mà sáng lập ra ký thần thuật"},{"chuong":"@c0908","loai":"nhắc tới","importance":"normal","giaiDoan":"Đại Diễn Thần Quân nhắc nguồn cơn nghiên cứu","text":"Đại Diễn Thần Quân nói vì thọ nguyên nên về sau phải khổ cực nghiên cứu ký thần thuật, dẫn tới cảnh ký hồn trên khôi lỗi.","anchor":"sau bởi vì thọ nguyên cho nên cũng không quay lại mà khổ cực nghiên cứu ký thần thuật"},{"chuong":"@c0964","loai":"nhắc tới","importance":"normal","giaiDoan":"Nguyên nhân bị nhốt","text":"Đại Diễn Thần Quân nói năm xưa ông vì dùng Ký thần thuật nên bị nhốt trong khôi lỗi, từ đó mới có thời gian nghiên cứu phân hồn thuật.","anchor":"Năm đó bởi vì ta sử dụng ký thần thuật mà bị nhốt trong khôi lỗi"}]},"nguon":["@c0796","@c0908","@c0964"]},{"id":"dong-hoa-thuat","name":"Đồng Hóa Thuật","cn":"同化术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông Hàn Lập dùng qua nguyên anh chủ thao túng nguyên anh thứ hai, có thể khiến tinh hồn đối phương cùng nguyên anh thứ hai đồng thời yên diệt.","detail":"Hàn Lập dùng thông qua nguyên anh chủ để thao túng nguyên anh thứ hai, đe dọa khiến tinh hồn Đại Diễn Thần Quân cùng nguyên anh thứ hai đồng quy vu tận, tạo thế cân bằng uy hiếp trong lần gặp đầu tiên tại mật thất Thiên Trúc Giáo.","congNang":["Thao túng nguyên anh, khiến tinh hồn đối phương cùng nguyên anh đồng thời yên diệt"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0796","tangDatToi":"","trangThai":"Đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0796","loai":"thi triển","importance":"normal","giaiDoan":"Phản kích Đại Diễn Thần Quân","text":"Hàn Lập dùng Đồng Hóa Thuật qua nguyên anh chủ phản kích Đại Diễn Thần Quân, đe dọa đồng quy vu tận tạo thế giằng co.","anchor":"sử dụng đồng hóa thuật, khiến cho tinh hồn ngươi cùng nguyên anh thứ hai đồng thời yên diệt"}]},"nguon":["@c0796"]},{"id":"thuong-co-ma-cong","name":"Thượng cổ ma công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":[],"blurb":"Đường lối tu luyện của Cổ ma giới còn sót lại, được hậu nhân sáng tạo thêm. Tu tới tận cùng khi phi thăng sẽ đi Ma Giới thay vì Linh giới.","detail":"Ma đạo tu sĩ tu luyện thượng cổ ma công vốn là đường lối tu luyện của Cổ ma còn sót lại. Có bí thuật cách giới mượn khí cổ ma phụ lên người để tăng thần thông. Nghe đồn tu luyện loại ma công này đến mức tận cùng khi phi thăng sẽ đi thượng cổ Ma giới, trở thành thành viên cổ ma chứ không phải đến Linh giới.","thuocTinh":"Ma","nguonGoc":"Đường lối tu luyện của Cổ ma giới, sót lại từ thời thượng cổ, hậu nhân sáng tạo thêm","dacDiem":"Tu tới cùng phi thăng tới Ma Giới thay vì Linh giới; có thể cách giới mượn khí cổ ma phụ lên người","congNang":["Tăng thần thông bằng cách mượn khí cổ ma qua bí thuật cách giới"],"tabs":{"tienTrinh":[{"chuong":"@c0797","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Tiết lộ nguồn gốc","text":"Đại Diễn Thần Quân tiết lộ ma đạo tu sĩ tu luyện thượng cổ ma công vốn là đường lối tu luyện của Cổ ma giới còn sót lại, được hậu nhân sáng tạo thêm. Tu tới cùng phi thăng tới Ma Giới.","anchor":"tu sĩ ma đạo bây giờ cũng đang tu luyện một ít thượng cổ ma công, đó là đường lối tu luyện của Cổ ma giới còn sót lại"}]},"nguon":["@c0797"]},{"id":"phuong-phap-luyen-che-khoi-loi-ket-dan-ky","name":"Phương pháp luyện chế Khôi Lỗi cấp bậc Kết Đan Kỳ","loai":"cong-phap","loaiLabel":"Công pháp luyện khí","phamCap":"Kết Đan Kỳ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Phương pháp luyện chế Khôi Lỗi chiến đấu cấp Kết Đan, ghi trong ngọc giản Đại diễn Thần Quân đưa, gồm hai biến thể: hình cự quy (phòng ngự + lôi hỏa cầu) và hình hổ yêu (cận chiến nhanh nhẹn).","detail":"Gồm hai loại Khôi Lỗi: Khôi Lỗi hình cự quy (da dày chống được năm ba đòn Nguyên Anh Kỳ, phun lôi hỏa cầu uy lực ngang toàn lực Kết Đan Trung Kỳ, nhưng vụng về chậm chạp) và Khôi Lỗi hình hổ yêu (không công kích tầm xa, phòng ngự trung bình, nhưng rất nhanh nhẹn, hổ trảo phóng trảo mang nửa thước xé rách vòng bảo hộ Kết Đan, chuyên cận chiến). Hàn Lập nghiên cứu ba ngày ba đêm rồi quyết định luyện cả hai loại.","thuocTinh":"Luyện khí / Khôi Lỗi","nguonGoc":"Ngọc giản Đại diễn Thần Quân","dacDiem":"Hai biến thể bổ trợ: cự quy phòng ngự tầm xa, hổ yêu cận chiến tốc độ","congNang":["Luyện chế Khôi Lỗi hình cự quy phòng ngự + phun lôi hỏa cầu","Luyện chế Khôi Lỗi hình hổ yêu cận chiến nhanh nhẹn"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0799","tangDatToi":"","trangThai":"dang-hoc"}],"tabs":{"tienTrinh":[{"chuong":"@c0799","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập nghiên cứu và bắt đầu luyện chế","text":"Hàn Lập nghiên cứu ngọc giản ba ngày ba đêm, nắm rõ đặc điểm hai loại Khôi Lỗi Kết Đan Kỳ, quyết định luyện chế cả hai loại, bắt đầu luyện chế.","anchor":"Hai loại Khôi Lỗi này cùng với việc luyện chế cự viên khôi lỗi cấp bậc Trúc Cơ kỳ đem ra so sánh thì có sự bất đồng thật lớn"}]},"nguon":["@c0799"]},{"id":"dan-huong-truyen-tong-tran","name":"Đan Hướng Truyền Tống Trận","cn":"丹向传送阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Đặc chế (cải biến từ thượng cổ Truyền Tống Trận)","hePhai":"Quỷ Linh Môn","soHuu":["Quỷ Linh Môn"],"blurb":"Pháp trận cực lớn do Quỷ Linh Môn cùng nhiều trận pháp đại sư nghiên cứu nhiều năm, cải biến từ thượng cổ Truyền Tống Trận. Đơn hướng truyền tống người từ cốc khẩu vào bên trong Trụy Ma Cốc.","detail":"Pháp trận cao hơn trăm trượng, cần linh thạch bậc cao kim chúc tính để thúc dục. Đơn hướng truyền tống từ cốc khẩu vào Trụy Ma Cốc, vị trí đích không cố định, có xác suất nhỏ truyền tống vào khe hở không gian. Chỉ truyền tống số người có hạn. Quỷ Linh Môn sẽ vào cuối cùng rồi hủy trận để ngăn kẻ không có Trụy ma lệnh lẻn vào.","nguonGoc":"Quỷ Linh Môn cùng nhiều trận pháp đại sư khổ tâm nghiên cứu nhiều năm, cải biến từ thượng cổ Truyền Tống Trận","congNang":["Đơn hướng truyền tống người từ cốc khẩu vào bên trong Trụy Ma Cốc @c0803"],"dacDiem":"Vị trí đích không cố định, có rủi ro rơi vào khe hở không gian. Cần linh thạch bậc cao kim chúc tính mới thúc dục được. Chỉ truyền tống số người có hạn.","tabs":{"tienTrinh":[{"chuong":"@c0803","loai":"xuất hiện","importance":"major","giaiDoan":"Thiết trí và kích hoạt tại cốc khẩu Trụy Ma Cốc","text":"Quỷ Linh Môn thiết trí Đan Hướng Truyền Tống Trận tại cốc khẩu Trụy Ma Cốc. Vương Thiên Cổ đặt linh thạch bậc cao kim hoàng sắc vào trung tâm. Vương Thiên Thắng tuyên bố quy tắc sử dụng: chỉ người có Trụy ma lệnh mới được dùng, Quỷ Linh Môn vào cuối cùng rồi hủy trận.","anchor":"do Quỷ Linh Môn chúng ta cùng nhiều vị trận pháp đại sư khổ tư suy nghĩ nhiều năm mới nghiên cứu chế tạo ra được"}]},"nguon":["@c0803"]},{"id":"truyen-tong-tran","name":"Truyền Tống Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Quỷ Linh Môn","soHuu":["Quỷ Linh Môn"],"blurb":"Trận pháp truyền tống tu sĩ vào Trụy Ma Cốc, mỗi lần chỉ chở được 3 người, vị trí đích ngẫu nhiên, cần linh thạch cấp cao và trận kỳ kích hoạt.","detail":"Trận pháp lớn do Quỷ Linh Môn chủ trì tại cốc khẩu Trụy Ma Cốc. Mỗi lần truyền tống tối đa 3 người, vị trí đến trong cốc hoàn toàn ngẫu nhiên. Đệ tử Quỷ Linh Môn bay trên không trung cầm trận kỳ bắn cột sáng xuống để kích hoạt. Năng lượng vận hành từ linh thạch bậc cao, sau hơn 300 người đã tiêu hao 7-8 phần.","congNang":["Truyền tống tu sĩ vào Trụy Ma Cốc, mỗi lần tối đa 3 người","Vị trí đích trong cốc hoàn toàn ngẫu nhiên"],"tabs":{"tienTrinh":[{"chuong":"@c0804","loai":"thi triển","importance":"major","giaiDoan":"Kích hoạt truyền tống hơn 300 tu sĩ","text":"Quỷ Linh Môn mở trận, lần lượt truyền tống hơn 300 tu sĩ vào Trụy Ma Cốc. Linh thạch cấp cao tiêu hao 7-8 phần, quang mang ảm đạm.","anchor":"tựa hồ một lần chỉ có thể truyền đi được ba người"}]},"nguon":["@c0804"]},{"id":"bac-cuc-nguyen-quang","name":"Bắc cực nguyên quang","cn":"","loai":"khac","loaiLabel":"Hiện tượng/cấm chế","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Luồng quang lực tràn đầy trong thông đạo dẫn vào nơi hỏa thiềm thú ở nội cốc Trụy Ma Cốc, đủ sức diệt sát tu sĩ xông bừa vào.","detail":"Bắc cực nguyên quang tràn ngập thông đạo bí mật mà Thương Khôn Thượng Nhân tìm được, dẫn đến nơi hỏa thiềm thú trong nội cốc. Cần có Lưỡng nghi hoàn mới có thể xông qua, nếu không có sẽ bị diệt sát.","congNang":["Chặn đường vào nội cốc, giết tu sĩ không có phương tiện bảo hộ thích hợp"],"tabs":{"tienTrinh":[{"chuong":"@c0807","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến khi bàn kế sách vào nội cốc","text":"Thông đạo bí mật dẫn vào nơi hỏa thiềm thú tràn đầy bắc cực nguyên quang, cần Lưỡng nghi hoàn mới xông qua được.","anchor":"bắc cực nguyên quang nhất định cần phải có Lưỡng nghi hoàn mới có thể xông qua"}]},"nguon":["@c0807"]},{"id":"phap-tran-che-giau-dong-tinh","name":"Pháp trận che giấu động tĩnh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Đại trận do Hàn Lập bày bằng trận kỳ trong suốt tại hai tòa sơn phong, đè nén tiếng vang và linh khí ba động trong một khu vực để che giấu động tĩnh chiến đấu.","detail":"Hàn Lập dùng trận kỳ trong suốt bày pháp trận phạm vi lớn tại thông đạo nội cốc Trụy Ma Cốc, công dụng chủ yếu là đem tiếng vang cùng linh khí ba động tận lực đè nén trong một khu vực, ngăn kinh động tu sĩ phụ cận khi giao chiến với cự mãng.","congNang":["Đè nén tiếng vang và linh khí ba động trong khu vực phủ trận"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0808","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0808","loai":"thi triển","importance":"normal","giaiDoan":"Bày trận tại thông đạo nội cốc","text":"Hàn Lập dùng trận kỳ trong suốt bố trí đại trận tại hai tòa sơn phong trước thông đạo nội cốc để che giấu động tĩnh chiến đấu với cự mãng.","anchor":"Công dụng của pháp trận này chủ yếu là đem tiếng vang cùng linh khí ba động tận lực đè nén trong một khu vực"}]},"nguon":["@c0808"]},{"id":"phap-quyet-khu-su-phe-kim-trung-khai-thac","name":"Pháp quyết điều khiển Phệ Kim Trùng khai thác khoáng vật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Khu Trùng Thuật","soHuu":["Hàn Lập"],"blurb":"Pháp quyết cổ văn cho phép thao túng Phệ Kim Trùng (và một số linh trùng khác) chui vào đá cắn nuốt khoáng vật cứng rồi nhả ra tinh thể ngưng kết. Đại Diễn Thần Quân đoạt từ một tu sĩ bị lão đánh chết năm xưa, truyền lại cho Hàn Lập.","detail":"Pháp quyết viết bằng cổ văn, dùng thần thức bắt ấn quyết điều khiển linh trùng. Phệ Kim Trùng là loài dễ dùng nhất — chúng chui vào thạch bích không để lại vết tích, cắn nuốt khoáng vật rồi nhả tinh thể ngưng kết. Đại Diễn Thần Quân lấy phương pháp này từ một tu sĩ bị lão đánh chết, nay truyền cho Hàn Lập để khai thác Cương Ngân Sa trong Trụy Ma Cốc.","thuocTinh":"Khu trùng","nguonGoc":"Đại Diễn Thần Quân đoạt từ tu sĩ bị giết","dacDiem":"Cổ văn, chuyên dùng cho Phệ Kim Trùng","congNang":["Điều khiển linh trùng chui vào đá cắn nuốt khoáng vật cứng rồi nhả tinh thể ngưng kết @c0811"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0811","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0811","loai":"xuất hiện","importance":"major","giaiDoan":"Được truyền thụ","text":"Đại Diễn Thần Quân truyền pháp quyết cổ văn cho Hàn Lập, dùng điều khiển Phệ Kim Trùng khai thác Cương Ngân Sa trong thạch bích Trụy Ma Cốc. Hàn Lập lập tức sử dụng, bí mật phóng thích toàn bộ Phệ Kim Trùng vào đá.","anchor":"Ta sẽ dạy cho ngươi một loại pháp quyết có thể thao túng Phệ Kim Trùng chui vào trong thạch bích cắn nuốt Cương Ngân Sa"}]},"nguon":["@c0811"]},{"id":"mac-giao-thuat","name":"Mặc Giao thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Ma đạo","soHuu":["Chung trưởng lão"],"blurb":"Thần thông ngưng tụ âm khí thành hình Mặc Giao chiến đấu, do lão giả họ Chung thi triển.","detail":"Người thi triển bắt quyết, vô số luồng khí đen nhánh như mực từ trên người toát ra, âm khí ngưng tụ hóa hình thành hai con Mặc Giao tấn công đối phương. Kết hợp với pháp bảo cự võng lửa để tiêu diệt bích hổ cổ thú.","congNang":["Ngưng tụ âm khí thành hình Mặc Giao chiến đấu"],"nguoiTu":[{"ten":"Chung trưởng lão","tuChuong":"@c0812","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0812","loai":"thi triển","importance":"normal","giaiDoan":"Lão giả họ Chung thi triển diệt bích hổ cổ thú","text":"Lão giả họ Chung bắt quyết, âm khí đen nhánh từ người toát ra hóa hình hai con Mặc Giao tấn công bích hổ cổ thú tại thung lũng băng tuyết trong Trụy Ma Cốc.","anchor":"vô số luồng khí đen nhánh như mực từ trên người toát ra, đám âm khí này trong nháy mắt đã hóa hình ngưng tụ thành hai con Mặc Giao"}]},"nguon":["@c0812"]},{"id":"than-thong-cam-ung-khe-ho-khong-gian","name":"Thần thông cảm ứng khe hở không gian","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thương Khôn Thượng Nhân"],"blurb":"Thần thông cho phép cảm ứng sự tồn tại của khe hở không gian, kể cả loại vô hình. Thương Khôn Thượng Nhân nhờ thần thông này mà dù trọng thương vẫn thoát khỏi Trụy Ma Cốc an toàn.","detail":"Thương Khôn Thượng Nhân tu luyện loại thần thông đặc biệt này, cho phép cảm ứng được sự tồn tại của các khe hở không gian — bao gồm cả loại vô hình mà mắt thường không thể nhìn thấy. Nhờ thần thông này mà năm xưa dù nguyên khí đại thương, ông vẫn tìm được đường an toàn thoát khỏi Trụy Ma Cốc, chứ không phải dựa vào may mắn.","congNang":["Cảm ứng sự tồn tại của khe hở không gian, kể cả loại vô hình"],"nguoiTu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0813","tangDatToi":"","trangThai":"da-mat (chủ nhân đã tử vong)"}],"tabs":{"tienTrinh":[{"chuong":"@c0813","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Được tiết lộ qua di thư","text":"Nam Lũng Hầu tiết lộ rằng Thương Khôn Thượng Nhân thoát khỏi Trụy Ma Cốc nhờ tu luyện thần thông cảm ứng khe hở không gian, chứ không phải may mắn. Thông tin này ghi trong di thư.","anchor":"Toàn bộ việc này đều dựa vào một loại thần thông mà Thượng nhân tu luyện mới giúp cho hắn có thể cảm ứng được sự tồn tại của khe hở không gian"}]},"nguon":["@c0813"]},{"id":"linh-nhan-than-thong","name":"Linh nhãn thần thông","cn":"灵眼神通","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông cho phép nhìn thấy khe hở không gian vô hình mà mắt thường và thần thức không thể cảm ứng, là chỗ dựa lớn nhất của Hàn Lập trong Trụy Ma Cốc.","detail":"Linh nhãn thần thông giúp chủ nhân nhìn thấy các khe hở không gian vô hình dày đặc mà phương pháp thông thường không thể phát hiện. Hàn Lập coi đây là bí mật lớn nhất, kiên quyết không bại lộ trước mặt đồng hành trừ khi vạn bất đắc dĩ.","congNang":["Nhìn thấy khe hở không gian vô hình"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0814","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0814","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập giấu kín trong Trụy Ma Cốc","text":"Hàn Lập nhận ra có thể dùng Linh nhãn nhìn thấy khe hở không gian vô hình ở ngọn núi bên phải, nhưng kiên quyết giấu bí mật này trước mặt Nam Lũng Hầu và Lỗ Vệ Anh, chấp nhận đối mặt với Tử Vân hạt thay thế.","anchor":"Đây là chỗ dựa lớn nhất của hắn ở trong Trụy Ma Cốc"}]},"nguon":["@c0814"]},{"id":"dai-tran-thuy-thuoc-tinh","name":"Đại trận Thủy thuộc tính","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thủy thuộc tính","soHuu":["Nam Lũng Hầu"],"blurb":"Pháp trận Thủy thuộc tính do Nam Lũng Hầu chuẩn bị sẵn bộ khí cụ, dùng để khắc chế Hỏa Thiềm thú bằng cách dẫn dụ nó ra khỏi sào huyệt dung nham rồi tiêu diệt.","detail":"Nam Lũng Hầu đã chuẩn bị trước một bộ khí cụ chuyên dùng để bày trận Thủy thuộc tính, nhằm khắc chế Hỏa thuộc tính của Hỏa Thiềm thú. Kế hoạch là thiết lập pháp trận trước rồi dẫn dụ thú ra khỏi sào huyệt nằm trong dung nham để tiêu diệt, vì thú có khả năng hồi phục nguyên trạng nếu nhảy vào dung nham. Hàn Lập bổ sung thêm mấy loại pháp trận bên ngoài để phòng bất trắc.","congNang":["Khắc chế Hỏa Thiềm thú, ngăn nó quay lại dung nham hồi phục"],"tabs":{"tienTrinh":[{"chuong":"@c0815","loai":"xuất hiện","importance":"normal","giaiDoan":"Bày trận chuẩn bị diệt Hỏa Thiềm thú","text":"Nam Lũng Hầu triển khai bộ khí cụ bày đại trận Thủy thuộc tính tại chân núi đỏ Dung Nham Chi Địa, Hàn Lập bổ sung thêm pháp trận phụ bên ngoài.","anchor":"Phương pháp tốt nhất là nên thiết hạ pháp trận trước tiên rồi sau đó dẫn dụ nó ra khỏi sào huyệt để tiêu diệt"}]},"nguon":["@c0815"]},{"id":"hoa-don-chi-thuat","name":"Hỏa độn chi thuật","cn":"火遁之术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa hệ","soHuu":["Hỏa Thiềm Thú"],"blurb":"Thuật đào thoát bản năng của Hỏa Thiềm Thú, chui vào dung nham trong đất, trong nháy mắt thoát xa hơn ngàn trượng.","detail":"Theo tài liệu Hàn Lập nghiên cứu trước khi vào Trụy Ma Cốc, Hỏa Thiềm Thú tinh thông thuật này, có thể đào thoát siêu tốc qua dung nham trong lòng đất.","nguon":["@c0816"]},{"id":"than-thong-quang-thuan-do","name":"Thần thông quang thuẫn đỏ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa hệ","soHuu":["Hỏa Thiềm Thú"],"blurb":"Thần thông bảo mệnh của Hỏa Thiềm Thú, co rút thân rồi giãn ra, tạo vòng bảo vệ ba tầng quang thuẫn đỏ dày đặc chặn được đa công kích.","detail":"Cổ thú co rút rồi giãn thân, trên thân xuất hiện từng tầng quang thuẫn đỏ dung hợp thành vòng bảo vệ ba tầng, chặn được bích ngọc chỉ hoàn, thủy long và phi qua đồng loạt. Còn tách ra quang trụ to lớn xuyên thủng thủy mạc pháp trận.","nguon":["@c0816"]},{"id":"phap-tran-thuy-mac","name":"Pháp trận thủy mạc","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thủy hệ","soHuu":["Hàn Lập","Nam Lũng Hầu","Lỗ Vệ Anh"],"blurb":"Pháp trận thủy hệ bố trí sẵn tại chân núi để khốn trụ Hỏa Thiềm Thú, sinh thủy mạc lam và thủy long trắng.","detail":"Pháp trận bố trí trước tại chân núi, khi mục tiêu lọt vào thì hiện thủy mạc lam bao quanh, sinh ra thủy long trắng ẩn hiện, không khí lạnh lẽo. Hàn Lập điều khiển trận kỳ phát động cấm chế. Bị Hỏa Thiềm Thú bắn quang trụ xuyên thủng thủy mạc tạo lỗ hổng.","nguon":["@c0816"]},{"id":"cuc-han-lam-diem","name":"Cực Hàn lam diễm","cn":"","aliases":["Lam sắc băng diễm"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Băng hệ","soHuu":["Hàn Lập"],"blurb":"Lam sắc băng diễm do Hàn Lập nắm giữ, ngưng tụ thành đóa hoa băng nhỏ vài tấc nhưng bao bọc được hỏa cầu đường kính năm sáu trượng, đối kháng ngang ngửa yêu hỏa Hỏa Thiềm Thú.","detail":"Hàn Lập cầm trong tay, ngưng tụ thành đóa hoa băng nhỏ vài tấc vô thanh vô tức. Khi nghênh đón hỏa cầu, băng diễm bao bọc từng tầng băng dày bên ngoài hỏa cầu tạo viên cầu băng khổng lồ phong ấn hỏa diễm bên trong, chứng tỏ uy lực ngang hoặc nhỉnh hơn yêu hỏa cổ thú cấp bốn.","congNang":["Ngưng tụ thành đóa hoa băng đối kháng hỏa diễm cấp cao","Bao bọc phong ấn hỏa cầu thành viên cầu băng khổng lồ"],"tabs":{"tienTrinh":[{"chuong":"@c0816","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Hỏa Thiềm Thú","text":"Hàn Lập dùng lam sắc băng diễm ngưng đóa hoa băng nghênh đón hỏa cầu Hỏa Thiềm Thú, bao bọc phong ấn thành viên cầu băng khổng lồ, đối kháng ngang ngửa.","anchor":"lam quang, hỏa cầu lóe lên, từng tầng từng tầng băng dày bao lấy bên ngoài hỏa cầu"}]},"nguon":["@c0816"]},{"id":"am-ma-tram","name":"Âm Ma trảm","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Hàn Lập"],"blurb":"Thần thông phóng hắc quang chém từ xa, uy lực cực lớn nhưng để lại hắc khí trên tay người dùng.","detail":"Hàn Lập sử dụng trong tình huống khẩn cấp khi Hỏa Thiềm thú sắp thoát pháp trận, hắc quang lóe lên chém đứt chân trước yêu thú. Sau khi dùng, hắn phất tay xua đi hắc khí trên cánh tay — phản ứng phụ khi sử dụng thần thông này.","congNang":["Phóng hắc quang chém từ xa, đủ sức chém đứt chân trước thượng cổ kỳ thú cấp Nguyên Anh"],"dacDiem":"Để lại hắc khí trên tay người dùng sau khi sử dụng","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0817","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0817","loai":"thi triển","importance":"normal","giaiDoan":"Chém đứt chân Hỏa Thiềm thú","text":"Hàn Lập sử dụng Âm Ma trảm từ xa, hắc quang chém đứt chân trước Hỏa Thiềm thú đang sắp thoát pháp trận, ngăn yêu thú trốn thoát.","anchor":"chính đang phất tay, xua đi hắc khí trên một cánh tay"}]},"nguon":["@c0817"]},{"id":"bat-diet-chi-the","name":"Bất diệt chi thể","cn":"不灭之体","loai":"than-thong","loaiLabel":"Thiên phú thần thông","phamCap":"Không rõ","hePhai":"Yêu thú","soHuu":["Hỏa Thiềm thú"],"blurb":"Thiên phú thần thông của Hỏa Thiềm thú, cho phép tái sinh sau khi bị cắt đứt bộ phận. Thực chất chỉ là sinh mệnh lực mạnh hơn yêu thú thường, không phải bất diệt chân chính.","detail":"Đầu và thân thể sau khi bị chém đứt sẽ tỏa hồng quang, hai phần tự tiếp cận nhau để tái sinh. Hàn Lập giải thích đây chỉ là sinh mệnh lực cường đại hơn yêu thú bình thường, không phải thực sự bất diệt — có thể phá giải bằng cách phong bế hồng quang (dùng băng diễm đông kết) rồi phá hủy hoàn toàn.","congNang":["Tái sinh/hồi phục bộ phận sau khi bị cắt đứt, đầu và thân tự tiếp cận nhau nhờ hồng quang"],"tabs":{"tienTrinh":[{"chuong":"@c0818","loai":"thi triển","importance":"normal","giaiDoan":"Hỏa Thiềm thú thể hiện và bị phá giải","text":"Hỏa Thiềm thú bị chém đứt đầu, tỏa hồng quang hai phần tự tiếp cận tái sinh. Hàn Lập dùng băng diễm đông kết cả đầu và thân thành tượng băng, phong bế hồng quang rồi phá hủy hoàn toàn.","anchor":"Bất diệt chi thế! Hỏa Thiềm thú này lại có thiên phú thần thông loại này ư?"}]},"nguon":["@c0818"]},{"id":"huyet-chu-cam-che","name":"Huyết chú (cấm chế thượng cổ)","cn":"血咒","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Thượng cổ","hePhai":"","soHuu":[],"blurb":"Cấm chế thượng cổ dùng phong bế Huyết chú chi môn, bảo vệ địa phương có trọng bảo. Người thi triển phải hy sinh bản thân, hài cốt biến trong suốt.","detail":"Loại cấm chế từ thời thượng cổ, chuyên dùng phong ấn cánh cửa chứa trọng bảo. Đại giá thi triển cực lớn: người thi triển tọa hóa tại chỗ, hài cốt biến thành trong suốt. Bộ hài cốt cổ tu sĩ chính là chìa khóa phá giải cấm chế.","congNang":["Phong ấn cánh cửa chứa trọng bảo, cần hài cốt người thi triển làm chìa khóa phá giải"],"tabs":{"tienTrinh":[{"chuong":"@c0820","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ diện qua lời Nam Lũng Hầu và Lỗ Vệ Anh","text":"Nam Lũng Hầu và Lỗ Vệ Anh tiết lộ bộ hài cốt cổ tu sĩ trong suốt chính là chìa khóa phá giải Huyết chú chi môn — cánh cửa phong bế bằng cấm chế huyết chú thượng cổ, phía sau chứa trọng bảo.","anchor":"Ở thời kỳ thượng cổ, Huyết chú chi môn đều dùng để bảo vệ địa phương có trọng bảo"}]},"nguon":["@c0820"]},{"id":"truyen-tong-tran-noi-coc","name":"Truyền Tống trận (nội cốc → ngoại cốc)","cn":"傳送陣","loai":"cong-phap","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Truyền Tống trận được Thương Khôn thượng nhân phát hiện trong nội cốc Trụy Ma Cốc, có thể di chuyển ra ngoại cốc nhưng đường đi xa hơn đường cũ.","detail":"Trận pháp truyền tống nằm trong nội cốc Trụy Ma Cốc, do Thương Khôn thượng nhân phát hiện trước đây. Cho phép di chuyển từ nội cốc ra ngoại cốc, tuy nhiên đường đi xa hơn so với đường cũ mà Hàn Lập đã dùng để vào.","congNang":["Truyền tống từ nội cốc ra ngoại cốc Trụy Ma Cốc"],"tabs":{"tienTrinh":[{"chuong":"@c0820","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến bởi Nam Lũng Hầu","text":"Nam Lũng Hầu tiết lộ Thương Khôn thượng nhân trước đây đã tìm được Truyền Tống trận có thể di chuyển ra ngoại cốc.","anchor":"Thương Khôn thượng nhân trước đây đã tìm được một cái Truyền Tống trận có thể di chuyển ra ngoại cốc"}]},"nguon":["@c0820"]},{"id":"am-cong-tu-van-hat","name":"Âm công thiên phú của Tử Vân hạt","loai":"khac","loaiLabel":"Thiên phú yêu thú","hePhai":"Âm công","soHuu":["Tử Vân hạt"],"blurb":"Âm thanh bén nhọn kỳ quái của đàn Tử Vân hạt, đánh thẳng tới chân nguyên tu sĩ thay vì tác động thần thức.","detail":"Khi đàn Tử Vân hạt phát ra âm thanh bén nhọn kỳ quái, cả ba tu sĩ Nguyên Anh đều khí huyết quay cuồng, đầu óc choáng váng. Hàn Lập nhận định loại công kích này không đánh vào thần thức mà trực tiếp đánh tới chân nguyên, nên thần thức cường đại cũng không chống đỡ tốt hơn — thiên phú cổ quái ngoài ghi chép điển tịch.","congNang":["Công kích bằng âm thanh đánh thẳng chân nguyên, không qua thần thức (@c0815)"],"dacDiem":"Thiên phú cổ quái, điển tịch không ghi chép","capNhatToi":"@c0815","tabs":{"tienTrinh":[{"chuong":"@c0815","loai":"xuất hiện","importance":"normal","text":"Đàn Tử Vân hạt phát âm công khiến ba tu sĩ Nguyên Anh khí huyết quay cuồng khi vượt ải.","anchor":"Loại công kích bằng âm thanh quái dị này hình như không phải tác động lên thần thức mà là trực tiếp đánh tới chân nguyên"}]},"nguon":["@c0815"]},{"id":"huyet-chu-chi-mon","name":"Huyết Chú chi môn","cn":"血咒之门","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Tà môn","soHuu":[],"blurb":"Cấm chế tà môn phong ấn thạch môn, huyết quang ngưng tụ thành mặt quỷ có thể nuốt mọi công kích. Phá giải cần tinh nguyên hoặc huyết nhục của người hạ chú.","detail":"Loại cấm chế tà môn được đặt trên thạch môn có điêu khắc quỷ đầu. Khi bị công kích, huyết quang trên cửa bùng lên ngưng tụ thành mặt quỷ to cỡ một trượng giống hệt quỷ đầu điêu khắc, có thể nuốt chửng hỏa cầu và hút phong long — mọi loại công kích thông thường đều vô hiệu. Muốn giải trừ cấm chế này cần tinh nguyên hoặc huyết nhục của người hạ chú; nếu huyết nhục không còn, có thể dùng cốt phấn nghiền từ hài cốt cổ tu đã tọa hóa vì trong đó vẫn lưu giữ tinh nguyên. Nam Lũng Hầu dùng phương pháp phá giải do Thương Khôn Thượng Nhân truyền lại: bắt quyết đánh pháp quyết lên cốt phấn trong kim sắc hà quang, khiến cốt phấn hóa quang điểm bay vào mặt quỷ, tạo sương mù xám hóa giải huyết quang. Trong sương mù vang tiếng quỷ khóc và xúc tua huyết sắc lao ra nhưng bị sương mù ngăn chặn. Sau đó hai người hợp lực tổng công kích phá hủy cấm chế. Thạch môn bị chém nát, các mảnh vỡ chảy ra dòng máu đỏ sậm hôi thối.","nguon":["@c0823"]},{"id":"tieu-tu-di-kim-cuong-tran","name":"Tiểu tu di kim cương trận","cn":"小须弥金刚阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Phật tông","soHuu":[],"blurb":"Phật tông pháp trận, ký hiệu ẩn hiện trên vách tường bốn phía đại sảnh chứa linh dược, dùng làm bẫy bảo vệ bảo vật.","detail":"Một pháp trận thuộc Phật tông, được bố trí bằng các ký hiệu ẩn hiện trên vách tường bốn phía của đại sảnh dưới lòng đất — nơi bày sáu bảy thứ linh dược quý hiếm bao gồm Thiên nguyên quả, tử sắc linh chi ngàn năm tuổi và Kim Lôi Trúc. Trận pháp đóng vai trò bẫy bảo vệ, ngăn người xâm nhập lỗ mãng lấy bảo vật. Lỗ Vệ Anh nhận ra trận pháp này từ các ký hiệu trên vách tường và cảm thấy bất ngờ vì gặp Phật tông pháp trận ở nơi mà bên ngoài là cấm chế tà môn Huyết Chú chi môn, gợi ý lai lịch phức tạp của bảo tàng.","nguon":["@c0823"]},{"id":"huyen-thuat-ngan-nguyet","name":"Huyễn thuật Ngân Nguyệt","cn":null,"loai":"bi-thuat","loaiLabel":"Huyễn thuật","phamCap":"Không rõ","hePhai":null,"soHuu":["Ngân Nguyệt"],"blurb":"Huyễn thuật riêng của Ngân Nguyệt, phun sương mù đỏ biến toàn bộ cảnh quan thành hình ảnh khác. Không phải pháp trận cấm chế, chỉ tồn tại trong hai ngày.","detail":"Ngân Nguyệt phun sương mù màu đỏ từ miệng, sương mù vô ảnh vô hình lan ra che phủ toàn bộ khu vực (ví dụ cả ngọn núi), biến hình cảnh quan thành hình ảnh hoàn toàn khác (rừng rậm thay thế ngọn núi). Cần kết hợp với khí cụ bày trận để tăng hiệu quả. Hạn chế: chỉ tồn tại tối đa hai ngày, không chắc lừa được thần thức Nguyên Anh tu sĩ.","congNang":["Biến đổi hình ảnh địa hình, che khuất cảnh quan thật bằng ảo ảnh"],"dacDiem":"Thời hạn tối đa hai ngày, cần khí cụ bày trận hỗ trợ, không đảm bảo lừa được thần thức Nguyên Anh tu sĩ","nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0828","tangDatToi":null,"trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0828","loai":"thi triển","importance":"normal","giaiDoan":"Che khuất phi điểu sơn phong","text":"Ngân Nguyệt dùng hai bộ khí cụ bày trận tạo sương mù trắng che hơn nửa ngọn núi, sau đó phun sương mù đỏ biến toàn bộ ngọn núi thành rừng rậm ảo, che giấu tiêu ký phi điểu sơn phong.","anchor":"Cả ngọn núi phụ cận đột nhiên vặn vẹo biến hình một trận, rồi bỗng biến mất không nhìn thấy đâu nữa"}]},"nguon":["@c0828"]},{"id":"mat-quy-tren-lung","name":"Mặt quỷ trên lưng","cn":"","aliases":["Thôn Anh"],"loai":"than-thong","loaiLabel":"Thần thông tà thuật","phamCap":"","hePhai":"Ma đạo","soHuu":["Nam Lũng Hầu"],"blurb":"Mặt quỷ hiện trên sống lưng thân ma hóa của Nam Lũng Hầu, có khả năng phun lưỡi tử sắc xuyên trán và nuốt Nguyên Anh đối thủ.","detail":"Thần thông này biểu hiện bằng một mặt quỷ mọc trên sống lưng, giống bộ mặt quỷ trên Huyết Chú chi môn. Khi Lỗ Vệ Anh cho Nguyên Anh xuất khiếu bỏ chạy, mặt quỷ mở mắt với con ngươi ngân bạch, phun ra lưỡi tử sắc dài hơn một thước xuyên thủng trán Nguyên Anh, khiến nó mất hết khí lực rồi cuốn nuốt trọn. Đây là thủ đoạn thôn Nguyên Anh gắn với trạng thái ma hóa của Nam Lũng Hầu.","nguon":["@c0830"]},{"id":"cam-che-truy-ma-coc-tia-chop-do","name":"Cấm chế Trụy Ma Cốc","cn":"","aliases":["Tia chớp đỏ Trụy Ma Cốc"],"loai":"khac","loaiLabel":"Trận pháp · Cấm chế","phamCap":"","hePhai":"","soHuu":[],"blurb":"Cấm chế trong Trụy Ma Cốc phóng ra vô số tia chớp đỏ như máu khi bị kích động.","detail":"Khi Nam Lũng Hầu bay lên cao khoảng trăm trượng trên ngọn núi đá, cấm chế Trụy Ma Cốc bị kích động và phóng xuống vô số tia chớp đỏ như máu. Tuy nhiên các tia chớp đều bị chệch đi khi còn cách hắn khoảng một trượng, khiến hắn bình yên vô sự, cho thấy cấm chế này không thể chế trụ thân ma hóa của hắn ở thời điểm đó.","nguon":["@c0830"]},{"id":"cam-che-pham-vi-lon-gan-te-dan","name":"Cấm chế phạm vi lớn gần tế đàn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp · Cấm chế","phamCap":"","hePhai":"","soHuu":[],"blurb":"Lớp cấm chế diện rộng nằm cách tế đàn hơn mười dặm, làm đoàn Quỷ Linh Môn chậm hơn nửa ngày.","detail":"Trên đường đến tế đàn, đoàn Quỷ Linh Môn gặp một cấm chế phạm vi lớn ở vị trí cách tế đàn hơn mười dặm. Họ phải phá cấm chế này mới có thể tiếp tục đi tới, khiến hành trình chậm hơn dự định hơn nửa ngày.","nguon":["@c0830"]},{"id":"cam-che-trong-luc-tren-cau-thang-te-dan","name":"Cấm chế trọng lực trên cầu thang tế đàn","cn":"","aliases":["Cấm chế cầu thang tế đàn"],"loai":"khac","loaiLabel":"Trận pháp · Cấm chế","phamCap":"","hePhai":"","soHuu":[],"blurb":"Cấm chế trên cầu thang tế đàn phát ra hoàng quang, tạo áp lực nặng như ngàn cân lên người bước vào.","detail":"Khi đoàn Quỷ Linh Môn bước lên cầu thang tế đàn, hoàng quang lóe lên và thân hình người tiến vào bị đè nặng, hai vai như chịu sức nặng ngàn cân. Ngụy Vô Nhai gần như không bị ảnh hưởng, trong khi ba đệ tử Kết Đan Quỷ Linh Môn run rẩy, sắc mặt trắng bệch, cho thấy hiệu quả cấm chế có liên quan rõ tới tu vi người xâm nhập.","nguon":["@c0830"]},{"id":"liem-tuc-bien-hinh","name":"Liễm tức biến hình","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ thú vô danh","soHuu":["Cổ thú vô danh"],"blurb":"Thần thông ẩn nặc và biến hóa của cổ thú vô danh bên hồ Linh Chúc Quả.","detail":"Khi thi triển, cổ thú có thể biến hóa ẩn nặc tới mức tu sĩ Nguyên Anh hậu kỳ cũng khó phát hiện. Sở trường của thần thông này là che giấu khí tức và lẩn tránh thần thức, nhưng cổ thú bị Thanh Minh Linh Nhãn nhìn thấu nên không phát huy được ưu thế.","thuocTinh":"Ẩn nặc, biến hóa","uyLuc":"Có thể khiến tu sĩ Nguyên Anh hậu kỳ cũng không phát hiện được khi cổ thú thi triển.","dacDiem":"Mạnh về liễm tức và che giấu tung tích, không trực tiếp thể hiện sức chiến đấu mạnh.","congNang":["Biến hóa ẩn nặc và lẩn tránh thần thức ở mức rất cao @c0831"],"nguoiTu":[{"ten":"Cổ thú vô danh","tuChuong":"@c0831","tangDatToi":"Không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0831","loai":"xuất hiện","importance":"normal","giaiDoan":"Cổ thú thủ hộ Linh Chúc Quả","text":"Sau khi cổ thú bị tiêu diệt, Hàn Lập nhận ra thần thông chủ yếu của nó là liễm tức biến hình chứ không phải chính diện giao chiến.","anchor":"Khi thi triển thần thống, nó có thể biến hóa ẩn nặc, cho dù tu sĩ Nguyên Anh hậu kỳ cũng không thể phát hiện được"}]},"trangThai":"Đã lộ diện","capNhatToi":"@c0831","nguon":["@c0831"]},{"id":"kinh-hon-chu","name":"Kinh Hồn Chú","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Mật chú Quỷ Linh Môn","hePhai":"Quỷ Linh Môn","soHuu":["Môn chủ Quỷ Linh Môn"],"blurb":"Mật chú ác độc của Quỷ Linh Môn, được Môn chủ Quỷ Linh Môn dùng huyết sắc lệnh bài kích phát để khống chế và hành hạ nho sinh. Bí thuật này được nhận xét còn ác độc hơn Cấm Thần thuật ba phần.","detail":"Kinh Hồn Chú là một trong các mật chú của Quỷ Linh Môn. Người hạ chú có thể thông qua huyết sắc lệnh bài kích phát chú lực, khiến phù văn đỏ xuất hiện khắp thân thể đối tượng, gây đau đớn dữ dội; hồn phách của người trúng chú có thể bị diệt chỉ bằng một ý niệm của người hạ chú. Trong chương này, Môn chủ Quỷ Linh Môn dùng Kinh Hồn Chú trừng phạt nho sinh là phân thần hóa thân của Thương Khôn Thượng Nhân, buộc hắn phải ngoan ngoãn dẫn đường. Về sau trong không gian xám, Môn chủ tiếp tục kích phát chú này khi nho sinh bỏ trốn, nhưng chú lực chỉ khiến hắn khựng lại trong chốc lát rồi mất hiệu quả đau đớn, cho thấy nho sinh đã có thể kháng lại sự khống chế của mật chú trong hoàn cảnh đó.","nguon":["@c0834"]},{"id":"luc-sac-doc-vu","name":"Lục sắc độc vụ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Ngụy Vô Nhai"],"blurb":"Sương mù độc sáu màu do Ngụy Vô Nhai bắt quyết toát ra, cuồn cuộn bao phủ toàn thân để phòng ngự khi lâm nguy.","detail":"Khi nhận ra nho sinh chính là Cổ ma trong không gian giao giới Nhân giới với Thánh giới, Ngụy Vô Nhai vội vàng hai tay bắt quyết, lục sắc độc vụ trên người cuồn cuộn toát ra đem thân thể bao phủ ở trong đó làm lớp phòng thân tức thời.","nguon":["@c0835"]},{"id":"giai-the-hoa-hinh","name":"Giải Thể Hóa Hình","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật vô thượng trong ma công","hePhai":"Ma công thượng cổ","soHuu":["Nho sinh"],"blurb":"Bí thuật ma công vô thượng được nho sinh thi triển trong nơi phong ấn ma thể. Thuật này mượn lực từ ma thể bị phong ấn để ngưng kết lại thân xác thực thể cho quỷ đầu.","detail":"Giải Thể Hóa Hình được Vương Thiên Cổ nhận ra là bí thuật vô thượng trong ma công. Khi thi triển, quỷ đầu kích hoạt ma thể bị phong ấn, để hai đạo quang trụ đỏ từ mắt ma thể bao bọc bản thân trong huyết tráo, khiến vô số hồng quang li ti ngưng thành huyết ti, da thịt và xương cốt đỏ yêu dị, còn ma thể bị phong ấn thì nhỏ dần.","thuocTinh":"Ma công","nguonGoc":"Ma công thượng cổ","uyLuc":"Có thể hút lực từ ma thể bị phong ấn để tái tạo thân thể thực thể cho hồn phách quỷ đầu.","dacDiem":"Khi vận chuyển, ma thể phát ô quang và huyết mang, quỷ đầu được huyết tráo bảo hộ trong lúc thân thể mới thành hình.","congNang":["Hút năng lượng từ ma thể bị phong ấn để ngưng kết thành thân thể thực thể mới cho hồn phách @c0836"],"nguoiTu":[{"ten":"Nho sinh","tuChuong":"@c0836","tangDatToi":"Thi triển tạo thân thể mới","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0836","loai":"xuất hiện","importance":"major","giaiDoan":"Tái tạo thân xác","text":"Nho sinh trong hình thái quỷ đầu thi triển Giải Thể Hóa Hình, hút lực từ ma thể bị phong ấn để ngưng tụ thân thể thực thể mới.","anchor":"Giải Thể Hóa Hình! Đây là loại bí thuật vô thượng trong ma công!"}]},"dinhDanh":"goc","trangThai":"đang thi triển @c0836","capNhatToi":"@c0836","nguon":["@c0836"]},{"id":"thuat-an-than-thanh-ha","name":"Thuật ẩn thân thanh hà","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông ẩn nặc Hàn Lập thi triển trong Trụy Ma Cốc để che giấu cả mình và Tử Linh.","detail":"Khi phát hiện hai đạo độn quang bị truy sát và lo ngại gặp cao thủ Mộ Lan, Hàn Lập bắt quyết khiến một mảng thanh hà hiện trên đầu hai người rồi hạ xuống. Sau đó thân ảnh Hàn Lập và Tử Linh mờ dần, biến mất vô ảnh vô tung.","thuocTinh":"ẩn nặc","uyLuc":"Có thể che giấu đồng thời Hàn Lập và Tử Linh trong tình huống ma hồn truy sát gần đó.","dacDiem":"Biểu hiện thành thanh hà phủ xuống trước khi thân ảnh biến mất.","congNang":["Ẩn nặc thân hình người được bao phủ @c0838"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0838","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0838","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn nặc trước ma hồn","text":"Hàn Lập thi triển thanh hà bao phủ mình và Tử Linh, khiến cả hai biến mất để tránh lộ diện trước cuộc truy sát.","anchor":"một mảng thanh hà bỗng nhiên xuất hiện trên đầu hai người, nhẹ nhàng hạ xuống"}]},"capNhatToi":"@c0838","nguon":["@c0838"]},{"id":"thu-phap-thu-bang-diem-vao-co-the","name":"Thủ pháp thu băng diễm vào cơ thể","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật vận dụng băng diễm do Hàn Lập cảm ngộ trong huyễn cảnh, dùng để thu băng diễm vào cơ thể.","detail":"Sau khi khí lãng qua đi, Hàn Lập phất tay thu lam sắc băng sơn thành hỏa diễm rồi dung nhập vào lòng bàn tay. Đây là phương pháp hắn hiểu ra từ cảm ngộ trong huyễn cảnh, lần đầu sử dụng nhưng điều khiển thuần thục như đã luyện tập nhiều lần.","thuocTinh":"băng diễm","nguonGoc":"Cảm ngộ trong huyễn cảnh của Hàn Lập.","uyLuc":"Giúp Hàn Lập thu phóng lam sắc băng diễm vào cơ thể một cách thuần thục.","dacDiem":"Liên quan đến thiên địa lĩnh ngộ, khiến Hàn Lập thấy hy vọng tiến giai Nguyên Anh trung kỳ tăng lên.","congNang":["Thu lam sắc băng diễm vào cơ thể @c0838"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0838","tangDatToi":"lần đầu thi triển thuần thục","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0838","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu vận dụng","text":"Hàn Lập lần đầu dùng thủ pháp cảm ngộ trong huyễn cảnh để thu băng diễm vào cơ thể và xác nhận cảm ngộ ấy có ích cho việc tiến giai.","anchor":"Loại thủ pháp đem băng diễm thu vào trong cơ thể chính là một phương pháp vận dụng nó mà hắn hiểu được nhờ cảm ngộ khi chìm trong huyễn cảnh"}]},"capNhatToi":"@c0838","nguon":["@c0838"]},{"id":"hac-mang-di-chuyen-quy-di","name":"Hắc mang di chuyển quỷ dị","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ma đạo","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Nam Lũng Hầu"],"blurb":"Bí thuật di chuyển bằng hắc mang của Nam Lũng Hầu bị ma hóa, khiến Hàn Lập cũng khó dùng thần thức nhìn thấu.","detail":"Ma hồn trong thân thể Nam Lũng Hầu dùng hắc mang chợt ẩn chợt hiện để truy sát Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông. Mỗi lần hắc mang thoáng hiện, khoảng cách với hai người phía trước lại rút ngắn rất nhanh.","thuocTinh":"ma khí","uyLuc":"Tốc độ truy đuổi rất nhanh và có thể che chắn thần thức dò xét của Hàn Lập.","dacDiem":"Hắc mang phiêu hốt, chợt ẩn chợt hiện.","congNang":["Di chuyển truy kích tốc độ cao @c0838","Khiến thần thức Hàn Lập không xuyên thấu được @c0838"],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0838","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0838","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Nguyên Anh","text":"Nam Lũng Hầu bị ma hóa dùng hắc mang quỷ dị truy đuổi hai tu sĩ Nguyên Anh và khiến Hàn Lập không thể nhìn thấu bằng thần thức.","anchor":"không biết hắc mang kia là công pháp bí thuật nào mà với tu vi của mình, Hàn Lập cũng không thể dùng thần thức xuyên thấu qua"}]},"capNhatToi":"@c0838","nguon":["@c0838"]},{"id":"kim-thien-thoat-xac","name":"Kim thiền thoát xác","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"khong-ro","hePhai":"Cổ ma","soHuu":["Nam Lũng Hầu"],"blurb":"Bí thuật cổ ma dùng để để lại hóa thân giả, còn bản thể lặng lẽ chuyển vị sang nơi khác. Trong chương này nó qua mặt cả thần thức của hai tu sĩ Nguyên Anh.","detail":"Nam Lũng Hầu dùng thủ đoạn này khi bị ngũ sắc quang trụ khống chế, để hóa thân tiếp tục ở lại trong vùng công kích còn bản thể âm thầm áp sát Hàn Lập. Hiệu quả của nó đủ mạnh để Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông đều không phát giác kịp.","thuocTinh":"ẩn thân, hóa thân, đánh lừa thần thức","uyLuc":"Có thể tạo hóa thân giả qua mặt thần thức tu sĩ Nguyên Anh kỳ trong lúc bản thể tiến hành tập kích.","dacDiem":"Thi triển trong lúc bị vây hãm vẫn đổi được thật giả, rất thích hợp cho đánh lén.","congNang":["Tạo hóa thân giả để đánh lừa đối phương trong khi bản thể lặng lẽ hành động."],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0839","tangDatToi":"khong-ro","trangThai":"dang-su-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0839","loai":"thi triển","importance":"major","giaiDoan":"Dùng để đánh lén Hàn Lập","text":"Nam Lũng Hầu để lại hóa thân trong quang trụ rồi dùng bản thể âm thầm áp sát Hàn Lập.","anchor":"Nhưng Nam Lũng Hẫu lại thi triển kế kim thiền thoát xác, khiến cho đối phương thần không biết, quỷ không hay"}]},"nguon":["@c0839"]},{"id":"an-hinh-thuat-cua-co-ma","name":"Ẩn hình thuật của cổ ma","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Ma công","soHuu":["Nam Lũng Hầu"],"blurb":"Ẩn hình thuật được cổ ma trong thân xác Nam Lũng Hầu sử dụng khi giao chiến với Hàn Lập.","detail":"Khi thi triển, cổ ma dậm chân biến mất cùng tàn ảnh, khiến thần thức Hàn Lập không thể dò ra tung tích. Thủ đoạn này chỉ bị Hàn Lập phát hiện nhờ Minh Thanh Linh Nhãn.","thuocTinh":"ẩn thân, ma công","uyLuc":"Có thể tránh khỏi thần thức dò xét thông thường của Hàn Lập trong trận đấu.","dacDiem":"Bị Minh Thanh Linh Nhãn khắc chế khi Hàn Lập nhìn ra vị trí thật.","congNang":["Ẩn giấu thân hình khiến thần thức khó truy ra tung tích trong giao chiến @c0840"],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0840","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0840","loai":"thi triển","importance":"normal","giaiDoan":"Sơ đấu Ma Hồn","text":"Cổ ma dùng ẩn hình thuật biến mất khỏi cảm ứng thần thức của Hàn Lập, buộc Hàn Lập phải dùng Minh Thanh Linh Nhãn mới phát hiện được.","anchor":"dùng thần thức dò xét xung quanh nhưng căn bản không tìm được tung tích đối phương"}]},"capNhatToi":"@c0840","nguon":["@c0840"]},{"id":"hac-hong-ma-diem","name":"Hắc hồng ma diễm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Ma công","soHuu":["Nam Lũng Hầu"],"blurb":"Ma diễm hắc hồng do cổ ma phun ra để đối kháng Ích Tà Thần Lôi của Hàn Lập.","detail":"Ma diễm này va chạm trực diện với kim hồ Ích Tà Thần Lôi rồi cùng hóa thành khói xanh biến mất. Sau khi dùng, sắc mặt cổ ma thoáng trắng bệch, cho thấy thủ đoạn này tiêu hao tinh nguyên linh lực rất lớn.","thuocTinh":"hắc hồng hỏa diễm, ma công","uyLuc":"Triệt tiêu được kim hồ Ích Tà Thần Lôi trong lần giao phong ở @c0840.","dacDiem":"Uy lực mạnh nhưng tiêu hao tinh nguyên linh lực của người dùng.","congNang":["Đối kháng và triệt tiêu Ích Tà Thần Lôi trong va chạm trực diện @c0840"],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0840","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0840","loai":"thi triển","importance":"normal","giaiDoan":"Sơ đấu Ma Hồn","text":"Cổ ma phun hắc hồng ma diễm để đối kháng Ích Tà Thần Lôi, khiến cả ma diễm và kim hồ cùng hóa khói tiêu tán.","anchor":"hỏa diễm cùng kim hồ va chạm vào nhau giống như nước với lửa, cả hai đều hóa thành khói xanh biến mất"}]},"capNhatToi":"@c0840","nguon":["@c0840"]},{"id":"ma-cong-o-ue-co-bao","name":"Ma công ô uế cổ bảo","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Nam Lũng Hầu"],"blurb":"Ma hồn dùng hắc dịch như mực phun lên cổ bảo của đối phương để ô uế và cưỡng đoạt bảo vật.","detail":"Khi giao chiến, Ma hồn phun hắc dịch lên Minh Dương Hoàn, khiến cổ bảo biến đổi, cắt đứt liên lạc giữa Lệnh Hồ lão tổ và bảo vật rồi bị hắn chiếm dụng.","thuocTinh":"ma khí ô uế","uyLuc":"Có thể cắt đứt liên hệ của chủ nhân với cổ bảo trong giao chiến.","dacDiem":"Biểu hiện bằng hắc dịch như mực, khiến bảo vật bị ô uế chuyển đen và lóe ô quang yêu dị.","congNang":["Ô uế cổ bảo của đối phương và hỗ trợ cưỡng đoạt quyền sử dụng @c0842"],"nguoiTu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0842","tangDatToi":"không rõ","trangThai":"đang thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0842","loai":"thi triển","importance":"normal","giaiDoan":"Cưỡng đoạt cổ bảo","text":"Ma hồn phun hắc dịch như mực lên Minh Dương Hoàn để ô uế cổ bảo trong lúc giao chiến.","anchor":"phun ra một chất dịch màu đen như mực lên trên cự hoàn"}]},"capNhatToi":"@c0842","nguon":["@c0842"]},{"id":"phuc-thi-doc-van","name":"Phúc Thi Độc Vân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độc công","phamCap":"không rõ","hePhai":"Ngụy Vô Nhai","soHuu":["Ngụy Vô Nhai"],"blurb":"Độc công của Ngụy Vô Nhai, khi thi triển hóa thành lục sắc vân vụ rộng lớn. Tu sĩ bình thường dính phải có thể chết ngay.","detail":"Trong trận chiến ở trung tâm nội cốc Trụy Ma cốc, Ngụy Vô Nhai dùng Phúc Thi Độc Vân đối đầu ma vật. Lục sắc vân vụ có thanh thế lớn, rộng vài mẫu, nhưng vẫn bị hắc tử quang mang chứa ma khí áp chế xuống phía dưới.","thuocTinh":"độc","uyLuc":"Tu sĩ bình thường dính phải là chết ngay, nhưng trong lần giao chiến này bị ma vật áp chế.","dacDiem":"Biến thành vân vụ kịch độc màu lục có phạm vi lớn.","congNang":["Biến thành lục sắc vân vụ kịch độc để công kích và áp chế đối thủ."],"nguoiTu":[{"ten":"Ngụy Vô Nhai","tuChuong":"@c0843","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0843","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu ma vật","text":"Ngụy Vô Nhai thi triển Phúc Thi Độc Vân thành lục sắc vân vụ rộng lớn, nhưng bị hắc tử quang mang của ma vật ép xuống.","anchor":"Phúc Thi Độc Vân! Đó là độc công biến thành vân vụ của Ngụy đạo hữu, tu sĩ bình thường dính phải là chết ngay lập tức"}]},"capNhatToi":"@c0843","nguon":["@c0843"]},{"id":"ma-quang-hac-tu","name":"Ma quang hắc tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma tộc","phamCap":"không rõ","hePhai":"Ma tộc","soHuu":["Nho sinh"],"blurb":"Ma quang hắc tử là thủ đoạn diện rộng do Cổ ma phát động trong Trụy Ma Cốc. Ma quang bao trùm phạm vi lớn và có thể hấp thu pháp lực tu sĩ qua vòng bảo hộ.","detail":"Cổ ma xoay tròn phóng ra hắc tử quang mang bành trướng khắp bốn phương, khiến vùng trời phụ cận nhuốm màu yêu dị. Ma quang bao trùm phương viên hơn mười dặm, trực tiếp rút pháp lực qua vòng bảo hộ với mức độ nhỏ nhưng liên tục, bị điện hồ Thần Lôi của Hàn Lập đẩy lùi vài tấc và ngăn hấp thu.","thuocTinh":"ma khí hắc tử","uyLuc":"Bao trùm diện rộng hơn mười dặm và bào mòn pháp lực tu sĩ.","dacDiem":"Bị lôi điện khắc chế rõ rệt khi gặp điện hồ của Hàn Lập.","congNang":["Bao trùm chiến trường phạm vi lớn và áp chế tu sĩ bên trong @c0845","Trực tiếp hấp thu pháp lực qua vòng bảo hộ với tốc độ nhỏ nhưng liên tục @c0845"],"nguoiTu":[{"ten":"Nho sinh","tuChuong":"@c0845","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0845","loai":"thi triển","importance":"normal","giaiDoan":"Bao phủ chiến trường","text":"Cổ ma phát động ma quang hắc tử bao trùm phương viên hơn mười dặm, khiến các tu sĩ phải lập tức phòng thủ và tìm cách khắc chế khả năng hấp thu pháp lực.","anchor":"hắc tử quang mạc này lại có thể trực tiếp hấp thu pháp lực của tu sĩ"}]},"capNhatToi":"@c0845","nguon":["@c0845"]},{"id":"phep-an-hinh-cua-ma-hon","name":"Phép ẩn hình của Ma hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma tộc","phamCap":"không rõ","hePhai":"Ma tộc","soHuu":["Ma hồn"],"blurb":"Phép ẩn hình của Ma hồn là thủ đoạn biến mất quỷ dị trong lúc ma quang Cổ ma bùng phát. Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông đều không chắc có thể phá giải.","detail":"Khi song ma phát động tấn công, Ma hồn không né tránh ma quang mà thân hình thoáng động rồi biến mất vô tung vô ảnh. Thủ đoạn này khiến các tu sĩ phải dè chừng vì khó xác định vị trí của hắn trong chiến trường bị ma quang bao phủ.","thuocTinh":"ẩn hình ma tộc","uyLuc":"Ẩn thân hoàn toàn trước mắt các tu sĩ Nguyên Anh trong tình thế hỗn chiến.","dacDiem":"Quỷ dị, khó bị Lệnh Hồ lão tổ và Đại trưởng lão Yểm Nguyệt Tông phá giải.","congNang":["Ẩn hình biến mất vô tung vô ảnh trong chiến đấu @c0845"],"nguoiTu":[{"ten":"Ma hồn","tuChuong":"@c0845","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0845","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn thân trong ma quang","text":"Ma hồn dùng phép ẩn hình biến mất vô tung vô ảnh, khiến nhóm tu sĩ khó nắm bắt hướng tấn công tiếp theo.","anchor":"phép ẩn hình rất quỷ dị của Ma hồn kia, hai người bọn họ cũng không có nắm chắc phá được"}]},"capNhatToi":"@c0845","nguon":["@c0845"]},{"id":"ham-ba-ma-cong","name":"Hám Ba ma công","cn":null,"loai":"bi-thuat","loaiLabel":"Ma công","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Ma hồn"],"blurb":"Ma hồn dùng đầu ác quỷ phun sóng khí đen của môn ma công này để đánh rơi Phệ Kim Trùng. Tuy vậy đàn trùng chưa trưởng thành chỉ bị ảnh hưởng nhất thời rồi tự hồi phục.","detail":"Trong trận chiến với Hàn Lập, Ma hồn tự xưng môn công pháp này là Hám Ba ma công của mình. Sóng khí đen do nó tạo ra có thể làm linh trùng mất khống chế và rơi xuống, nhưng trước Phệ Kim Trùng chưa trưởng thành vẫn không đủ sức triệt sát hoàn toàn.","thuocTinh":"Sóng khí đen","uyLuc":"Có thể làm linh trùng mất tự chủ trong chốc lát.","dacDiem":"Tác dụng rõ lên Phệ Kim Trùng chưa trưởng thành nhưng không diệt được chúng.","congNang":["Phun sóng khí đen đánh rơi linh trùng khỏi không trung."],"nguoiTu":[{"ten":"Ma hồn","tuChuong":"@c0846","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0846","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu lộ tên","text":"Ma hồn dùng Hám Ba ma công phun sóng khí đen đánh rơi Phệ Kim Trùng, nhưng đàn trùng nhanh chóng tự hồi phục.","anchor":"Đám phi trùng kia không sợ Hám Ba ma công của bổn tôn"}]},"capNhatToi":"@c0846","nguon":["@c0846"]},{"id":"ma-cong-thanh-gioi-chien-giap-vay-den","name":"Ma công Thánh giới","aliases":["Ma công Thánh giới (chiến giáp vảy đen)"],"cn":null,"loai":"bi-thuat","loaiLabel":"Ma công","phamCap":"Không rõ","hePhai":"Thánh giới","soHuu":["Ma hồn"],"blurb":"Ma hồn bộc phát một loại ma công đến từ Thánh giới, khiến thân thể hiện ra tầng vảy đen như chiến giáp. Môn công này đi kèm hắc mang, sóng khí dữ dội và khí thế tăng vọt.","detail":"Khi quyết chiến với Hàn Lập, Ma hồn kết pháp quyết cổ quái, phun hắc mang chói mắt rồi chấn động không gian bằng tiếng thét của hai đầu. Kết quả rõ nhất là trên thân xuất hiện một tầng vảy cứng màu đen bóng loáng như chiến giáp, biểu hiện năng lực phòng ngự và áp chế tăng mạnh.","thuocTinh":"Ma khí Thánh giới","uyLuc":"Đánh tan quang trụ của khôi lỗi và ép lui Phệ Kim Trùng.","dacDiem":"Biểu hiện thành tầng vảy cứng đen bóng bao phủ toàn thân như chiến giáp.","congNang":["Bộc phát ma khí mạnh, tăng khí thế và năng lực phòng hộ thân thể.","Phát sóng khí dữ dội làm xiêu vẹo Phệ Kim Trùng và phá quang trụ khôi lỗi."],"nguoiTu":[{"ten":"Ma hồn","tuChuong":"@c0846","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0846","loai":"thi triển","importance":"major","giaiDoan":"Bộc phát chiến giáp","text":"Ma hồn thi triển ma công Thánh giới, phun hắc mang, chấn động không gian rồi hiện ra tầng vảy đen như chiến giáp trên toàn thân.","anchor":"Một tầng vảy cứng dài, màu đen bóng loáng, cực kỳ cổ quái giống như chiến giáp xuất hiện trên thân thể Ma hồn"}]},"capNhatToi":"@c0846","nguon":["@c0846"]},{"id":"dai-canh-kiem-tran","name":"Đại Canh Kiếm trận","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kiếm trận của Hàn Lập, trong chương này được nhắc tới như thủ đoạn khó kịp bố trí trước tốc độ của Ma hồn.","detail":"Hàn Lập nhận định tốc độ gần như thuấn di của Ma hồn khiến việc bố trí Đại Canh Kiếm trận trở nên rất khó khăn trong thế đối đầu trực diện.","congNang":["Dùng để bố trí kiếm trận đối địch, nhưng cần điều kiện triển khai đủ thời gian và khoảng cách @c0847"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0847","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0847","loai":"nhắc tới","importance":"bridge","giaiDoan":"Đối đầu Ma hồn","text":"Hàn Lập nhận ra rất khó bố trí Đại Canh Kiếm trận trước tốc độ gần như thuấn di của Ma hồn.","anchor":"muốn bố trí Đại Canh Kiếm trận là một việc rất khó khăn"}]},"capNhatToi":"@c0847","nguon":["@c0847"]},{"id":"ma-am","name":"Ma âm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / ma công","phamCap":"Không rõ","hePhai":"Thánh giới","soHuu":["Ma hồn"],"blurb":"Thần thông sóng âm màu đen do Ma hồn thi triển để phong tỏa và phá hủy mục tiêu.","detail":"Ma hồn há mồm phun ra vòng tròn sóng âm màu đen, bao vây toàn bộ Phệ Kim trùng tam sắc rồi khiến chúng nổ tung và bị diệt sạch.","thuocTinh":"Sóng âm màu đen","uyLuc":"Có thể bao vây và phá hủy cả đám Phệ Kim trùng tam sắc trong một lần thi triển.","dacDiem":"Biểu hiện thành vòng tròn sóng âm đen từ miệng Ma hồn.","congNang":["Sóng âm phong tỏa mục tiêu trong phạm vi bao vây @c0847","Phá hủy thực thể bị bao trong vòng sóng âm, khiến Phệ Kim trùng tam sắc tự nổ tung @c0847"],"nguoiTu":[{"ten":"Ma hồn","tuChuong":"@c0847","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0847","loai":"thi triển","importance":"normal","giaiDoan":"Diệt Phệ Kim trùng tam sắc","text":"Ma hồn thi triển Ma âm, dùng vòng sóng âm màu đen bao vây và phá hủy toàn bộ Phệ Kim trùng tam sắc.","anchor":"há mồm phun ra một vòng tròn sóng âm màu đen, đem toàn bộ tam sắc trùng vân bao vây vào trong"}]},"capNhatToi":"@c0847","nguon":["@c0847"]},{"id":"hac-nhan","name":"Hắc Nhận","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Ma hồn"],"blurb":"Chiêu thức hắc sắc quang nhận do Ma hồn ngưng tụ, có thể chém phóng đao mang và hợp nhất thành cự nhận.","detail":"Ma hồn dùng bốn tay xé hai quang đoàn ô mang thành bốn phần, tạo bốn thanh quang nhận dài khoảng hai thước, cong như ngưu đao; khi rung động khiến không gian xung quanh vặn vẹo, biến dạng. Bốn nhận có thể hợp thành một hắc sắc cự nhận dài khoảng một trượng, đủ sức chẻ đôi Thiên Trọng Phong và tiêu diệt hai ác quỷ khôi lỗi trong nháy mắt; đại giá là đầu người phía sau bị rút gần nửa tinh huyết, trắng bệch đau đớn.","nguon":["@c0848"]},{"id":"hang-linh-thuat","name":"Hàng Linh Thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông được Hàn Lập thi triển cùng Hàng Linh Phù, có thể giải trừ bằng huyết quang để phù lục bay ra khỏi cơ thể.","detail":"Sau khi Ma hồn bị ngân sắc hỏa diễm diệt sát trong mảnh Linh Miểu Viên, Hàn Lập giải trừ Hàng Linh Thuật, huyết quang hiện lên và một đạo huyết sắc phù lục bay ra. Việc này cho thấy thuật liên hệ trực tiếp với Hàng Linh Phù và có thể thu hồi sau khi thi triển.","dinhDanh":"goc","congNang":["Kết hợp với Hàng Linh Phù để Hàn Lập duy trì trạng thái thi triển thuật, sau đó có thể giải trừ bằng huyết quang @c0852"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0852","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0852","loai":"thi triển","importance":"normal","giaiDoan":"Giải trừ sau trận với Ma hồn","text":"Hàn Lập giải trừ Hàng Linh Thuật sau khi Ma hồn bị diệt, huyết quang hiện lên và phù lục bay ra khỏi cơ thể.","anchor":"huyết quang chợt hiện giải trừ Hàng Linh Thuật, một đạo huyết sắc phù lục trong cơ thể bay ra"}]},"capNhatToi":"@c0852","nguon":["@c0852"]},{"id":"kiem-lam-bang-diem","name":"Kiềm lam Băng Diễm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông băng hàn","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông băng hàn của Hàn Lập, được xếp cùng Tử La Thiên Hỏa là loại thần thông lạnh vô cùng. Tuyết Phách Hoàn có thể hỗ trợ xúc tiến uy lực của thần thông này.","detail":"Trong khi xem xét công dụng Tuyết Phách Hoàn, Hàn Lập nhận ra loại linh đan phụ trợ công pháp băng hàn này có thể dùng để tăng uy lực Kiềm lam Băng Diễm. Chương này chưa cho thấy hắn thi triển, chỉ xác định mối liên hệ giữa đan dược và thần thông.","thuocTinh":"băng hàn","uyLuc":"Được xem là thần thông lạnh vô cùng.","dacDiem":"Có thể được Tuyết Phách Hoàn hỗ trợ tăng uy lực.","congNang":["Tạo và vận dụng băng diễm thuộc tính cực hàn; Tuyết Phách Hoàn có thể hỗ trợ xúc tiến uy lực @c0853"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0853","tangDatToi":"không rõ","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0853","loai":"nhắc tới","importance":"normal","giaiDoan":"Liên hệ Tuyết Phách Hoàn","text":"Hàn Lập xem Kiềm lam Băng Diễm là thần thông băng hàn có thể được Tuyết Phách Hoàn hỗ trợ tăng uy lực.","anchor":"Dù sao Kiềm lam Băng Diễm cùng Tử La Thiên Hỏa đều là những thần thông lạnh vô cùng"}]},"capNhatToi":"@c0853","nguon":["@c0853"]},{"id":"cam-che-duoi-dat","name":"Cấm chế dưới đất","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Không gian lạ","soHuu":[],"blurb":"Cấm chế nằm dưới mặt đất trong không gian lạ, do Ngân Nguyệt phát hiện khi dùng thổ độn dò xét. Cấm chế này đã không đầy đủ và chưa lộ đường thoát.","detail":"Ngân Nguyệt đi xuống lòng đất kiểm tra và phát hiện dưới đó có một cấm chế không hoàn chỉnh. Nàng lần theo lỗ hổng xâm nhập nhiều nơi nhưng không thấy dị thường có thể giúp Hàn Lập rời khỏi không gian.","trangThai":"không đầy đủ","dacDiem":"Có lỗ hổng để xâm nhập nhưng không dẫn tới dị thường rõ ràng.","congNang":["Ngăn trở hoặc phản hồi dò xét dưới mặt đất trong không gian lạ @c0853"],"tabs":{"tienTrinh":[{"chuong":"@c0853","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngân Nguyệt dò xét","text":"Ngân Nguyệt phát hiện cấm chế dưới đất đã không đầy đủ, theo lỗ hổng dò xét nhưng không tìm thấy lối ra.","anchor":"Phía dưới con một cái cấm chế, nhưng đã không được đầy đủ"}]},"capNhatToi":"@c0853","nguon":["@c0853"]},{"id":"cam-che-tren-khong","name":"Cấm chế trên không","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Không gian lạ","soHuu":[],"blurb":"Cấm chế gắn với vùng vân vụ mênh mông trên không trong không gian lạ. Nó từng diệt sát Ma hồn hoặc cổ ma, khiến Hàn Lập phải cân nhắc khi muốn dò đường thoát.","detail":"Sau khi bốn phía và lòng đất đều không lộ sơ hở, Hàn Lập chỉ còn vùng vân vụ trên cao để thử dò xét. Cấm chế trên không rất nguy hiểm vì trước đó đã đánh chết Ma hồn trước mắt hắn, nhưng Hàn Lập suy đoán ngân sắc hỏa diễm có thể chuyên khắc cổ ma và chưa chắc hại nhân loại tu sĩ.","uyLuc":"Có thể diệt sát cổ ma hoặc Ma hồn.","dacDiem":"Liên quan khối vân vụ mênh mông trên không và là hướng dò xét cuối cùng của Hàn Lập trong chương này.","congNang":["Diệt sát cổ ma hoặc Ma hồn bằng ngân sắc hỏa diễm @c0853"],"tabs":{"tienTrinh":[{"chuong":"@c0853","loai":"xuất hiện","importance":"normal","giaiDoan":"Dò vùng vân vụ","text":"Hàn Lập quyết định mạo hiểm dò cấm chế trên không sau khi các hướng khác không tìm thấy lối ra.","anchor":"Nếu Ngân Sắc Hỏa diễm có thể diệt sát cổ ma"}]},"capNhatToi":"@c0853","nguon":["@c0853"]},{"id":"phong-ho-chu","name":"Phong hồ chú","loai":"bi-thuat","loaiLabel":"Độc chú","phamCap":"Không rõ","hePhai":"Chú thuật","soHuu":["Nam Cung Uyển"],"blurb":"Đây là độc chú đang vây khốn Nam Cung Uyển và là áp lực khiến Hàn Lập phải tìm đường rời khỏi tàn tích Linh Miểu Viên. Chương này xác nhận bí thuật của nàng có thể trì hoãn phát tác hơn trăm năm.","detail":"Phong hồ chú là mối lo trực tiếp của Hàn Lập trong lúc bị kẹt trong không gian. Theo ngọc giản Nam Cung Uyển để lại, bí thuật nàng dùng có thể kéo dài thời gian độc chú phát tác hơn trăm năm, nên việc chậm hai ba mươi năm tạm thời vẫn còn trong giới hạn chịu đựng.","thuocTinh":"Độc chú kéo dài","uyLuc":"Có thể vây khốn Nam Cung Uyển trong thời gian dài nếu không được giải trừ.","dacDiem":"Có thể bị bí thuật trì hoãn phát tác hơn trăm năm.","congNang":["Vây khốn Nam Cung Uyển bằng độc chú kéo dài @c0854","Có thể trì hoãn phát tác hơn trăm năm nhờ bí thuật @c0854"],"nguoiTu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0854","tangDatToi":"Đang mang chú","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0854","loai":"nhắc tới","importance":"normal","giaiDoan":"Áp lực thời hạn giải chú","text":"Phong hồ chú tiếp tục là nguyên nhân khiến Hàn Lập phải tính chuyện sớm rời khỏi không gian. Ngọc giản Nam Cung Uyển để lại cho thấy bí thuật của nàng có thể trì hoãn phát tác hơn trăm năm.","anchor":"Nam Cung Uyển lưu lại ngọc giản có nói qua, nàng dùng bí thuật đại khái có thể đem thời gian độc chú phát tác trì hoãn hơn trăm năm"}]},"trangThai":"Đang được trì hoãn phát tác","capNhatToi":"@c0854","nguon":["@c0854"]},{"id":"phap-tran-phong-kin-linh-tuyen","name":"Pháp trận phong kín linh tuyền","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"Không rõ","hePhai":"Ba gia tộc Hoàng, Lý, Vương Linh Lân sơn","soHuu":["Ba gia tộc Hoàng, Lý, Vương Linh Lân sơn"],"blurb":"Pháp trận và hệ thống cấm chế dùng để phong kín lối vào linh tuyền trên chủ phong Linh Lân sơn. Ba gia tộc mười năm mới mở một lần để lấy nước linh tuyền cho đệ tử trẻ.","detail":"Khi mở trận, hơn mười tu sĩ Luyện Khí cao giai phối hợp với ba Trúc Cơ trưởng lão niệm chú, dùng pháp khí, pháp kỳ và pháp quyết tháo cấm chế phù triện trên thạch bích. Pháp trận giúp ba nhà tích trữ lượng nước linh tuyền ít ỏi trong thời gian dài.","congNang":["Phong kín lối vào linh tuyền trên thạch bích chủ phong Linh Lân sơn @c0855"],"tabs":{"tienTrinh":[{"chuong":"@c0855","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở linh tuyền","text":"Ba gia tộc vận hành nghi thức mở pháp trận phong kín linh tuyền để lộ ngọc trì phía sau thạch bích.","anchor":"Trong miệng bọn họ đọc chú ngữ liên tiếp không ngừng tiến hành nghi thức mở pháp trận"}]},"capNhatToi":"@c0855","nguon":["@c0855"]},{"id":"khe-ho-khong-gian-tren-ngoc-tri","name":"Khe hở không gian trên ngọc trì","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hiện tượng không gian","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Hiện tượng không gian đột ngột xuất hiện trên ngọc trì linh tuyền ở Linh Lân sơn. Nó ném Hàn Lập ra khỏi tàn tích Linh Miểu Viên rồi biến mất.","detail":"Trên ngọc trì trước hết vang lên tiếng sấm trầm, hiện ngũ sắc hà quang và quang cầu đen, sau đó quang cầu biến dạng thành khe hở rộng khoảng một trượng. Ngũ sắc thải hà từ khe hở ném một nhân ảnh áo xanh xuống ngọc trì, mở ra cảnh Hàn Lập trở lại Thiên Nam sau hơn hai mươi bảy năm.","congNang":["Đưa Hàn Lập từ tàn tích Linh Miểu Viên rơi xuống ngọc trì Linh Lân sơn @c0855"],"tabs":{"tienTrinh":[{"chuong":"@c0855","loai":"xuất hiện","importance":"major","giaiDoan":"Thoát thân","text":"Khe hở không gian xuất hiện trên ngọc trì, ném Hàn Lập ra ngoài rồi biến mất.","anchor":"nó bắt đầu vặn vẹo biến hình và hóa thành một cái khe hở không gian rộng tầm một trượng"}]},"capNhatToi":"@c0855","nguon":["@c0855"]},{"id":"bi-thuat-truy-tung-cua-truong-lao-ma-dao","name":"Bí thuật truy tung của trưởng lão Ma đạo","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Trưởng lão Ma đạo tông môn trước khi chết"],"blurb":"Bí thuật được một trưởng lão Ma đạo hạ lên yêu ma trước khi chết. Nhờ dấu vết này, Diệt ma đội truy tung được yêu ma tới Lạc Hồn sơn.","detail":"Bí thuật có tác dụng đánh dấu hoặc truy tung yêu ma. Nó xuất hiện trong lời kể về giai đoạn cuối của cuộc vây quét, khi yêu ma bị lần ra tung tích sau thời gian tàn sát tu sĩ và các thế lực nhỏ.","thuocTinh":"truy tung","congNang":["Giúp lần theo tung tích yêu ma sau khi bị hạ lên mục tiêu tại @c0856."],"tabs":{"tienTrinh":[{"chuong":"@c0856","loai":"thi triển","importance":"normal","giaiDoan":"trước khi trưởng lão Ma đạo chết","text":"Trưởng lão Ma đạo trước khi chết hạ bí thuật lên yêu ma, giúp Diệt ma đội truy tung nó tới Lạc Hồn sơn.","anchor":"nó cuối cùng bị một vị Ma đạo tông môn trưởng lão trước khi chết hạ bí thuật"}]},"capNhatToi":"@c0856","nguon":["@c0856"]},{"id":"bi-thuat-thoat-vay-cua-co-ma","name":"Bí thuật thoát vây của Cổ ma","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Cổ ma"],"blurb":"Bí thuật được nhắc trong tin đồn về kết cục Cổ ma sau trận vây công. Công dụng được truyền là giúp Cổ ma tìm đường sống trong chỗ chết và thoát khỏi vòng vây.","detail":"Hoàng Nguyên Minh kể rằng có tin Cổ ma không chết tại chỗ mà dùng một bí thuật khó tin để thoát vây. Chương này chỉ ghi nhận dưới dạng tin đồn, chưa xác nhận thật giả.","dinhDanh":"goc","thuocTinh":"ma đạo","uyLuc":"Có thể liên quan khả năng thoát khỏi vây công trong tình thế sinh tử, nhưng mới được nêu qua tin đồn.","dacDiem":"Chưa rõ điều kiện thi triển và cái giá phải trả.","congNang":["Giúp người thi triển tìm đường sống trong chỗ chết khi bị vây công @c0857"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c0857","tangDatToi":"không rõ","trangThai":"nghi vấn"}],"tabs":{"tienTrinh":[{"chuong":"@c0857","loai":"nhắc tới","importance":"normal","giaiDoan":"Tin đồn sau trận vây công","text":"Bí thuật được nhắc như khả năng giúp Cổ ma thoát khỏi vòng vây sau trận chiến, nhưng sự thật chưa được xác nhận.","anchor":"nhưng cũng có người nói nó sử dụng bí thuật khó tin tìm được đường sống trong chỗ chết thoát vây chạy thoát"}]},"capNhatToi":"@c0857","nguon":["@c0857"]},{"id":"ma-khi-quan-dinh","name":"Ma khí quán đỉnh","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí pháp ma hóa","phamCap":"","hePhai":"Ma đạo","soHuu":["Cổ ma cấp cao"],"blurb":"Bí pháp được Cổ ma cấp cao dùng để ma hóa tu sĩ nhân loại, khiến đối tượng trực tiếp biến thành Cổ ma.","detail":"Đại Diễn Thần Quân kể thời thượng cổ từng có một bộ phận tu sĩ bị Cổ ma cấp cao dụ dỗ dùng ma khí quán đỉnh. Sau khi bị ma hóa, những người này vẫn giữ nhân hình và thần trí, nhưng cam tâm chịu Cổ ma cấp cao sai khiến.","nguon":["@c0858"]},{"id":"cong-phap-ba-dau-sau-tay-tren-pham-thanh-chan-phien","name":"Công pháp ba đầu sáu tay trên Phạm Thánh Chân Phiến","cn":"","aliases":["Công pháp ba đầu sáu tay"],"loai":"cong-phap","loaiLabel":"Công pháp yêu tộc nghi vấn","phamCap":"","hePhai":"Yêu tộc","soHuu":["Hàn Lập"],"blurb":"Công pháp ghi trên Phạm Thánh Chân Phiến, được Hàn Lập nhận ra có nét giống thủ đoạn của Cổ ma hai đầu bốn tay.","detail":"Hàn Lập nhớ tới Phạm Thánh Chân Phiến trong túi trữ vật và liên tưởng công pháp ba đầu sáu tay trên đó với công pháp mà Cổ ma hai đầu bốn tay từng thi triển. Hắn chưa xác nhận quan hệ giữa yêu tộc và Cổ ma, cũng không định tu luyện vì trong tay chỉ có tàn phiến và chuyện này không liên quan trực tiếp tới mình.","nguon":["@c0858"]},{"id":"kiem-tran-cua-han-lap","name":"Kiếm trận của Hàn Lập","cn":"","aliases":["Kiếm trận"],"loai":"khac","loaiLabel":"Trận pháp kiếm","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kiếm trận mà Hàn Lập cần đủ phi kiếm mới có thể bố trí.","detail":"Hàn Lập nói với Đại Diễn Thần Quân rằng mình cần luyện chế thêm hai khẩu phi kiếm nữa, nếu không sẽ không thể bố trí kiếm trận. Việc này khiến hắn thúc Đại Diễn giao phương pháp luyện phiến để sắp xếp việc luyện khí tiếp theo.","nguon":["@c0858"]},{"id":"bi-thuat-cam-ung-thien-tuyet-ma-thi","name":"Bí thuật cảm ứng Thiên Tuyệt ma thi","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật khống thi cảm ứng","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật giúp Hàn Lập cảm ứng trạng thái của Thiên Tuyệt ma thi sau biến cố Trụy Ma cốc.","detail":"Sau khi thoát khỏi khe hở không gian, Hàn Lập thông qua bí thuật này xác nhận Thiên Tuyệt ma thi vẫn chưa bị tiêu diệt. Nhờ cảm ứng đó, hắn trước khi rời Đông Dụ quốc đã quay lại khu vực ngoài Trụy Ma cốc để tìm cách thu hồi ma thi.","nguon":["@c0858"]},{"id":"phap-quyet-thuc-giuc-thien-tuyet-ma-thi","name":"Pháp quyết thúc giục Thiên Tuyệt ma thi","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Pháp quyết khống thi","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp quyết Hàn Lập dùng để thúc giục và triệu hồi Thiên Tuyệt ma thi.","detail":"Hàn Lập dùng nhiều kiểu pháp quyết để thúc giục Thiên Tuyệt ma thi ra khỏi Trụy Ma cốc, nhưng ma thi tựa hồ bị nhốt ở một nơi nào đó trong cốc nên không thể xuất cốc gặp hắn. Vì vậy Hàn Lập chỉ có thể tạm gác việc cứu ma thi lại.","nguon":["@c0858"]},{"id":"dien-dao-phuong-boi-nguyen-cong","name":"Điên Đảo Phượng Bồi Nguyên Công","aliases":["Điên Phượng Bồi Nguyên Công"],"loai":"cong-phap","loaiLabel":"Song tu công pháp","phamCap":"không rõ","hePhai":"song tu","soHuu":["Mộ Phái Linh","Hàn Lập"],"blurb":"Song tu công pháp được Hàn Lập nghĩ tới khi biết Mộ Phái Linh đã đạt Giả Đan Kỳ. Công pháp này được hé lộ là vẫn hữu dụng đối với việc đột phá Nguyên Anh Hậu Kỳ.","detail":"Hàn Lập vốn từng tính đến Điên Đảo Phượng Bồi Nguyên Công trong kế hoạch liên quan Mộ Phái Linh, nhưng sau cơ duyên Trụy Ma Cốc hắn đã tự đột phá bình cảnh lên Nguyên Anh Trung Kỳ. Chương này hé lộ công pháp vẫn có ích cho đột phá Nguyên Anh Hậu Kỳ, song đòi hỏi hỏa hầu sâu hơn và nữ tu đạt Kết Đan Hậu Kỳ.","thuocTinh":"song tu","uyLuc":"Có thể hỗ trợ đột phá cảnh giới Nguyên Anh Hậu Kỳ khi điều kiện tu luyện đạt đủ.","dacDiem":"Cần hỏa hầu sâu và yêu cầu nữ tu đạt Kết Đan Hậu Kỳ mới phát huy cho mục tiêu cao hơn.","congNang":["Hỗ trợ đột phá cảnh giới, trong chương này được nhắc là có chỗ hữu dụng đối với Nguyên Anh Hậu Kỳ @c0859"],"nguoiTu":[{"ten":"Mộ Phái Linh","tuChuong":"@c0859","tangDatToi":"đang tu luyện, đã đến Giả Đan Kỳ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0859","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ tác dụng cao hơn","text":"Hàn Lập nhớ lại công pháp này khi biết Mộ Phái Linh đã đạt Giả Đan Kỳ và nhận ra nó vẫn có ích cho việc đột phá Nguyên Anh Hậu Kỳ.","anchor":"Song tu công pháp Điên Phượng Bồi Nguyên Công đối với việc đột phá cảnh giới Nguyên Anh Hậu Kỳ cũng có chỗ hữu dụng"}]},"capNhatToi":"@c0859","nguon":["@c0859"]},{"id":"cam-than-thuat","name":"Cấm thần thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Cấm thuật tác động vào thần thức, dùng để ràng buộc Mộ Phái Linh. Hàn Lập nói có thể giải trừ cấm thuật này để trả tự do cho nàng.","detail":"Trong cuộc nói chuyện với Mộ Phái Linh, Hàn Lập nêu rõ nếu nàng không muốn chuyển tu Điên Đảo Phượng Bồi Nguyên Công thì sau khi nàng tự trùng kích Kết Đan, bất luận thành bại, hắn sẽ giải trừ Cấm thần thuật trong thần thức nàng và cắt liên quan giữa hai bên.","congNang":["Khống chế hoặc ràng buộc thần thức người bị thi triển; Hàn Lập có thể giải trừ để trả tự do cho Mộ Phái Linh @c0860","Khống chế linh thú thông qua việc đối phương buông thần thức để bị đặt cấm chế @c0969"],"tabs":{"tienTrinh":[{"chuong":"@c0860","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nêu như ràng buộc có thể tháo bỏ","text":"Hàn Lập nói nếu Mộ Phái Linh không nhận điều kiện chuyển tu, hắn sẽ giải trừ Cấm thần thuật trong thần thức nàng sau khi nàng trùng kích Kết Đan.","anchor":"ta đều giải trừ Cấm thần thuật trong thần thức của nàng, trả lại tự do cho nàng"},{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Điều kiện hàng phục","text":"Hàn Lập dùng Cấm thần thuật làm ràng buộc để biến Thổ giáp long thành linh thú chịu sai sử.","anchor":"liền tự động buông thần thức, để ta thi triển cấm thần thuật trên người của ngươi"}]},"capNhatToi":"@c0860","nguon":["@c0860","@c0969"]},{"id":"kien-lam-bang-diem","name":"Kiền Lam Băng Diễm","cn":"","aliases":["Kiềm lam Băng Diễm"],"loai":"than-thong","loaiLabel":"Linh diễm thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Linh diễm mà Hàn Lập đang trong giai đoạn luyện hóa cuối cùng. Trước khi đi dự lễ Bách Xảo Viện, hắn ưu tiên luyện nốt tia cuối cùng của nó.","detail":"Ở chương này, Hàn Lập nói vẫn cần đem một tia cuối cùng của Kiền Lam Băng Diễm luyện hóa xong; điều đó cho thấy quá trình thu phục và luyện hóa loại linh diễm này đã gần hoàn tất.","thuocTinh":"băng diễm","trangThai":"đang dùng","capNhatToi":"@c0862","congNang":["Có thể được Hàn Lập luyện hóa để tăng thêm thủ đoạn chiến đấu @c0862","Phá thất sắc quang tráo phòng hộ @c0885","Là thần thông hàn diễm của Hàn Lập và được Tuyết phách hoàn hỗ trợ tinh luyện @c0932"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0862","tangDatToi":"Đang dùng","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0862","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"luyện hóa tia cuối","text":"Hàn Lập quyết định trước khi đi xem lễ phải luyện hóa xong tia Kiền Lam Băng Diễm cuối cùng.","anchor":"vẫn cần phải đem một tia cuối cùng của Kiền Lam Băng Diễm luyện hóa cho xong"},{"chuong":"@c0885","loai":"thi triển","importance":"normal","giaiDoan":"Phá quang tráo","text":"Hàn Lập dùng lượng nhỏ Kiền lam băng diễm để phá thất sắc quang tráo trên người Phong Nhạc.","anchor":"không thể dùng quá nhiều Kiền lam băng diễm"},{"chuong":"@c0932","loai":"nhắc tới","importance":"normal","giaiDoan":"Được đan dược tinh luyện","text":"Kiền lam băng diễm được Tuyết phách hoàn hỗ trợ, khiến uy lực băng hàn của Hàn Lập ngày càng tinh thuần.","anchor":"Kiền lam băng diễm và hàn khí Lục dực sương công ngày càng trở nên tinh thuần"}]},"nguon":["@c0862","@c0885","@c0932"]},{"id":"thuat-luyen-che-thuong-co-nguyen-anh-khoi-loi","name":"Thuật luyện chế thượng cổ Nguyên Anh Khôi Lỗi","cn":"","aliases":["Thượng cổ Nguyên Anh Khôi Lỗi"],"loai":"khac","loaiLabel":"Khôi lỗi thuật","phamCap":"thượng cổ","hePhai":"Đại Diễn Thần Quân","soHuu":["Hàn Lập","Đại Diễn Thần Quân"],"blurb":"Khôi lỗi thuật dùng để luyện chế khôi lỗi cấp Nguyên Anh. Đại Diễn Thần Quân cho biết khi tài liệu đã đủ thì nên luyện chế, vì thành phẩm có thể mạnh đến mức không dưới ông lúc đương thời.","detail":"Sau khi Hàn Lập nhận đủ vật liệu còn thiếu, Đại Diễn Thần Quân nhắc hắn không được quên việc luyện khôi lỗi. Theo lời ông, nếu khôi lỗi được luyện chế ra thì uy lực không dưới bản thân ông lúc còn đương thời, đủ trở thành bảo đảm tự vệ trước Cổ ma.","nguonGoc":"Đại Diễn Thần Quân nắm giữ và chỉ điểm","uyLuc":"Thành phẩm được Đại Diễn Thần Quân đánh giá có thể không dưới ông lúc đương thời","dacDiem":"Cần nhiều tài liệu hiếm, có thể luyện ra khôi lỗi cấp Nguyên Anh","trangThai":"đã đủ tài liệu để Hàn Lập chuẩn bị luyện chế","capNhatToi":"@c0862","congNang":["Luyện chế thượng cổ khôi lỗi cấp Nguyên Anh @c0862","Tạo thêm chiến lực giúp Hàn Lập tự bảo vệ khi đối mặt Cổ ma @c0862"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0862","tangDatToi":"chuẩn bị luyện chế","trangThai":"đang chuẩn bị"},{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0862","tangDatToi":"nắm phương pháp chỉ điểm","trangThai":"đang chỉ điểm"}],"tabs":{"tienTrinh":[{"chuong":"@c0862","loai":"xuất hiện","importance":"normal","giaiDoan":"đủ tài liệu","text":"Đại Diễn Thần Quân nhắc Hàn Lập đã có đủ tài liệu để luyện chế khôi lỗi và hé lộ uy lực cực cao của thành phẩm.","anchor":"Nếu như Khôi Lỗi này được luyện chế ra được thì đối với ta lúc còn đương thời nó cũng không ở dưới ta nữa"}]},"nguon":["@c0862"]},{"id":"bach-hoa-duong-xuan-quyet","name":"Bách Hoa Dương Xuân Quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"đỉnh bậc Mộc thuộc tính @c0864","hePhai":"Mộc thuộc tính","soHuu":["Minh Hĩnh"],"blurb":"Bách Hoa Dương Xuân Quyết là công pháp Mộc thuộc tính do Minh Hĩnh tu luyện. Đinh trưởng lão nhận xét đây là loại công pháp đỉnh bậc của Mộc thuộc tính.","detail":"Công pháp được nhắc trong buổi gặp tại Bách Xảo Viện khi Đinh trưởng lão giới thiệu Minh Hĩnh của Cổ Kiếm Môn. Nó gắn với hình tượng Minh Hĩnh và pháp bảo luyện từ ngàn năm Hoàng Mộc của nàng.","thuocTinh":"Mộc thuộc tính","nguoiTu":[{"ten":"Minh Hĩnh","tuChuong":"@c0864","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0864","loai":"nhắc tới","importance":"normal","giaiDoan":"Được giới thiệu","text":"Đinh trưởng lão nêu Bách Hoa Dương Xuân Quyết là công pháp Mộc thuộc tính đỉnh bậc do Minh Hĩnh tu luyện.","anchor":"mà công pháp tu luyện cũng thuộc loại đỉnh bậc của mộc thuộc tính tên gọi là Bách Hoa Dương Xuân Quyết"}]},"capNhatToi":"@c0864","nguon":["@c0864"]},{"id":"thien-hoa-quyet","name":"Thiên Hỏa quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Hỏa thuộc tính","soHuu":["Liệt Hỏa lão quái"],"blurb":"Thiên Hỏa quyết là công pháp của Liệt Hỏa lão quái. Ông tự nhận công pháp này có uy lực không nhỏ, nhưng không muốn luận bàn với Kim lão quái vì cảnh giới kém hơn.","detail":"Công pháp được nhắc khi Kim lão quái muốn cùng Liệt Hỏa lão quái luận bàn trong buổi xem lễ tại Bách Xảo Viện. Liệt Hỏa lão quái xác nhận uy lực của công pháp nhưng từ chối so tài do chênh lệch cảnh giới.","thuocTinh":"Hỏa thuộc tính","uyLuc":"Uy lực không nhỏ theo lời Liệt Hỏa lão quái.","congNang":["Dùng làm công pháp Hỏa thuộc tính của Liệt Hỏa lão quái @c0864"],"nguoiTu":[{"ten":"Liệt Hỏa lão quái","tuChuong":"@c0864","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0864","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Kim lão quái gợi luận bàn","text":"Liệt Hỏa lão quái xác nhận Thiên Hỏa quyết của mình uy lực không nhỏ nhưng từ chối luận bàn vì cảnh giới kém Kim lão quái.","anchor":"Thiên Hỏa quyết của ta uy lực không nhỏ"}]},"capNhatToi":"@c0864","nguon":["@c0864"]},{"id":"tran-man-hao-quang-lam-khai-dinh","name":"Trận màn hào quang lam khai đỉnh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Bách Xảo Viện","soHuu":["Bách Xảo Viện"],"blurb":"Trận pháp dùng trong nghi thức khai đỉnh ở Bách Xảo Viện, tạo màn hào quang lam bao phủ cự đỉnh và khu vực pháp bảo bay ra.","detail":"Hơn mười tu sĩ Kết Đan dùng trận bàn lam quang tạo màn hào quang lớn bao một nửa cự đỉnh đỏ sậm, vừa phục vụ nghi thức khai đỉnh vừa phong tỏa phạm vi để pháp bảo không dễ bay thoát.","congNang":["Tạo màn hào quang màu lam rộng lớn phong tỏa khu vực khai đỉnh @c0865"],"tabs":{"tienTrinh":[{"chuong":"@c0865","loai":"xuất hiện","importance":"normal","giaiDoan":"Khai đỉnh Càn Khôn Tháp","text":"Trận màn hào quang lam được lập khi Bách Xảo Viện bắt đầu nghi thức khai đỉnh, bao phủ cự đỉnh để pháp bảo xuất hiện trong phạm vi khống chế.","anchor":"Bụp một tiếng phát ra. Một tầng hào quang màu lam rộng lớn hiện ra ở phía trên cao."}]},"nguon":["@c0865"]},{"id":"mi-cong","name":"Mị công","cn":"","loai":"khac","loaiLabel":"Thủ đoạn mê hoặc","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Loại thủ đoạn mê hoặc tâm thần được Hàn Lập thoáng nghĩ tới khi cảm thấy hương hoa của Minh Hĩnh ảnh hưởng đến mình.","detail":"Hàn Lập ban đầu nghi Minh Hĩnh dùng mị công, nhưng tự phủ định vì hai mắt nàng trong suốt và không có dấu hiệu thi triển trực tiếp; điều này làm nổi bật thủ đoạn hương hoa kín đáo của Bách Hoa Dương Xuân quyết.","congNang":["Có thể khiến người bị tác động liên tưởng đến thủ đoạn mê hoặc tâm thần, nhưng trong tình huống này Hàn Lập xác định Minh Hĩnh không trực tiếp thi triển mị công @c0865"],"tabs":{"tienTrinh":[{"chuong":"@c0865","loai":"nhắc tới","importance":"bridge","giaiDoan":"Hàn Lập nhận ra hương hoa","text":"Hàn Lập thoáng nghi Minh Hĩnh dùng mị công rồi lập tức phủ định khi quan sát thần sắc và ánh mắt của nàng.","anchor":"Mị công? Không đúng. Tất nhiên rồi. Đối phương hai mắt trong suốt. Không có dấu hiệu thi triển mị công."}]},"nguon":["@c0865"]},{"id":"cach-am-trao","name":"Cách âm trảo","cn":"","loai":"khac","loaiLabel":"Pháp thuật cấm âm","phamCap":"không rõ","hePhai":"","soHuu":["Chí Dương Thượng Nhân"],"blurb":"Pháp thuật cách âm được Chí Dương Thượng nhân dùng khi nói riêng với Hàn Lập.","detail":"Chí Dương Thượng nhân tiện tay thả Cách âm trảo để ngăn người ngoài nghe cuộc trao đổi về Cổ ma, Ích Tà Thần Lôi và Thất Linh đảo.","congNang":["Cách âm khi trao đổi bí mật @c0866"],"nguon":["@c0866"],"tabs":{"tienTrinh":[{"chuong":"@c0866","loai":"xuất hiện","importance":"normal","giaiDoan":"Nói riêng với Hàn Lập","text":"Chí Dương Thượng nhân thả Cách âm trảo để nói chuyện riêng với Hàn Lập.","anchor":"Chí Dương Thượng nhân tiện tay thả ra một cái Cách âm trảo"}]},"capNhatToi":"@c0866"},{"id":"bi-thuat-ton-hao-nguyen-khi-cua-ba-dai-tu-si","name":"Bí thuật tổn hao nguyên khí của ba đại tu sĩ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Tam đại tu sĩ Thiên Nam","soHuu":["Chí Dương Thượng Nhân","Ngụy Vô Nhai","Hợp Hoan lão ma"],"blurb":"Bí thuật phải trả giá lớn được ba đại tu sĩ dùng trong trận cuối với Cổ ma phân hồn.","detail":"Ba đại tu sĩ Thiên Nam không tiếc đại tổn nguyên khí thi triển bí thuật này mới chém rơi hai đầu và mấy cánh tay của Cổ ma phân hồn, nhưng vẫn không thể diệt hẳn ma vật.","congNang":["Giúp ba đại tu sĩ trọng thương Cổ ma phân hồn với đại giá tổn hao nguyên khí @c0866"],"nguon":["@c0866"],"tabs":{"tienTrinh":[{"chuong":"@c0866","loai":"thi triển","importance":"normal","giaiDoan":"Trận cuối với Cổ ma phân hồn","text":"Ba đại tu sĩ thi triển bí thuật với đại giá tổn nguyên khí để trọng thương Cổ ma phân hồn.","anchor":"ba chúng ta không tiếc đại tổn Nguyên khí thi triển bí thuật"}]},"capNhatToi":"@c0866"},{"id":"yeu-dang-ba-dau-sau-tay","name":"Yêu dạng ba đầu sáu tay","cn":"","loai":"bi-thuat","loaiLabel":"Ma công biến hóa","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Cổ ma phân hồn"],"blurb":"Hình thái biến hóa của Cổ ma phân hồn, khiến tu vi bạo tăng trong trận cuối với ba đại tu sĩ.","detail":"Khi biến hóa thành yêu dạng ba đầu sáu tay, Cổ ma phân hồn khiến tu vi gần như lập tức bạo tăng gấp đôi và có thể so sánh với tu sĩ Hóa Thân sơ kỳ.","congNang":["Làm tu vi Cổ ma phân hồn bạo tăng gần gấp đôi, gần sánh Hóa Thân sơ kỳ @c0866"],"nguon":["@c0866"],"tabs":{"tienTrinh":[{"chuong":"@c0866","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Tam đại tu sĩ","text":"Cổ ma phân hồn biến hóa thành yêu dạng ba đầu sáu tay khiến tu vi bạo tăng.","anchor":"biến hóa thành yêu dạng ba đầu sáu tay khiến tu vi cơ hồ là lập tức bạo tăng gấp đôi"}]},"capNhatToi":"@c0866"},{"id":"hoa-kiem-vi-ti","name":"Hóa kiếm vi ti","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Kiếm tu thần thông","phamCap":"Không rõ","hePhai":"Cổ Kiếm Môn","soHuu":["Kim lão quái"],"blurb":"Kiếm tu thần thông giúp Kim lão quái hóa phi kiếm thành nhiều đạo kiếm ti cực mảnh để công kích.","detail":"Trong trận tỷ thí với Hàn Lập, Kim lão quái khiến kim hồng biến mất rồi hóa ra hơn trăm đạo kim ti dài mấy trượng, số lượng nhiều đến mức khiến Hàn Lập kinh ngạc.","congNang":["Hóa phi kiếm thành nhiều đạo kiếm ti cực mảnh để triển khai thế công @c0867"],"nguoiTu":[{"ten":"Kim lão quái","tuChuong":"@c0867","tangDatToi":"Thi triển trong tỷ thí","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0867","loai":"thi triển","importance":"normal","giaiDoan":"Tỷ thí ba tông","text":"Kim lão quái thi triển Hóa kiếm vi ti, biến kim hồng thành hơn trăm đạo kim ti khiến Hàn Lập kinh ngạc.","anchor":"Hàn Lập trong mắt hàn quang chợt lóe, trên mặt lộ ra vẻ kinh ngạc vì đối phương mặc dù chỉ là một kiếm tu, nhưng một lần có thể huyển hóa ra nhiều kiếm ti như vậy"}]},"capNhatToi":"@c0867","nguon":["@c0867"]},{"id":"xuan-ti-tram","name":"Xuân ti trảm","cn":"","aliases":[],"loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"Cổ Kiếm Môn","soHuu":["Kim lão quái"],"blurb":"Tuyệt chiêu sở trường của Kim lão quái, dùng kim sắc kiếm ti kết thành cự võng chụp xuống đối thủ.","detail":"Kim lão quái dùng Xuân ti trảm sau khi thi triển Hóa kiếm vi ti, khiến chúng kiếm ti hóa thành kim sắc cự võng vây chém lam sắc hỏa điểu của Hàn Lập, nhưng bị Kiền Lam Băng Diễm khắc chế.","congNang":["Dùng kim sắc kiếm ti kết thành cự võng để chụp và chém địch @c0867"],"nguoiTu":[{"ten":"Kim lão quái","tuChuong":"@c0867","tangDatToi":"Tuyệt chiêu sở trường","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0867","loai":"thi triển","importance":"normal","giaiDoan":"Tỷ thí ba tông","text":"Kim lão quái dùng Xuân ti trảm tạo kim sắc cự võng công kích lam sắc hỏa điểu, nhưng không phá được Kiền Lam Băng Diễm.","anchor":"Nhất thời linh quang cuồng hiện, chúng kiếm ti hóa thành một đạo kim sắc cự võng cuồn cuộn bắn ra hóa thành cái lồng hướng đến lam sắc hỏa Điểu phía đối diện chụp xuống."}]},"capNhatToi":"@c0867","nguon":["@c0867"]},{"id":"phong-loi-si","name":"Phong Lôi Sí","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độn thuật gắn với pháp bảo","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Năng lực độn tốc của Phong Lôi Sí giúp Hàn Lập di chuyển quỷ dị ra sau lưng Kim lão quái trong nháy mắt.","detail":"Trong trận tỷ thí, Hàn Lập dùng Phong Lôi Sí để áp sát sau lưng Kim lão quái trước khi đối thủ kịp tế thêm bảo vật, góp phần quyết định thắng bại.","congNang":["Giúp Hàn Lập di chuyển quỷ dị với tốc độ cực nhanh để áp sát sau lưng đối thủ @c0867"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0867","tangDatToi":"Vận dụng trong đấu pháp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0867","loai":"thi triển","importance":"normal","giaiDoan":"Chế trụ Kim lão quái","text":"Hàn Lập dùng Phong Lôi Sí dịch chuyển ra sau Kim lão quái và nhanh chóng chế trụ đối thủ.","anchor":"Từ lúc Kiềm Lam Băng Diễm biến thành quang liên làm đông lạnh và phong trụ phi kiếm, đến lúc Hàn Lập sử dụng Phong Lôi Sí quỷ dị di chuyển đến phía sau Kim lão quái"}]},"capNhatToi":"@c0867","nguon":["@c0867"]},{"id":"bi-thuat-kiem-tra-phong-hon-chu","name":"Bí thuật kiểm tra Phong hồn chú","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật Hàn Lập dùng để kiểm tra tình trạng Phong hồn chú trong cơ thể Nam Cung Uyển.","detail":"Hàn Lập hao tổn không ít nguyên khí để thi triển bí thuật này trong lúc tra xét tình hình Phong hồn chú, qua đó xác nhận yêu đan Hỏa Thiềm Thú đã khiến thần thức Nam Cung Uyển xuất hiện một tia yếu ớt.","congNang":["Kiểm tra trạng thái Phong hồn chú trong cơ thể người bị chú thuật ảnh hưởng @c0868"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0868","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0868","loai":"thi triển","importance":"normal","giaiDoan":"Kiểm tra Phong hồn chú","text":"Hàn Lập thi triển bí thuật để kiểm tra tình trạng Phong hồn chú của Nam Cung Uyển sau khi dùng yêu đan Hỏa Thiềm Thú.","anchor":"hao phí không ít Nguyên khí thi triển một loại bí thuật để kiểm tra tình huống Phong hồn chú"}]},"nguon":["@c0868"]},{"id":"thanh-minh-linh-nhan","name":"Thanh minh linh nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông linh nhãn Hàn Lập dùng để ngưng thần quan sát tiểu đỉnh và phát hiện manh mối kích phát Hư Thiên Đỉnh.","detail":"Trong chương 869, Hàn Lập thi triển Thanh minh linh nhãn để nhìn kỹ Hư Thiên Đỉnh, từ đó phát hiện điểm có thể kích phát bảo vật bằng linh ti và linh lực.","congNang":["Quan sát và phát hiện dị trạng trên Hư Thiên Đỉnh @c0869"],"tabs":{"tienTrinh":[{"chuong":"@c0869","loai":"thi triển","importance":"normal","giaiDoan":"Quan sát Hư Thiên Đỉnh","text":"Hàn Lập dùng Thanh minh linh nhãn để ngưng thần quan sát tiểu đỉnh và tìm ra manh mối kích phát.","anchor":"Sau khi thi triển thần thông Thanh minh linh nhãn ngưng thần nhìn tiểu đỉnh"}]},"nguon":["@c0869"]},{"id":"thong-bao-quyet","name":"Thông bảo quyết","cn":"","loai":"cong-phap","loaiLabel":"Pháp quyết","phamCap":"thượng cổ","hePhai":"Thông Thiên linh bảo","soHuu":["Hàn Lập"],"blurb":"Thông bảo quyết là thượng cổ pháp quyết chuyên dùng để khu sử Thông Thiên linh bảo. Pháp quyết hiện ra từ Hư Thiên Đỉnh và chia ba tầng với điều kiện cảnh giới rất cao.","detail":"Kinh văn trên Hư Thiên Đỉnh cho biết muốn khu sử đỉnh phải luyện hóa Kiềm Lam Băng Diễm và tu luyện Thông bảo quyết. Pháp quyết giúp phong ấn linh bảo trong thân thể, bồi luyện linh tính bằng thần thức và khu sử uy lực của linh bảo theo từng tầng.","thuocTinh":"Khu sử Thông Thiên linh bảo","nguonGoc":"Hiện ra từ cổ văn trên Hư Thiên Đỉnh","yeuCau":"Tầng một cần Nguyên Anh Trung Kỳ, tầng hai cần Nguyên Anh Hậu Kỳ, tầng ba cần Hóa Thần Kỳ","uyLuc":"Có thể giúp người tu luyện phong ấn và bồi luyện Thông Thiên linh bảo, nhưng tầng thấp chỉ mượn được chút uy lực.","dacDiem":"Mỗi Thông Thiên linh bảo cần pháp quyết tương ứng để khu sử.","cacTang":[{"ten":"Tầng thứ nhất","moTa":"Cần tu vi Nguyên Anh Trung Kỳ mới có thể tu luyện.","chuong":"@c0869"},{"ten":"Tầng thứ hai","moTa":"Cần tiến vào Nguyên Anh Hậu Kỳ.","chuong":"@c0869"},{"ten":"Tầng thứ ba","moTa":"Cần tiến vào Hóa Thần Kỳ.","chuong":"@c0869"}],"congNang":["Khu sử và bồi luyện Thông Thiên linh bảo @c0869","Phong ấn linh bảo vào thân thể để dùng thần thức ảnh hưởng linh tính @c0869","Khu động Hư Thiên đỉnh để hút linh quang, thu thánh đỉnh và nhốt phân thân Thiên Lan thánh thú @c0897"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0869","tangDatToi":"Tầng thứ nhất","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0869","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện từ Hư Thiên Đỉnh","text":"Thông bảo quyết hiện ra trong kinh văn trên Hư Thiên Đỉnh và được xác lập là pháp quyết khu sử Thông Thiên linh bảo.","anchor":"phải tu luyện một loại thượng cổ công pháp có tên là “Thông bảo quyết”"},{"chuong":"@c0897","loai":"thi triển","importance":"major","giaiDoan":"Tầng thứ nhất","text":"Hàn Lập vận tầng thứ nhất Thông Bảo quyết vào Hư Thiên đỉnh, trực tiếp kích phát dị biến thu thánh đỉnh và phân thân Thiên Lan thánh thú.","anchor":"Hàn Lập hai mắt nhíu lại, đem Thông Bảo quyết tầng thứ nhất công pháp lưu động vận chuyển vào tiểu đỉnh"}]},"capNhatToi":"@c0869","nguon":["@c0869","@c0897"]},{"id":"thuong-co-phong-an-phap-tran","name":"Thượng cổ Phong ấn pháp trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Chân Cực môn, Thái Chân môn","soHuu":["Thái Chân môn"],"blurb":"Thượng cổ Phong ấn pháp trận là đại trận trấn áp ma khí dưới Đại tuyền qua. Đại tuyền qua là trận nhãn, còn bảy tòa linh đảo chỉ là một bộ phận của pháp trận.","detail":"Pháp trận có quy mô cực lớn, lấy Đại tuyền qua làm trận nhãn và dùng bố cục bảy tòa linh đảo quanh đó làm một phần trận thế. Nhiệm vụ của nó là phong ấn vô biên ma khí dưới Vô Biên Hải, được Thái Chân môn trông coi theo nguồn gốc từ Chân Cực môn Đại Tấn.","congNang":["Phong ấn và trấn áp ma khí sâu dưới Đại tuyền qua @c0870"],"dacDiem":"Đại tuyền qua là trận nhãn, bảy linh đảo chỉ là một bộ phận của pháp trận.","trangThai":"đang duy trì","capNhatToi":"@c0870","tabs":{"tienTrinh":[{"chuong":"@c0870","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ bản chất trận nhãn","text":"Chí Dương Thượng nhân tiết lộ Đại tuyền qua vốn là trận nhãn của Thượng cổ Phong ấn pháp trận, còn bảy linh đảo chỉ là một bộ phận của pháp trận dùng để trấn áp ma khí dưới Vô Biên Hải.","anchor":"Đại tuyền qua này không biết bao nhiêu năm trước là trận nhãn của một cái Phong ấn đại trận"}]},"nguon":["@c0870"]},{"id":"linh-khi-tran-ap-ma-khi-duoi-dai-tuyen-qua","name":"Linh khí trấn áp ma khí dưới Đại tuyền qua","cn":"","loai":"khac","loaiLabel":"Cơ chế phong ấn","phamCap":"không rõ","hePhai":"Thượng cổ Phong ấn pháp trận","soHuu":["Thái Chân môn"],"blurb":"Đây là cơ chế dùng linh khí tinh thuần trong suối chảy để trấn áp ma khí dưới Đại tuyền qua. Nếu cơ chế bị phá, ma khí có thể bộc phát thành đại kiếp cho Thiên Nam.","detail":"Chí Dương Thượng nhân nói vô biên ma khí dưới Đại tuyền qua hiện bị vạn trượng linh khí tinh thuần trong dòng suối trấn áp. Cơ chế này là phần then chốt giúp ma khí không tràn ra và biến đổi linh khí Thiên Nam.","congNang":["Dùng vạn trượng linh khí tinh thuần trong suối chảy để trấn áp vô biên ma khí @c0870"],"uyLuc":"Có thể ngăn ma khí dưới Đại tuyền qua bộc phát thành đại kiếp.","trangThai":"đang duy trì","capNhatToi":"@c0870","tabs":{"tienTrinh":[{"chuong":"@c0870","loai":"xuất hiện","importance":"normal","giaiDoan":"Cơ chế trấn áp","text":"Chí Dương Thượng nhân giải thích ma khí dưới Đại tuyền qua hiện được linh khí tinh thuần trong suối chảy trấn áp, nếu phá vỡ sẽ gây đại kiếp cho Thiên Nam.","anchor":"Toàn bộ đều dựa vào vạn trượng tinh thuần linh khí trong suối chảy trấn áp"}]},"nguon":["@c0870"]},{"id":"phong-an-phap-tran-duoi-dai-tuyen-qua","name":"Phong ấn pháp trận dưới Đại Tuyền Qua","cn":"","aliases":[],"loai":"khac","loaiLabel":"Pháp trận phong ấn","phamCap":"Thượng cổ","hePhai":"Liên quan Thái Chân Môn và Đại Tuyền Qua","soHuu":[],"blurb":"Phong ấn pháp trận nằm sâu dưới Đại Tuyền Qua, là trọng tâm khiến ba đại tu sĩ Thiên Nam phải tìm cách chữa trị. Vị trí cấu hình của pháp trận được ghi trong thượng cổ điển tịch nhưng chi tiết còn mơ hồ.","detail":"Thượng cổ điển tịch do Chí Dương thượng nhân tìm được chỉ ra vị trí cấu hình phong ấn pháp trận dưới Đại Tuyền Qua. Ba đại tu sĩ cùng các trận pháp đại sư đã nghiên cứu nhiều năm và tìm ra phương pháp chữa trị, nhưng muốn thi hành phải đưa trận bàn xuống vị trí chỉ định sâu dưới đáy biển.","dinhDanh":"goc","congNang":["Phong ấn ma khí dưới Đại Tuyền Qua và là đối tượng cần được chữa trị @c0871"],"trangThai":"cần chữa trị","capNhatToi":"@c0871","tabs":{"tienTrinh":[{"chuong":"@c0871","loai":"xuất hiện","importance":"normal","giaiDoan":"Phương án chữa trị được hé lộ","text":"Ba đại tu sĩ cho biết đã dựa vào thượng cổ điển tịch và nhiều năm nghiên cứu để tìm ra cách chữa phong ấn pháp trận dưới Đại Tuyền Qua.","anchor":"trải qua mấy năm nghiên cứu, cuối cùng tìm được một phương pháp chữa trị pháp trận"}]},"nguon":["@c0871"]},{"id":"tran-ban-dat-trong-ma-khi","name":"Trận bàn đặt trong ma khí","cn":"","loai":"khac","loaiLabel":"Trận bàn / trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Mấy vị pháp trận đại sư"],"blurb":"Trận bàn then chốt dự định được mang vào Ma Khí Chi Uyên để bố trí. Hàn Lập yêu cầu biết rõ vị trí đặt vì độ sâu ảnh hưởng trực tiếp tới mức tiêu hao Ích Tà Thần Lôi.","detail":"Trận bàn này được nhắc trong kế hoạch xử lý Ma Khí Chi Uyên. Hàn Lập cho rằng nếu phải xâm nhập quá sâu, Ích Tà Thần Lôi chưa chắc duy trì nổi tốc độ tiêu hao, nên các đại tu sĩ cần lấy trận bàn từ các pháp trận đại sư rồi bàn kỹ vị trí và đường lui.","congNang":["Dùng để bố trí trong Ma Khí Chi Uyên @c0872"],"dacDiem":"Vị trí đặt trận quyết định mức độ nguy hiểm đối với người mang trận bàn vào ma khí.","capNhatToi":"@c0872","tabs":{"tienTrinh":[{"chuong":"@c0872","loai":"xuất hiện","importance":"normal","giaiDoan":"Bàn vị trí đặt trận","text":"Hàn Lập yêu cầu biết rõ trận bàn sẽ đặt ở đâu trong Ma Khí Chi Uyên trước khi nhận lời thử mang vào.","anchor":"rốt cuộc là định đem trận bàn kia đặt ở nơi nào"}]},"nguon":["@c0872"]},{"id":"tran-ban-phong-ma-khi","name":"Trận bàn phong ma khí","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận khí/trận pháp","phamCap":"không rõ","hePhai":"phong ma","soHuu":["Ngụy Vô Nhai","Hàn Lập"],"blurb":"Trận bàn được bố trí dưới vũng xoáy để phối hợp chữa trị phong ấn ma khí. Khi Ngụy Vô Nhai kiểm tra, trận bàn phát quang ngũ sắc và được xác nhận đã bày xong.","detail":"Hàn Lập hoàn tất việc bố trí trận bàn ở khu vực ma khí dưới vũng xoáy. Ngụy Vô Nhai dùng một trận bàn khác kiểm nghiệm, thấy phản ứng linh quang và kết luận việc bố trí thành công, tạm thời giảm nguy cơ ma khí đột ngột bạo phát.","congNang":["Kiểm soát và hỗ trợ trấn áp ma khí bạo phát dưới vũng xoáy @c0875"],"trangThai":"đã bố trí","capNhatToi":"@c0875","tabs":{"tienTrinh":[{"chuong":"@c0875","loai":"xuất hiện","importance":"major","giaiDoan":"Bố trí thành công","text":"Trận bàn dưới ma khí được Ngụy Vô Nhai kiểm nghiệm và xác nhận đã bố trí tốt, có thể mời tu sĩ đến chữa trị pháp trận.","anchor":"Tốt, quả nhiên đã bố trí tốt trận bàn"}]},"nguon":["@c0875"]},{"id":"de-nhi-nguyen-anh","name":"Đệ nhị Nguyên Anh","cn":"","aliases":["đệ nhị Nguyên Anh"],"loai":"bi-thuat","loaiLabel":"Bí thuật/nguyên anh phụ","phamCap":"không rõ","hePhai":"Nguyên Anh bí thuật","soHuu":["Hàn Lập"],"blurb":"Bí thuật tu thành nguyên anh thứ hai của Hàn Lập. Nếu hoàn toàn tu thành, nó giúp thần thông tăng lên và như có thêm một phần sinh cơ.","detail":"Sau khi trở về Lạc Vân Tông, Hàn Lập quyết định bế quan nhiều năm để tăng pháp lực và hoàn toàn tu thành đệ nhị Nguyên Anh. Chương nhấn mạnh năng lực này có thể khiến thần thông của hắn tăng mạnh và tương đương thêm một tính mạng.","congNang":["Tăng thần thông và đem lại thêm một phần sinh cơ cho Hàn Lập @c0875"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0875","tangDatToi":"sắp hoàn toàn tu thành","trangThai":"đang tu"}],"trangThai":"đang tu luyện","capNhatToi":"@c0875","tabs":{"tienTrinh":[{"chuong":"@c0875","loai":"nhắc tới","importance":"normal","giaiDoan":"Chuẩn bị hoàn thành","text":"Hàn Lập trở về Lạc Vân Tông bế quan để hoàn toàn tu thành đệ nhị Nguyên Anh.","anchor":"muốn đem đệ nhị Nguyên anh hoàn toàn tu thành"}]},"nguon":["@c0875"]},{"id":"huyen-am-dai-phap","name":"Huyền Âm Đại Pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp ma đạo","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Nguyên anh thứ hai của Hàn Lập"],"blurb":"Huyền Âm Đại Pháp là công pháp ma đạo có các biến hóa thông huyền được Hàn Lập dùng để bồi dưỡng Nguyên anh thứ hai.","detail":"Ở chương này, Hàn Lập dùng thân thể bản thân và ma khí tinh thuần trong Âm La phiến để giúp Nguyên anh thứ hai tu thành một ít công pháp biến hóa thông huyền trong Huyền Âm Đại Pháp.","nguoiTu":[{"ten":"Nguyên anh thứ hai của Hàn Lập","tuChuong":"@c0876","tangDatToi":"một ít công pháp biến hóa thông huyền","trangThai":"đang tu"}],"congNang":["Giúp Nguyên anh thứ hai nắm một ít biến hóa thông huyền bằng ma khí tinh thuần trong Âm La phiến @c0876"],"tabs":{"tienTrinh":[{"chuong":"@c0876","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"bồi dưỡng Nguyên anh thứ hai","text":"Hàn Lập dùng ma khí tinh thuần trong Âm La phiến để giúp Nguyên anh thứ hai tu thành một ít biến hóa của Huyền Âm Đại Pháp.","anchor":"giúp nó tu thành một ít công pháp biến hóa thông huyền trong Huyền Âm Đại Pháp"}]},"capNhatToi":"@c0876","nguon":["@c0876"]},{"id":"hoa-than-thuat","name":"Hóa thân thuật","cn":"","loai":"than-thong","loaiLabel":"Hóa thân thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Hóa thân thuật là loại thần thông được dùng để đối chiếu với Huyền Mẫu Hóa Anh Đại Pháp.","detail":"Hàn Lập nói Huyền Mẫu Hóa Anh Đại Pháp cũng thuộc loại Hóa thân thuật nhưng không trực tiếp tăng cường tu vi, chủ yếu có diệu dụng ứng đối và bảo mệnh.","nguon":["@c0876"]},{"id":"ngu-quy-toa-than","name":"Ngũ Quỷ Tỏa Thần","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật/cấm chế","phamCap":"Chưa rõ","hePhai":"Đại Diễn Thần Quân sáng chế","soHuu":["Đại Diễn Thần Quân","Hàn Lập"],"blurb":"Bí thuật do Đại Diễn Thần Quân sáng chế, nay truyền cho Hàn Lập để áp chế sát khí cắn trả. Pháp này dùng sát khí làm mồi dẫn ngũ quỷ phụ thân, đồng thời phong ấn một phần tu vi của người thi triển.","detail":"Ngũ Quỷ Tỏa Thần vốn được Đại Diễn Thần Quân tạo ra để khống chế tình trạng Đại Diễn Quyết tẩu hỏa nhập ma. Khi áp dụng cho Hàn Lập, bí thuật lấy sát khí làm mồi dẫn, đưa ngũ quỷ phụ thân, nhờ đó tạm áp chế sát khí nhưng cũng khiến tu vi Hàn Lập chỉ còn có thể phát huy khoảng Trúc Cơ Trung Kỳ.","thuocTinh":"Khống chế sát khí, phong ấn tu vi","nguonGoc":"Do Đại Diễn Thần Quân sáng chế","uyLuc":"Có thể áp chế sát khí cắn trả hung mãnh nhưng phải trả giá bằng việc phong ấn một phần pháp lực.","dacDiem":"Dùng sát khí làm mồi dẫn ngũ quỷ phụ thân, hiệu quả vừa là trấn áp vừa là khóa thần thông.","trangThai":"Mất hiệu quả với sát khí","capNhatToi":"@c0878","congNang":["Khống chế sát khí cắn trả trong cơ thể người dùng @c0878","Phong ấn một phần tu vi, khiến Hàn Lập hiện nhiều nhất chỉ còn khoảng Trúc Cơ Trung Kỳ @c0878","Từng được dùng để khóa hoặc áp chế ảnh hưởng của sát khí, nhưng công hiệu đã biến mất trong tình thế hiện tại @c0901"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0878","tangDatToi":"Đang vận dụng để áp chế sát khí","trangThai":"đang dùng"},{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0878","tangDatToi":"Người sáng chế","trangThai":"nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0878","loai":"xuất hiện","importance":"major","giaiDoan":"Dùng trên Hàn Lập","text":"Đại Diễn Thần Quân hé lộ Ngũ Quỷ Tỏa Thần là bí thuật do ông sáng chế, nay dùng sát khí làm mồi dẫn ngũ quỷ phụ thân để áp chế sát khí và phong ấn một phần tu vi của Hàn Lập.","anchor":"nếu đã dùng sát khí tố dẫn, đưa tới ngũ quỷ phụ thân"},{"chuong":"@c0901","loai":"nhắc tới","importance":"normal","giaiDoan":"Mất công hiệu","text":"Hàn Lập xác nhận Ngũ quỷ tỏa thần mất hiệu quả, khiến hắn phải tìm công pháp Phật môn giải trừ sát khí.","anchor":"công hiệu của Ngũ quỷ tỏa thần không hiểu tại sau biến mất"}]},"nguon":["@c0878","@c0901"]},{"id":"phap-quyet-giai-phong-an-lam-thoi","name":"Pháp quyết giải phong ấn lâm thời","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật do Đại Diễn Thần Quân truyền cho Hàn Lập để tạm thời giải phong ấn Ngũ Quỷ Tỏa Thần trong lúc nguy cấp.","detail":"Mỗi lần thi triển cần dùng hai giọt Vạn niên linh dịch để trung hòa ngũ quỷ và sát khí, giúp Hàn Lập khôi phục pháp lực khoảng một canh giờ. Cái giá là sát khí sẽ xâm nhập sâu hơn, dùng nhiều lần có thể khiến ngũ quỷ mất khống chế.","nguon":["@c0879"]},{"id":"cong-phap-phan-chia-nguyen-anh-cua-truong-lao-dot-ngot","name":"Công pháp phân chia Nguyên Anh của trưởng lão Đột Ngột","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Đột Ngột nhân","soHuu":["Trưởng lão Nguyên Anh trung kỳ người Đột Ngột"],"blurb":"Công pháp chủ tu quái dị của trưởng lão Đột Ngột, cho phép chia Nguyên Anh thành nhiều phần để thoát thân.","detail":"Công pháp này có thể đem Nguyên Anh phân chia làm bảy phần, mỗi phần đều tinh thông Mộc độn thuật. Nhờ đặc tính đó, dù bị Hàn Lập đánh diệt thân thể và phần lớn phân thần, một phân thần của trưởng lão Đột Ngột vẫn trốn thoát, kéo theo cuộc truy sát Hàn Lập trên thảo nguyên.","nguon":["@c0879"]},{"id":"dan-hon-thuat","name":"Dẫn hồn thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật truy tung","phamCap":"Không rõ","hePhai":"Mộ Lan","soHuu":["Vài vị thượng bậc tiên sư Mộ Lan","Tú tiên sư","Lê tiên sư"],"blurb":"Bí thuật được các thượng bậc tiên sư Mộ Lan thi triển lên những kết đan tiên sư tham gia truy tìm Hàn Lập.","detail":"Tú tiên sư cho rằng dẫn hồn thuật không chỉ dùng để cứu viện, mà còn có thể khiến người bị thi thuật trở thành mồi dẫn đường: nếu họ gặp nạn, thượng bậc tiên sư có thể lần theo tung tích để bức ngoại tộc tu sĩ hiện thân.","thuocTinh":"Truy tung, cảm ứng","congNang":["Theo nhận định của Tú tiên sư, thuật này giúp thượng bậc tiên sư lần theo người bị thi thuật khi họ gặp biến cố @c0880"],"tabs":{"tienTrinh":[{"chuong":"@c0880","loai":"nhắc tới","importance":"normal","giaiDoan":"Nhiệm vụ truy tìm Hàn Lập","text":"Tú tiên sư nêu khả năng dẫn hồn thuật được dùng để biến các kết đan tiên sư đi lục soát thành mồi dẫn tung tích.","anchor":"Không phải trước khi chúng ta ra đi, bọn họ cho chúng ta một người thi triển một cái dẫn hồn thuật sao"}]},"capNhatToi":"@c0880","nguon":["@c0880"]},{"id":"cam-che-bao-ho-trong-xe","name":"Cấm chế bảo hộ trong xe","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Cấm chế nhỏ được Hàn Lập dựng trong xe bằng vài cây trận kỳ nhiều màu.","detail":"Cấm chế có phạm vi khoảng một trượng, dùng để cách ly và bảo hộ khi Hàn Lập luyện hóa nguyên thần Phệ Kim Trùng thành thục, tránh động tĩnh ảnh hưởng tới đoàn xe Thương Lộ bộ.","thuocTinh":"Bảo hộ, cách ly","congNang":["Tạo vòng cấm chế khoảng một trượng trong xe để che chắn quá trình luyện hóa @c0880"],"tabs":{"tienTrinh":[{"chuong":"@c0880","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập luyện hóa Phệ Kim Trùng thành thục","text":"Hàn Lập dùng trận kỳ dựng vòng cấm chế bảo hộ trước khi gọi đệ nhị nguyên anh và Quỷ La phiên ra luyện trùng.","anchor":"Một vòng cấm chế bảo hộ tầm một trượng, bỗng đột nhiên xuất hiện ở bên trong xe"}]},"capNhatToi":"@c0880","nguon":["@c0880"]},{"id":"phap-tran-lam-thoi","name":"Pháp trận lâm thời","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Thiên Lan","soHuu":["Hồn Hình","Bạch diện lão giả","Lão giả hơi béo","Lão giả tóc bạc còn lại"],"blurb":"Pháp trận được lập trong mật thất để phối hợp pháp kỳ và trận bàn cứu chữa Nguyên Anh Quế tiên sư.","detail":"Bốn phía trận bàn cắm các trận kỳ khác nhau, hợp thành pháp trận lâm thời để tụ lục vụ hướng vào trận bàn bát tròn màu ngọc xanh, hỗ trợ Quế tiên sư hồi phục thân thể Nguyên Anh.","congNang":["Hỗ trợ hồi phục và ổn định Nguyên Anh Quế tiên sư @c0881"],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"xuất hiện","importance":"normal","giaiDoan":"Cứu chữa Nguyên Anh","text":"Pháp trận lâm thời được bốn lão giả Thiên Lan dùng trong mật thất để hỗ trợ Quế tiên sư hồi phục Nguyên Anh.","anchor":"bốn phía cắm các trận kỳ khác nhau, hợp thành một cái pháp trận lâm thời"}]},"nguon":["@c0881"]},{"id":"luc-hon-phan-nguyen-thuat","name":"Lục Hồn Phân Nguyên Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Thiên Lan","soHuu":["Quế tiên sư"],"blurb":"Bí thuật mà Quế tiên sư mang theo, được nhắc trong lúc các tiên sư bàn về việc ông vẫn bị Hàn Lập trọng thương.","detail":"Hồn Hình nhắc Quế tiên sư thân mang Lục Hồn Phân Nguyên Thuật nhưng vẫn gặp kết cục trọng thương, qua đó cho thấy Hàn Lập là đối thủ cực kỳ nguy hiểm đối với nhóm tiên sư Thiên Lan.","nguoiTu":[{"ten":"Quế tiên sư","tuChuong":"@c0881","tangDatToi":"không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị nhắc sau trọng thương","text":"Lục Hồn Phân Nguyên Thuật được nêu như thần thông Quế tiên sư mang theo nhưng vẫn không giúp ông tránh khỏi bị trọng thương.","anchor":"Trách không được Quế sư đệ thân mang ‘Lục Hồn Phân Nguyên Thuật’ mà vẫn bị kết cục như thế"}]},"nguon":["@c0881"]},{"id":"dai-ngu-hanh-cam-tien-thu","name":"Đại Ngũ Hành Cầm Tiên Thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Lan","soHuu":["Hô đại tiên sư"],"blurb":"Thần thông của Hô đại tiên sư từng bất ngờ đánh trọng thương Hàn Lập trong trận vây bắt.","detail":"Hô đại tiên sư âm thầm thi triển Đại Ngũ Hành Cầm Tiên Thủ, đánh ra một kích khiến Hàn Lập trọng thương giữa lúc nhiều tiên sư Thiên Lan đang vây bắt nhưng chưa chế ngự được hắn.","uyLuc":"Từng trọng thương Hàn Lập trong một kích @c0881","congNang":["Đánh bắt bất ngờ bằng đại thần thông ngũ hành, đủ làm Hàn Lập trọng thương @c0881"],"nguoiTu":[{"ten":"Hô đại tiên sư","tuChuong":"@c0881","tangDatToi":"thi triển được","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"thi triển","importance":"normal","giaiDoan":"Trọng thương Hàn Lập","text":"Đại Ngũ Hành Cầm Tiên Thủ được Hô đại tiên sư âm thầm thi triển để bất ngờ đánh trọng thương Hàn Lập.","anchor":"âm thầm thi triển ‘Đại Ngũ Hành Cầm Tiên Thủ’ bất ngờ đánh ra một kích"}]},"nguon":["@c0881"]},{"id":"loi-don-thuat","name":"Lôi độn thuật","cn":"","loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Độn thuật được Hàn Lập thi triển nhờ đôi cánh trắng, giúp hắn tránh vây bắt không cần niệm chú.","detail":"Các tiên sư Thiên Lan hồi tưởng rằng đôi cánh trắng trên lưng Hàn Lập cho phép hắn trực tiếp thi triển lôi độn thuật mà không cần niệm chú, khiến việc vây bắt trở nên cực kỳ khó khăn.","congNang":["Dịch chuyển bằng lôi độn để né vây bắt, không cần niệm chú khi dựa vào đôi cánh trắng @c0881"],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"thi triển","importance":"normal","giaiDoan":"Thoát vây","text":"Lôi độn thuật được nhắc như năng lực Hàn Lập dùng qua đôi cánh trắng để thoát khỏi vòng vây tiên sư Thiên Lan.","anchor":"Đôi cánh khiến hắn có thể trực tiếp thi triển lôi độn thuật mà ngay cả chú ngữ cũng không cần niệm"}]},"nguon":["@c0881"]},{"id":"kim-sac-loi-dien","name":"Kim sắc lôi điện","cn":"","loai":"than-thong","loaiLabel":"Lôi điện","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Kim sắc lôi điện của Hàn Lập được các tiên sư Thiên Lan nhắc là có thể vây khốn Nguyên Anh tu sĩ.","detail":"Bạch diện lão giả nói kim sắc lôi điện có khả năng vây khốn Nguyên Anh, phối hợp với tử sắc hỏa diễm khiến các tiên sư Thiên Lan chịu thương vong lớn.","congNang":["Vây khốn Nguyên Anh của tu sĩ @c0881"],"uyLuc":"Phối hợp tử sắc hỏa diễm gây tử vong cho tiên sư Nguyên Anh @c0881","tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Thiên Lan phân tích","text":"Kim sắc lôi điện được bạch diện lão giả nêu là thủ đoạn vây khốn Nguyên Anh trong trận Hàn Lập giao chiến với các tiên sư Thiên Lan.","anchor":"Kim sắc lôi điện có thể vây khốn nguyên anh của tu tiên"}]},"nguon":["@c0881"]},{"id":"ma-dao-bi-thuat-cong-kich-tinh-hon-nguyen-than","name":"Ma đạo bí thuật công kích tinh hồn nguyên thần","cn":"","loai":"bi-thuat","loaiLabel":"Ma đạo bí thuật","phamCap":"đỉnh cấp","hePhai":"Ma đạo","soHuu":[],"blurb":"Bí thuật ma đạo được bạch diện lão giả nêu như cách có thể tiêu diệt Phệ Kim Trùng trưởng thành bằng cách đánh thẳng vào tinh hồn nguyên thần.","detail":"Khi nghe Phệ Kim Trùng trưởng thành gần như bất diệt về thân thể vẫn bị diệt, bạch diện lão giả suy đoán có thể không cần phá thân thể trùng mà dùng ma đạo bí thuật đỉnh cấp trực tiếp công kích tinh hồn nguyên thần.","congNang":["Công kích trực tiếp tinh hồn nguyên thần thay vì hủy diệt thân thể @c0881"],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"nhắc tới","importance":"normal","giaiDoan":"Cách khắc chế Phệ Kim Trùng","text":"Bí thuật này được nêu như khả năng giải thích việc Phệ Kim Trùng trưởng thành bị diệt nguyên thần dù thân thể gần như bất diệt.","anchor":"ma đạo bí thuật đỉnh cấp có thể trực tiếp công kích tinh hồn nguyên thần"}]},"nguon":["@c0881"]},{"id":"luyen-che-yeu-thi-tu-phe-kim-trung","name":"Luyện chế yêu thi từ Phệ Kim Trùng","cn":"","loai":"bi-thuat","loaiLabel":"Luyện thi","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Thủ pháp Hàn Lập dùng để biến xác Phệ Kim Trùng trưởng thành đã mất sinh cơ thành yêu thi.","detail":"Hàn Lập đưa nguyên thần Phệ Kim Trùng đã bị Âm La phiên xử lý trở lại xác trùng, khiến nó sống lại dưới dạng yêu thi. Hắn nhận định yêu thi này kém hơn lúc còn sống nhưng vẫn rất lợi hại, cần luyện hóa ma khí thêm để điều khiển như ý.","congNang":["Biến trùng thi Phệ Kim Trùng trưởng thành thành yêu thi có thể điều khiển sau khi luyện hóa ma khí @c0881"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0881","tangDatToi":"bước đầu luyện thành","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0881","loai":"thi triển","importance":"major","giaiDoan":"Tạo yêu thi trùng","text":"Hàn Lập đưa nguyên thần đã ma hóa vào xác Phệ Kim Trùng trưởng thành và xác nhận có thể luyện nó như yêu thi.","anchor":"Đem con trùng này coi như yêu thi mà luyện chế cũng không sai"}]},"nguon":["@c0881"]},{"id":"hoa-xa-thuat","name":"Hoả xà thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"cấp thấp","hePhai":"không rõ","soHuu":["Phong tiên sư"],"blurb":"Hoả xà thuật là pháp thuật được Phong tiên sư thi triển thông qua phù để công kích Viên Thứu. Vì điều khiển không tinh, các hỏa xà chỉ lao thẳng và bị yêu cầm tránh dễ dàng.","detail":"Phong tiên sư dùng mấy đạo phù hóa thành những con hỏa xà dài hơn trượng nhằm đánh ba con Viên Thứu. Hàn Lập nhận ra cách thi triển này khá xa xỉ nhưng người dùng hiểu thuật còn nông cạn, không biết điều khiển pháp thuật truy tung đối thủ ở khoảng cách xa.","thuocTinh":"hỏa","uyLuc":"Có thể hóa phù thành hỏa xà tấn công, nhưng hiệu quả phụ thuộc vào khả năng điều khiển của người thi triển.","dacDiem":"Khi bị điều khiển kém, hỏa xà lao thẳng và dễ bị đối thủ linh hoạt né tránh.","nguoiTu":[{"ten":"Phong tiên sư","tuChuong":"@c0882","tangDatToi":"mức nông cạn","trangThai":"đang dùng"}],"congNang":["Phù hóa thành hỏa xà dài hơn trượng để công kích mục tiêu @c0882"],"tabs":{"tienTrinh":[{"chuong":"@c0882","loai":"thi triển","importance":"normal","giaiDoan":"Phong tiên sư dùng phù thuật","text":"Phong tiên sư phóng mấy đạo phù hóa thành hỏa xà đánh Viên Thứu, nhưng không điều khiển truy tung được nên bị tránh thoát.","anchor":"trong nháy mắt biến thành mấy con hoả xà dài hơn trượng"}]},"capNhatToi":"@c0882","nguon":["@c0882"]},{"id":"khau-quyet-pha-giai-phong-an","name":"Khẩu quyết phá giải phong ấn","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Khẩu quyết","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Khẩu quyết phá giải phong ấn là pháp quyết Hàn Lập chuẩn bị tham ngộ trong lúc tu vi đang bị phong ấn. Nó được dùng làm phương án ứng phó bất trắc trên hành trình thảo nguyên.","detail":"Sau khi bố trí Phệ Kim Trùng và Âm La Phiên vào đệ nhị nguyên anh, Hàn Lập định nhập định tham ngộ khẩu quyết phá giải phong ấn. Mục đích là tìm cách ứng phó tình thế tu vi bị phong ấn nếu xảy ra biến cố ngoài ý muốn.","congNang":["Hỗ trợ phá giải phong ấn đang hạn chế tu vi @c0882"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0882","tangDatToi":"tham ngộ","trangThai":"đang tham ngộ"}],"tabs":{"tienTrinh":[{"chuong":"@c0882","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập chuẩn bị tham ngộ","text":"Hàn Lập định nhập định để tham ngộ khẩu quyết phá giải phong ấn nhằm đề phòng bất trắc.","anchor":"bắt đầu tham ngộ khẩu quyết phá giải phong ấn"}]},"capNhatToi":"@c0882","nguon":["@c0882"]},{"id":"khau-quyet-dai-dien-than-quan-dua-cho","name":"Khẩu quyết Đại Diễn Thần Quân đưa cho","aliases":["Khẩu quyết Đại Diễn Thần Quân đưa"],"cn":"","loai":"khac","loaiLabel":"Khẩu quyết","phamCap":"chưa rõ","hePhai":"Đại Diễn Thần Quân","soHuu":["Hàn Lập"],"blurb":"Khẩu quyết do Đại Diễn Thần Quân đưa cho Hàn Lập nghiên cứu trong lúc ẩn thân ngoài trú địa.","detail":"Hàn Lập nhập định tham ngộ khẩu quyết này sau khi dựng động phủ tạm bằng cự thạch. Việc tham ngộ thuận lợi hơn dự tính và hắn đã hiểu quá nửa trước khi bị thần thức cảnh báo.","nguon":["@c0884"],"dinhDanh":"goc","thuocTinh":"khẩu quyết","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0884","tangDatToi":"hiểu quá nửa","trangThai":"đang tham ngộ"}],"congNang":["Giúp Hàn Lập tham ngộ các vấn đề tu luyện do Đại Diễn Thần Quân truyền lại tại @c0884."],"capNhatToi":"@c0884","tabs":{"tienTrinh":[{"chuong":"@c0884","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tham ngộ","text":"Hàn Lập nhập định nghiên cứu khẩu quyết và đã tham ngộ hơn nửa trước khi bị biến cố bên ngoài làm kinh động.","anchor":"Việc tham ngộ khẩu quyết thuận lợi hơn so với hắn nghĩ"}]}},{"id":"tran-phap-an-hinh","name":"Trận pháp ẩn hình","aliases":[],"cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"chưa rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Trận pháp Hàn Lập bố trí bằng trận kỳ quanh cự thạch để che giấu nơi ẩn thân tạm.","detail":"Sau khi khoét cự thạch thành không gian trú thân, Hàn Lập dùng một bộ trận kỳ bố trí trận pháp ẩn hình. Từ bên ngoài nhìn vào, vị trí cự thạch chỉ còn như khoảng không.","nguon":["@c0884"],"dinhDanh":"goc","thuocTinh":"ẩn hình","congNang":["Ẩn giấu cự thạch và người bên trong khỏi tầm nhìn từ bên ngoài tại @c0884."],"capNhatToi":"@c0884","tabs":{"tienTrinh":[{"chuong":"@c0884","loai":"xuất hiện","importance":"normal","giaiDoan":"Dựng nơi ẩn thân","text":"Hàn Lập dùng trận kỳ bố trí trận pháp ẩn hình quanh cự thạch, khiến từ bên ngoài nhìn vào chỉ còn khoảng không.","anchor":"Từ bên ngoài nhìn vào, phía cự thạch bây giờ chỉ còn là một khoảng không"}]}},{"id":"phap-tran-bao-ve-tru-dia","name":"Pháp trận bảo vệ trú địa","aliases":[],"cn":"","loai":"khac","loaiLabel":"Pháp trận","phamCap":"chưa rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh điện"],"blurb":"Pháp trận khổng lồ do thánh điện bố trí quanh trú địa để bảo vệ tòa thành tạm của các bộ lạc.","detail":"Các thạch trụ lớn quanh trú địa phát quang, được Hàn Lập nhận định là pháp trận khổng lồ do thánh điện bố trí nhằm bảo vệ nơi tập kết.","nguon":["@c0884"],"dinhDanh":"goc","thuocTinh":"phòng hộ","congNang":["Bảo vệ trú địa do Thiên Lan thánh điện chỉ định tại @c0884."],"capNhatToi":"@c0884","tabs":{"tienTrinh":[{"chuong":"@c0884","loai":"xuất hiện","importance":"normal","giaiDoan":"Quan sát trú địa","text":"Hàn Lập nhìn thấy các thạch trụ phát quang quanh trú địa và nhận ra đó là pháp trận bảo vệ do thánh điện bố trí.","anchor":"hiển nhiên đó là một pháp trận khổng lồ được thánh điện bố trí nhằm bảo vệ tòa thành"}]}},{"id":"cam-che-cam-khong-tai-tru-dia","name":"Cấm chế cấm không tại trú địa","aliases":[],"cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"chưa rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh điện"],"blurb":"Cấm chế khiến tu tiên giả không bay qua bầu trời trú địa của thánh điện.","detail":"Khi quan sát trú địa, Hàn Lập không thấy tu tiên giả bay qua bầu trời và suy đoán nơi này có cấm chế cấm không.","nguon":["@c0884"],"dinhDanh":"goc","thuocTinh":"cấm bay","congNang":["Ngăn tu tiên giả phi hành trong phạm vi trú địa tại @c0884."],"capNhatToi":"@c0884","tabs":{"tienTrinh":[{"chuong":"@c0884","loai":"xuất hiện","importance":"normal","giaiDoan":"Quan sát trú địa","text":"Hàn Lập thấy bầu trời trú địa không có tu tiên giả bay qua và suy đoán nơi này có cấm chế cấm không.","anchor":"hiển nhiên tại đây cũng có cấm chế cấm không"}]}},{"id":"bi-thuat-cong-phap-phat-tong-giai-sat-khi","name":"Bí thuật/công pháp Phật tông giải sát khí","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật/công pháp","phamCap":"Không rõ","hePhai":"Phật tông","soHuu":["Phật tông"],"blurb":"Nhóm bí thuật và công pháp Phật tông được Đại Diễn Thần Quân xác nhận là hữu hiệu hơn cả trong việc giải sát khí. Đặc điểm thường thấy là pháp lực ẩn chứa phật lực và thất sắc linh quang.","detail":"Khi Hàn Lập hỏi về cách giải sát khí trên người, Đại Diễn Thần Quân cho biết trong các phương pháp hữu hiệu thì bí thuật công pháp Phật tông chiếm hơn nửa. Phần lớn công pháp này tu luyện pháp lực có phật lực và biểu hiện bằng thất sắc linh quang, khiến Hàn Lập liên hệ tới quang tráo trên người Phong Nhạc.","thuocTinh":"Phật lực, thất sắc linh quang","uyLuc":"Có khả năng hỗ trợ hóa giải sát khí theo nhận định của Đại Diễn Thần Quân.","dacDiem":"Pháp lực thường ẩn chứa phật lực và có thất sắc linh quang.","congNang":["Giải sát khí trên người tu sĩ @c0885"],"tabs":{"tienTrinh":[{"chuong":"@c0885","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập hỏi Đại Diễn Thần Quân","text":"Đại Diễn Thần Quân xác nhận bí thuật công pháp Phật tông là nhóm nổi bật trong việc giải sát khí và thường có thất sắc linh quang.","anchor":"các bí thuật công pháp Phật tông lại chiếm hơn nửa"}]},"capNhatToi":"@c0885","nguon":["@c0885"]},{"id":"nguyen-anh-thu-hai-bien-hoa-cong-kich","name":"Nguyên anh thứ hai biến hóa công kích","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông nguyên anh","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập","Nguyên anh thứ hai của Hàn Lập"],"blurb":"Thần thông do Hàn Lập vận dụng qua Nguyên anh thứ hai, biến hóa thành lục sắc ô vân và bàn tay lớn để công kích. Trong lần này nó bắt Tam lăng đinh, cắt liên hệ tâm thần của đối phương và diệt sát tu sĩ Kết Đan khinh địch.","detail":"Hàn Lập thả Nguyên anh thứ hai ra đối phó lão giả mắt ưng. Nguyên anh hóa thành lục sắc ô vân, ngưng thành bàn tay màu lục lớn, bắt lấy Tam lăng đinh rồi đánh nát thân thể lão giả, sau đó hiện lại thành lục sắc anh nhi đứng trên vai Hàn Lập.","uyLuc":"Có thể diệt sát tu sĩ Kết Đan khinh địch trong chớp mắt.","dacDiem":"Biến hóa linh hoạt giữa ô vân, bàn tay lớn và hình thái anh nhi màu lục.","congNang":["Bắt giữ pháp khí công kích của đối thủ @c0885","Đánh nát thân thể tu sĩ Kết Đan khinh địch @c0885"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0885","tangDatToi":"Vận dụng qua Nguyên anh thứ hai","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0885","loai":"thi triển","importance":"normal","giaiDoan":"Diệt lão giả mắt ưng","text":"Hàn Lập dùng Nguyên anh thứ hai hóa thành bàn tay màu lục để bắt Tam lăng đinh và diệt sát lão giả mắt ưng.","anchor":"hóa thành một bàn tay màu lục to vài thước"}]},"capNhatToi":"@c0885","nguon":["@c0885"]},{"id":"minh-thanh-linh-nhan","name":"Minh thanh linh nhãn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông linh nhãn","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Linh nhãn thần thông của Hàn Lập dùng để quan sát tình trạng khó nhận biết bằng mắt thường. Trong chương này, hắn dùng nó để xem xét độc trạng của Phong Nhạc sau khi thần thức rà soát toàn thân.","detail":"Sau khi phá quang tráo bảo vệ Phong Nhạc, Hàn Lập dùng thần thức kiểm tra rồi tiếp tục vận dụng Minh thanh linh nhãn. Việc dò xét giúp hắn nhận rõ tình trạng kịch độc và sau đó xác định đó là Khổ độc trong Thập tuyệt độc.","congNang":["Dò xét độc trạng trên thân thể Phong Nhạc @c0885","Nhìn thấu ảo trận ẩn trong Bắc Cực Nguyên Quang @c1019"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0885","tangDatToi":"có thể dùng để phá ảo trận","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0885","loai":"thi triển","importance":"normal","giaiDoan":"Dò xét Khổ độc","text":"Hàn Lập dùng Minh thanh linh nhãn để xem xét tình trạng Phong Nhạc sau khi thần thức kiểm tra toàn thân.","anchor":"bắt đầu dùng minh thanh linh nhãn xem xét"},{"chuong":"@c1019","loai":"thi triển","importance":"normal","giaiDoan":"Phá ảo trận trong Bắc Cực Nguyên Quang","text":"Hàn Lập dùng Minh Thanh linh nhãn nhìn thấu ảo trận do cổ tu bố trí trong Bắc Cực Nguyên Quang.","anchor":"Nếu như ta không có Minh Thanh linh nhãn, sợ là gặp chút phiền toái"}]},"capNhatToi":"@c0885","nguon":["@c0885","@c1019"]},{"id":"phat-gia-cong-phap-cua-phung-gia","name":"Phật gia công pháp của Phùng gia","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chưa rõ","hePhai":"Phật môn","soHuu":["Phùng gia","Tổ tiên Phùng gia"],"blurb":"Truyền thừa Phật gia công pháp mà Phùng gia vốn tu luyện, bắt nguồn từ quan hệ của tổ tiên Phùng gia với Thiên Quang tự thuộc Kim La môn.","detail":"Phong Nhạc nói Phùng gia nguyên bản tu luyện Phật gia công pháp, về sau mới đổi sang Nho gia công pháp sau khi Thiên Quang tự rời Liêu châu. Phương pháp tu luyện cũ vẫn được giữ lại và liên quan trực tiếp tới mật quật Phùng gia.","nguon":["@c0887"],"dinhDanh":"goc","nguonGoc":"Thiên Quang tự thuộc Kim La môn","thuocTinh":"Phật môn","trangThai":"còn lưu trong Phùng gia","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ nguồn gốc","text":"Phong Nhạc cho biết Phùng gia vốn tu luyện Phật gia công pháp và vẫn còn bảo tồn phương pháp tu luyện liên quan trong mật quật.","anchor":"Phùng gia chúng ta nguyên bản tu luyện chính là phật gia công pháp"}]}},{"id":"phuong-phap-tieu-tru-sat-khi","name":"Phương pháp tiêu trừ sát khí","cn":"","loai":"cong-phap","loaiLabel":"Pháp môn","phamCap":"Chưa rõ","hePhai":"Phật môn","soHuu":[],"blurb":"Pháp môn Phật môn mà Hàn Lập đang tìm để hóa giải sát khí trên người. Đại Diễn Thần Quân chỉ ra điều kiện then chốt là người tu phải có xá lợi tử Phật môn trong người.","detail":"Trong lúc Hàn Lập truy hỏi Phong Nhạc, Đại Diễn Thần Quân nhắc rằng chỉ người đã tu ra xá lợi tử Phật môn mới có thể tu luyện phương pháp tiêu trừ sát khí. Tổ tiên Phùng gia từng tu ra xá lợi tử, khiến Hàn Lập thấy có hy vọng tìm được pháp môn này qua mật quật Phùng gia.","nguon":["@c0887"],"dinhDanh":"goc","thuocTinh":"Phật môn","yeuCau":"Có xá lợi tử Phật môn trong người","congNang":["Tiêu trừ sát khí @c0887"],"trangThai":"được nhắc là mục tiêu tìm kiếm của Hàn Lập","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ điều kiện tu luyện","text":"Đại Diễn Thần Quân nhắc Hàn Lập rằng phương pháp tiêu trừ sát khí cần điều kiện xá lợi tử Phật môn trong người.","anchor":"mới có thể tu luyện phương pháp tiêu trừ sát khí"}]}},{"id":"suu-hon-bi-thuat-do-than-thuc-cua-han-lap","name":"Sưu hồn / bí thuật dò thần thức của Hàn Lập","cn":"","aliases":["Bí thuật dò thần thức của Hàn Lập"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Hàn Lập"],"blurb":"Bí thuật Hàn Lập dùng để dò xét thần thức, khác sưu hồn thuật thông thường khi chỉ nhằm xác minh thật giả các chuyện đơn giản nếu đối phương phối hợp.","detail":"Hàn Lập yêu cầu Phong Nhạc phối hợp để hắn tìm kiếm trong thần thức nhằm xác minh chuyện mật quật và Phật tông công pháp. Phong Nhạc lo sợ sưu hồn thuật, nhưng Hàn Lập nói chỉ cần đối phương phối hợp thì việc đoán thật giả từ thần thức tu sĩ Trúc Cơ kỳ là dễ dàng.","nguon":["@c0887"],"dinhDanh":"goc","congNang":["Xác minh ký ức và thật giả chuyện đơn giản trong thần thức đối phương khi có phối hợp @c0887"],"trangThai":"Hàn Lập dự định thi triển với Phong Nhạc","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"xuất hiện","importance":"normal","giaiDoan":"Yêu cầu phối hợp","text":"Hàn Lập yêu cầu Phong Nhạc cho hắn tìm kiếm trong thần thức để xác minh chuyện mật quật và Phật tông công pháp.","anchor":"nhưng là theo thần thức đoán được chuyện gì thực giả, vẫn là dễ dàng"}]}},{"id":"doc-mon-bi-thuat-cua-phung-gia","name":"Độc môn bí thuật của Phùng gia","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật cấm chế","phamCap":"Chưa rõ","hePhai":"Phùng gia","soHuu":["Phùng gia"],"blurb":"Bí thuật Phùng gia từng hạ lên Phùng Chẩm, cho phép tộc nhân hệ Trúc Cơ trở lên cấm chế tu vi người bị hạ thuật.","detail":"Phong Nhạc giải thích Phùng Chẩm không dám trực tiếp ra tay vì bị Phùng gia đặt độc môn bí thuật. Chỉ cần là tộc nhân hệ Phùng gia đạt Trúc Cơ kỳ trở lên, đều có thể thi pháp cấm chế tu vi của Phùng Chẩm, nên hắn phải dùng khổ độc đánh lén.","nguon":["@c0887"],"dinhDanh":"goc","congNang":["Cấm chế tu vi người đã bị Phùng gia hạ thuật @c0887"],"trangThai":"đã hạ lên Phùng Chẩm","capNhatToi":"@c0887","tabs":{"tienTrinh":[{"chuong":"@c0887","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ tác dụng","text":"Phong Nhạc nói Phùng gia đã hạ bí thuật lên Phùng Chẩm, khiến tộc nhân hệ Trúc Cơ trở lên có thể chế trụ tu vi hắn.","anchor":"chỉ cần là Phùng gia hệ tộc nhân đã ngoài Phùng gia Trúc Cơ kỳ, cũng có thể thi pháp cấm chế trụ tu vi của hắn"}]}},{"id":"cam-tien-thu","name":"Cầm Tiên Thủ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đột Ngột","soHuu":["Đại tiên sư Đột Ngột"],"blurb":"Cầm Tiên Thủ là thần thông của đại tiên sư Đột Ngột từng đánh trúng ngoại nhân. Ưng tiền bối dựa vào thương thế này để cho rằng đối phương tuy đáng sợ nhưng không còn ở trạng thái toàn thịnh.","detail":"Thần thông này được nhắc trong bối cảnh phe Đột Ngột truy bắt Hàn Lập, có tác dụng gây thương thế hoặc kiềm chế khiến ngoại nhân rơi vào tình trạng nguy hiểm.","thuocTinh":"Khống chế hoặc gây thương thế","uyLuc":"Được Ưng tiền bối xem là đòn khiến ngoại nhân bị thương, giảm bớt uy hiếp so với lúc toàn thịnh.","dacDiem":"Gắn với đại tiên sư Đột Ngột trong cuộc vây bắt ngoại nhân.","congNang":["Gây thương thế hoặc phong tỏa ngoại nhân trong cuộc truy bắt @c0888"],"nguoiTu":[{"ten":"Đại tiên sư Đột Ngột","tuChuong":"@c0888","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0888","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Ưng tiền bối nhắc trong cuộc bàn kế hoạch","text":"Ưng tiền bối nói ngoại nhân đã dính Cầm Tiên Thủ của đại tiên sư nên hiện bị thương, dù vẫn rất đáng sợ.","anchor":"Nhưng bây giờ đối dính Cầm Tiên Thủ của đại tiên sư"}]},"capNhatToi":"@c0888","nguon":["@c0888"]},{"id":"bi-thuat-than-thuc-dac-biet","name":"Bí thuật thần thức đặc biệt","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Thần thức","soHuu":["Ưng tiền bối"],"blurb":"Bí thuật liên quan đến thần thức khiến Hàn Lập cảm thấy bí ẩn khó lường. Nó được dùng để dò xét đoàn xe nhưng không trực tiếp xác minh được thân phận Hàn Lập.","detail":"Thần thức dò xét đoàn xe được Hàn Lập nhận định là rất bí ẩn kỳ diệu, không giống cách dò xét thông thường và có liên quan đến công pháp hoặc bí thuật đặc biệt. Do Hàn Lập đang thu liễm khí tức trong trạng thái tu vi suy giảm, sự dò xét này làm hắn cảnh giác nhưng cuối cùng không dẫn tới truy đuổi.","thuocTinh":"thần thức bí ẩn khó lường","trangThai":"đang được sử dụng","capNhatToi":"@c0889","nguoiTu":[{"ten":"Ưng tiền bối","tuChuong":"@c0889","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0889","loai":"thi triển","importance":"normal","giaiDoan":"Dò xét đoàn xe","text":"Thần thức bí ẩn dò xét đoàn xe khiến Hàn Lập nhận ra người dùng có liên quan đến một loại công pháp hoặc bí thuật đặc biệt.","anchor":"Mà thần thức kia bí ẩn kỳ diệu như vậy, vừa nhìn qua đã biết tu luyện công pháp có liên quan đến bí thuật đặc biệt"}]},"nguon":["@c0889"]},{"id":"lam-quang-dong-tu","name":"Lam quang đồng tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông quan sát","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông quan sát biểu hiện bằng ánh lam trong đồng tử của Hàn Lập, giúp hắn nhìn rõ đoàn người phía sau cự bức từ xa.","detail":"Hàn Lập vận ánh lam trong đồng tử để quan sát cự bức và sớm thấy rõ tám tu sĩ phía sau, qua đó đánh giá nhóm này có hai Kết Đan kỳ và sáu Trúc Cơ kỳ.","thuocTinh":"Quan sát","congNang":["Nhìn rõ mục tiêu từ xa trong lúc cự bức còn đang bay đến @c0890"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0890","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0890","loai":"thi triển","importance":"normal","giaiDoan":"Quan sát cự bức","text":"Hàn Lập dùng ánh lam trong đồng tử để nhìn rõ nhóm tu sĩ cưỡi cự bức từ xa.","anchor":"khi đồng tử lam quang lóe lên, hắn sớm đã thấy rõ ràng"}]},"capNhatToi":"@c0890","nguon":["@c0890"]},{"id":"mat-thuat-quan-sat-dung-mao","name":"Mật thuật quan sát dung mạo","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Mật thuật kiểm tra","phamCap":"","hePhai":"Cửu Tiên cung","soHuu":["Cố thống lĩnh"],"blurb":"Mật thuật do Cố thống lĩnh thi triển qua ánh mắt để kiểm tra dung mạo thật giả của người trước mặt.","detail":"Cố thống lĩnh dùng mật thuật này khi buộc Hàn Lập tháo nón lá, sau đó kết luận dung mạo của Hàn Lập là thật và không phải phản đồ đang truy tìm.","thuocTinh":"Quan sát, kiểm tra","congNang":["Kiểm tra diện mạo thật giả của người bị quan sát @c0890"],"nguoiTu":[{"ten":"Cố thống lĩnh","tuChuong":"@c0890","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0890","loai":"thi triển","importance":"normal","giaiDoan":"Kiểm tra Hàn Lập","text":"Cố thống lĩnh dùng mật thuật quan sát Hàn Lập rồi xác nhận hắn không phải phản đồ đang truy bắt.","anchor":"dĩ nhiên đang thi triển mật thuật gì đó quan sát hắn"}]},"capNhatToi":"@c0890","nguon":["@c0890"]},{"id":"han-vu-tuyet-tinh-chau","name":"Hàn vụ Tuyết Tinh châu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông từ pháp bảo","phamCap":"","hePhai":"","soHuu":["Giang Kiếm Anh"],"blurb":"Thần thông hàn vụ do Tuyết Tinh châu phát ra khi Giang Kiếm Anh thúc động bảo châu để tự vệ.","detail":"Giang Kiếm Anh dùng Tuyết Tinh châu hóa ra một đoàn hàn vụ hơn hai mươi trượng bao phủ bản thân, nhưng do chưa đủ tu vi luyện hóa châu nên hàn vụ dần bị hỏa vân pháp kỳ của sáu tu sĩ Cửu Tiên cung áp chế.","thuocTinh":"Hàn khí","congNang":["Tạo hàn vụ hơn hai mươi trượng để bao phủ và phòng ngự quanh người dùng @c0890"],"nguoiTu":[{"ten":"Giang Kiếm Anh","tuChuong":"@c0890","tangDatToi":"","trangThai":"bị áp chế"}],"tabs":{"tienTrinh":[{"chuong":"@c0890","loai":"thi triển","importance":"normal","giaiDoan":"Chống truy bắt","text":"Giang Kiếm Anh thúc Tuyết Tinh châu tạo hàn vụ để chống Cửu Tiên cung nhưng bị hỏa vân pháp kỳ áp chế.","anchor":"hóa thành một đoàn hàn vụ hơn hai mươi trượng đưa hắn bao phủ"}]},"capNhatToi":"@c0890","nguon":["@c0890"]},{"id":"hoa-van-phap-ky-hop-kich","name":"Hỏa vân pháp kỳ hợp kích","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Trận pháp hợp kích","phamCap":"","hePhai":"Cửu Tiên cung","soHuu":["Sáu tu sĩ Trúc Cơ Cửu Tiên cung"],"blurb":"Hợp kích bằng hồng mông pháp kỳ của sáu tu sĩ Trúc Cơ Cửu Tiên cung, tạo hỏa vân để áp chế hàn vụ.","detail":"Sáu tu sĩ Trúc Cơ mỗi người dùng một cây hồng mông pháp kỳ đỏ đậm, hợp lực tạo một mảnh hỏa vân phía trên hàn vụ của Tuyết Tinh châu, khiến hàn vụ suy yếu dần.","thuocTinh":"Hỏa","congNang":["Hợp lực tạo hỏa vân để áp chế hàn vụ do Tuyết Tinh châu sinh ra @c0890"],"nguoiTu":[{"ten":"Sáu tu sĩ Trúc Cơ Cửu Tiên cung","tuChuong":"@c0890","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0890","loai":"thi triển","importance":"normal","giaiDoan":"Áp chế Tuyết Tinh châu","text":"Sáu tu sĩ Trúc Cơ Cửu Tiên cung hợp lực dùng hồng mông pháp kỳ tạo hỏa vân áp chế hàn vụ của Giang Kiếm Anh.","anchor":"Một mảnh hỏa vân xuất hiện phía trên hàn vụ"}]},"capNhatToi":"@c0890","nguon":["@c0890"]},{"id":"hoa-viem-tran","name":"Hỏa Viêm trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đại Tấn","soHuu":["Sáu gã Trúc Cơ kỳ tu sĩ Đại Tấn"],"blurb":"Trận pháp hỏa hệ được nhóm Trúc Cơ Đại Tấn định dùng để luyện hóa Hàn Lập. Trận chưa kịp phát huy thì pháp kỳ và hỏa vân bị Âm La phiên cuốn sạch.","detail":"Nhóm Trúc Cơ Đại Tấn tế pháp kỳ đỏ rực để bố trí Hỏa Viêm trận bên trên quầng sáng của Hàn Lập. Mục đích của trận là dùng hỏa vân luyện hóa mục tiêu, nhưng bị đệ nhị Nguyên Anh thúc Âm La phiên phá ngang.","thuocTinh":"Hỏa hệ","uyLuc":"Dùng hỏa vân để luyện hóa mục tiêu.","dacDiem":"Cần các pháp kỳ đỏ rực phối hợp bố trí.","congNang":["Luyện hóa mục tiêu bằng hỏa vân @c0891"],"nguoiTu":[{"ten":"Sáu gã Trúc Cơ kỳ tu sĩ Đại Tấn","tuChuong":"@c0891","tangDatToi":"Không rõ","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0891","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí chưa hoàn tất","text":"Sáu Trúc Cơ Đại Tấn định bố trí Hỏa Viêm trận để luyện hóa Hàn Lập, nhưng trận bị Âm La phiên cuốn sạch trước khi phát huy.","anchor":"Nhanh bố trí hỏa viêm trận đến luyện hóa người này"}]},"capNhatToi":"@c0891","nguon":["@c0891"]},{"id":"phi-don-thuat-cua-bach-y-nu-tu","name":"Phi độn thuật của bạch y nữ tử","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Độn thuật","phamCap":"Không rõ","hePhai":"Tiên cung","soHuu":["Bạch y nữ tử Kết Đan Đại Tấn"],"blurb":"Độn thuật bạch y nữ tử am hiểu để tăng tốc khi bỏ chạy. Nàng dùng pháp quyết thúc cự bức nhưng vẫn không thoát khỏi ma vân của đệ nhị Nguyên Anh.","detail":"Trong lúc bỏ chạy, bạch y nữ tử thúc pháp quyết làm cự bức tăng tốc, thể hiện nàng am hiểu phi độn thuật. Thủ đoạn này không đủ giúp nàng thoát khỏi ma vân Âm La phiên.","thuocTinh":"Phi độn","uyLuc":"Tăng tốc bỏ chạy cùng tọa kỵ phi hành.","dacDiem":"Phối hợp pháp quyết và cự bức.","congNang":["Tăng tốc bỏ chạy khi bị truy sát @c0891"],"nguoiTu":[{"ten":"Bạch y nữ tử Kết Đan Đại Tấn","tuChuong":"@c0891","tangDatToi":"Không rõ","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0891","loai":"thi triển","importance":"normal","giaiDoan":"Bỏ chạy khỏi ma vân","text":"Bạch y nữ tử thi triển phi độn thuật để thúc cự bức tăng tốc, nhưng vẫn bị ma vân bắt kịp.","anchor":"tựa hồ am hiểu phi độn thuật, dưới sự thúc giục của pháp quyết"}]},"capNhatToi":"@c0891","nguon":["@c0891"]},{"id":"ma-van-am-la-phien","name":"Ma vân Âm La phiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông pháp bảo","phamCap":"Không rõ","hePhai":"Âm La phiên","soHuu":["Nguyên anh thứ hai của Hàn Lập"],"blurb":"Ma vân do Âm La phiên phóng ra dưới sự điều khiển của đệ nhị Nguyên Anh. Trong chương này, ma vân truy sát bạch y nữ tử hơn mười dặm và khiến nàng biến mất.","detail":"Đệ nhị Nguyên Anh nhập vào Âm La phiên rồi điều khiển ma vân cuồn cuộn truy theo bạch y nữ tử. Ma vân bao phủ mục tiêu dù nàng am hiểu phi độn và có cự bức tăng tốc.","thuocTinh":"Ma khí","uyLuc":"Truy kích và diệt tu sĩ Kết Đan.","dacDiem":"Có thể rời chiến trường truy sát mục tiêu ở khoảng cách xa.","congNang":["Truy kích và bao phủ mục tiêu bằng ma vân @c0891","Tiêu diệt bạch y nữ tử Kết Đan sau khi truy hơn mười dặm @c0891"],"nguoiTu":[{"ten":"Nguyên anh thứ hai của Hàn Lập","tuChuong":"@c0891","tangDatToi":"Điều khiển truy sát Kết Đan","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0891","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát bạch y nữ tử","text":"Ma vân Âm La phiên được đệ nhị Nguyên Anh điều khiển truy sát bạch y nữ tử và bao phủ nàng ngoài hơn mười dặm.","anchor":"bị ma vân phô thiên cái địa không hề có ý thương hương tiếc ngọc bao lại"}]},"capNhatToi":"@c0891","nguon":["@c0891"]},{"id":"tieu-hoa-cau","name":"Tiểu hỏa cầu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thuật pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật pháp hỏa cầu nhỏ được Hàn Lập dùng để thiêu hủy thi thể.","detail":"Hàn Lập bắn ra một tiểu hỏa cầu, khiến thi thể thanh niên tự sát hóa thành tro bụi.","congNang":["Thiêu hủy thi thể @c0892"],"tabs":{"tienTrinh":[{"chuong":"@c0892","loai":"thi triển","importance":"normal","giaiDoan":"Thiêu xác","text":"Hàn Lập dùng tiểu hỏa cầu thiêu thi thể thanh niên tự sát thành tro bụi.","anchor":"một tiểu hỏa cầu bắn ra, nhất thời đem thi thể thanh niên biến thành tro bụi"}]},"capNhatToi":"@c0892","nguon":["@c0892"]},{"id":"thu-ma-khi-bang-tieu-phien","name":"Thu ma khí bằng tiểu phiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông khu sử pháp bảo","phamCap":"không rõ","hePhai":"","soHuu":["Nguyên anh thứ hai của Hàn Lập"],"blurb":"Thủ đoạn dùng tiểu phiên thu hồi toàn bộ ma khí sau trận chiến.","detail":"Nguyên anh thứ hai của Hàn Lập cầm tiểu phiên hiện ra, cuốn ma khí vào trong phiên rồi nhập lại thiên linh cái Hàn Lập.","congNang":["Thu hồi ma khí bằng tiểu phiên @c0892"],"tabs":{"tienTrinh":[{"chuong":"@c0892","loai":"thi triển","importance":"normal","giaiDoan":"Thu hồi ma khí","text":"Nguyên anh thứ hai dùng tiểu phiên thu toàn bộ ma khí còn lại sau trận chiến.","anchor":"Một trận cuồng phong qua đi, tất cả ma khí đều bị thu vào trong phiên"}]},"capNhatToi":"@c0892","nguon":["@c0892"]},{"id":"cu-hinh-tran-do-trieu-hoan","name":"Cự hình trận đồ triệu hoán","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh điện"],"blurb":"Cự hình trận đồ đặt trong cấm địa thánh điện, dùng làm nền cho nghi thức triệu hoán phân thân thánh thú.","detail":"Trận đồ nằm giữa quảng trường trong cấm địa thánh điện, trung tâm có tế đàn làm trận nhãn cho nghi thức triệu hoán.","congNang":["Làm pháp trận trung tâm cho nghi thức triệu hoán @c0892"],"tabs":{"tienTrinh":[{"chuong":"@c0892","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí cấm địa","text":"Cự hình trận đồ xuất hiện tại trung tâm quảng trường trong cấm địa thánh điện, phục vụ nghi thức triệu hoán.","anchor":"ở trung tâm có một bộ cự hình trận đồ"}]},"capNhatToi":"@c0892","nguon":["@c0892"]},{"id":"nghi-thuc-trieu-hoan-phan-than-thanh-thu","name":"Nghi thức triệu hoán phân thân thánh thú","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Nghi thức trận pháp","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh nữ","Thiên Lan thánh điện"],"blurb":"Nghi thức do Thiên Lan thánh nữ chủ trì nhằm truy sát người ngoại tộc và giữ phân thân thánh thú ở lại thánh điện.","detail":"Nghi thức cần hơn trăm cao giai tiên sư hỗ trợ, hai yêu thú thất cấp đỉnh làm tế phẩm và cổ đỉnh thanh diễm trong cấm địa thánh điện.","congNang":["Triệu hoán phân thân thánh thú và khiến phân thân lưu lại thánh điện @c0892"],"tabs":{"tienTrinh":[{"chuong":"@c0892","loai":"xuất hiện","importance":"normal","giaiDoan":"Mục tiêu nghi thức","text":"Thiên Lan thánh nữ công bố nghi thức nhằm truy sát người ngoại tộc và khiến phân thân thánh thú vĩnh cửu ở lại thánh điện.","anchor":"không riêng gì vì đuổi giết người ngoại tộc nọ,mà còn làm cho phân thân thánh thú vĩnh cửu ở lại"}]},"capNhatToi":"@c0892","nguon":["@c0892"]},{"id":"ngan-ti-ngan-tac-cua-thien-lan-thanh-nu","name":"Ngân ti / ngân tác của Thiên Lan thánh nữ","cn":"","aliases":["Ngân ti","Ngân tác của Thiên Lan thánh nữ"],"loai":"than-thong","loaiLabel":"Thần thông trói buộc","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh nữ"],"blurb":"Thần thông phóng ngân ti hóa thành ngân tác để trói buộc mục tiêu.","detail":"Thiên Lan thánh nữ phóng ngân ti từ tay, hóa thành hơn trăm đạo ngân tác trói chặt Thanh Phong Ngưu và kéo nó lên tế đàn.","congNang":["Trói buộc và kéo yêu thú tế phẩm lên tế đàn @c0892"],"tabs":{"tienTrinh":[{"chuong":"@c0892","loai":"thi triển","importance":"normal","giaiDoan":"Trói tế phẩm","text":"Thiên Lan thánh nữ phóng ngân ti để trói Thanh Phong Ngưu và đưa nó lên tế đàn.","anchor":"Một chùm ngân ti từ ngọc thủ bắn nhanh ra"}]},"capNhatToi":"@c0892","nguon":["@c0892"]},{"id":"thanh-thu-chu-than","name":"Thánh Thú Chú Thân","cn":"","loai":"bi-thuat","loaiLabel":"Nghi thức triệu hoán","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh nữ","Đột Ngột nhân tiên sư"],"blurb":"Nghi thức triệu hoán phân thân thánh thú bằng huyết tế hai yêu thú thất cấp, thanh sa, pháp trận, cự đỉnh và linh lực của hai đại tiên sư.","detail":"Thiên Lan thánh nữ dùng nghi thức này để gọi xích mang thánh thú nhập vào huyết vân, tạo kén máu rồi nuôi luyện trong cự đỉnh nhằm đúc linh thân phân thân thánh thú ở nhân giới.","thuocTinh":"triệu hoán, huyết tế, đúc linh thân","uyLuc":"Có thể giúp phân thân thánh thú tạm lưu lại và dùng thần thông truy tìm kẻ ngoại tộc.","dacDiem":"Cần thanh sa, hai yêu thú thất cấp hiến tế, pháp trận, cự đỉnh và đại tiên sư trợ lực.","congNang":["Triệu hoán và đúc linh thân phân thân thánh thú @c0893"],"nguoiTu":[{"ten":"Thiên Lan thánh nữ","tuChuong":"@c0893","tangDatToi":"chủ trì nghi thức","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"xuất hiện","importance":"major","giaiDoan":"Triệu hoán phân thân","text":"Thiên Lan thánh nữ bắt đầu nghi thức, nhờ hai đại tiên sư trợ lực để triệu hoán phân thân thánh thú.","anchor":"Bắt đầu triệu hoán thánh thú. Hai vị xin trợ giúp ta một tay."}]},"capNhatToi":"@c0893","nguon":["@c0893"]},{"id":"huyet-te-thanh-sa","name":"Huyết tế thanh sa","cn":"","loai":"bi-thuat","loaiLabel":"Nghi thức phụ trợ","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh nữ"],"blurb":"Nghi thức phụ trợ dùng thanh sa hút tinh hồn huyết nhục yêu thú, tạo huyết vân làm môi giới cho phân thân thánh thú.","detail":"Trong nghi thức, thanh sa hút sạch tinh hồn huyết nhục của Thanh Phong Ngưu và Băng Giáp Mãng, sau đó hóa thành huyết vân để bao lấy xích mang thánh thú thành kén máu.","thuocTinh":"huyết tế","congNang":["Lấy huyết nhục tinh hồn yêu thú làm môi giới triệu hoán @c0893"],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"xuất hiện","importance":"normal","giaiDoan":"Hút tinh hồn huyết nhục","text":"Thanh sa liên tiếp hút tinh hồn huyết nhục hai yêu thú thất cấp để hóa thành huyết vân.","anchor":"liên tiếp hút tinh hồn huyết nhục hai con thất cấp yêu thú"}]},"capNhatToi":"@c0893","nguon":["@c0893"]},{"id":"phap-tran-trieu-hoan-quanh-te-dan","name":"Pháp trận triệu hoán quanh tế đàn","cn":"","loai":"cong-phap","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh nữ","Đột Ngột nhân tiên sư"],"blurb":"Pháp trận nghi lễ quanh tế đàn, cộng hưởng với cự đỉnh để tụ linh khí và hỗ trợ triệu hoán phân thân thánh thú.","detail":"Khi được Thiên Lan thánh nữ kích hoạt, pháp trận sáng lên, vận chuyển linh quang và phối hợp với cự đỉnh, quang cầu trong quá trình gọi thánh thú.","thuocTinh":"trận pháp triệu hoán","congNang":["Cộng hưởng cự đỉnh, tụ linh khí và hỗ trợ mở nghi thức triệu hoán @c0893"],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"xuất hiện","importance":"normal","giaiDoan":"Vận chuyển nghi thức","text":"Pháp trận quanh tế đàn được kích hoạt, linh quang đồng thời sáng lên để vận chuyển nghi thức.","anchor":"trong nháy mắt các nơi linh quang đồng thời sáng lên, pháp trận vận chuyển"}]},"capNhatToi":"@c0893","nguon":["@c0893"]},{"id":"huyet-anh-don","name":"Huyết ảnh độn","cn":"","loai":"bi-thuat","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Độn thuật Hàn Lập dùng trong lúc bị ba đại tiên sư Đột Ngột nhân truy đuổi trên Thiên Thủy hà.","detail":"Hàn Lập nhiều lần hóa huyết ảnh để bỏ xa đội truy đuổi cả ngàn dặm, nhưng vẫn bị thánh thú phân thân dựa vào linh giác chỉnh hướng bám theo.","thuocTinh":"độn thuật","congNang":["Độn xa nhanh bằng huyết ảnh trong lúc bỏ chạy @c0893","Độn hành trong thời gian gấp nhưng làm tinh nguyên tiêu hao mạnh @c0959"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0893","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"thi triển","importance":"normal","giaiDoan":"Đào thoát","text":"Hàn Lập dùng Huyết ảnh độn nhiều lần để bỏ xa nhóm truy đuổi cả ngàn dặm.","anchor":"liên tiếp mấy lần đều bị Hàn Lập dùng huyết ảnh độn bỏ xa cả ngàn dặm"},{"chuong":"@c0959","loai":"nhắc tới","importance":"normal","giaiDoan":"Đại giá sau khi thi triển","text":"Đại Diễn Thần Quân nhắc Hàn Lập đã dùng huyết ảnh độn quang nhiều ngày khiến tinh nguyên hao hụt.","anchor":"“mấy ngày nay ngươi sử dụng huyết ảnh độn quang khiến tinh nguyên tiêu hao”"}]},"capNhatToi":"@c0893","nguon":["@c0893","@c0959"],"aliases":["Huyết ảnh độn quang"]},{"id":"giai-phong-cua-han-lap","name":"Giải phong của Hàn Lập","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật giải phong","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Trạng thái hoặc bí thuật giải phong Hàn Lập bị ép dùng liên tiếp trong cuộc truy đuổi của ba đại tiên sư.","detail":"Cuối chương, Hàn Lập phải liên tiếp sử dụng ba lần giải phong nhưng vẫn chưa thể cắt đuôi Thiên Lan thánh nữ, Từ đạo hữu và Tôn tiên sứ.","thuocTinh":"giải phong","dacDiem":"Bị dùng liên tiếp khi tình thế truy đuổi trở nên nguy hiểm.","congNang":["Tạm thời giải phong trong lúc bị truy gắt @c0893"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0893","tangDatToi":"sử dụng ba lần liên tiếp","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"thi triển","importance":"normal","giaiDoan":"Bị ép giải phong","text":"Hàn Lập bị truy quá gắt nên phải liên tiếp sử dụng ba lần giải phong.","anchor":"Mà Hàn Lập bị ép liên tiếp sử dụng ba lần giải phong"}]},"capNhatToi":"@c0893","nguon":["@c0893"]},{"id":"linh-giac-thanh-thu","name":"Linh giác thánh thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông cảm ứng","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh thú phân thân"],"blurb":"Thần thông cảm ứng của Thiên Lan thánh thú phân thân, dùng để truy tung Hàn Lập qua dấu vết Phệ Kim Trùng.","detail":"Dù Hàn Lập lẩn dưới sông và không bị khóa bằng thần thức từ xa, việc mang nhiều Phệ Kim Trùng khiến y vẫn khó qua mặt linh giác thánh thú.","thuocTinh":"cảm ứng, truy tung","congNang":["Truy tung kẻ mang nhiều Phệ Kim Trùng dù đang lẩn trốn @c0893"],"nguoiTu":[{"ten":"Thiên Lan thánh thú phân thân","tuChuong":"@c0893","tangDatToi":"dùng truy tung Hàn Lập","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0893","loai":"thi triển","importance":"normal","giaiDoan":"Truy tung Phệ Kim Trùng","text":"Thánh thú phân thân dùng linh giác phát hiện Hàn Lập nhờ số lượng Phệ Kim Trùng trên người y.","anchor":"cũng không thể gạt được linh giác thánh thú"}]},"capNhatToi":"@c0893","nguon":["@c0893"]},{"id":"dai-dien-quyet","name":"Đại Diễn quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"khong-ro","hePhai":"Đại Diễn Thần Quân","soHuu":["Đại Diễn Thần Quân","Hàn Lập"],"blurb":"Công pháp cường hóa thần thức được Hàn Lập đem ra so sánh khi không hiểu vì sao bị truy tung chuẩn xác ngoài khoảng cách cực xa.","detail":"Trong cuộc truy sát, Hàn Lập nghi đối phương có công pháp cường hóa thần thức còn hơn Đại Diễn quyết. Đại Diễn Thần Quân thừa nhận không thể nói Đại Diễn quyết tuyệt đối đệ nhất tu tiên giới, nhưng phủ nhận khả năng phe truy kích chỉ dựa vào thần thức nhân giới ngoài ngàn dặm để khóa Hàn Lập.","thuocTinh":"Thần thức","dacDiem":"Cường hóa thần thức nhưng không được khẳng định là tuyệt đối đệ nhất tu tiên giới.","congNang":["Dùng làm chuẩn so sánh về năng lực thần thức khi Hàn Lập bị truy tung cực xa @c0894","Tăng mạnh thần thức tinh hồn của người tu luyện, được dùng làm cơ sở để Đại Diễn Thần Quân có thể lấy tinh hồn bản thân thay tinh hồn yêu thú cho khôi lỗi @c0964"],"tabs":{"tienTrinh":[{"chuong":"@c0894","loai":"nhắc tới","importance":"normal","giaiDoan":"So sánh truy tung","text":"Hàn Lập đem Đại Diễn quyết ra so sánh khi nghi ngờ phe Đột Ngột có công pháp thần thức mạnh hơn, còn Đại Diễn Thần Quân cho rằng nguyên nhân truy tung không đơn giản là thần thức.","anchor":"Thế gian thật có công pháp gì cường hóa thần thức so với Đại Diễn quyết"},{"chuong":"@c0964","loai":"nhắc tới","importance":"normal","giaiDoan":"Cơ sở tinh hồn cho khôi lỗi","text":"Hàn Lập nhắc Đại Diễn Thần Quân nhờ tu luyện Đại diễn quyết mà thần thức tinh hồn mạnh tới mức có thể thay tinh hồn yêu thú trong khôi lỗi.","anchor":"sau khi tu luyện đại diễn quyết thần thức tinh hồn"}]},"capNhatToi":"@c0894","nguon":["@c0894","@c0964"],"nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0964","tangDatToi":"không rõ","trangThai":"đã tu luyện"}]},{"id":"phap-quyet-gia-chet","name":"Pháp quyết giả chết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"khong-ro","hePhai":"Đại Diễn Thần Quân","soHuu":["Đại Diễn Thần Quân","Hàn Lập"],"blurb":"Bí thuật đơn giản do Đại Diễn Thần Quân tạm truyền cho Hàn Lập trong lúc bị Thiên Lan thánh thú truy tung.","detail":"Pháp quyết này có tác dụng hoàn toàn tiêu trừ sinh khí thân thể, nhằm thử che giấu Hàn Lập trước năng lực truy tung của thánh thú. Đại Diễn Thần Quân không bảo đảm hiệu quả vì chưa chắc thánh thú lần theo hơi thở thông thường.","thuocTinh":"Liễm tức","nguonGoc":"Đại Diễn Thần Quân truyền tạm cho Hàn Lập","uyLuc":"Có thể tiêu trừ sinh khí thân thể, nhưng hiệu quả với Thiên Lan thánh thú chưa chắc chắn.","dacDiem":"Được dùng như biện pháp ứng cấp trong tình thế truy sát nguy cấp.","congNang":["Tiêu trừ sinh khí thân thể để giả chết và thử cắt truy tung @c0894"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0894","tangDatToi":"khong-ro","trangThai":"duoc-truyen"}],"tabs":{"tienTrinh":[{"chuong":"@c0894","loai":"xuất hiện","importance":"normal","giaiDoan":"Ứng phó truy tung","text":"Đại Diễn Thần Quân tạm truyền pháp quyết giả chết cho Hàn Lập để tiêu trừ sinh khí thân thể trong lúc bị Thiên Lan thánh thú truy sát.","anchor":"Cho ngươi hoàn toàn tiêu trừ sinh khí thân thể"}]},"capNhatToi":"@c0894","nguon":["@c0894"]},{"id":"than-thong-truy-tung-cua-thien-lan-thanh-thu","name":"Thần thông truy tung của Thiên Lan thánh thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Thiên Lan thánh thú","soHuu":["Thiên Lan thánh thú phân thân"],"blurb":"Năng lực truy tung khiến Hàn Lập nhiều lần dùng Huyết ảnh độn và bỏ xa truy binh vẫn bị lần ra tung tích.","detail":"Đại Diễn Thần Quân cho rằng Hàn Lập không bị khóa bởi thần thức nhân giới thông thường mà bị một tồn tại phi nhân, rất có thể là Thiên Lan thánh thú, truy dấu. Năng lực này buộc Hàn Lập phải nghĩ tới kế diệt thánh thú thay vì chỉ trốn chạy.","thuocTinh":"Truy tung","uyLuc":"Có thể lần ra tung tích Hàn Lập sau nhiều lần bị bỏ xa khoảng cách rất lớn.","dacDiem":"Không được giải thích như thần thức thông thường của tu sĩ nhân giới.","congNang":["Truy tung mục tiêu cực xa dù mục tiêu dùng Huyết ảnh độn và đổi hướng bỏ chạy @c0894"],"tabs":{"tienTrinh":[{"chuong":"@c0894","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Hàn Lập","text":"Thiên Lan thánh thú dùng năng lực truy tung khiến Hàn Lập liên tục bị lần ra tung tích, trở thành mấu chốt khiến hắn phải đặt bẫy chia địch.","anchor":"mỗi lần đều truy tung được tung tích vãn bối"}]},"capNhatToi":"@c0894","nguon":["@c0894"]},{"id":"trieu-hoan-thanh-cam-mo-lan","name":"Triệu hoán thánh cầm Mộ Lan","cn":"","loai":"than-thong","loaiLabel":"Triệu hoán thuật","phamCap":"khong-ro","hePhai":"Mộ Lan nhân","soHuu":["Mộ Lan nhân"],"blurb":"Phương thức Mộ Lan nhân mượn bảo vật triệu một phần lực lượng linh cầm thượng giới xuống nhân giới, được Đại Diễn Thần Quân dùng làm đối chiếu.","detail":"Đại Diễn Thần Quân phân biệt phép triệu hoán thánh cầm của Mộ Lan với tình huống Thiên Lan thánh thú. Mộ Lan nhân mượn lực bảo vật đem bộ phận lực lượng linh cầm thượng giới triệu xuống, tạo ra ảo ảnh hóa hình tại nhân giới.","thuocTinh":"Triệu hoán thượng giới","nguonGoc":"Mộ Lan nhân","dacDiem":"Dựa vào bảo vật để mượn lực linh cầm thượng giới, không phải phân thần mượn thân thật thể như Thiên Lan thánh thú được suy đoán.","congNang":["Mượn lực bảo vật để triệu bộ phận lực lượng linh cầm thượng giới xuống nhân giới @c0894"],"tabs":{"tienTrinh":[{"chuong":"@c0894","loai":"nhắc tới","importance":"normal","giaiDoan":"Đối chiếu thánh thú","text":"Đại Diễn Thần Quân nhắc phép triệu hoán thánh cầm Mộ Lan để đối chiếu với khả năng Thiên Lan thánh thú mượn yêu thú thật thể giáng phân thần.","anchor":"mượn lực của bảo vật đem bộ phận lực lượng linh cầm ở thượng giới triệu xuống"}]},"capNhatToi":"@c0894","nguon":["@c0894"]},{"id":"ma-hoa-muon-the","name":"Ma hóa mượn thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Cổ Ma","soHuu":["Cổ Ma"],"blurb":"Thần thông của Cổ Ma được Đại Diễn Thần Quân dùng để giải thích khả năng mượn thể làm môi giới giáng phân thần.","detail":"Khi phân tích Thiên Lan thánh thú, Đại Diễn Thần Quân nêu khả năng nó dùng thủ đoạn tương tự Cổ Ma ma hóa mượn thể, mượn yêu thú khác làm môi giới để đưa phân thần bản thân xuống giới này.","thuocTinh":"Mượn thể","nguonGoc":"Cổ Ma","congNang":["Mượn thân thể khác làm môi giới để đưa phân thần xuống giới này @c0894"],"tabs":{"tienTrinh":[{"chuong":"@c0894","loai":"nhắc tới","importance":"normal","giaiDoan":"Giải thích thánh thú","text":"Ma hóa mượn thể được nhắc như phép so sánh cho cách Thiên Lan thánh thú có thể mượn yêu thú khác làm môi giới giáng phân thần.","anchor":"Mượn các yêu thú khác làm môi giới, đưa phân thần của bản thân xuống giới này"}]},"capNhatToi":"@c0894","nguon":["@c0894"]},{"id":"ao-thuat-bien-ao-cua-ngan-nguyet","name":"Ảo thuật biến ảo của Ngân Nguyệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông ảo thuật","phamCap":"không rõ","hePhai":"Khí linh","soHuu":["Ngân Nguyệt"],"blurb":"Ảo thuật giúp Ngân Nguyệt biến thành Hàn Lập với hình dáng, khí tức và linh khí gần như giống hệt.","detail":"Ở chương này, ảo thuật không chỉ mô phỏng dung mạo mà còn bắt chước khí tức độc nhất của Hàn Lập, khiến truy binh khó phân biệt thật giả trong thời gian ngắn.","thuocTinh":"ảo thuật biến hình và giả khí tức","uyLuc":"Ngay cả Đại Diễn Thần Quân cũng nhận xét khó nhìn thấu trong chốc lát.","dacDiem":"Có thể phối hợp với việc mang theo Phệ Kim Trùng để đánh lạc hướng truy tung theo khí tức linh trùng.","congNang":["Giả dạng hình thể, khí tức và linh khí của Hàn Lập @c0895"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0895","tangDatToi":"mô phỏng cả khí tức","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0895","loai":"thi triển","importance":"normal","giaiDoan":"Giả dạng Hàn Lập","text":"Ngân Nguyệt biến thành Hàn Lập và mô phỏng cả khí tức để chia đôi truy binh.","anchor":"ảo thuật biến ảo của nàng, ngay cả lão phu cũng có cảm giác nhìn không thấu"}]},"capNhatToi":"@c0895","nguon":["@c0895"]},{"id":"hang-linh-phu-yeu-hoa-giao-long","name":"Hàng Linh Phù yêu hóa giao long","cn":"","loai":"than-thong","loaiLabel":"Phù thuật thần thông","phamCap":"không rõ","hePhai":"Hàng Linh Phù","soHuu":["Hàn Lập"],"blurb":"Trạng thái yêu hóa do Hàn Lập kích hoạt bằng Hàng Linh Phù, khiến thân thể mang đặc trưng giao long.","detail":"Khi giao chiến với Thiên Lan thánh nữ, Hàn Lập vỗ Hàng Linh Phù lên người, hiện huyết sắc giao long ảo ảnh, mọc huyết lân và sừng giao long, chuyển thành hình thái nửa giao long nửa người.","thuocTinh":"yêu hóa thân thể","uyLuc":"Khí thế của Hàn Lập tăng mạnh sau khi chuyển sang hình thái nửa giao long nửa người.","dacDiem":"Biểu hiện ra huyết lân và sừng giao long trên thân thể người.","congNang":["Yêu hóa thân thể thành trạng thái nửa giao long nửa người @c0895"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0895","tangDatToi":"kích hoạt khi giao chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0895","loai":"thi triển","importance":"normal","giaiDoan":"Yêu hóa giao long","text":"Hàn Lập vỗ Hàng Linh Phù lên người và chuyển sang hình thái yêu hóa giao long.","anchor":"hiện ra từng khối huyết sắc lân phiến, trên đầu chui ra sừng giao long"}]},"capNhatToi":"@c0895","nguon":["@c0895"]},{"id":"tu-diem","name":"Tử diễm","cn":"","loai":"than-thong","loaiLabel":"Thần thông hỏa diễm hàn khí","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Ngọn diễm tím của Hàn Lập có thể bọc lên cự kiếm và ngưng thành tường băng tím phòng hộ.","detail":"Trong trận với Thiên Lan thánh nữ, Hàn Lập phun tử diễm hóa thành hỏa điểu quấn quanh cự kiếm phục kích, sau đó dùng hàn khí tím dựng tường băng cao khoảng mười trượng để chống ngân ti.","thuocTinh":"tử diễm, hàn khí","uyLuc":"Có thể vừa gia trì công kích cho cự kiếm vừa lập tức tạo phòng tuyến băng tím.","dacDiem":"Diễm tím khi bạo liệt chuyển thành hàn khí dựng tường băng trong suốt.","congNang":["Bọc cự kiếm để phục kích @c0895","Dựng tường băng tím phòng ngự ngân ti @c0895"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0895","tangDatToi":"bọc kiếm và dựng tường băng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0895","loai":"thi triển","importance":"normal","giaiDoan":"Bọc kiếm dựng băng","text":"Hàn Lập dùng tử diễm bọc cự kiếm rồi dựng tường băng tím chống ngân ti.","anchor":"một tường băng màu tím cao tầm mười trượng, trong suốt diễm lệ hiện ra sừng sững"}]},"capNhatToi":"@c0895","nguon":["@c0895"]},{"id":"hop-kiem-thanh-cu-kiem","name":"Hợp kiếm thành cự kiếm","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết thần thông","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn hợp nhiều khẩu phi kiếm thành một cự kiếm để tạo đòn phục kích mạnh.","detail":"Hàn Lập hợp hơn mười khẩu phi kiếm thành cự kiếm dài sáu bảy trượng, bọc tử diễm rồi giấu vào mây đen phía trên chiến trường để chờ thời cơ.","thuocTinh":"kiếm quyết hợp kiếm","uyLuc":"Hợp nhiều phi kiếm thành một cự kiếm lớn để tích lực phục kích từ trên cao.","dacDiem":"Cự kiếm có thể được che giấu trong mây đen sau khi bọc tử diễm.","congNang":["Hợp hơn mười khẩu phi kiếm thành cự kiếm phục kích @c0895"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0895","tangDatToi":"hợp cự kiếm dài sáu bảy trượng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0895","loai":"thi triển","importance":"normal","giaiDoan":"Cự kiếm phục kích","text":"Hàn Lập hợp phi kiếm thành cự kiếm, bọc tử diễm và giấu vào mây đen.","anchor":"trong nháy mắt một cự kiếm dài sáu bảy trượng bất ngờ thành hình"}]},"capNhatToi":"@c0895","nguon":["@c0895"]},{"id":"thong-bao-quyet-hu-thien-dinh-tang-thu-nhat","name":"Thông Bảo quyết Hư Thiên đỉnh tầng thứ nhất","cn":"","aliases":["Thông Bảo quyết Hư Thiên đỉnh"],"loai":"bi-thuat","loaiLabel":"Pháp quyết khu bảo","phamCap":"Chưa rõ","hePhai":"Hư Thiên đỉnh","soHuu":["Hàn Lập"],"blurb":"Pháp quyết Hàn Lập đã luyện tới tầng thứ nhất để vận dụng một phần uy năng của Hư Thiên đỉnh.","detail":"Trong trận với Thiên Lan thánh nữ, Hàn Lập vận dụng tầng thứ nhất pháp quyết này để phóng lam hà hộ thân và khiến thanh sa đang vây khốn hắn sụp tán, mất hiệu lực trước Hư Thiên đỉnh.","thuocTinh":"Khu sử pháp bảo đỉnh","dacDiem":"Tầng thứ nhất cho phép Hàn Lập mượn một phần uy năng Hư Thiên đỉnh để hộ thân và khắc chế linh sa.","chieuTieuBieu":"Lam hà hộ thân","cacTang":[{"ten":"Tầng thứ nhất","moTa":"Phát lam hà và lam quang gợn sóng từ Hư Thiên đỉnh, phá vây thanh sa.","chuong":"@c0896"}],"congNang":["Phát lam hà hộ thân quanh Hàn Lập trong lúc bị thanh sa vây kín @c0896","Khi phối hợp Hư Thiên đỉnh, làm thanh sa từ thánh đỉnh mất liên hệ thần thức với chủ @c0896"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0896","tangDatToi":"Tầng thứ nhất","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0896","loai":"thi triển","importance":"normal","giaiDoan":"Tầng thứ nhất","text":"Hàn Lập vận tầng thứ nhất Thông Bảo quyết Hư Thiên đỉnh để phóng lam hà hộ thân và phá thế vây thanh sa.","anchor":"Chính là tầng thứ nhất Thông Bảo quyết Hư Thiên đỉnh mà hắn tu luyện qua"}]},"capNhatToi":"@c0896","nguon":["@c0896"]},{"id":"bang-diem-mau-tim","name":"Băng diễm màu tím","cn":"","aliases":["Tử diễm"],"loai":"than-thong","loaiLabel":"Hàn diễm","phamCap":"Chưa rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Ngọn băng diễm màu tím Hàn Lập dùng để phản chế ngân tia và áp chế bạch diễm của Thiên Lan thánh nữ.","detail":"Băng diễm lan theo ngân tia từ băng thuẫn bị đâm thủng, phản kích về pháp bảo khăn gấm. Nó áp chế bạch diễm do ngân tàm phun ra, chỉ bị chặn lại khi Thiên Lan thú phun thêm thanh diễm trợ lực.","thuocTinh":"Hàn diễm màu tím","uyLuc":"Áp đảo bạch diễm của pháp bảo khăn gấm cho tới khi có thanh diễm Thiên Lan thú hỗ trợ.","congNang":["Men theo ngân tia phản kích pháp bảo khăn gấm @c0896","Áp chế bạch diễm của ngân tàm trên khăn gấm @c0896"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0896","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0896","loai":"thi triển","importance":"normal","giaiDoan":"Phản chế ngân tia","text":"Hàn Lập dùng băng diễm màu tím men theo ngân tia phản kích khăn gấm và ép bạch diễm lùi lại.","anchor":"tử diễm rõ ràng đại chiếm thượng phong, đem bạch diễm liên tiếp lui về phía sau"}]},"capNhatToi":"@c0896","nguon":["@c0896"]},{"id":"huyen-hoa-chi-thuat-cua-thien-lan-thu","name":"Huyễn Hóa Chi Thuật của Thiên Lan thú","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông huyễn hóa","phamCap":"Chưa rõ","hePhai":"Thiên Lan thú","soHuu":["Thiên Lan thú"],"blurb":"Thần thông tạo hư ảnh trong sương trắng, dùng để đánh lừa đối thủ trong giao chiến.","detail":"Thiên Lan thú dùng thuật này biến ra hư ảnh trong vụ hải, khiến Hàn Lập tưởng có thể tách thánh thú khỏi Thiên Lan thánh nữ và dùng cự kiếm chém xuống, nhưng mục tiêu chỉ hóa thành sương trắng.","thuocTinh":"Huyễn hóa","congNang":["Tạo hư ảnh Thiên Lan thú trong sương trắng để dụ đối thủ đánh nhầm @c0896"],"nguoiTu":[{"ten":"Thiên Lan thú","tuChuong":"@c0896","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0896","loai":"thi triển","importance":"normal","giaiDoan":"Huyễn ảnh trong vụ hải","text":"Thiên Lan thú tạo hư ảnh trong sương trắng, dụ Hàn Lập dùng cự kiếm chém nhầm.","anchor":"Con thú này đúng là là dùng Huyễn Hóa Chi Thuật biến ảo ra một cái hư ảnh"}]},"capNhatToi":"@c0896","nguon":["@c0896"]},{"id":"ba-dong-tieng-gam-cua-thien-lan-thu","name":"Ba động tiếng gầm của Thiên Lan thú","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông áp chế","phamCap":"Chưa rõ","hePhai":"Thiên Lan thú","soHuu":["Thiên Lan thú"],"blurb":"Tiếng gầm phát ra ba động vô hình, có thể can thiệp độn thuật bằng hồ quang bạc của Hàn Lập.","detail":"Khi Hàn Lập định dùng ngân sí thi triển lôi độn thoát khỏi thanh quang, tiếng gầm từ trong sương trắng tạo ba động vô hình quét qua, làm hồ quang trên ngân sí tắt và lôi độn mất hiệu lực trong chốc lát.","thuocTinh":"Âm ba và ba động vô hình","congNang":["Làm hồ quang trên ngân sí tắt, khiến lôi độn thuật tạm mất hiệu lực @c0896"],"nguoiTu":[{"ten":"Thiên Lan thú","tuChuong":"@c0896","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0896","loai":"thi triển","importance":"normal","giaiDoan":"Phá lôi độn","text":"Thiên Lan thú phát tiếng gầm tạo ba động vô hình, khiến lôi độn thuật của Hàn Lập tạm mất hiệu lực.","anchor":"một cỗ ba động vô hình trong nháy mắt từ trên thân Hàn Lập đảo qua"}]},"capNhatToi":"@c0896","nguon":["@c0896"]},{"id":"cam-che-don-gian-bang-tran-ky","name":"Cấm chế đơn giản bằng trận kỳ","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Cấm chế đơn giản được Hàn Lập bố trí quanh phòng trên thuyền Tào gia bằng một bộ trận kỳ. Nó dùng để che chắn và bảo hộ nơi hắn tĩnh tọa tu luyện.","detail":"Sau khi bàn xong với Đại Diễn thần quân, Hàn Lập lấy trận kỳ từ túi trữ vật, bày quanh bốn phía phòng thành một cấm chế đơn giản rồi uống đan dược tĩnh tọa.","dinhDanh":"goc","congNang":["Bố trí phòng hộ và che chắn quanh nơi tĩnh tọa @c0899"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0899","tangDatToi":"Có thể bố trí bằng trận kỳ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0899","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí trên thuyền Tào gia","text":"Hàn Lập dùng một bộ trận kỳ bày cấm chế đơn giản quanh phòng trước khi tĩnh tọa.","anchor":"tay từ trong túi trữ vật cầm một bộ trận kì, tại bốn phía bày ra một cái cấm chế đơn giản"}]},"capNhatToi":"@c0899","nguon":["@c0899"]},{"id":"phap-thuat-tho-thien-cua-huyen-ngoc-phai","name":"Pháp thuật thô thiển của Huyền Ngọc phái","cn":"","aliases":[],"loai":"khac","loaiLabel":"Pháp thuật","phamCap":"thô thiển","hePhai":"Huyền Ngọc phái","soHuu":["Tào Mộng Dung"],"blurb":"Một ít pháp thuật Huyền Ngọc phái truyền cho Tào Mộng Dung vì nàng chỉ là ký danh đệ tử. Chi tiết này cho thấy nền tảng tu luyện trong môn phái của nàng còn nông.","detail":"Sư phụ của Tào Mộng Dung chỉ truyền cho nàng một chút pháp thuật thô thiển do thân phận ký danh đệ tử, khiến nàng không được hưởng truyền thừa đầy đủ của Huyền Ngọc phái.","thuocTinh":"pháp thuật Huyền Ngọc phái","nguonGoc":"Huyền Ngọc phái","yeuCau":"Ký danh đệ tử chỉ được truyền ít pháp thuật cơ bản","dacDiem":"Mức truyền thụ hạn chế, phản ánh vị trí thấp của Tào Mộng Dung trong môn phái.","nguoiTu":[{"ten":"Tào Mộng Dung","tuChuong":"@c0900","tangDatToi":"không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0900","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc qua thân phận ký danh đệ tử","text":"Pháp thuật được nhắc như phần truyền thụ hạn chế mà Tào Mộng Dung nhận từ Huyền Ngọc phái.","anchor":"Tào sư muội đối với Huyền Ngọc chúng ta chỉ là ký danh đệ tử, sư phụ chỉ truyền thụ cho nàng một chút pháp thuật thô thiển"}]},"capNhatToi":"@c0900","nguon":["@c0900"]},{"id":"phu-luc-hoa-cau-hoa-hoa-mang","name":"Phù lục hỏa cầu hóa hỏa mãng","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật phù lục","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Cách Hàn Lập dùng nhiều phù lục hỏa cầu gom thành hỏa vân rồi hóa hỏa mãng để trói pháp khí đối phương.","detail":"Trong trận với Mã Ngọc Lâm, Hàn Lập không dùng pháp khí mà phóng nhiều phù lục, khiến hỏa cầu hợp lại thành hỏa vân rồi biến thành hỏa mãng quấn chặt Liên Hoàng Phượng xoa, ép đối phương nhận thua để bảo toàn pháp khí.","congNang":["Hỏa cầu hợp thành hỏa vân rồi hóa hỏa mãng trói pháp khí đối thủ @c0901"],"tabs":{"tienTrinh":[{"chuong":"@c0901","loai":"thi triển","importance":"normal","giaiDoan":"Trận với Mã Ngọc Lâm","text":"Hàn Lập dùng nhiều phù lục hỏa cầu hóa thành hỏa mãng, quấn chặt phi xoa của Mã Ngọc Lâm.","anchor":"đám hỏa cầu lập tức tập trung lại thành một đám hỏa vân"}]},"nguon":["@c0901"]},{"id":"cam-che-chong-nhin-len-cua-thien-co-oc","name":"Cấm chế chống nhìn lén của Thiên Cơ ốc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"cấp thấp","hePhai":"","soHuu":["Điện đường cho thuê mật thất"],"blurb":"Cấm chế gắn trên Thiên Cơ ốc dùng để ngăn thần thức dò xét từ bên ngoài. Dù không quá mạnh, nó đủ khiến người trong phòng phát hiện nếu bị cưỡng ép phá vào.","detail":"Trong chương này, Hàn Lập dùng thần thức thử thăm dò một thạch ốc đã phóng đại và bị tầng cấm chế chặn lại. Cấm chế có thể bị thần thức mạnh phá vỡ, nhưng khi bị phá thì chủ nhân trong phòng sẽ cảnh giác.","thuocTinh":"cấm chế phòng hộ thần thức","uyLuc":"Chặn thần thức dò xét thông thường và báo động khi bị cưỡng phá.","dacDiem":"Gắn với Thiên Cơ ốc cho thuê, thiên về bảo mật hơn là sát thương.","congNang":["Chặn thần thức dò xét từ bên ngoài @c0903","Báo động cho người trong phòng khi cấm chế bị phá @c0903"],"trangThai":"đang lưu hành trong điện đường cho thuê mật thất","capNhatToi":"@c0903","tabs":{"tienTrinh":[{"chuong":"@c0903","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập kiểm nghiệm","text":"Hàn Lập dùng thần thức dò thử thạch ốc và xác nhận cấm chế có thể ngăn nhìn lén, dù vẫn có thể bị cưỡng phá.","anchor":"thần thức có thể dễ dàng phá vỡ để vượt qua, nhưng sau khi cấm chế bị phá"}]},"nguon":["@c0903"]},{"id":"tho-thuoc-tinh-cong-phap","name":"Thổ thuộc tính công pháp","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Thổ thuộc tính","soHuu":["Kim Nguyên"],"blurb":"Công pháp thổ thuộc tính mà Kim Nguyên tu luyện khi làm tán tu.","detail":"Kim Nguyên tự nói mình là tán tu tu luyện thổ thuộc tính công pháp; nền tảng này đi cùng thổ linh thân thể và sở trường độn thổ thuật của ông.","nguoiTu":[{"ten":"Kim Nguyên","tuChuong":"@c0904","tangDatToi":"Không rõ","trangThai":"đang tu"}],"nguon":["@c0904"]},{"id":"than-niem-chi-bich","name":"Thần niệm chi bích","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông thần thức","phamCap":"không rõ","hePhai":"thần thức","soHuu":["Hàn Lập"],"blurb":"Thần niệm chi bích là thủ đoạn Hàn Lập dùng thần thức hóa hình thành bức tường vô hình. Trong chương này nó chặn đoàn lục quang nhỏ như hạt gạo đang bỏ chạy khỏi kim cương tráo.","detail":"Hàn Lập ngưng tụ thần niệm thành vách ngăn vô hình để cản độn quang. Đoàn lục quang từ bọt khí vàng bắn ra bị bức tường này chặn lại, tạo cơ hội cho Đề Hồn thú cuốn về và nuốt mất.","thuocTinh":"thần thức","uyLuc":"Có thể chặn đoàn lục quang đang bỏ chạy khỏi kim cương tráo.","dacDiem":"Do thần thức hóa hình tạo thành, không biểu hiện như pháp bảo hữu hình.","congNang":["Chặn độn quang hoặc linh thể nhỏ bằng thần thức @c0905"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0905","tangDatToi":"thi triển được thần niệm chi bích","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0905","loai":"thi triển","importance":"normal","giaiDoan":"Chặn lục quang","text":"Hàn Lập dùng thần niệm chi bích chặn đoàn lục quang đang thoát khỏi bọt khí vàng.","anchor":"Đúng là thần niệm chi bích do thần thức của Hàn Lập hóa hình thuật mà hình thành"}]},"capNhatToi":"@c0905","nguon":["@c0905"]},{"id":"minh-ha-thien-thi-quyet","name":"Minh hà thiên thi quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp thi đạo","phamCap":"không rõ","hePhai":"thi đạo","soHuu":["Vương nhi","Trung niên nam tử trong quan tài giữa"],"blurb":"Minh hà thiên thi quyết là công pháp thi đạo do trung niên nam tử trong quan tài giữa truyền cho Vương nhi. Theo lời ông, tiếp tục tu luyện công pháp này có thể giúp phân thần bị mất khôi phục như cũ.","detail":"Công pháp được nhắc trong mộ thất Tam Thi khi Vương nhi mất một phân thần trong kim cương tráo. Trung niên nam tử trấn an rằng nếu Vương nhi tiếp tục tu luyện Minh hà thiên thi quyết do phụ vương truyền thụ thì phân thần còn có thể khôi phục.","thuocTinh":"thi đạo","nguonGoc":"Do trung niên nam tử trong quan tài giữa truyền thụ cho Vương nhi.","uyLuc":"Có tác dụng giúp phân thần khôi phục sau khi bị mất.","congNang":["Khôi phục phân thần bị tổn thất khi tiếp tục tu luyện @c0905"],"nguoiTu":[{"ten":"Vương nhi","tuChuong":"@c0905","tangDatToi":"đang tu luyện","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0905","loai":"nhắc tới","importance":"normal","giaiDoan":"Được phụ vương nhắc tới","text":"Trung niên nam tử nói Vương nhi chỉ cần tiếp tục tu luyện Minh hà thiên thi quyết thì phân thần có thể khôi phục như cũ.","anchor":"chỉ cần ngươi tiếp tục tu luyện “Minh hà thiên thi quyết” do phụ vương truyền thụ"}]},"capNhatToi":"@c0905","nguon":["@c0905"]},{"id":"nguyet-hoa-chi-luc","name":"Nguyệt hoa chi lực","cn":"","aliases":[],"loai":"khac","loaiLabel":"Tu luyện/luyện bảo","phamCap":"","hePhai":"Thi đạo","soHuu":["Vương Nhi","Trung niên nam tử"],"blurb":"Lực lượng nguyệt hoa được Vương Nhi mượn để luyện hóa Kim cương tráo. Đại vương cũng cho rằng loại bảo tráo này chỉ vạn năm thi vương mới có thể nhờ nguyệt hoa mà luyện thành.","detail":"Vương Nhi từng dời phân huyệt lên mặt đất để mượn nguyệt hoa chi lực luyện hóa hoàn toàn Kim cương tráo và chuẩn bị nghi thức nhận chủ. Về sau, đại vương nhấn mạnh bảo vật dạng này không phải nhân loại có thể luyện hóa dễ dàng, mà cần vạn năm thi vương như hắn hoặc Vương Nhi dùng nguyệt hoa chi lực mới có khả năng luyện thành.","nguon":["@c0906"]},{"id":"cam-che-an-dau-trong-bao-vat","name":"Cấm chế ẩn dấu trong bảo vật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"","hePhai":"Thi đạo","soHuu":["Vương Nhi"],"blurb":"Cấm chế được giấu trong bảo vật làm mồi dụ tán tu, có thể bị phân thần của Vương Nhi thúc giục để giết người giữ bảo vật và cuốn nguyên thần về cổ mộ.","detail":"Khi tu sĩ bị khống chế đem bảo vật bán cho tán tu đơn độc, phân thần của Vương Nhi ẩn trong bảo vật có thể chờ thời cơ phát động cấm chế. Nếu mục tiêu không tự đến cổ mộ, cấm chế sẽ diệt thân thể người đó và đưa nguyên thần trở về. Cuối chương, cơ chế này bộc phát trên Kim Nguyên: hôi sắc hỏa diễm bao phủ, thân thể hóa thành khói xanh, nguyên thần bị cuốn bay đi.","nguon":["@c0906"]},{"id":"thi-hoa","name":"Thi hỏa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thi đạo thần thông","phamCap":"","hePhai":"Thi đạo","soHuu":["Trung niên nam tử","Vương Nhi"],"blurb":"Hỏa diễm thuộc thi đạo, được nhắc trong cơ chế bảo vật và từng được đại vương dùng để phá kim quang hộ thể từ xá lợi của lão tăng.","detail":"Thi hỏa được dùng như thủ đoạn giấu trong bảo vật để sát thương và bắt nguyên thần. Trong quá khứ, khi đối phó lão hòa thượng có xá lợi tử hộ thân, đại vương từng phát động thi hỏa liên tục ba ngày ba đêm mới làm kim quang trên xá lợi tiêu tán và tiêu diệt được đối thủ.","nguon":["@c0906"]},{"id":"cach-hon-thuat","name":"Cách hồn thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thuật tách nguyên thần","phamCap":"","hePhai":"Thi đạo","soHuu":["Trung niên nam tử"],"blurb":"Thuật pháp đại vương dự định dùng sau khi luyện thành thiên thi chi thể, nhằm đưa nguyên thần của nữ tử và Vương Nhi thoát khỏi mộ thất.","detail":"Đại vương nói nếu bản thân luyện thành thiên thi chi thể thì không chỉ hắn thoát khỏi ràng buộc mộ thất, mà còn có biện pháp thi triển cách hồn thuật để đem nguyên thần của nữ tử và Vương Nhi thoát ra. Thuật này gắn trực tiếp với kế hoạch giải phóng nhóm thi vương khỏi mộ thất.","nguon":["@c0906"]},{"id":"thien-thi-than-the","name":"Thiên thi thân thể","cn":"","aliases":["Thiên thi chi thể"],"loai":"luyen-the","loaiLabel":"Thi đạo thân thể","phamCap":"","hePhai":"Thi đạo","soHuu":["Trung niên nam tử"],"blurb":"Mục tiêu đột phá cuối cùng của đại vương, cần mượn tinh hồn tu sĩ nhân loại để luyện thành và thoát khỏi mộ thất.","detail":"Đại vương muốn thu lấy lượng lớn tinh hồn tu sĩ nhân loại để đột phá cảnh giới cuối cùng và luyện thành thiên thi thân thể. Khi đạt được thiên thi chi thể, hắn có thể thoát ly mộ thất, đồng thời dự định dùng cách hồn thuật để giúp nữ tử và Vương Nhi thoát khỏi nơi này.","nguon":["@c0906"]},{"id":"tran-phap-ngan-cach-khi-tuc","name":"Trận pháp ngăn cách khí tức","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp do Hàn Lập bố trí bằng nhiều trận kỳ quanh nơi thẩm vấn Khổng Đấu.","detail":"Hàn Lập cắm trận kỳ quanh hai người để hình thành trận pháp ngăn cách khí tức, tránh động tĩnh thẩm vấn bị bên ngoài phát hiện.","congNang":["Ngăn cách khí tức trong phạm vi bố trí @c0909"],"nguon":["@c0909"],"tabs":{"tienTrinh":[{"chuong":"@c0909","loai":"xuất hiện","importance":"normal","giaiDoan":"Thẩm vấn Khổng Đấu","text":"Hàn Lập dùng trận kỳ lập trận quanh hai người để ngăn cách khí tức trước khi tra hỏi Khổng Đấu.","anchor":"cắm ở bốn xung quanh hai người, hình thành một cái trận pháp ngăn cách khí tức"}]},"capNhatToi":"@c0909"},{"id":"mong-dan-thuat","name":"Mộng dẫn thuật","cn":"","loai":"khac","loaiLabel":"Thuật pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật pháp được Hàn Lập nhắc đến khi xử lý ký ức và tra hỏi Khổng Đấu.","detail":"Hàn Lập cho biết do tu vi hiện thời chưa đủ nên Mộng dẫn thuật không thể thi triển toàn lực, khiến việc tra hỏi và che giấu ký ức phải làm theo cách phiền toái hơn.","yeuCau":"Cần tu vi đủ để thi triển toàn lực @c0909","dacDiem":"Khi tu vi chưa đủ thì không thể phát huy toàn lực.","nguon":["@c0909"],"tabs":{"tienTrinh":[{"chuong":"@c0909","loai":"nhắc tới","importance":"normal","giaiDoan":"Sau thẩm vấn Khổng Đấu","text":"Hàn Lập nhắc Mộng dẫn thuật không thể thi triển toàn lực do tu vi chưa đủ.","anchor":"Mộng dẫn thuật không thể thi triển toàn lực"}]},"capNhatToi":"@c0909"},{"id":"khau-quyet-mo-phap-khi-tru-vat-cua-phung-cham","name":"Khẩu quyết mở pháp khí trữ vật của Phùng Chẩm","cn":"","loai":"bi-thuat","loaiLabel":"Pháp quyết","phamCap":"không rõ","hePhai":"Phùng gia","soHuu":["Phùng Chẩm","Hàn Lập"],"blurb":"Khẩu quyết dùng để mở viên gạch pháp khí trữ vật của Phùng Chẩm. Hàn Lập dùng đúng khẩu quyết này để tránh cưỡng ép khiến vật chứa hóa tro.","detail":"Pháp quyết chuyên dùng mở viên gạch pháp khí trữ vật do Phùng Chẩm để lại. Chương 910 cho thấy vật chứa này không thể tùy tiện phá mở mà phải dùng đúng khẩu quyết mới lấy được ngọc giản và văn thư bên trong.","dinhDanh":"goc","thuocTinh":"mở pháp khí trữ vật","congNang":["Mở viên gạch pháp khí trữ vật của Phùng Chẩm mà không phá hủy vật chứa @c0910"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0910","tangDatToi":"dùng được khẩu quyết","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0910","loai":"thi triển","importance":"normal","giaiDoan":"Mở vật chứa","text":"Hàn Lập dùng khẩu quyết Phùng Chẩm để lại để mở viên gạch pháp khí trữ vật.","anchor":"vật này phải có một bộ pháp quyết mới mở ra được"}]},"capNhatToi":"@c0910","nguon":["@c0910"]},{"id":"phap-quyet-ti-thuy","name":"Pháp quyết tị thủy","cn":"","loai":"bi-thuat","loaiLabel":"Pháp quyết","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Pháp quyết Hàn Lập sử dụng khi tiến vào thác nước che lối mật quật Phùng gia. Nó giúp hắn tránh nước trước khi mở lỗ hổng bằng thanh quang.","detail":"Khi tìm được thác nước khớp với ngọc giản mật quật, Hàn Lập bắt pháp quyết tị thủy rồi mới dùng thanh quang rẽ nước, tạo lỗ hổng để xuyên vào bên trong.","dinhDanh":"goc","thuocTinh":"tị thủy","congNang":["Giúp tránh nước khi tiến vào khu vực thác che lối mật quật @c0910"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0910","tangDatToi":"thi triển được","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0910","loai":"thi triển","importance":"normal","giaiDoan":"Vào thác nước","text":"Hàn Lập bắt pháp quyết tị thủy rồi dùng thanh quang mở lối trong thác nước.","anchor":"đầu tiên là bắt pháp quyết tị thủy, sau đó hai tay giương lên"}]},"capNhatToi":"@c0910","nguon":["@c0910"]},{"id":"truu-hon-hoa-than-bi-thuat","name":"Trừu hồn hóa thần bí thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật luyện hóa","phamCap":"không rõ","hePhai":"Thi đạo","soHuu":["Huyễn Vương"],"blurb":"Bí thuật bị nói là Huyễn Vương dùng để luyện thống lĩnh thủ hạ thành hóa thân hoặc khôi lỗi phụ thuộc.","detail":"Thiên Phong chân quân cho rằng Huyễn Vương dùng bí thuật này cưỡng ép luyện mấy thống lĩnh thủ hạ thành phụ chúc khôi lỗi. Những khôi lỗi này có cảnh giới Nguyên Anh kỳ nhưng yếu hơn tu sĩ đồng giai.","dinhDanh":"goc","congNang":["Luyện thống lĩnh thủ hạ thành hóa thân hoặc khôi lỗi phụ thuộc @c0911"],"nguoiTu":[{"ten":"Huyễn Vương","tuChuong":"@c0911","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0911","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phe mai phục nhận định","text":"Thiên Phong chân quân nói Huyễn Vương cưỡng ép luyện thống lĩnh thủ hạ thành phụ chúc khôi lỗi.","anchor":"đem mấy tên thống lĩnh thủ hạ của mình cường hành luyện chế thành phụ chúc khôi lỗi"}]},"capNhatToi":"@c0911","nguon":["@c0911"]},{"id":"thi-linh-dai-phap","name":"Thi linh đại pháp","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp khu thi","phamCap":"không rõ","hePhai":"Thi đạo","soHuu":["Chủ nhân thanh âm chói tai"],"blurb":"Công pháp của chủ nhân thanh âm chói tai, được nói có thể khu sử thi binh trong lăng mộ.","detail":"Thiên Phong chân quân nhận định chỉ có thi linh đại pháp của đồng bọn mới có thể khu sử mấy ngàn thi binh trong lăng mộ dễ như trở bàn tay.","dinhDanh":"goc","congNang":["Khu sử mấy ngàn thi binh trong lăng mộ @c0911"],"nguoiTu":[{"ten":"Chủ nhân thanh âm chói tai","tuChuong":"@c0911","tangDatToi":"không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0911","loai":"nhắc tới","importance":"normal","giaiDoan":"Dùng để chiếm thi binh","text":"Thi linh đại pháp được nêu là công pháp đủ để điều khiển mấy ngàn thi binh trong lăng mộ.","anchor":"Cũng chỉ có thi linh đại pháp của đạo hữu mới có thể khu sử những thi binh này dễ như trở bàn tay"}]},"capNhatToi":"@c0911","nguon":["@c0911"]},{"id":"truyen-tong-tran-phung-gia-mat-quat","name":"Truyền tống trận Phùng gia mật quật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"Phùng gia","soHuu":["Phùng gia"],"blurb":"Truyền tống trận trong lối vào mật quật Phùng gia, có bẫy đặt linh thạch sai.","detail":"Trận có nhiều lỗ đặt linh thạch nhưng chỉ dùng đúng năm lỗ. Nếu người không biết ảo diệu đặt linh thạch vào tất cả các lỗ thì khi truyền tống có thể bị không gian chi lực xé nát.","dinhDanh":"goc","dacDiem":"Có bảy, tám lỗ đặt linh thạch nhưng chỉ năm lỗ đúng là an toàn.","congNang":["Truyền tống vào đại sảnh mật quật Phùng gia @c0911","Dùng cách đặt linh thạch sai làm bẫy giết người xâm nhập @c0911"],"tabs":{"tienTrinh":[{"chuong":"@c0911","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập vượt bẫy truyền tống","text":"Hàn Lập nhận ra bố trí bẫy của truyền tống trận và chỉ đặt năm khối đê giai linh thạch vào đúng lỗ trước khi truyền tống.","anchor":"đặt linh thạch vào trong tất cả các lỗ , sợ rằng khi truyền tống trong nháy mắt sẽ bị không chi lực xé nát bấy"}]},"capNhatToi":"@c0911","nguon":["@c0911"]},{"id":"loi-don","name":"Lôi độn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông độn thuật","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Lôi độn là thủ đoạn giúp Hàn Lập áp sát cực nhanh trong chiến đấu. Ở chương này, hắn dùng lôi độn để mạo hiểm tiếp cận thanh bào lão giả và mở ra thế phản sát.","detail":"Hàn Lập dùng lôi độn chạy đến vị trí thanh bào lão giả, rút ngắn khoảng cách để phối hợp tử sắc hỏa diễm, kim sắc tiểu kiếm và lưới điện. Tác dụng nổi bật trong trận là áp sát đột kích.","congNang":["Áp sát đột kích trong chiến đấu, giúp Hàn Lập nhanh chóng tiếp cận mục tiêu @c0915."],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0915","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0915","loai":"thi triển","importance":"normal","giaiDoan":"Áp sát thanh bào lão giả","text":"Hàn Lập dùng lôi độn mạo hiểm áp sát để tạo điều kiện phản sát thanh bào lão giả.","anchor":"Hàn Lập nếu mạo hiểm dùng lôi độn chạy đến nơi đây"}]},"capNhatToi":"@c0915","nguon":["@c0915"]},{"id":"kim-sac-dien-ho","name":"Kim sắc điện hồ","cn":"","aliases":["Kim võng"],"loai":"than-thong","loaiLabel":"Thần thông lôi điện","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kim sắc điện hồ là lôi điện được Hàn Lập dùng biến thành kim sắc lưới điện. Trong trận này, kim võng khóa Nguyên Anh đang muốn thuấn di và tiêu diệt nó.","detail":"Hàn Lập dùng kim sắc lưới điện chụp lấy Nguyên Anh của thanh bào lão giả, khiến đối phương không thể dùng độn thuật thoát đi. Sau đó kim võng co lại rồi nổ tung, diệt sạch Nguyên Anh.","congNang":["Khóa độn thuật của Nguyên Anh và tiêu diệt mục tiêu bị vây trong lưới điện @c0915."],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0915","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0915","loai":"thi triển","importance":"normal","giaiDoan":"Diệt Nguyên Anh","text":"Hàn Lập dùng kim sắc lưới điện chụp Nguyên Anh của thanh bào lão giả, khiến nó không thể độn thoát rồi bị tiêu diệt.","anchor":"không cách nào từ trong lưới sử dụng độn thuật thoát đi"}]},"capNhatToi":"@c0915","nguon":["@c0915"]},{"id":"van-nam-thi-diem","name":"Vạn năm thi diễm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thi diễm","phamCap":"không rõ","hePhai":"","soHuu":["Huyễn Diệp vương"],"blurb":"Vạn năm thi diễm là thi diễm do Huyễn Diệp vương khổ tu vô số năm. Lão dùng nó tạo hỏa đoàn lớn để tự bảo vệ trước Lạc hồn sa.","detail":"Khi Lạc hồn sa tràn vào cấm chế, Huyễn Diệp vương phun thi diễm hóa thành hỏa đoàn để hộ thân. Năng lực này được nêu là thủ đoạn do lão khổ tu nhiều năm mới có thể ngăn cản loại cát âm tà ấy.","nguonGoc":"Do Huyễn Diệp vương khổ tu vô số năm tháng.","congNang":["Tạo hỏa đoàn thi diễm hộ thân để chống đỡ Lạc hồn sa @c0915."],"nguoiTu":[{"ten":"Huyễn Diệp vương","tuChuong":"@c0915","tangDatToi":"khổ tu vô số năm","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0915","loai":"thi triển","importance":"normal","giaiDoan":"Tự vệ trước Lạc hồn sa","text":"Huyễn Diệp vương dùng vạn năm thi diễm để tự bảo vệ khi Lạc hồn sa tràn tới.","anchor":"vạn năm thi diễm do hắn khổ tu vô số năm tháng"}]},"capNhatToi":"@c0915","nguon":["@c0915"]},{"id":"phap-tran-sa-vu","name":"Pháp trận sa vụ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Pháp trận sa vụ là cấm chế bao phủ chiến trường bằng sa vụ. Trong chương này, pháp trận biến hóa từ hoàng sa sang ô hắc sa âm hàn để phối hợp Lạc hồn sa vây ép Hàn Lập và Huyễn Diệp vương.","detail":"Bốn phía pháp trận xuất hiện biến hóa, sa vụ chuyển màu và dồn ép vào trung tâm. Khi Cuồng Sa thượng nhân phóng toàn bộ Lạc hồn sa, cấm chế trở thành môi trường vây công bằng hắc sa âm hàn.","congNang":["Vây ép mục tiêu bằng sa vụ và phối hợp Lạc hồn sa tràn vào trung tâm pháp trận @c0915."],"tabs":{"tienTrinh":[{"chuong":"@c0915","loai":"xuất hiện","importance":"normal","giaiDoan":"Biến hóa thành hắc sa","text":"Pháp trận sa vụ biến hóa, để ô hắc sa âm hàn tràn vào vây ép Hàn Lập và Huyễn Diệp vương.","anchor":"bốn phía pháp trận lại xuất hiện kinh người biến hóa"}]},"capNhatToi":"@c0915","nguon":["@c0915"]},{"id":"minh-vuong-quyet","name":"Minh Vương Quyết","cn":"","aliases":["Minh Vương quyết"],"loai":"cong-phap","loaiLabel":"Công pháp luyện thể","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Công pháp luyện thể mà Hàn Lập dự định tu luyện để hóa giải sát khí cắn trả. Tầng một yêu cầu linh khí không cao, còn tầng hai trở lên cần linh mạch tốt và đại lượng linh lực.","detail":"Hàn Lập cho biết tầng một của Minh Vương Quyết đã hoàn hảo và không đòi hỏi linh khí quá lớn, có thể tu luyện trong khoảng một năm tại nơi vắng. Từ tầng hai trở lên, pháp quyết cần lượng linh lực lớn; phải đại thành tầng hai mới miễn cưỡng biến sát khí cắn trả thành của mình.","thuocTinh":"luyện thể","yeuCau":"Tầng một yêu cầu linh khí không cao; tầng hai trở lên cần linh mạch tốt và đại lượng linh lực.","uyLuc":"Có thể hỗ trợ tu sĩ luyện thể và hướng tới hóa giải sát khí cắn trả khi tầng hai đại thành.","dacDiem":"Tầng một pháp quyết hoàn hảo, tầng hai là mốc then chốt để xử lý sát khí.","congNang":["Tiêu trừ hoặc chuyển hóa sát khí cắn trả khi tầng hai đại thành @c0917"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0917","tangDatToi":"dự tính tu luyện tầng một","trangThai":"chuẩn bị tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0917","loai":"xuất hiện","importance":"major","giaiDoan":"Tầng một đến tầng hai","text":"Hàn Lập xác định tầng một yêu cầu linh khí không cao nhưng muốn tu luyện sâu hơn cần trà trộn vào đại tông môn Nam Châu có linh mạch tốt.","anchor":"Tầng thứ nhất pháp quyết hoàn hảo, đối với linh khí yêu cầu cũng không quá lớn"}]},"capNhatToi":"@c0917","nguon":["@c0917"]},{"id":"tran-che-dong-phu-tam","name":"Trận che động phủ tạm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bộ trận pháp Hàn Lập dùng để che giấu động phủ tạm dưới chân núi vắng. Trận được bày bằng một bộ khí cụ mang theo.","detail":"Sau khi rời xa sơn mạch, Hàn Lập chọn một núi nhỏ vắng vẻ, mở động phủ đơn giản dưới chân núi rồi dùng một bộ khí cụ bày trận để che giấu nơi ở tạm thời.","thuocTinh":"ẩn nấp","congNang":["Che giấu động phủ tạm của Hàn Lập @c0917"],"tabs":{"tienTrinh":[{"chuong":"@c0917","loai":"xuất hiện","importance":"normal","giaiDoan":"Bày trận tại động phủ tạm","text":"Hàn Lập dùng một bộ khí cụ bày trận để che kín động phủ mới mở dưới chân núi vắng.","anchor":"Sau đó lập tức dùng một bộ khí cụ bày trận"}]},"capNhatToi":"@c0917","nguon":["@c0917"]},{"id":"hao-nhien-chi-khi","name":"Hạo Nhiên chi khí","cn":"","aliases":[],"loai":"khac","loaiLabel":"Khí phụ trợ tu luyện","phamCap":"không rõ","hePhai":"Nho môn","soHuu":[],"blurb":"Hạo Nhiên chi khí là nền tảng phụ trợ cho nhiều công pháp nho môn trong Bạch Lộ thư viện. Đệ tử hạ viện đọc sách vào giờ ngọ để bồi dưỡng khí này trước khi có cơ hội vào thượng viện tu hành.","detail":"Bạch Lộ thư viện yêu cầu đệ tử hạ viện đọc sách để bồi dưỡng Hạo Nhiên chi khí. Hơn nửa công pháp nho môn cần khí này phụ trợ, khí càng nhiều và mạnh thì tu luyện về sau càng tiến triển nhanh.","thuocTinh":"Nho môn","congNang":["Phụ trợ tu luyện hơn nửa công pháp nho môn và ảnh hưởng tốc độ tiến triển về sau @c0921"],"tabs":{"tienTrinh":[{"chuong":"@c0921","loai":"xuất hiện","importance":"normal","giaiDoan":"Giải thích tại Bạch Lộ thư viện","text":"Thanh niên áo trắng giải thích đệ tử hạ viện đọc sách để bồi dưỡng Hạo Nhiên chi khí, vì hơn nửa công pháp nho môn cần khí này phụ trợ.","anchor":"Dù sao hơn nửa công pháp của nho môn chúng ta đều lấy Hạo Nhiên chi khí làm phụ trợ"}]},"capNhatToi":"@c0921","nguon":["@c0921"]},{"id":"phe-chan-hop-nguyen-quyet","name":"Phệ Chân Hợp Nguyên quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Nho môn","soHuu":["Lỗ Đại tiên sinh"],"blurb":"Phệ Chân Hợp Nguyên quyết là công pháp Lỗ Đại tiên sinh muốn tu thành nhờ nho sinh họ Nghiêm lấy thân trợ giúp. Công pháp này liên quan việc kế thừa hạo nhiên chi khí của người trợ tu.","detail":"Trong chương 922, Lỗ Đại tiên sinh nói cần nho sinh họ Nghiêm trợ giúp tu thành Phệ Chân Hợp Nguyên quyết thì mới có bảy tám phần nắm chắc tiêu diệt Ngưu Thiên Đức. Sau khi kế thừa hạo nhiên chi khí của nho sinh họ Nghiêm, oán khí trong đó khiến ông phải diệt Ngưu Thiên Đức thì mới có thể chính thức hóa thành của mình.","thuocTinh":"hạo nhiên chi khí","yeuCau":"cần người lấy thân trợ giúp","congNang":["Kế thừa hạo nhiên chi khí của người trợ tu @c0922"],"dacDiem":"Hạo nhiên chi khí kế thừa còn mang oán khí, buộc người tu phải hoàn thành việc báo thù liên quan thì mới hoàn toàn hóa thành của mình.","nguoiTu":[{"ten":"Lỗ Đại tiên sinh","tuChuong":"@c0922","tangDatToi":"đang chuẩn bị tu thành","trangThai":"chuẩn bị"}],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ điều kiện tu luyện","text":"Lỗ Đại tiên sinh tiết lộ cần nho sinh họ Nghiêm lấy thân trợ giúp để tu thành Phệ Chân Hợp Nguyên quyết, qua đó kế thừa hạo nhiên chi khí và tăng nắm chắc khi đối phó Ngưu Thiên Đức.","anchor":"chỉ có trợ giúp ta tu thành ‘Phệ Chân Hợp Nguyên quyết’"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"toa-tam-chu","name":"Tỏa Tâm Chú","cn":"","loai":"bi-thuat","loaiLabel":"Chú thuật","phamCap":"không rõ","hePhai":"Nho môn","soHuu":["Lỗ Đại tiên sinh"],"blurb":"Tỏa Tâm Chú là chú thuật ràng buộc lời hứa mà Lỗ Đại tiên sinh đề nghị hạ trước tượng thánh hiền. Nó được dùng để bảo đảm ông không thất hứa với nho sinh họ Nghiêm.","detail":"Lỗ Đại tiên sinh nói có thể đối diện tượng thánh hiền hạ Tỏa Tâm Chú, nếu sau này không làm được như lời thì hạo nhiên chi khí của ông không thể tiến thêm. Đây là cách ông trấn an nho sinh họ Nghiêm trước khi hai bên ấn định việc tu luyện sau một tháng.","thuocTinh":"ràng buộc hạo nhiên chi khí","congNang":["Ràng buộc lời hứa, nếu thất hứa thì hạo nhiên chi khí không thể tiến thêm @c0922"],"nguoiTu":[{"ten":"Lỗ Đại tiên sinh","tuChuong":"@c0922","tangDatToi":"có thể thi triển","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"xuất hiện","importance":"normal","giaiDoan":"Dùng làm lời thề","text":"Lỗ Đại tiên sinh đề nghị hạ Tỏa Tâm Chú trước tượng thánh hiền để bảo đảm lời hứa báo thù cho nho sinh họ Nghiêm.","anchor":"Tại hạ có thể đối diện tượng của thánh hiền, hạ Tỏa Tâm Chú"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"nho-mon-cong-phap","name":"Nho môn công pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Nho môn","soHuu":["Nho môn","Bạch Lộ thư viện"],"blurb":"Nho môn công pháp được nhắc qua lời Hoa Liên tiên cô và Lỗ Đại tiên sinh. Giai đoạn đầu tốn thời gian hơn đạo, phật nhưng khi đại thành có hạo nhiên chi khí phụ trợ thì thần thông vượt xa đạo gia công pháp bình thường.","detail":"Chương 922 dùng Nho môn công pháp để so sánh với pháp môn Đạo gia của Tam Hoàng quan. Hàn Lập không có hạo nhiên chi khí bẩm sinh nên Lỗ Đại tiên sinh cho rằng vào Bạch Lộ thư viện chưa hẳn thích hợp bằng Hoàng Thanh quan.","thuocTinh":"hạo nhiên chi khí","congNang":["Tu hạo nhiên chi khí phụ trợ thần thông @c0922"],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"nhắc tới","importance":"normal","giaiDoan":"So sánh pháp môn","text":"Hoa Liên tiên cô và Lỗ Đại tiên sinh nhắc Nho môn công pháp khi khuyên Hàn Lập không nên cố nhập Bạch Lộ thư viện.","anchor":"có hạo nhiên chi khí phụ trợ, thần thông vượt xa"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"dao-gia-cong-phap-cua-tam-hoang-quan","name":"Đạo gia công pháp của Tam Hoàng quan","cn":"","loai":"cong-phap","loaiLabel":"Công pháp Đạo gia","phamCap":"không rõ","hePhai":"Tam Hoàng quan","soHuu":["Tam Hoàng quan","Hoàng Thanh quan"],"blurb":"Đạo gia công pháp của Tam Hoàng quan là hệ pháp môn được Hoa Liên tiên cô dùng để thuyết phục Hàn Lập. Dù Hoàng Thanh quan là nữ quan, hệ Tam Hoàng quan vẫn có nhánh nam tu và pháp môn cho nam tu.","detail":"Hoa Liên tiên cô nói Hoàng Thanh quan chỉ là một nhánh của Tam Hoàng quan, những nhánh khác như Hoàng Dương quan, Hoàng Thánh quan có đạo quán do nam tu chủ trì. Vì vậy pháp môn tu luyện cho nam tu không thiếu, có thể dùng để thu Hàn Lập.","thuocTinh":"Đạo gia","congNang":["Cung cấp pháp môn tu luyện cho nam tu trong hệ Tam Hoàng quan @c0922"],"tabs":{"tienTrinh":[{"chuong":"@c0922","loai":"nhắc tới","importance":"normal","giaiDoan":"Giải thích pháp môn nam tu","text":"Hoa Liên tiên cô nêu Đạo gia công pháp của Tam Hoàng quan để bác lý do Hàn Lập cho rằng nam tu không hợp Hoàng Thanh quan.","anchor":"Tu luyện pháp môn của nam tu căn bản không thiếu"}]},"capNhatToi":"@c0922","nguon":["@c0922"]},{"id":"luyen-khi-chi-dao-cua-vi-lao","name":"Luyện khí chi đạo của Vi lão","cn":"","aliases":[],"loai":"khac","loaiLabel":"Luyện khí thuật","phamCap":"Không rõ","hePhai":"Tam Hoàng quan","soHuu":["Vi lão","Hàn Lập"],"blurb":"Luyện khí chi đạo của Vi lão là hệ thống thủ pháp luyện khí mà Vi lão truyền thụ cho Hàn Lập trong một tháng. Nội dung bao gồm tinh luyện tài liệu, tinh chế tài liệu và nhiều thủ pháp đặc biệt.","detail":"Vi lão tuy tu vi không cao nhưng tạo nghệ luyện khí rất sâu, nắm nhiều thủ pháp mà Hàn Lập chưa từng nghe. Những điều ông truyền dạy giúp Hàn Lập mở rộng hiểu biết về tinh luyện tài liệu và luyện khí, trở thành cơ sở để Hàn Lập chuẩn bị cho việc luyện Thất Diễm phiến và khôi lỗi của Đại Diễn thần quân.","thuocTinh":"Luyện khí","nguonGoc":"Vi lão thuộc Tam Hoàng quan","uyLuc":"Giúp người học nhận biết và xử lý tài liệu luyện khí tinh vi hơn.","dacDiem":"Bao gồm cả các thủ pháp đặc biệt khiến Hàn Lập phải nhìn nhận lại trình độ luyện khí của Đại Tấn.","congNang":["Dùng để tinh luyện và tinh chế tài liệu luyện khí @c0923","Giúp chuẩn bị tốt hơn cho việc luyện chế pháp bảo và khôi lỗi @c0923"],"nguoiTu":[{"ten":"Vi lão","tuChuong":"@c0923","tangDatToi":"Tạo nghệ cao","trangThai":"dang-tu"},{"ten":"Hàn Lập","tuChuong":"@c0923","tangDatToi":"Được truyền thụ cơ sở trong một tháng","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0923","loai":"xuất hiện","importance":"normal","giaiDoan":"Vi lão truyền thụ cho Hàn Lập","text":"Vi lão truyền thụ một tháng luyện khí chi đạo, khiến Hàn Lập nhận ra tạo nghệ luyện khí của ông vượt xa dự đoán.","anchor":"lão giả này mặc dù tu vi không cao, nhưng ở luyện khí chi đạo tạo nghệ cực cao"}]},"capNhatToi":"@c0923","nguon":["@c0923"]},{"id":"thu-phap-luyen-khi-dai-tan","name":"Thủ pháp luyện khí Đại Tấn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hệ thống luyện khí thuật","phamCap":"Không rõ","hePhai":"Đại Tấn","soHuu":["Vi lão","Hàn Lập"],"blurb":"Thủ pháp luyện khí Đại Tấn là hệ thống kỹ thuật luyện khí được Hàn Lập đánh giá cao sau khi nghe Vi lão giảng giải. Nó vừa giữ lại thủ pháp thượng cổ, vừa tích lũy nhiều kỹ thuật mới qua nhiều đời.","detail":"Hàn Lập so sánh kiến thức luyện khí từ Thiên Nam, Loạn Tinh hải và Lạc Vân tông với hệ thống Đại Tấn, rồi nhận ra luyện khí thuật Đại Tấn vượt xa các thủ pháp đơn giản từng thấy. Điều này khiến hắn quyết định sau khi khôi phục pháp lực sẽ tiếp tục sưu tầm các luyện khí thuật này.","thuocTinh":"Luyện khí","nguonGoc":"Đại Tấn","dacDiem":"Kết hợp thủ pháp luyện khí thượng cổ được bảo tồn với tân luyện khí thuật tích lũy qua nhiều đời.","congNang":["Cung cấp nền tảng để hoàn thiện việc luyện chế pháp bảo và khôi lỗi @c0923"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0923","tangDatToi":"Bắt đầu ghi nhớ và học hỏi","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0923","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập nhận ra giá trị","text":"Hàn Lập nhận ra luyện khí thuật Đại Tấn có hệ thống phong phú hơn hẳn những gì hắn từng biết.","anchor":"vừa có bảo tồn hoàn hảo thủ pháp luyện khí từ thượng cổ"}]},"capNhatToi":"@c0923","nguon":["@c0923"]},{"id":"hoang-thanh-quan-ho-quan-dai-tran","name":"Hoàng Thanh quan hộ quan đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp phòng hộ","phamCap":"","hePhai":"Hoàng Thanh Quan","soHuu":["Hoàng Thanh Quan"],"blurb":"Đại trận hộ quan bảo vệ Hoàng Thanh Quan, được mô tả là rất khó bị phá từ bên ngoài trong thời gian ngắn.","detail":"Lão đạo cô Hoàng Thanh Quan cho biết hộ quan đại trận của bản quan đủ kiên cố đến mức ngay cả các trận pháp tông sư Đại Tấn cũng khó có cách nào phá từ bên ngoài trong một đêm. Nếu người ở trong trận tự rời đi thì việc thoát ra không quá khó, nên sự biến mất của Hàn Lập khiến cao tầng phải xét đến cả khả năng nội bộ.","nguon":["@c0927"]},{"id":"dai-than-thong-dong-bang-cua-dai-han-xau-xi","name":"Đại thần thông đóng băng của đại hán xấu xí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Đại hán xấu xí Nguyên Anh trung kỳ"],"blurb":"Thần thông băng phong mà đại hán xấu xí dùng để áp chế hai trưởng lão Nguyên Anh của Tông Bình gia.","detail":"Khi bị Tông Bình gia chủ mời hai đại trưởng lão Nguyên Anh ra tay đối phó, đại hán xấu xí Nguyên Anh trung kỳ dùng đại thần thông dễ dàng hóa cả hai thành hai khối băng lớn. Hai trưởng lão sau đó phải tốn nhiều công phu mới được phá băng cứu ra, tuy còn sống nhưng nguyên khí bị hao tổn.","nguon":["@c0927"]},{"id":"tran-phap-ngan-chan-khi-tuc-ngan-chan-linh-khi","name":"Trận pháp ngăn chặn khí tức, ngăn chặn linh khí","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Các trận pháp Hàn Lập bày trong sơn cốc rừng đào để phong tỏa khí tức và linh khí. Chúng là lớp che giấu chính của cạm bẫy nhắm Hạo Dương Điểu nhỏ.","detail":"Hàn Lập dùng nhiều bộ trận kỳ bố trí loại trận pháp này trong sơn cốc hẻo lánh. Tác dụng được nêu rõ là ngăn chặn khí tức và linh khí, giúp cạm bẫy không dễ bị phát hiện trước khi mục tiêu lọt vào.","congNang":["Che giấu khí tức và linh khí trong khu vực bố trí @c0928"],"tabs":{"tienTrinh":[{"chuong":"@c0928","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí cạm bẫy","text":"Hàn Lập bày nhiều trận pháp ngăn chặn khí tức và linh khí trong sơn cốc rừng đào.","anchor":"đều là các loại trận pháp ngăn chặn khí tức, ngăn chặn linh khí"}]},"nguon":["@c0928"]},{"id":"tran-phap-bao-vay-dich-nhan","name":"Trận pháp bao vây địch nhân","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Một phần trong cạm bẫy Hàn Lập bố trí ở sơn cốc rừng đào. Chỉ có hai ba trận thật sự dùng để vây khốn mục tiêu.","detail":"Trong số bảy tám bộ trận kỳ được Hàn Lập bày ra, các trận thật sự có tác dụng bao vây địch nhân chỉ chiếm số ít. Điều này cho thấy toàn bộ bố trí lấy che giấu làm chủ, còn vây khốn là lớp tác dụng trực tiếp khi mục tiêu rơi vào trận.","congNang":["Vây khốn mục tiêu lọt vào phạm vi trận pháp @c0928"],"tabs":{"tienTrinh":[{"chuong":"@c0928","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí cạm bẫy","text":"Hàn Lập đặt hai ba trận pháp chuyên dùng để bao vây địch nhân trong cạm bẫy.","anchor":"Những trận pháp chân chính có tác dụng bao vây địch nhân chỉ có hai ba cái mà thôi"}]},"nguon":["@c0928"]},{"id":"ao-tran-trong-rung-dao","name":"Ảo trận trong rừng đào","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Ảo trận Hàn Lập bố trí thêm tại vị trí của mình trong rừng đào. Trận này dùng để che giấu cảnh tượng và hoàn thiện lớp ngụy trang của cạm bẫy.","detail":"Sau khi bố trí các trận ngăn khí tức, ngăn linh khí và vây địch, Hàn Lập còn đặt một ảo trận ngay nơi mình ẩn thân. Ảo trận giúp che đậy tình hình trong rừng đào, khiến khu vực phục kích khó bị nhìn thấu.","congNang":["Che giấu cảnh tượng tại vị trí Hàn Lập ẩn thân @c0928"],"tabs":{"tienTrinh":[{"chuong":"@c0928","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí cạm bẫy","text":"Hàn Lập bố trí thêm một ảo trận ở vị trí của mình trong rừng đào.","anchor":"còn bố trí một cái ảo trận tại vị trí của chính mình"}]},"nguon":["@c0928"]},{"id":"cam-che-tran-ban","name":"Cấm chế trận bàn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận bàn và nhiều tầng cấm chế được Hàn Lập dùng để chia cắt Hạo Dương điểu với Thổ Giáp Long.","detail":"Hàn Lập kích hoạt trận bàn khiến vài đạo cấm chế hiện ra, trước tiên vây Hạo Dương điểu, đồng thời trì hoãn Thổ Giáp Long đang lao tới Nghê Thường thảo. Cấm chế đủ tạo thời gian xử lý từng mục tiêu nhưng không thể uy hiếp yêu thú cấp bảy lâu dài.","congNang":["Vây khốn và trì hoãn yêu thú trong thời gian ngắn @c0930"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0930","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0930","loai":"thi triển","importance":"normal","giaiDoan":"Chia cắt hai yêu thú","text":"Hàn Lập dùng trận bàn kích hoạt cấm chế để vây Hạo Dương điểu trước và tạm ngăn Thổ Giáp Long.","anchor":"tức thời vài đạo cấm chế chợt hiện ra"}]},"capNhatToi":"@c0930","nguon":["@c0930"]},{"id":"tho-don","name":"Thổ độn","cn":"","loai":"than-thong","loaiLabel":"Thần thông yêu thú","phamCap":"Không rõ","hePhai":"","soHuu":["Thổ Giáp Long"],"blurb":"Thổ độn là thần thông giúp Thổ Giáp Long độn xuống đất để thoát thân hoặc đoạt vật.","detail":"Đại Diễn Thần Quân nhắc Hàn Lập rằng Thổ Giáp Long có thần thông thổ độn, nếu để nó chạm đất thì sẽ rất khó bắt lại. Vì vậy Hàn Lập phục sẵn Lục Dực Sương công để chặn nó trước khi tiếp đất.","congNang":["Độn xuống đất để thoát khỏi truy bắt hoặc tiếp cận mục tiêu @c0930"],"nguoiTu":[{"ten":"Thổ Giáp Long","tuChuong":"@c0930","tangDatToi":"","trangThai":"so-huu"}],"tabs":{"tienTrinh":[{"chuong":"@c0930","loai":"nhắc tới","importance":"normal","giaiDoan":"Nguy cơ thoát thân","text":"Đại Diễn Thần Quân chỉ ra Thổ Giáp Long có thổ độn, buộc Hàn Lập phải chặn nó trước khi chạm đất.","anchor":"Nó có thần thông thổ độn mà"}]},"capNhatToi":"@c0930","nguon":["@c0930"]},{"id":"han-khi-luc-duc-suong-cong","name":"Hàn khí Lục Dực Sương công","cn":"","loai":"than-thong","loaiLabel":"Thần thông linh trùng","phamCap":"Không rõ","hePhai":"","soHuu":["Lục Dực Sương công","Hàn Lập"],"blurb":"Hàn khí của Lục Dực Sương công là luồng khí lạnh trong suốt có thể đóng băng mục tiêu mạnh.","detail":"Mười hai con Lục Dực Sương công đồng loạt phun hàn khí từ dưới đất, bao trùm Thổ Giáp Long ngay trước khi yêu thú này kịp chạm đất. Uy lực lần này đủ biến một yêu thú cấp bảy có thân thể cứng chắc thành băng điêu trắng.","uyLuc":"Đóng băng Thổ Giáp Long cấp bảy trong một lần phục kích.","congNang":["Phun hàn khí trong suốt để băng phong mục tiêu @c0930"],"nguoiTu":[{"ten":"Lục Dực Sương công","tuChuong":"@c0930","tangDatToi":"","trangThai":"ban-nang"}],"tabs":{"tienTrinh":[{"chuong":"@c0930","loai":"thi triển","importance":"normal","giaiDoan":"Băng phong Thổ Giáp Long","text":"Mười hai Lục Dực Sương công cùng phun hàn khí, làm Thổ Giáp Long biến thành băng điêu màu trắng.","anchor":"liền bị hàn khí phun ra bao trùm biến thành một khối băng điêu màu trắng"}]},"capNhatToi":"@c0930","nguon":["@c0930"]},{"id":"anh-hoa","name":"Anh hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên Anh tu sĩ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Anh hỏa là hỏa diễm do tu sĩ Nguyên Anh thi triển. Hàn Lập dùng nó bao bọc Hỏa linh để dẫn tinh hỏa đỏ sậm bên trong ra.","detail":"Trong thạch thất vô danh, Hàn Lập phun ra một đoàn anh hỏa, bao lấy Hỏa linh còn lại trước mặt để xử lý tài liệu. Lần xuất hiện này cho thấy anh hỏa được dùng trực tiếp trong luyện hóa và dẫn phát tinh hỏa của Hỏa linh.","thuocTinh":"hỏa","uyLuc":"Có thể bao bọc Hỏa linh và dẫn tinh hỏa đỏ sậm bên trong ra.","dacDiem":"Được Hàn Lập dùng khi xử lý tài liệu sau biến cố Thiên Nhạc sơn mạch.","congNang":["Luyện hóa và xử lý Hỏa linh, dẫn tinh hỏa đỏ sậm bên trong ra @c0931"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0931","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0931","loai":"thi triển","importance":"normal","giaiDoan":"Xử lý Hỏa linh","text":"Hàn Lập phun anh hỏa bao bọc Hỏa linh để dẫn tinh hỏa đỏ sậm bên trong ra.","anchor":"một đoàn anh hỏa bao bọc lấy hỏa linh vào trong"}]},"capNhatToi":"@c0931","nguon":["@c0931"]},{"id":"thu-doan-dan-du-yeu-thu","name":"Thủ đoạn dẫn dụ yêu thú","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"chưa rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn dẫn dụ yêu thú là phương pháp chưa rõ khiến Tôn lão ẩu và Mã đạo hữu cùng chú ý sau biến cố Thiên Nhạc sơn mạch. Hai bên cho rằng nếu nắm được cách này thì có giá trị lớn trong giết yêu lấy đan hoặc thuần hóa linh thú.","detail":"Sau khi Hạo Dương điểu mất Hỏa linh và Thổ Giáp Long mất tích, cả Nhạc Dương cung lẫn Ma Mộc Tông đều nhận ra có người sở hữu cách dụ dỗ hoặc kích động yêu thú. Mã đạo hữu coi đây là chuyện lớn cần báo sư huynh, còn Nhạc Dương cung cũng ngầm điều tra để tìm người nắm thủ đoạn ấy.","uyLuc":"Có thể khiến các cao thủ Nguyên Anh chú ý vì liên quan trực tiếp tới yêu thú quý hiếm.","dacDiem":"Chưa lộ tên thật hay phương thức vận hành, chỉ được suy ra từ hậu quả tại Thiên Nhạc sơn mạch.","congNang":["Dẫn dụ hoặc kích động yêu thú, có thể phục vụ giết yêu lấy đan hoặc thuần hóa linh thú @c0931"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0931","tangDatToi":"","trangThai":"bị nghi nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0931","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị hai thế lực truy tìm","text":"Tôn lão ẩu và Mã đạo hữu đều chú ý tới phương pháp dẫn dụ yêu thú sau biến cố Hạo Dương điểu và Thổ Giáp Long.","anchor":"Nếu có thể biết được phương pháp thì từ nay vô luận giết yêu lấy đan"}]},"capNhatToi":"@c0931","nguon":["@c0931"]},{"id":"tu-la-thien-hoa","name":"Tử la thiên hỏa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông hỏa diễm đặc thù","phamCap":"Không rõ","hePhai":"Băng hàn và hỏa diễm đặc thù","soHuu":["Hàn Lập"],"blurb":"Tử la thiên hỏa là thần thông đặc thù của Hàn Lập, còn sót tạp chất sau lần luyện hóa trước. Tuyết phách hoàn khiến phần tạp chất này dần dung hợp biến mất.","detail":"Chương này nhấn mạnh Tử la thiên hỏa có tiềm năng đạt tới cảnh giới truyền thuyết có thể đóng băng phạm vi ngàn dặm và khắc chế nhiều công pháp Chánh, Ma. Khi Hàn Lập luyện hóa Tuyết phách hoàn, tạp chất Tử la thiên hỏa còn sót lại dần được dung hợp.","thuocTinh":"Băng hàn và hỏa diễm đặc thù","uyLuc":"Có tiềm năng tu luyện tới cảnh giới truyền thuyết đóng băng phạm vi ngàn dặm.","dacDiem":"Không thua kém các thần thông cao nhất của hai đạo Chánh, Ma theo phần nhấn mạnh trong chương.","congNang":["Tạp chất còn sót lại có thể được Tuyết phách hoàn dung hợp dần @c0932","Nếu tu luyện tới cảnh giới truyền thuyết, có thể làm đóng băng trong phạm vi ngàn dặm @c0932"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0932","tangDatToi":"Đang tinh luyện","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0932","loai":"nhắc tới","importance":"normal","giaiDoan":"Tạp chất dung hợp","text":"Tuyết phách hoàn khiến phần tạp chất Tử la thiên hỏa còn sót lại dần dung hợp biến mất, đồng thời chương nhấn mạnh tiềm năng cực hạn của thần thông này.","anchor":"Nói không chừng sẽ tu luyện đến cảnh giới truyền thuyết có thể làm đóng băng trong phạm vi ngàn dặm"}]},"trangThai":"đang tinh luyện","capNhatToi":"@c0932","nguon":["@c0932"]},{"id":"hap-hon-thon-dan","name":"Hấp Hồn Thôn Đan","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Hấp Hồn Thôn Đan là ma công bá đạo được Đại Diễn Thần Quân nhắc tới khi phân tích tình trạng cổ ma.","detail":"Đại Diễn Thần Quân cho rằng nhờ sử dụng Hấp Hồn Thôn Đan, cổ ma sau khi bị thương nặng vẫn đã khôi phục được bảy tám phần thực lực.","thuocTinh":"Ma công bá đạo","uyLuc":"Có thể hỗ trợ cổ ma khôi phục thương thế sau tổn hại nặng.","dacDiem":"Được nhắc trực tiếp như nguyên nhân khiến cổ ma không còn suy yếu nhiều.","congNang":["Giúp cổ ma khôi phục bảy tám phần sau thương tổn nặng @c0934"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c0934","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0934","loai":"nhắc tới","importance":"normal","giaiDoan":"Cổ ma hồi phục","text":"Đại Diễn Thần Quân nói cổ ma dùng Hấp Hồn Thôn Đan nên đã khôi phục bảy tám phần.","anchor":"Nhưng sử dụng ma công bá đạo Hấp hồn thôn đan"}]},"dinhDanh":"goc","capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"anh-hoa-te-luyen-ban-menh-phi-kiem","name":"Anh hỏa tế luyện bản mệnh phi kiếm","cn":"","loai":"bi-thuat","loaiLabel":"Thủ pháp tế luyện","phamCap":"không rõ","hePhai":"Kiếm tu","soHuu":["Hàn Lập"],"blurb":"Anh hỏa tế luyện bản mệnh phi kiếm là cách Đại Diễn Thần Quân nêu ra để tăng mạnh uy lực phi kiếm và kiếm trận.","detail":"Theo Đại Diễn Thần Quân, nếu Hàn Lập toàn tâm dùng Anh hỏa tế luyện mười mấy thanh bản mệnh phi kiếm trong bốn trăm năm rồi lập kiếm trận, uy lực có thể cực kỳ đáng sợ, thậm chí được ví là không dưới Linh bảo.","thuocTinh":"Tế luyện bằng Anh hỏa","uyLuc":"Có thể khiến uy lực phi kiếm và kiếm trận tăng đến mức rất đáng sợ nếu duy trì lâu dài.","dacDiem":"Hiệu quả lớn nhưng đòi hỏi thời gian tế luyện cực dài.","congNang":["Tăng uy lực bản mệnh phi kiếm và Đại Canh Kiếm Trận nếu tế luyện lâu dài @c0934"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0934","tangDatToi":"được đề xuất","trangThai":"chưa chuyên tâm lâu dài"}],"tabs":{"tienTrinh":[{"chuong":"@c0934","loai":"nhắc tới","importance":"normal","giaiDoan":"Đề xuất tăng uy lực kiếm trận","text":"Đại Diễn Thần Quân nêu giả thiết Hàn Lập dùng Anh hỏa tế luyện bản mệnh phi kiếm suốt bốn trăm năm để tăng uy lực kiếm trận.","anchor":"toàn tâm toàn lực dùng anh hỏa tế luyện trong vòng bốn trăm năm"}]},"dinhDanh":"goc","capNhatToi":"@c0934","nguon":["@c0934"]},{"id":"dai-trao-thu-mau-xanh","name":"Đại trảo thủ màu xanh / quang thủ màu xanh","cn":"","aliases":["quang thủ màu xanh"],"loai":"than-thong","loaiLabel":"Thần thông khống chế","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông tạo quang thủ màu xanh để bắt giữ mục tiêu. Hàn Lập dùng nó sau khi phi châm xuyên thủng huyết vụ của lão gù.","detail":"Sau khi lão gù bị phi châm trong suốt hồng quang đánh trúng, quang thủ màu xanh quỷ mị bay tới, gạt ba kiện linh khí rồi chế trụ lão và kéo về phía Hàn Lập.","congNang":["Bắt giữ và kéo mục tiêu về sau khi đối phương đã bị chế trụ @c0935"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0935","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"thi triển","importance":"normal","giaiDoan":"Bắt lão gù","text":"Hàn Lập dùng quang thủ màu xanh bắt giữ lão gù sau khi phi châm xuyên thủng huyết vụ.","anchor":"một quang thủ màu xanh quỷ mị bay tới, đem ba kiện linh khí ném đi"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"hoang-tuyen-quy-tran","name":"Hoàng tuyền quỷ trận","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Quỷ trận","phamCap":"không rõ","hePhai":"Tam thi / phe Huyễn vương","soHuu":["Huyễn Diệp vương"],"blurb":"Quỷ trận do Huyễn Diệp vương lập bằng hàng nghìn thi vệ Trúc Cơ sau biến cố Tham vương đại hội. Trận này vây khốn thành viên ba nhà trong phạm vi hơn trăm dặm.","detail":"Huyễn Diệp vương lật các cổ mộ, thả mấy nghìn thi vệ Trúc Cơ rồi tạo thành hoàng tuyền quỷ trận từ Tuyết Lăng sơn mạch đánh ra, khiến tu sĩ tu vi thấp bên ba nhà gần như bị cắn nuốt hết.","congNang":["Vây khốn quy mô lớn và cắn nuốt tu sĩ tu vi thấp @c0935"],"uyLuc":"Có thể vây thành viên ba nhà hơn một tháng trong phạm vi hơn trăm dặm.","nguoiTu":[{"ten":"Huyễn Diệp vương","tuChuong":"@c0935","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"xuất hiện","importance":"normal","giaiDoan":"Vây ba nhà","text":"Huyễn Diệp vương thả hàng nghìn thi vệ Trúc Cơ, lập hoàng tuyền quỷ trận và vây khốn thành viên ba nhà sau Tham vương đại hội.","anchor":"thả mấy ngàn thi vệ trúc cơ kì tu vi. tạo thành hoàng tuyền quỷ trận"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"tam-thi-quy-tran","name":"Tam thi quỷ trận","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Quỷ trận","phamCap":"không rõ","hePhai":"Tam thi / phe Huyễn vương","soHuu":["Huyễn Diệp vương","Hai thi yêu"],"blurb":"Quỷ trận gắn với tam thi gồm Huyễn Diệp vương và hai thi yêu. Trận này khiến vài tu sĩ Nguyên Anh cũng không chiếm được lợi.","detail":"Trong biến cố Tuyết Lăng sơn mạch, vài tu sĩ Nguyên Anh giao thủ trong tam thi quỷ trận đều không có chỗ tốt, một người còn trọng thương sau khi đối mặt với Huyễn Diệp vương và hai thi yêu.","congNang":["Áp chế và gây trọng thương cho tu sĩ Nguyên Anh khi giao thủ trong trận @c0935"],"uyLuc":"Khiến vài tu sĩ Nguyên Anh không chiếm được lợi, một người còn bị trọng thương.","nguoiTu":[{"ten":"Huyễn Diệp vương","tuChuong":"@c0935","tangDatToi":"","trangThai":"dang-dung"},{"ten":"Hai thi yêu","tuChuong":"@c0935","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"xuất hiện","importance":"normal","giaiDoan":"Đối đầu Nguyên Anh","text":"Tam thi quỷ trận khiến vài tu sĩ Nguyên Anh cũng không chiếm được lợi trong biến cố Tuyết Lăng sơn mạch.","anchor":"Về phần vài tên nguyên anh tu sĩ, cũng không có chỗ tốt nào trong tam thi quỷ trận"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"phap-tran-an-dau-tay-tan-phuong-thi","name":"Pháp trận ẩn dấu Tây Tấn phường thị","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"cao minh","hePhai":"Tây Tấn phường thị","soHuu":["Tây Tấn phường thị"],"blurb":"Pháp trận che giấu khu phường thị tu tiên ở phía tây Tấn kinh. Nhờ cấm chế này, khu đường phố phường thị tách khỏi khu vực phàm tục bên ngoài.","detail":"Pháp trận ẩn dấu Tây Tấn phường thị bao phủ một khu đường phố hẻo lánh phía tây Tấn kinh, khiến phường thị không lộ ra như đường phố thường. Hàn Lập dựa vào thông tin trong ngọc giản để đến lối vào và dễ dàng thông qua cấm chế vào trong.","thuocTinh":"ẩn giấu, cấm chế","uyLuc":"Che giấu cả một khu phường thị trong Tấn kinh.","dacDiem":"Pháp trận được miêu tả là cao minh, dùng để bảo vệ tính bí mật của Tây Tấn phường thị.","congNang":["Ẩn giấu Tây Tấn phường thị trong một khu đường phố hẻo lánh phía tây Tấn kinh @c0936"],"trangThai":"đang vận hành","capNhatToi":"@c0936","tabs":{"tienTrinh":[{"chuong":"@c0936","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập vào phường thị","text":"Pháp trận ẩn dấu được nhắc khi Hàn Lập tìm tới Tây Tấn phường thị và thông qua cấm chế để đi vào khu phố tu tiên.","anchor":"Vì Tây Tấn phường thị có một pháp trận ẩn dấu cao minh"}]},"nguon":["@c0936"]},{"id":"quy-linh-quyet","name":"Quy linh quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Thiên Cơ Các","soHuu":["Vương trưởng lão Thiên Cơ các"],"blurb":"Công pháp mà Vương trưởng lão Thiên Cơ các tu luyện. Ông tự nói mình chỉ có thể dừng ở tầng thứ bảy và gần như không còn hy vọng tiến giai Nguyên Anh trung kỳ.","detail":"Quy linh quyết được nhắc khi Vương trưởng lão giải thích tình trạng tu luyện của mình trước Hàn Lập và lão Phú. Sắc mặt trắng quái dị của ông cũng được Hàn Lập suy đoán là liên quan tới pháp quyết đặc thù này.","nguoiTu":[{"ten":"Vương trưởng lão Thiên Cơ các","tuChuong":"@c0938","tangDatToi":"tầng thứ bảy","trangThai":"đang tu"}],"congNang":["Công pháp tu luyện khiến Vương trưởng lão đạt tới tầng thứ bảy nhưng chưa thể tiến thêm @c0938"],"tabs":{"tienTrinh":[{"chuong":"@c0938","loai":"xuất hiện","importance":"normal","giaiDoan":"Tầng thứ bảy","text":"Vương trưởng lão tự nói Quy linh quyết của mình chỉ có thể dừng ở tầng thứ bảy.","anchor":"Quy linh quyết lão phu cũng chỉ có thể dừng lại ở tầng thứ bảy"}]},"dinhDanh":"goc","capNhatToi":"@c0938","nguon":["@c0938"]},{"id":"truyen-am","name":"Truyền âm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thủ đoạn","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Phú tiền bối"],"blurb":"Thủ đoạn nói riêng không phát tiếng ra ngoài. Lão Phú dùng nó để trao đổi kín với Hàn Lập về giao dịch hội dưới lòng đất.","detail":"Trong cuộc gặp tại Thiên Cơ các, lão Phú môi khẽ động nhưng không phát ra âm thanh, dùng truyền âm để tránh để Vương trưởng lão nghe rõ nội dung về hội giao dịch ngầm.","congNang":["Trao đổi bí mật với người được chọn mà không phát tiếng công khai @c0938"],"tabs":{"tienTrinh":[{"chuong":"@c0938","loai":"thi triển","importance":"normal","giaiDoan":"Trao đổi kín","text":"Lão Phú dùng truyền âm nói riêng với Hàn Lập về giao dịch hội dưới lòng đất.","anchor":"môi khẽ nhếch nhưng lại không phát ra chút thanh âm nào"}]},"dinhDanh":"goc","capNhatToi":"@c0938","nguon":["@c0938"]},{"id":"bi-thuat-gioi-tu-khong-gian","name":"Bí thuật giới tử không gian","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật không gian","phamCap":"không rõ","hePhai":"Đại Tấn","soHuu":["Thiên Cơ Các"],"blurb":"Bí thuật của Đại Tấn dùng vết nứt không gian luyện thành tư nhân không gian. Vương trưởng lão nói bí thuật này mới được nghiên cứu ra gần ngàn năm.","detail":"Bí thuật giới tử không gian được nhắc khi Vương trưởng lão chuẩn bị dẫn Hàn Lập vào không gian đặc chế của Thiên Cơ các để xem Thiên Cơ phủ. Hàn Lập kinh ngạc vì thân phận hải ngoại của mình khiến ông không biết rõ thành quả này của Đại Tấn.","nguonGoc":"Đại Tấn nghiên cứu ra gần ngàn năm trước","congNang":["Luyện vết nứt không gian thành tư nhân không gian @c0938"],"tabs":{"tienTrinh":[{"chuong":"@c0938","loai":"xuất hiện","importance":"normal","giaiDoan":"Giải thích bí thuật","text":"Vương trưởng lão giải thích giới tử không gian là bí thuật luyện vết nứt không gian thành tư nhân không gian.","anchor":"bí thuật đem vết nứt không gian luyện chế thành tư nhân không gian"}]},"dinhDanh":"goc","capNhatToi":"@c0938","nguon":["@c0938"]},{"id":"bi-thuat-luyen-che-gioi-tu-khong-gian","name":"Bí thuật luyện chế giới tử không gian","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Không gian bí thuật","phamCap":"Không rõ","hePhai":"Thiên Cơ Các","soHuu":["Thiên Cơ Các"],"blurb":"Bí thuật luyện hóa và củng cố khe hở không gian thành giới tử không gian. Nó do vài luyện khí đại sư của Thiên Cơ Các vô ý luyện ra, khó phổ biến và tiêu hao lớn.","detail":"Bí thuật này dùng để xử lý khe hở không gian, tạo thành giới tử không gian có thể dùng cất giữ, tránh địch hoặc thí nghiệm pháp khí pháp bảo. Vương trưởng lão cho biết Thiên Cơ Ốc và Thiên Cơ Phủ cũng là sản phẩm nghiên cứu dựa trên loại giới tử không gian này.","thuocTinh":"Không gian","nguonGoc":"Do vài luyện khí đại sư của Thiên Cơ Các vô ý luyện ra.","uyLuc":"Có thể gia cố khe hở không gian chưa chính thức sụp đổ, nhưng khó dùng phổ biến và bị hạn chế bởi tài liệu cùng chi phí.","dacDiem":"Không tạo ra không gian tùy thân hoàn chỉnh mà chủ yếu luyện hóa hoặc củng cố khe hở không gian đã có.","congNang":["Luyện hóa hoặc củng cố khe hở không gian thành giới tử không gian @c0939"],"nguoiTu":[{"ten":"Vương trưởng lão Thiên Cơ các","tuChuong":"@c0939","tangDatToi":"Không rõ","trangThai":"nắm hiểu biết vận dụng trong Thiên Cơ Các"}],"tabs":{"tienTrinh":[{"chuong":"@c0939","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ nguồn gốc","text":"Vương trưởng lão giải thích bí thuật luyện chế giới tử không gian vốn do luyện khí đại sư Thiên Cơ Các vô ý tạo ra và được dùng làm nền tảng nghiên cứu Thiên Cơ Ốc, Thiên Cơ Phủ.","anchor":"loại bí thuật này kì thật nguyên bản là do vài vị luyện khí đại sư của bổn các"}]},"capNhatToi":"@c0939","nguon":["@c0939"]},{"id":"truyen-tong-tran-vao-gioi-tu-khong-gian","name":"Truyền Tống Trận vào giới tử không gian","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Cơ Các","soHuu":["Thiên Cơ Các"],"blurb":"Trận pháp chuyên dùng để ra vào giới tử không gian của Thiên Cơ Các. Mỗi lần vận chuyển cần tiêu hao nhiều linh thạch bậc trung.","detail":"Trận nằm tại bãi đất trống phía sau lầu các của Thiên Cơ Các, là lối vào duy nhất để tới giới tử không gian. Hàn Lập nhìn thấy một lần truyền tống đã cần bảy tám khối linh thạch bậc trung, nên nhận ra chi phí ra vào không nhỏ.","thuocTinh":"Không gian truyền tống","nguonGoc":"Thuộc bố trí của Thiên Cơ Các tại khu vực dẫn vào giới tử không gian.","uyLuc":"Có thể đưa người trực tiếp vào giới tử không gian của Thiên Cơ Các.","dacDiem":"Chỉ dùng được tại vị trí bố trí trận, tiêu hao linh thạch bậc trung cho một lần truyền tống.","congNang":["Đưa người ra vào giới tử không gian của Thiên Cơ Các @c0939"],"tabs":{"tienTrinh":[{"chuong":"@c0939","loai":"xuất hiện","importance":"normal","giaiDoan":"Lối vào giới tử không gian","text":"Vương trưởng lão đưa Hàn Lập tới Truyền Tống Trận phía sau lầu các và nói muốn vào giới tử không gian chỉ có thể đi qua trận này.","anchor":"Muốn tới giới tử không gian, chỉ có thể từ Truyền Tống Trận này mới đi được"}]},"capNhatToi":"@c0939","nguon":["@c0939"]},{"id":"don-thuat-cua-han-lap","name":"Độn thuật của Hàn Lập","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông độn thuật","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Độn thuật mà Hàn Lập tự nhận đặc biệt tinh thông. Trong thế bị nhiều tu sĩ Nguyên Anh uy hiếp, hắn dùng khả năng thoát thân này làm cơ sở để đe dọa trả thù lâu dài.","detail":"Hàn Lập nói dù bốn người cùng ra tay, hắn vẫn có sáu bảy phần nắm chắc thoát được. Lời tuyên bố này khiến các thế lực lớn phải cân nhắc nguy cơ tạo ra một cường địch Nguyên Anh trung kỳ giỏi bỏ chạy và trả thù.","thuocTinh":"Độn thuật","uyLuc":"Có thể giúp Hàn Lập tự tin tìm đường thoát khi bị nhiều tu sĩ Nguyên Anh vây ép.","dacDiem":"Là căn cứ để Hàn Lập xây dựng thế uy hiếp tâm lý tại Tấn Tây phường thị.","congNang":["Thoát khỏi vây công của nhiều tu sĩ Nguyên Anh trong tình huống bị ép đến đường cùng @c0941"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0941","tangDatToi":"Tinh thông","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0941","loai":"nhắc tới","importance":"normal","giaiDoan":"Uy hiếp tại phường thị","text":"Hàn Lập công khai lấy độn thuật làm chỗ dựa, nói mình có sáu bảy phần nắm chắc thoát thân nếu bốn tu sĩ Nguyên Anh cùng ra tay.","anchor":"Cho dù bốn người các vị cùng lúc động thủ, tại hạ cũng có sáu bảy phần nắm chắc là thoát được."}]},"capNhatToi":"@c0941","nguon":["@c0941"]},{"id":"quy-anh-don","name":"Quỷ ảnh độn","cn":"","loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lão giả áo xanh khô gầy"],"blurb":"Độn thuật ẩn nấp theo dõi của lão giả áo xanh khô gầy. Hắn dùng pháp này bám theo Hàn Lập nhưng vẫn bị phát hiện.","detail":"Lão giả áo xanh gọi quỷ ảnh độn là công phu khổ tu của mình, dùng để lặng lẽ theo dõi Hàn Lập từ khu chợ tới nơi vắng. Pháp này có tác dụng ẩn nấp và bám đuôi, nhưng không vượt qua được khả năng nhận biết của Hàn Lập.","thuocTinh":"ẩn nấp, độn thuật","uyLuc":"Có thể dùng để theo dõi kín đáo nhưng vẫn bị Hàn Lập nhìn ra.","dacDiem":"Gắn với thân pháp ẩn mình của lão giả áo xanh.","congNang":["Ẩn nấp theo dõi mục tiêu @c0942"],"nguoiTu":[{"ten":"Lão giả áo xanh khô gầy","tuChuong":"@c0942","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0942","loai":"thi triển","importance":"normal","giaiDoan":"Theo dõi Hàn Lập","text":"Lão giả áo xanh dùng quỷ ảnh độn bám theo Hàn Lập nhưng bị phát hiện tại sân bỏ hoang.","anchor":"ngay cả công phu khổ tu của lão phu là quỷ ảnh độn"}]},"capNhatToi":"@c0942","nguon":["@c0942"]},{"id":"phuong-phap-luyen-che-ngoc-cam-ung","name":"Phương pháp luyện chế ngọc cảm ứng","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp luyện khí/cảm ứng","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Đại Diễn Thần Quân","Hàn Lập"],"blurb":"Bí pháp do Đại Diễn Thần Quân từng thu thập, dùng khí tức đối thủ để luyện thành vật cảm ứng. Vật luyện thành có thể cảnh báo khi đối phương tới gần trong phạm vi trăm dặm.","detail":"Đại Diễn Thần Quân giải thích rằng ngọc bội có khí tức của Lâm Ngân Bình có thể được dùng làm nền để luyện ngọc cảm ứng. Sau khi luyện thành, vật này mượn khí tức của đối phương để cảm ứng trong vòng trăm dặm, chỉ phương hướng và duy trì khoảng một năm.","thuocTinh":"cảm ứng khí tức, cảnh báo","nguonGoc":"Do Đại Diễn Thần Quân từng thu thập được phương pháp luyện chế.","uyLuc":"Có thể cảnh báo sự tiếp cận của đối phương trong phạm vi trăm dặm khoảng một năm.","dacDiem":"Cần vật mang khí tức của đối phương làm nền luyện chế.","congNang":["Mượn khí tức đối thủ để cảm ứng trong vòng trăm dặm @c0942","Cảnh báo và chỉ phương hướng khi đối phương tới gần @c0942"],"nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0942","tangDatToi":"nắm phương pháp","trangThai":"đang truyền ý"},{"ten":"Hàn Lập","tuChuong":"@c0942","tangDatToi":"chuẩn bị sử dụng","trangThai":"đang giữ vật liệu"}],"tabs":{"tienTrinh":[{"chuong":"@c0942","loai":"xuất hiện","importance":"normal","giaiDoan":"Giải thích công dụng","text":"Đại Diễn Thần Quân nói có thể dùng ngọc bội mang khí tức Lâm Ngân Bình để luyện thành ngọc cảm ứng cảnh báo trong phạm vi trăm dặm.","anchor":"có thể mượn khí tức của đối thủ, tại trong vòng trăm dặm cảm ứng được"}]},"capNhatToi":"@c0942","nguon":["@c0942"]},{"id":"thu-doan-bien-ao-ong-sao-thanh-truong-dao","name":"Thủ đoạn biến ảo ống sáo thành trường đao","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn che mắt giúp Hàn Lập biến ống sáo bằng trúc thành trường đao trong mắt người khác. Nhuyễn trùng thú biến dị của tiểu lão đầu có thể nhìn thấu thủ đoạn này.","detail":"Đây là thủ pháp ngụy trang vật phẩm từng được Hàn Lập dùng khi đối đầu nhóm Âm La Tông. Tiểu lão đầu dùng Nhuyễn trùng thú biến dị làm bằng chứng rằng thủ đoạn ấy không qua mắt được linh thú của lão, từ đó uy hiếp đòi bảo vật hoặc linh thạch.","thuocTinh":"Ảo thuật, thủ thuật che mắt","uyLuc":"Có thể che giấu hình dạng thật của vật phẩm trước người khác, nhưng bị Nhuyễn trùng thú biến dị nhìn thấu.","dacDiem":"Tác dụng chính là ngụy trang vật phẩm.","congNang":["Ngụy trang ống sáo bằng trúc thành trường đao trước mắt người ngoài @c0943"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0943","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0943","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị nhìn thấu","text":"Tiểu lão đầu nêu rõ thủ đoạn Hàn Lập biến ống sáo bằng trúc thành trường đao đã bị Nhuyễn trùng thú nhìn thấu.","anchor":"Cảnh đạo hữu đem ống sáo bằng trúc biến ảo thành trường đao,có thể giấu diếm được người khác"}]},"trangThai":"Đã lộ sơ hở trước Nhuyễn trùng thú","capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"tieng-hu-lanh-cong-kich-than-thuc","name":"Tiếng hừ lạnh công kích thần thức","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông thần thức được Hàn Lập dùng trong khoảnh khắc tiểu lão đầu định cầu viện. Một tiếng hừ lạnh khiến thần thức đối phương đau đớn, làm tiếng huýt sáo bị nghẹn lại.","detail":"Khi tiểu lão đầu bị Tam sắc Phệ kim trùng cắn xé và định huýt sáo gọi người, Hàn Lập phát ra một tiếng hừ lạnh công kích thẳng vào thần thức. Đòn này cắt ngang hành động cầu viện, tạo thời cơ để Hàn Lập dùng kim kiếm phủ tử diễm chém đôi thân thể lão.","thuocTinh":"Thần thức công kích","uyLuc":"Khiến thần thức mục tiêu đau như bị xé rách, đủ để ngăn tiếng cầu viện trong thời điểm sinh tử.","dacDiem":"Phát động bằng một tiếng hừ lạnh, tác dụng trực tiếp lên thần thức.","congNang":["Cắt ngang tiếng huýt sáo cầu viện bằng đau đớn thần thức @c0943"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0943","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0943","loai":"thi triển","importance":"normal","giaiDoan":"Chặn cầu viện","text":"Hàn Lập dùng tiếng hừ lạnh làm thần thức tiểu lão đầu đau nhức, khiến tiếng huýt sáo cầu viện bị cắt ngang.","anchor":"thần thức truyền đến từng cơn đau nhức như bị xé rách ra"}]},"trangThai":"Đã thi triển","capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"tu-la-cuc-hoa","name":"Tử La Cực Hoả","cn":"紫罗极火","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông hàn diễm","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông tử diễm của Hàn Lập, có thể dùng để kháng hàn khí cực mạnh. Trong chương này, nó được dùng để chống hàn quang từ bình Hàn tuỷ.","detail":"Khi mở bình ngọc chứa Hàn tuỷ, Hàn Lập để tử diễm bao quanh thân và tay nhằm chống lại hàn khí khiến căn phòng đóng băng. Diễn biến cho thấy Tử La Cực Hoả có khả năng đối kháng hàn khí cực lạnh phát ra từ Hàn tuỷ.","congNang":["Kháng hàn khí cực mạnh phun ra từ bình Hàn tuỷ @c0944","Tạo linh quang hộ thể khi phối hợp với Ích Tà Thần Lôi.","Hóa thành Hỏa Điểu tử sắc uy hiếp yêu thú băng thuộc tính @c1083","Tạo tử sắc quang vụ đông kết mục tiêu trong khối băng tím cao mười trượng @c1083"],"uyLuc":"Có thể giúp Hàn Lập đứng vững trước hàn khí làm cả căn phòng ngưng kết băng dày.","chuHienThoi":"Hàn Lập","trangThai":"đang sử dụng","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"thi triển","importance":"normal","giaiDoan":"Kháng hàn khí Hàn tuỷ","text":"Hàn Lập dùng Tử La Cực Hoả bao quanh thân và tay để chống hàn quang cực lạnh từ bình Hàn tuỷ.","anchor":"quanh thân bỗng nhiên toát ra một tầng tử diễm"},{"chuong":"@c1060","loai":"thi triển","importance":"normal","giaiDoan":"hộ thể","text":"Hàn Lập dùng Tử La Cực Hỏa cùng Ích Tà Thần Lôi hộ thân nhưng bị bạch quang của Linh Lung chém xuyên.","anchor":"Tử La Cực Hỏa hình thành linh quang hộ thể nhưng lại vô thanh vô tức bị chém làm hai"},{"chuong":"@c1083","loai":"thi triển","importance":"normal","giaiDoan":"Bắt sống Băng Nanh thú","text":"Hàn Lập phun Tử La Cực Hỏa hóa Hỏa Điểu tử sắc uy hiếp Băng Nanh thú thất cấp, sau đó tạo quang vụ đông kết nó trong khối băng tím cao mười trượng.","anchor":"một đoàn tử diễm từ trong miệng phun ra, liền theo đó một tiếng thanh minh phát ra, liền hóa thành một con đại Hỏa Điểu"}]},"nguon":["@c0944","@c1007","@c1060","@c1083"]},{"id":"kinh-than-thu","name":"Kinh Thần Thứ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông thần thức","phamCap":"Không rõ","hePhai":"Đại Diễn Quyết","soHuu":["Đại Diễn Thần Quân"],"blurb":"Thần thông thuộc Đại Diễn Quyết do Đại Diễn Thần Quân nêu tên. Ông hứa sẽ dùng chiêu này trợ giúp Hàn Lập nếu gặp nguy hiểm khi thu thập tài liệu khôi lỗi.","detail":"Kinh Thần Thứ được Đại Diễn Thần Quân xem là thủ đoạn có thể phá lệ thi triển để giúp Hàn Lập trong tình huống nguy hiểm. Chương này chỉ nêu tên và vai trò trợ chiến của nó, chưa mô tả chi tiết cách vận hành.","nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0944","tangDatToi":"Có thể thi triển","trangThai":"đang tu luyện"}],"congNang":["Dùng làm thủ đoạn trợ chiến thần thức khi Hàn Lập gặp nguy hiểm @c0944"],"trangThai":"đã hé lộ","capNhatToi":"@c0944","tabs":{"tienTrinh":[{"chuong":"@c0944","loai":"xuất hiện","importance":"normal","giaiDoan":"Được hứa dùng trợ giúp","text":"Đại Diễn Thần Quân nói sẽ phá lệ dùng Kinh Thần Thứ của Đại Diễn Quyết để giúp Hàn Lập khi cần.","anchor":"lão phu sẽ phá lệ như lúc chiến đấu vừa rồi vậy"}]},"nguon":["@c0944"]},{"id":"dich-dung-huyen-hoa-chi-thuat","name":"Dịch dung Huyễn Hóa Chi Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật dịch dung","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật dịch dung và biến ảo dung mạo. Âm La tông biết mục tiêu tinh thông thủ đoạn này nên cho rằng canh cửa khó nhận ra chân thân.","detail":"Trong ngày hội đấu giá, Hàn Lập đổi dung mạo thành đại hán mặt đen để vào Tây Tấn thị. Phe Âm La tông cũng nhắc mục tiêu tinh thông Dịch dung Huyễn Hóa Chi Thuật, vì vậy cần pháp bảo phá hình mới có hy vọng nhận diện.","thuocTinh":"che giấu dung mạo","congNang":["Che giấu hoặc thay đổi dung mạo để tránh bị nhận ra @c0947"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0947","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0947","loai":"thi triển","importance":"normal","giaiDoan":"Cải trang vào Tây Tấn thị","text":"Hàn Lập dùng thủ đoạn dịch dung để biến thành đại hán mặt đen trước khi tham dự hội đấu giá.","anchor":"nghe nói người nọ tinh thông dịch dung Huyễn Hóa Chi Thuật"}]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"than-thuc-do-xet-cuong-ep","name":"Thần thức dò xét cưỡng ép","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật thần thức","phamCap":"không rõ","hePhai":"","soHuu":["Huyền Thanh","Thất Diệu chân nhân"],"blurb":"Thủ đoạn dùng thần thức để cưỡng ép dò xét bí mật. Nghiệp gia sợ các trưởng lão biết kế hoạch bị ám toán rồi bị ép dò thần thức.","detail":"Trung niên nhân Nghiệp gia cảnh báo các trưởng lão biết kế hoạch phải đi cùng nhau khi ra ngoài. Nỗi lo chính là nếu bị Huyền Thanh hoặc Thất Diệu ám toán, họ có thể bị cưỡng ép dò xét thần thức khiến bí mật kế hoạch bại lộ.","thuocTinh":"thần thức","congNang":["Ép dò xét thần thức để moi bí mật từ người bị chế trụ @c0947"],"tabs":{"tienTrinh":[{"chuong":"@c0947","loai":"nhắc tới","importance":"normal","giaiDoan":"Nghiệp gia đề phòng","text":"Nghiệp gia yêu cầu trưởng lão đi cùng nhau để tránh bị ám toán rồi cưỡng ép dò thần thức.","anchor":"rồi lại bị mạnh mẽ ép dò xét thần thức thì không xong"}]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"bi-thuat-cua-that-dieu-chan-nhan","name":"Bí thuật của Thất Diệu chân nhân","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Thiên Ma tông","soHuu":["Thất Diệu chân nhân"],"blurb":"Các bí thuật mà Thất Diệu chân nhân am hiểu. Nghiệp gia đặc biệt kiêng dè vì tu sĩ Nguyên Anh nếu bất cẩn gặp ám toán cũng có thể không tự chủ mà thổ lộ.","detail":"Thất Diệu chân nhân của Thiên Ma tông được nhấn mạnh là người rất am hiểu các loại bí thuật. Vì vậy Nghiệp gia cảnh báo các trưởng lão biết kế hoạch phải tránh đi một mình, phòng trường hợp bị ám toán rồi lộ bí mật.","thuocTinh":"bí thuật","uyLuc":"Có thể uy hiếp cả tu sĩ Nguyên Anh nếu đối phương bất cẩn gặp ám toán.","congNang":["Khiến người bị ám toán có nguy cơ thổ lộ bí mật ngoài ý muốn @c0947"],"nguoiTu":[{"ten":"Thất Diệu chân nhân","tuChuong":"@c0947","tangDatToi":"am hiểu nhiều loại bí thuật","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0947","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Nghiệp gia kiêng dè","text":"Trung niên nhân Nghiệp gia nhấn mạnh Thất Diệu chân nhân am hiểu bí thuật nên các trưởng lão biết kế hoạch phải đặc biệt cảnh giác.","anchor":"cho dù có là tu sĩ cấp Nguyên Anh nhưng không cẩn thận mà gặp phải ám toán"}]},"capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"huyen-nhan-bi-thuat","name":"Huyễn nhan bí thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật biến đổi dung mạo được nhắc như khả năng khiến Diệu Âm bảo kính không nhìn thấu. Chương này liên hệ trực tiếp với việc Hàn Lập đổi mặt để tránh bị nhận ra.","detail":"Cát Thiên Hào nêu khả năng thần thông huyễn nhan bí thuật của mục tiêu còn cao hơn Diệu Âm bảo kính, giải thích vì sao bảo kính không phát hiện Hàn Lập ở lối ra phường thị.","thuocTinh":"biến đổi dung mạo","congNang":["Che giấu hoặc biến ảo diện mạo, khiến pháp bảo truy xét dung mạo khó phát hiện @c0949"],"trangThai":"đang được dùng","capNhatToi":"@c0949","tabs":{"tienTrinh":[{"chuong":"@c0949","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị nghi là vượt qua bảo kính","text":"Cát Thiên Hào cho rằng Hàn Lập có thể nhờ huyễn nhan bí thuật cao minh nên Diệu Âm bảo kính không nhìn thấu.","anchor":"người nọ thần thông huyễn nhan bí thuật vẫn là trên cả Diệu Âm bảo kính"}]},"nguon":["@c0949"]},{"id":"bat-cuc-phan-quang-tran","name":"Bát Cực Phân Quang trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"danh tiếng lừng lẫy","hePhai":"Đạo môn","soHuu":[],"blurb":"Bát Cực Phân Quang trận là trận pháp bảo vệ phường thị được Lâm Ngân Bình nhắc tới. Uy danh của trận khiến nàng cho rằng Hàn Lập khó lặng lẽ phá trận rời đi.","detail":"Trận pháp này được bố trí ở phường thị, có tác dụng phong tỏa và bảo vệ khu vực. Lâm Ngân Bình dựa vào danh tiếng của trận để phán đoán Hàn Lập phần lớn vẫn còn trong phường thị.","thuocTinh":"phòng hộ và phong tỏa","nguonGoc":"Đạo môn","congNang":["Bảo vệ phường thị và khiến người ngoài khó âm thầm phá trận rời đi @c0949"],"capNhatToi":"@c0949","tabs":{"tienTrinh":[{"chuong":"@c0949","loai":"nhắc tới","importance":"normal","giaiDoan":"Được dùng để phán đoán","text":"Lâm Ngân Bình nhắc Bát Cực Phân Quang trận để giải thích vì sao Hàn Lập khó lặng lẽ rời khỏi phường thị bằng cách phá trận.","anchor":"phường thị bố trí là do đạo môn danh tiếng lừng lẫy - Bát Cực Phân Quang trận"}]},"nguon":["@c0949"]},{"id":"truyen-tong-tran-tam-thoi-cua-sau-linh-trai","name":"Truyền tống trận tạm thời của Sấu Linh trai","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Sấu Linh trai","soHuu":["Chủ nhân Sấu Linh trai"],"blurb":"Truyền tống trận tạm thời được đặt trong lầu Sấu Linh trai. Nó giúp Hàn Lập và lão giả họ Phú rời phường thị mà không đi qua lối ra đang bị canh giữ.","detail":"Trận này chỉ tồn tại trong thời gian ngắn theo lời lão giả họ Phú, được thế lực quản phường thị cho phép vì nguyên nhân đặc thù. Nó truyền tống người dùng tới gần giao dịch hội dưới đất.","thuocTinh":"truyền tống","congNang":["Truyền tống trực tiếp tới gần giao dịch hội dưới đất, giúp rời phường thị qua đường bí mật @c0949"],"trangThai":"đang hoạt động","capNhatToi":"@c0949","tabs":{"tienTrinh":[{"chuong":"@c0949","loai":"xuất hiện","importance":"normal","giaiDoan":"Đưa Hàn Lập rời phường thị","text":"Hàn Lập và lão giả họ Phú dùng truyền tống trận tạm thời trong Sấu Linh trai để tới sơn động bí mật gần giao dịch hội dưới đất.","anchor":"trong lầu các có bố trí một loại truyền tống trận tạm thời"}]},"nguon":["@c0949"]},{"id":"than-thong-pha-phap-cua-dieu-am-bao-kinh","name":"Thần thông phá pháp của Diệu Âm bảo kính","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thất Diệu chân bảo","soHuu":["Lâm Ngân Bình"],"blurb":"Thần thông phá pháp là năng lực của Diệu Âm bảo kính được Lâm Ngân Bình giải thích. Do tế luyện chưa lâu, bảo kính chưa thể phát huy hết uy lực này.","detail":"Năng lực này dùng để phá các thủ đoạn che giấu, ảo thuật hoặc bí thuật biến đổi dung mạo. Trong chương, Diệu Âm bảo kính đã từng phá được tu sĩ dùng bí thuật tương tự nhưng không phát hiện Hàn Lập.","thuocTinh":"phá pháp","congNang":["Phá bí thuật che giấu dung mạo và ảo thuật của tu sĩ bị soi xét @c0949"],"trangThai":"chưa phát huy toàn bộ uy lực","capNhatToi":"@c0949","tabs":{"tienTrinh":[{"chuong":"@c0949","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Giới hạn do tế luyện","text":"Lâm Ngân Bình nói Diệu Âm bảo kính chưa được tế luyện lâu nên chưa phát huy hết thần thông phá pháp.","anchor":"không thể phát huy hết toàn bộ uy lực thần thông phá pháp"}]},"nguon":["@c0949"]},{"id":"suu-hon-bi-thuat-cua-cat-thien-hao","name":"Sưu hồn bí thuật của Cát Thiên Hào","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Âm La Tông","soHuu":["Cát Thiên Hào"],"blurb":"Bí thuật Cát Thiên Hào dùng để cướp lấy trí nhớ của tu sĩ lạ bị bắt sau khi kẻ này theo dõi nhóm Âm La Tông.","detail":"Cát Thiên Hào thi triển bí thuật này lên một tu sĩ lạ cách địa điểm giao dịch hội ngầm hơn trăm dặm. Thuật pháp nhằm cưỡng đoạt ký ức đối phương, khiến người bị thi triển đau đớn, thất khiếu chảy máu đen rồi chết; sau đó Cát Thiên Hào còn thiêu xác thành tro để xóa dấu vết.","nguon":["@c0950"]},{"id":"than-thong-cua-dich-tay-thien","name":"Thần thông của Dịch Tẩy Thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Dịch Tẩy Thiên"],"blurb":"Thần thông được lão giả họ Phú nhắc tới khi kể về Dịch Tẩy Thiên, đủ uy lực để dễ dàng chém giết yêu thú cấp tám.","detail":"Theo lời lão giả họ Phú, ông từng tận mắt thấy Dịch Tẩy Thiên thi triển thần thông thông thiên, dễ dàng chém giết yêu thú cấp tám. Chi tiết pháp môn chưa được nêu, nhưng lời kể dùng để nhấn mạnh thực lực cao thâm của Dịch Tẩy Thiên trong hàng Nguyên Anh hậu kỳ Đại Tấn.","nguon":["@c0950"]},{"id":"an-than-may-tia-bang-quat-nho","name":"Ẩn thân mây tía bằng quạt nhỏ","cn":"","loai":"khac","loaiLabel":"Thủ đoạn phụ trợ","phamCap":"","hePhai":"","soHuu":["Tu sĩ dùng quạt nhỏ tạo mây tía"],"blurb":"Thủ đoạn dùng quạt nhỏ tạo mây tía bao phủ thân hình rồi biến mất, phục vụ việc lén theo dõi nhóm Cát Thiên Hào.","detail":"Sau khi nhóm Âm La Tông rời khu chợ, một tu sĩ bí ẩn cầm quạt nhỏ phất lên, khiến thân hình bị mây tía bao phủ rồi lập tức biến mất. Thủ đoạn này được dùng để che giấu hành tung và bám theo hướng Cát Thiên Hào đã rời đi.","nguon":["@c0950"]},{"id":"tran-phap-co-quai-cua-giao-dich-hoi","name":"Trận pháp cổ quái của giao dịch hội","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Giao dịch hội ẩn danh","soHuu":["Giao dịch hội ẩn danh"],"blurb":"Trận pháp bao trùm đại sảnh giao dịch hội, phối hợp với lá bùa đặc chế để che giấu thân phận người tham dự.","detail":"Trận pháp này khiến quầng sáng trên người khách dự hội ngăn thần thức dò xét. Hàn Lập nhận ra lá bùa đặc chế chỉ phát huy tác dụng khi đi vào phạm vi trận pháp này.","thuocTinh":"che giấu, ngăn dò xét","congNang":["Che lấp hình dáng người dự hội khi phối hợp với lá bùa đặc chế @c0951","Ngăn thần thức dò xét quầng sáng trên người khách dự hội @c0951"],"tabs":{"tienTrinh":[{"chuong":"@c0951","loai":"xuất hiện","importance":"normal","giaiDoan":"Che giấu hội trường","text":"Trận pháp bao trùm đại sảnh, phối hợp với lá bùa đặc chế để tạo cơ chế ẩn danh cho người dự hội.","anchor":"cả gian phòng tựa hồ cũng ở trong ảnh hưởng của một cái trận pháp cổ quái"}]},"capNhatToi":"@c0951","nguon":["@c0951"]},{"id":"phap-thuat-cam-ung-than-giac-cua-lam-ngan-binh","name":"Pháp thuật cảm ứng thần giác của Lâm Ngân Bình","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Lâm Ngân Bình"],"blurb":"Pháp thuật thiên về cảm ứng thần giác của Lâm Ngân Bình, giúp nàng nhận ra cảm giác bất ổn khi bị theo dõi.","detail":"Nhờ pháp thuật này, Lâm Ngân Bình cảm thấy khác thường sau khi rời khu chợ, rồi dùng Diệu Âm Bảo Kính kiểm tra và phát hiện tán tu Diệp gia bám theo.","thuocTinh":"cảm ứng","congNang":["Giúp người tu luyện cảm ứng bất ổn và dấu hiệu bị theo dõi @c0951"],"tabs":{"tienTrinh":[{"chuong":"@c0951","loai":"nhắc tới","importance":"normal","giaiDoan":"Phát hiện bị theo dõi","text":"Lâm Ngân Bình nói pháp thuật của mình chú trọng cảm ứng thần giác nên mới sinh nghi sau khi rời khu chợ.","anchor":"pháp thuật của ta tu luyện chú trọng cảm ứng thần giác"}]},"capNhatToi":"@c0951","nguon":["@c0951"]},{"id":"linh-ap-cua-khon-vo-cuc","name":"Linh áp của Khôn Vô Cực","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Uy áp thần thông","phamCap":"Nguyên Anh hậu kỳ","hePhai":"Ma đạo","soHuu":["Khôn Vô Cực"],"blurb":"Linh áp vô hình do Khôn Vô Cực phát ra để áp chế đối thủ trong trao đổi hội.","detail":"Khôn Vô Cực dùng linh áp này nhắm riêng vào nữ tu trong ngân sắc hà quang, khiến nàng mồ hôi đầm đìa và phải lùi lại, trong khi Hàn Lập đứng gần đó không bị ảnh hưởng.","thuocTinh":"Uy áp vô hình","uyLuc":"Áp chế trực tiếp nữ tu tại hội mà không lan sang Hàn Lập bên cạnh.","dacDiem":"Có thể tập trung vào một mục tiêu cụ thể trong không gian giao dịch.","congNang":["Áp chế đối thủ bằng linh áp vô hình trong phạm vi gần @c0953"],"nguoiTu":[{"ten":"Khôn Vô Cực","tuChuong":"@c0953","tangDatToi":"thi triển được linh áp vô hình","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0953","loai":"thi triển","importance":"normal","giaiDoan":"Áp chế nữ tu","text":"Khôn Vô Cực phát linh áp vô hình nhắm vào nữ tu trong ngân sắc hà quang khi nàng định chen vào giao dịch Ma Tuỷ Toản.","anchor":"một cỗ linh áp vô hình trực tiếp hướng nữ tu áp chế"}]},"capNhatToi":"@c0953","nguon":["@c0953"]},{"id":"huyet-don","name":"Huyết độn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật độn pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Huyết độn là bí thuật Hàn Lập dùng để đào thoát trong lúc bị Cổ ma truy sát. Thuật này tiêu hao tinh huyết, tạo huyết vụ bao thân rồi hóa thành huyết ảnh bay xa cực nhanh.","detail":"Trong chương 956, Hàn Lập phun tinh huyết, dùng huyết vụ nồng đậm bao quanh thân thể rồi hóa thành huyết ảnh, thoát khỏi phạm vi truy kích của Cổ ma sau vài nhịp thở.","thuocTinh":"huyết đạo, độn pháp","uyLuc":"Tăng tốc đào thoát rất nhanh trong cự ly ngắn, đủ giúp Hàn Lập thoát khỏi Cổ ma khi đối phương bị chậm một nhịp.","dacDiem":"Cần phun tinh huyết để thi triển.","congNang":["Tạo huyết vụ bao thân và hóa thành huyết ảnh đào thoát cực nhanh @c0956"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0956","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0956","loai":"thi triển","importance":"normal","giaiDoan":"Thoát khỏi Cổ ma","text":"Hàn Lập phun tinh huyết, dùng huyết vụ bao thân rồi hóa huyết ảnh chạy xa khỏi Cổ ma.","anchor":"miệng khẽ hé phun ra một đoàn tinh huyết,một mảng huyết vụ nồng đậm"}]},"capNhatToi":"@c0956","nguon":["@c0956"]},{"id":"hoa-anh-don","name":"Hóa ảnh độn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật độn pháp","phamCap":"không rõ","hePhai":"","soHuu":["Thiết sí ma"],"blurb":"Hóa ảnh độn là bí thuật được Cổ ma liên hệ với Thiết sí ma khi thấy độn pháp Hàn Lập vừa dùng. Cổ ma nhận ra có nét giống nhưng không hoàn toàn trùng khớp.","detail":"Sau khi Hàn Lập thoát khỏi tầm thần thức, Cổ ma lẩm bẩm rằng độn pháp ấy giống Hóa ảnh độn của Thiết sí ma, rồi lại phủ định vì cảm thấy không giống hẳn.","thuocTinh":"độn pháp","nguonGoc":"Được Cổ ma liên hệ với Thiết sí ma.","dacDiem":"Giống độn pháp Hàn Lập dùng nhưng còn có điểm khác biệt chưa rõ.","congNang":["Liên quan đến thủ đoạn hóa ảnh để độn đi, theo nhận xét của Cổ ma @c0956"],"nguoiTu":[{"ten":"Thiết sí ma","tuChuong":"@c0956","tangDatToi":"được nhắc là bí thuật liên quan","trangThai":"khong-ro"}],"tabs":{"tienTrinh":[{"chuong":"@c0956","loai":"nhắc tới","importance":"normal","giaiDoan":"Cổ ma nhận ra nét tương đồng","text":"Cổ ma cho rằng độn pháp Hàn Lập vừa dùng giống Hóa ảnh độn của Thiết sí ma nhưng lại không hoàn toàn giống.","anchor":"Hóa ảnh độn này không phải là bí thuật của lão gia hỏa Thiết sí ma kia sao"}]},"capNhatToi":"@c0956","nguon":["@c0956"]},{"id":"ma-hoa-nua-nguoi-nua-ma-cua-co-ma","name":"Ma hóa nửa người nửa ma của Cổ ma","cn":"","loai":"than-thong","loaiLabel":"Ma công biến thân","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Đây là trạng thái biến thân của Cổ ma sau khi ra tay với Ác hỏa đầu đà. Thân hình lộ dáng nửa người nửa ma, tay chân tím đen phình to, lưỡi tím có thể hóa đao xuyên bắt Nguyên Anh.","detail":"Trong trận với Ác hỏa đầu đà, Cổ ma lộ thân dạng nửa người nửa ma, dùng ma trảo xuyên phá phòng hộ và dùng lưỡi tím như đao để bắt Nguyên Anh đối thủ.","thuocTinh":"ma khí, biến thân","uyLuc":"Giúp Cổ ma áp đảo tu sĩ Nguyên Anh trung kỳ trong một lượt giao thủ.","dacDiem":"Tay chân tím đen phình to, lưỡi tím hóa thành công cụ tấn công và bắt Nguyên Anh.","congNang":["Tăng mạnh sức phá phòng hộ và khả năng giết thân thể tu sĩ @c0956","Dùng lưỡi tím xuyên bắt Nguyên Anh @c0956"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c0956","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0956","loai":"thi triển","importance":"normal","giaiDoan":"Giết Ác hỏa đầu đà","text":"Cổ ma hóa thành dáng nửa người nửa ma, dùng ma trảo và lưỡi tím phá phòng hộ, xé thân thể rồi bắt Nguyên Anh Ác hỏa đầu đà.","anchor":"Chỉ thấy Cổ ma lúc này đã hóa thân thành bộ dáng nửa người nửa ma"}]},"capNhatToi":"@c0956","nguon":["@c0956"]},{"id":"ma-than-hai-dau-bon-tay","name":"Ma thân hai đầu bốn tay","cn":"","loai":"than-thong","loaiLabel":"Ma công biến thân","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Ma thân hai đầu bốn tay là hình thái ma vật hiện ra trong hắc tử sắc ma khí của Cổ ma. Hình thái này xuất hiện khi Cổ ma chuẩn bị săn nhóm tu sĩ mới tới để cắn nuốt Nguyên Anh.","detail":"Cuối chương 956, Cổ ma phóng hắc tử sắc ma khí, trong đó mơ hồ hiện ra một cự đại ma vật hai đầu bốn tay, bốn mắt hắc tử sắc lạnh lẽo nhìn về phía các độn quang đang tới.","thuocTinh":"ma khí, biến thân","dacDiem":"Hai đầu bốn tay, bốn mắt hắc tử sắc, hiện trong ma khí cuồn cuộn.","congNang":["Tạo ma thân khổng lồ trong hắc tử sắc ma khí để chuẩn bị đối phó nhiều tu sĩ @c0956"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c0956","tangDatToi":"đã hiện ra","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0956","loai":"xuất hiện","importance":"normal","giaiDoan":"Chuẩn bị săn Nguyên Anh","text":"Cổ ma phóng hắc tử sắc ma khí, trong ma khí hiện ra ma vật hai đầu bốn tay để nghênh nhóm tu sĩ mới tới.","anchor":"một cái cự đại ma vật hai đầu bốn tay từ trong ma khí mơ hồ hiện lên"}]},"capNhatToi":"@c0956","nguon":["@c0956"]},{"id":"tam-dai-mat-phu","name":"Tam đại mật phù","cn":"","aliases":[],"loai":"khac","loaiLabel":"Mật phù","phamCap":"Không rõ","hePhai":"Thiên Phù môn","soHuu":["Thiên Phù chân nhân","Thiên Phù môn"],"blurb":"Tam đại mật phù là ba mật phù từng do Thiên Phù chân nhân vẽ ra. Chúng uy chấn Đại Tấn và là biểu tượng huy hoàng cũ của Thiên Phù môn.","detail":"Thiên Phù chân nhân từng vẽ tam đại mật phù uy chấn Đại Tấn, khiến Thiên Phù môn một thời gần được liệt vào hàng Thập đại chính môn. Chương này chỉ nêu lai lịch và danh tiếng, chưa lộ tên riêng từng phù hay công năng cụ thể.","nguon":["@c0957"],"dinhDanh":"goc","nguonGoc":"Do Thiên Phù chân nhân vẽ ra trong thời kỳ hưng thịnh của Thiên Phù môn.","uyLuc":"Uy chấn Đại Tấn.","dacDiem":"Là cội nguồn danh tiếng chế phù của Thiên Phù môn.","congNang":["Tạo nên uy danh khiến Thiên Phù môn một thời suýt vào hàng Thập đại chính môn @c0957"],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"normal","giaiDoan":"Lai lịch Thiên Phù môn","text":"Tam đại mật phù được nhắc như thành tựu chế phù do Thiên Phù chân nhân lưu lại, làm nên thời kỳ huy hoàng của Thiên Phù môn.","anchor":"người sáng lập ra môn phái này “Thiên Phù chân nhân” cũng đã từng vẽ ra tam đại mật phù uy chấn cả Đại tấn"}]},"capNhatToi":"@c0957"},{"id":"bi-thuat-che-phu-dac-thu-cua-thien-phu-mon","name":"Bí thuật chế phù đặc thù của Thiên Phù môn","cn":"","aliases":["Bí thuật chế phù đặc thù của Thiên Phù môn"],"loai":"bi-thuat","loaiLabel":"Bí thuật chế phù","phamCap":"Không rõ","hePhai":"Thiên Phù môn","soHuu":["Thiên Phù môn","Hàn Lập"],"blurb":"Bí thuật chế phù đặc thù là phần truyền thừa còn lại giúp Thiên Phù môn duy trì qua thời suy tàn. Chương này chỉ nêu tác dụng duy trì truyền thừa, chưa mô tả chi tiết cách thi triển.","detail":"Sau khi Thiên Phù môn suy bại, môn phái không còn dựa vào công pháp chủ tu nổi bật mà chỉ nhờ một chút bí thuật đặc thù khi chế phù để kéo dài truyền thừa qua mấy vạn năm.","nguon":["@c0957","@c0969"],"dinhDanh":"goc","nguonGoc":"Truyền thừa chế phù của Thiên Phù môn.","dacDiem":"Gắn trực tiếp với năng lực chế phù còn sót lại của môn phái.","congNang":["Giúp Thiên Phù môn miễn cưỡng duy trì truyền thừa chế phù qua thời suy tàn @c0957","Luyện hóa Thiên cơ phủ để có thể thu vào trong cơ thể @c0969"],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"normal","giaiDoan":"Truyền thừa suy tàn","text":"Bí thuật chế phù đặc thù được nhắc là chỗ dựa còn lại của Thiên Phù môn sau khi môn phái suy yếu.","anchor":"Thiên phù môn cũng chỉ có thể dựa vào một chút đặc thù bí thuật khi chế phù"},{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Luyện hóa Thiên cơ phủ","text":"Hàn Lập từng dùng bí thuật Thiên Phù môn để luyện hóa và thu Thiên cơ phủ vào cơ thể.","anchor":"sử dụng bí thuật của thiên phù môn mới luyện hóa và thu được Thiên cơ phủ vào trong cơ thể"}]},"capNhatToi":"@c0957"},{"id":"hang-linh-phu","name":"Hàng Linh phù","cn":"","aliases":["Hàng linh phù"],"loai":"khac","loaiLabel":"Phù lục / phương pháp luyện chế","phamCap":"Không rõ","hePhai":"Thiên Phù môn","soHuu":["Thiên Phù môn"],"blurb":"Hàng Linh phù là phù lục mà Hàn Lập muốn học phương pháp luyện chế khi tới Thiên Phù môn. Chương này chỉ xác nhận mục tiêu học luyện chế, chưa giải thích công dụng đầy đủ.","detail":"Hàn Lập nghĩ nếu không vì mấy ác giao xuất hiện tại Hoa Vân châu và vì bản thân chưa học phương pháp luyện chế Hàng Linh phù, hắn sẽ không tìm đến tiểu phái Thiên Phù môn.","nguon":["@c0957"],"dinhDanh":"goc","congNang":["Là phù lục có phương pháp luyện chế mà Hàn Lập cần tìm hiểu trong mạch liên quan mấy ác giao ở Hoa Vân châu @c0957"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0957","tangDatToi":"Chưa học phương pháp luyện chế","trangThai":"dang-tim-hoc"}],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu đến Thiên Phù môn","text":"Hàng Linh phù được nêu là một nguyên nhân khiến Hàn Lập tới Thiên Phù môn để tìm phương pháp luyện chế.","anchor":"mà hắn cũng không học phương pháp luyện chế hàng linh phù"}]},"capNhatToi":"@c0957"},{"id":"tu-tan-linh-luc-toan-than-hoa-nguyen-anh-vo-hinh","name":"Tự tán linh lực toàn thân, hóa Nguyên Anh vô hình","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Hóa Thần kỳ","hePhai":"không rõ","soHuu":["Tu sĩ Hóa Thần kỳ"],"blurb":"Đây là năng lực được Đại Diễn Thần Quân nêu khi bàn về khả năng lão giả ở Thiên Phù môn đã đạt Hóa Thần kỳ. Thần thông này giúp người thi triển tạm thời tán linh lực toàn thân và khiến Nguyên Anh trở nên vô hình.","detail":"Khi Hàn Lập và Đại Diễn Thần Quân không thể dò ra tu vi thật của lão giả, Đại Diễn nêu một khả năng là đối phương đã tiến vào Hóa Thần kỳ. Theo lời ông, tu sĩ cấp này có thể tự tán linh lực toàn thân và trong thời gian ngắn hóa Nguyên Anh thành vô hình, qua đó che giấu nền tảng khiến thần thức khó nhận biết.","thuocTinh":"ẩn giấu tu vi và Nguyên Anh","uyLuc":"Có thể khiến cả Hàn Lập và Đại Diễn Thần Quân không dò ra nền tảng chân chính nếu người dùng thật sự là tu sĩ Hóa Thần.","dacDiem":"Hiệu lực được mô tả là trong một thời gian ngắn.","congNang":["Tự tán linh lực toàn thân để che giấu biểu hiện tu vi @c0959","Tạm thời hóa Nguyên Anh thành vô hình khiến người ngoài khó dò xét @c0959"],"nguoiTu":[{"ten":"Tu sĩ Hóa Thần kỳ","tuChuong":"@c0959","tangDatToi":"năng lực cơ bản được nêu","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c0959","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ năng lực Hóa Thần","text":"Đại Diễn Thần Quân nêu năng lực tự tán linh lực và hóa Nguyên Anh vô hình như lời giải thích cho việc lão giả Thiên Phù môn che giấu tu vi.","anchor":"“có thể tự tán linh lực toàn thân, trong một thời gian ngắn cũng có khể hóa Nguyên Anh thành vô hình”"}]},"dinhDanh":"goc","capNhatToi":"@c0959","nguon":["@c0959"]},{"id":"hoa-kiep","name":"Hóa Kiếp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"ma đạo","hePhai":"Ma đạo","soHuu":[],"blurb":"Thần thông ma đạo được dùng làm chuẩn so sánh cho Hóa linh phù.","detail":"Hóa linh phù được ghi có thể đạt công hiệu tương tự Hóa Kiếp nhưng không gây phản phệ cơ thể như công pháp ma đạo.","nguon":["@c0960"],"thuocTinh":"bảo mệnh, né kiếp","congNang":["Làm chuẩn so sánh cho công hiệu bảo mệnh của Hóa linh phù @c0960"],"tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"nhắc tới","importance":"bridge","giaiDoan":"Được so sánh với Hóa linh phù","text":"Hóa Kiếp được nhắc như thần thông ma đạo có công hiệu tương tự Hóa linh phù nhưng có nhược điểm phản phệ.","anchor":"thậm chí có thể so sánh với loại thần thông “Hóa Kiếp"}]},"capNhatToi":"@c0960"},{"id":"luc-dinh-thien-giap-thuat","name":"Lục Đinh Thiên Giáp thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Mật thuật phù lục","phamCap":"mật phù Thiên Phù Môn","hePhai":"Thiên Phù Môn","soHuu":["Thiên Phù Môn"],"blurb":"Thuật luyện liên quan Lục đinh thiên giáp phù, từng là truyền thừa trọng yếu của Thiên Phù Môn.","detail":"Ngọc giản chứa Lục Đinh Thiên Giáp thuật được ghi là thất lạc sau khi Thiên Phù chân nhân tọa hóa. Cao tầng Thiên Phù Môn từng gắt gao truy tìm nhưng không có manh mối.","nguon":["@c0960"],"trangThai":"thất lạc","congNang":["Dùng để truyền thừa hoặc luyện chế Lục đinh thiên giáp phù @c0960"],"tabs":{"tienTrinh":[{"chuong":"@c0960","loai":"thất truyền/tái hiện","importance":"major","giaiDoan":"Xác nhận thất lạc","text":"Ngọc giản Lục Đinh Thiên Giáp thuật được xác nhận đã biến mất sau khi Thiên Phù chân nhân tọa hóa, khiến cao tầng Thiên Phù Môn truy tìm không có kết quả.","anchor":"ngọc giản Lục Đinh Thiên Giáp thuật sau khi Thiên Phù chân nhân tọa hóa"}]},"capNhatToi":"@c0960"},{"id":"mat-thuat-che-phu-thien-phu-mon","name":"Mật thuật chế phù Thiên Phù môn","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật chế phù","phamCap":"truyền thừa tông môn","hePhai":"Thiên Phù môn","soHuu":["Thiên Phù môn"],"blurb":"Truyền thừa chế phù của Thiên Phù môn được đem làm điều kiện mời Hàn Lập xuất thủ. Giá trị của bộ mật thuật đủ khiến Hàn Lập cân nhắc lời mời khách khanh danh nghĩa.","detail":"Thiên Phù môn nguyện dâng các mật thuật chế phù cho Hàn Lập để đổi lấy việc hắn ra tay giải quyết một phiền toái cho ba phái. Đây là phần thù lao chính trước khi Ôn lão giả đưa thêm Hóa linh phù.","dinhDanh":"goc","thuocTinh":"chế phù","nguonGoc":"Thiên Phù môn","congNang":["Truyền thừa phương pháp chế phù của Thiên Phù môn dùng làm thù lao mời Hàn Lập xuất thủ @c0961"],"tabs":{"tienTrinh":[{"chuong":"@c0961","loai":"xuất hiện","importance":"normal","giaiDoan":"Được đem làm thù lao","text":"Thiên Phù môn hứa dâng mật thuật chế phù cho Hàn Lập để đổi lấy một lần hắn ra tay.","anchor":"Thiên Phù môn nguyện ý đem các mật thuật chế phù dâng tặng cho tiền bối"}]},"capNhatToi":"@c0961","nguon":["@c0961"]},{"id":"bi-thuat-truyen-thua-kim-ha-son-va-minh-duong-coc","name":"Bí thuật truyền thừa Kim Hà sơn và Minh Dương cốc","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật tông môn","phamCap":"truyền thừa tông môn","hePhai":"Kim Hà sơn; Minh Dương cốc","soHuu":["Kim Hà sơn","Minh Dương cốc"],"blurb":"Bí thuật truyền thừa của Kim Hà sơn và Minh Dương cốc được hứa giao cho Hàn Lập cùng với truyền thừa chế phù Thiên Phù môn. Chúng là một phần thù lao chung của ba phái.","detail":"Khi ba phái thương lượng với Hàn Lập, Kim Hà sơn và Minh Dương cốc đồng ý dâng bí thuật truyền thừa để hắn tìm hiểu, phối hợp với thù lao của Thiên Phù môn nhằm mời hắn xuất thủ.","dinhDanh":"goc","thuocTinh":"bí thuật tông môn","congNang":["Dùng làm truyền thừa trao đổi trong thỏa thuận mời Hàn Lập ra tay @c0961"],"tabs":{"tienTrinh":[{"chuong":"@c0961","loai":"xuất hiện","importance":"normal","giaiDoan":"Được hứa dâng cho Hàn Lập","text":"Kim Hà sơn và Minh Dương cốc hứa dâng bí thuật truyền thừa cùng Thiên Phù môn để mời Hàn Lập xuất thủ.","anchor":"Kim Hà sơn và Minh Dương cốc đồng dạng cũng sẽ dâng tặng các bí thuật truyền thừa"}]},"capNhatToi":"@c0961","nguon":["@c0961"]},{"id":"thuy-thuat-cua-bat-cap-lam-giao","name":"Thủy thuật của bát cấp lam giao","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông yêu thú","phamCap":"không rõ","hePhai":"yêu thú giao long","soHuu":["Bát cấp lam giao"],"blurb":"Thủy thuật giúp bát cấp lam giao đánh rồi rút trong đại hội đồ giao. Sau khi tập kích, nó có thể lẩn xuống đáy biển khiến tu sĩ nhân loại khó truy bắt.","detail":"Bát cấp lam giao dùng thủy thuật xuất thần nhập hóa để rời khỏi chiến trường ngay sau khi tập kích các tổ tu sĩ ít người. Nhờ thủ đoạn này, phe đồ giao tổn thất thêm Kết Đan mà chưa giữ chân được ác giao.","dinhDanh":"goc","thuocTinh":"thủy thuộc tính","congNang":["Ẩn độn xuống đáy biển sau khi tập kích, giúp bát cấp lam giao thoát khỏi đội săn giao @c0961"],"tabs":{"tienTrinh":[{"chuong":"@c0961","loai":"thi triển","importance":"normal","giaiDoan":"Đánh rồi rút","text":"Bát cấp lam giao dùng thủy thuật để lẩn xuống đáy biển sau các đợt tập kích tu sĩ nhân loại.","anchor":"lập thức dùng thủy thuật xuất thần nhập hóa lẻn vào đáy biển rời đi"}]},"capNhatToi":"@c0961","nguon":["@c0961"]},{"id":"than-thuc-do-xet-muoi-dam-cua-han-lap","name":"Thần thức dò xét mười dặm của Hàn Lập","cn":"","loai":"than-thong","loaiLabel":"Thần niệm","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Cách Hàn Lập thu hẹp phạm vi thần niệm khi đi cùng đội tu sĩ. Hắn chỉ bao phủ chu vi mười dặm quanh mặt biển để dò xét mà không lộ toàn bộ thực lực.","detail":"Trong nhiệm vụ dò xét hải vực phía tây Quỳnh Anh đảo, Hàn Lập không phát tán toàn bộ thần thức trước nhiều tu sĩ mà chỉ dùng thần niệm bao trùm phạm vi mười dặm mặt biển xung quanh. Cách làm này vừa giúp hắn cảnh giác trước ác giao, vừa tránh khiến người khác nghi ngờ.","congNang":["Dò xét phạm vi mười dặm quanh mặt biển trong khi che giấu phần lớn thần thức @c0962"],"dinhDanh":"goc","nguon":["@c0962"],"tabs":{"tienTrinh":[{"chuong":"@c0962","loai":"xuất hiện","importance":"normal","giaiDoan":"Dò xét hải vực","text":"Hàn Lập dùng thần niệm bao phủ chu vi mười dặm quanh mặt biển để đề phòng ác giao mà không lộ hết thần thức.","anchor":"chỉ dùng thần niệm đem chu vi mười dặm mặt biển xung quanh bao hết"}]},"capNhatToi":"@c0962"},{"id":"long-nham-hoa-dich-cua-xich-hoa-giao","name":"Long nham hóa dịch của xích hỏa giao","cn":"","loai":"than-thong","loaiLabel":"Yêu hỏa thần thông","phamCap":"Không rõ","hePhai":"Yêu giao","soHuu":["Xích Hỏa Giao"],"blurb":"Yêu hỏa do xích hỏa giao bát cấp phun ra. Hỏa diễm đỏ sậm đã đạt tới mức hóa lửa thành dịch thể.","detail":"Xích Hỏa Giao hiện bản thể rồi há miệng phun long nham đỏ sậm. Hàn Lập nhận định đối phương có thể luyện yêu hỏa tới mức hóa lửa thành dịch thể, chứng tỏ bản lĩnh không tồi, nhưng hỏa dịch này bị Tử La Cực Hỏa phối hợp Tuyết Tinh Châu áp chế.","thuocTinh":"Hỏa","uyLuc":"Có thể hóa hỏa diễm thành dịch thể đỏ sậm.","congNang":["Tạo long nham đỏ sậm ở trạng thái hỏa dịch để công kích đối thủ @c0962"],"dinhDanh":"goc","nguon":["@c0962"],"tabs":{"tienTrinh":[{"chuong":"@c0962","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Hàn Lập","text":"Xích Hỏa Giao phun long nham đỏ sậm đã luyện tới mức hóa lửa thành dịch thể để công kích Hàn Lập.","anchor":"Hóa lửa thành dịch thể, có thể đem yêu hỏa luyện thành bậc này bản lãnh thật không tồi"}]},"capNhatToi":"@c0962"},{"id":"hoa-song-cua-xich-hoa-giao","name":"Hỏa sóng của xích hỏa giao","cn":"","loai":"than-thong","loaiLabel":"Yêu hỏa thần thông","phamCap":"Không rõ","hePhai":"Yêu giao","soHuu":["Xích Hỏa Giao"],"blurb":"Thần thông điều động biển lửa của xích hỏa giao. Hai hỏa sóng cao hơn mười trượng từ hai bên ập xuống để ép Hàn Lập.","detail":"Khi yêu hỏa bị áp chế, Xích Hỏa Giao tiếp tục điều động biển lửa quanh Hàn Lập, tạo hai hỏa sóng cao hơn mười trượng đánh ép từ hai bên. Đòn này bị Hàn Lập dựng hai đỉnh băng ba mươi trượng có tử sắc hàn quang đè lại.","thuocTinh":"Hỏa","congNang":["Điều động biển lửa tạo hỏa sóng từ hai bên để bao vây và ép đối thủ @c0962"],"dinhDanh":"goc","nguon":["@c0962"],"tabs":{"tienTrinh":[{"chuong":"@c0962","loai":"thi triển","importance":"normal","giaiDoan":"Ép từ hai bên","text":"Xích Hỏa Giao tạo hai hỏa sóng cao hơn mười trượng từ hai bên ập xuống Hàn Lập nhưng bị băng phong chặn lại.","anchor":"một hỏa sóng cao hơn mười trượng xuất hiện hùng hổ từ hai bên ập xuống Hàn Lập"}]},"capNhatToi":"@c0962"},{"id":"tu-sac-bang-phong-cua-han-lap","name":"Tử sắc băng phong của Hàn Lập","cn":"","loai":"than-thong","loaiLabel":"Hàn băng thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thủ đoạn hàn băng Hàn Lập dùng để chặn hỏa sóng của xích hỏa giao. Hai đỉnh băng ba mươi trượng mang tử sắc hàn quang đột ngột vươn lên từ mặt biển.","detail":"Trước hai hỏa sóng của Xích Hỏa Giao, Hàn Lập chà hai tay rồi vẫy ra hai bên, khiến hai đỉnh băng cao ba mươi trượng mang tử sắc hàn quang dựng lên. Hai đỉnh băng trấn áp hỏa sóng đang ép tới, buộc xích hỏa giao đổi sang tập kích cận thân.","thuocTinh":"Hàn băng","congNang":["Dựng hai đỉnh băng cao ba mươi trượng để phòng ngự và trấn áp hỏa sóng @c0962"],"dinhDanh":"goc","nguon":["@c0962"],"tabs":{"tienTrinh":[{"chuong":"@c0962","loai":"thi triển","importance":"normal","giaiDoan":"Chặn hỏa sóng","text":"Hàn Lập dựng hai đỉnh băng ba mươi trượng có tử sắc hàn quang để đè lại hỏa sóng của xích hỏa giao.","anchor":"hai đỉnh băng ba mươi trượng từ đất đột ngột vươn thẳng lên"}]},"capNhatToi":"@c0962"},{"id":"linh-anh-thuat","name":"Linh ảnh thuật","aliases":["bí thuật truyền thừa của Kim Hà sơn"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông phân ảnh","phamCap":"không rõ","hePhai":"Kim Hà sơn","soHuu":["Hàn Lập"],"blurb":"Linh ảnh thuật là thần thông phân ảnh Hàn Lập dùng trong trận với Xích hỏa giao. Thuật này tạo thân ảnh giống nhau để làm nhiễu phán đoán của đối thủ.","detail":"Khi đối chiến Xích hỏa giao, Hàn Lập hóa thành ba thân ảnh giống nhau như đúc, khiến ác giao khó phân biệt thật giả trước ba đạo kim mang. Hàn Lập nhận xét thuật này là bí thuật truyền thừa của Kim Hà sơn, tuy nhỏ nhưng hữu dụng khi đối địch thật sự.","thuocTinh":"phân ảnh, mê hoặc","nguonGoc":"Kim Hà sơn","congNang":["Tạo nhiều thân ảnh giống nhau để mê hoặc đối thủ khi giao chiến @c0963"],"uyLuc":"Có thể khiến Xích hỏa giao bát cấp phán đoán sai trong khoảnh khắc quyết định.","dacDiem":"Thích hợp phối hợp phi kiếm hoặc đòn đánh bất ngờ.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0963","tangDatToi":"thi triển trong thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Xích hỏa giao","text":"Hàn Lập dùng Linh ảnh thuật hóa thành ba thân ảnh giống nhau để làm Xích hỏa giao phán đoán sai trước đòn phi kiếm.","anchor":"thân hình hóa thành ba Hàn Lập giống nhau như đúc"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"kim-sac-dien-vong","name":"Kim sắc điện võng","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi điện","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Kim sắc điện võng là thủ đoạn lôi điện Hàn Lập dùng để bắt giao hồn Xích hỏa giao. Điện võng được tạo từ kim hồ bắn ra từ phi kiếm.","detail":"Sau khi Xích hỏa giao bị chém đầu, tiểu giao hồn vừa thoát ra đã bị hai đạo kim hồ từ phi kiếm hóa thành điện võng chụp lại. Hàn Lập không dẫn bạo điện võng mà thu nhỏ thành kim ti, trói giao hồn thành ti cầu rồi cho vào bích lục tiểu bình.","thuocTinh":"lôi điện, bắt hồn","congNang":["Chụp giữ yêu hồn hoặc nguyên thần và thu nhỏ thành kim ti trói buộc @c0963"],"uyLuc":"Đủ để bắt sống giao hồn của yêu giao bát cấp khi đối phương vừa thoát xác.","dacDiem":"Có thể dùng để tiêu diệt hoặc chuyển sang trói giữ mục tiêu.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0963","tangDatToi":"thi triển trong thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"thi triển","importance":"normal","giaiDoan":"Bắt giao hồn","text":"Hàn Lập dùng kim sắc điện võng chụp lấy giao hồn Xích hỏa giao rồi thu nhỏ thành kim ti để bắt sống.","anchor":"hai đạo kim hồ đồng thời từ hai phi kiếm bắn ra hóa thành một kim sắc điện võng"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"tu-sac-lien-hoa-han-khi","name":"Tử sắc liên hoa hàn khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông hàn khí","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Tử sắc liên hoa hàn khí là thủ đoạn khống chế Hàn Lập dùng trong khoảnh khắc quyết định với Xích hỏa giao. Hàn khí bộc phát khiến ác giao khựng lại để phi kiếm chém đầu.","detail":"Một đóa tử sắc liên hoa hiện dưới chân Xích hỏa giao, liên ảnh vừa hiện đã bộc phát hàn khí bao lấy thân ác giao. Khoảnh khắc chậm lại này giúp hai đạo kim quang của Hàn Lập chém rời đầu giao.","thuocTinh":"hàn khí, khống chế","congNang":["Bộc phát hàn khí để làm chậm hoặc đóng băng mục tiêu trong khoảnh khắc @c0963"],"uyLuc":"Có thể làm thân hình Xích hỏa giao bát cấp trì trệ đúng lúc bị phi kiếm chém tới.","dacDiem":"Tác dụng mạnh khi phối hợp với đòn sát thương nhanh.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0963","tangDatToi":"thi triển trong thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"thi triển","importance":"normal","giaiDoan":"Chém đầu Xích hỏa giao","text":"Tử sắc liên hoa bộc phát hàn khí bao lấy Xích hỏa giao, tạo cơ hội để phi kiếm của Hàn Lập chém đầu nó.","anchor":"một cỗ hàn khí đột nhiên bạo phát nhất thời bao lấy thân ác giao"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"uy-luc-canh-tinh-quan-nhap-phi-kiem","name":"Uy lực Canh tinh quán nhập phi kiếm","cn":"","loai":"bi-thuat","loaiLabel":"Cách vận dụng phi kiếm","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Đây là cách Hàn Lập dồn lượng lớn linh lực vào phi kiếm để phát huy uy lực Canh tinh. Trong trận với Xích hỏa giao, cách vận dụng này giúp phi kiếm gần như không gì không phá được.","detail":"Hàn Lập dồn hơn nửa linh lực vào hai khẩu phi kiếm, nhờ đó bộc phát toàn bộ uy lực đáng sợ của Canh tinh trong khoảnh khắc. Uy lực ấy góp phần quyết định việc chém rời đầu Xích hỏa giao.","thuocTinh":"phi kiếm, Canh tinh, bộc phát linh lực","congNang":["Tăng uy lực xuyên phá của phi kiếm bằng cách dồn linh lực để phát huy Canh tinh @c0963"],"uyLuc":"Trong khoảnh khắc bộc phát, phi kiếm đạt sức chém cực mạnh đủ kết liễu yêu giao bát cấp.","dacDiem":"Tiêu hao linh lực lớn nhưng đổi lại sức công phá rất cao.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0963","tangDatToi":"thi triển trong thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Bộc phát phi kiếm","text":"Hàn Lập quán hơn nửa linh lực vào phi kiếm để phát huy toàn bộ uy lực Canh tinh khi chém Xích hỏa giao.","anchor":"đem toàn bộ uy lực đáng sợ của canh tinh phát ra"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"tinh-hon-phan-liet-mat-thuat","name":"Tinh hồn phân liệt mật thuật","cn":"","aliases":["Phân hồn thuật"],"loai":"bi-thuat","loaiLabel":"Bí thuật hồn phách","phamCap":"không rõ","hePhai":"Đại Diễn Thần Quân","soHuu":["Đại Diễn Thần Quân"],"blurb":"Bí thuật phân liệt tinh hồn thật sự do Đại Diễn Thần Quân hé lộ. Nó cho phép ông chia tinh hồn thành hai phần để vừa dung hợp khôi lỗi, vừa giữ phần mang ký ức tình cảm đi vào Luân Hồi.","detail":"Đại Diễn Thần Quân phân biệt thuật này với việc phân liệt thần niệm thường thấy. Ông dự định lấy phần chứa hơn nửa tinh hồn chi lực dung hợp vào khôi lỗi, còn phần mang tình cảm và trí nhớ sẽ tọa hóa để trở lại Luân Hồi đạo.","thuocTinh":"hồn phách","nguonGoc":"Được Đại Diễn Thần Quân phát hiện trong thời gian bị Ký thần thuật nhốt trong khôi lỗi","congNang":["Chia tinh hồn thành hai phần, một phần dùng để dung hợp vào khôi lỗi, phần còn lại giữ tình cảm và trí nhớ để tọa hóa vào Luân Hồi @c0964"],"uyLuc":"Có thể quyết định số phận của Đại Diễn Thần Quân và lõi tinh hồn của khôi lỗi cấp cao.","dacDiem":"Không phải phân liệt thần niệm thông thường mà là phân liệt tinh hồn thật sự.","nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0964","tangDatToi":"nắm giữ","trangThai":"chuẩn bị thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c0964","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ phân hồn","text":"Đại Diễn Thần Quân hé lộ mật thuật phân liệt tinh hồn và dự định dùng nó để chia hồn trước khi dung hợp khôi lỗi.","anchor":"Đến lúc đó ta đem tinh hồn chia ra làm hai"}]},"capNhatToi":"@c0964","nguon":["@c0964"]},{"id":"ao-tran-che-phu-ngon-nui","name":"Ảo trận che phủ ngọn núi","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp che giấu","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Trận pháp che giấu được Hàn Lập bố trí quanh ngọn núi đặt Thiên Cơ Phủ. Nó phối hợp sương mù che phủ phạm vi mười dặm để tránh người khác nhòm ngó.","detail":"Sau khi đặt Thiên Cơ Phủ trong hang núi trên đảo nhỏ vô danh, Hàn Lập dùng ảo trận bao phủ toàn bộ ngọn núi nhỏ, khiến sương mù mênh mông che kín phương viên mười dặm quanh nơi luyện chế.","congNang":["Che giấu động phủ luyện khôi lỗi và ngăn người ngoài nhìn thấy bố trí trong ngọn núi @c0964"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0964","tangDatToi":"đã bố trí","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0964","loai":"xuất hiện","importance":"normal","giaiDoan":"Che phủ động phủ","text":"Hàn Lập bố trí ảo trận quanh ngọn núi đặt Thiên Cơ Phủ để che giấu nơi luyện chế khôi lỗi.","anchor":"dùng ảo trận che phủ toàn bộ ngọn núi nhỏ"}]},"capNhatToi":"@c0964","nguon":["@c0964"]},{"id":"liet-hon-thuat","name":"Liệt hồn thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Thần hồn","soHuu":["Đại Diễn Thần Quân"],"blurb":"Bí thuật thần hồn dùng để phân liệt hồn phách, cho phép một phần tinh hồn nhập vào khôi lỗi. Khi thi triển gây đau đớn dữ dội và khiến tàn hồn khó tồn tại lâu.","detail":"Đại Diễn Thần Quân thi triển liệt hồn thuật để đưa một phần tinh hồn vào khôi lỗi màu bạc, nhằm khiến tinh hồn và khôi lỗi trở thành một thể. Bí thuật này là mốc sinh tử đối với tàn hồn của ông, vì phần hồn còn lại chỉ có thể kéo dài trong thời gian ngắn.","thuocTinh":"Thần hồn","uyLuc":"Có thể phân liệt tinh hồn và đưa một phần nhập vào khôi lỗi.","dacDiem":"Thi triển đau đớn dữ dội, phần hồn còn lại suy yếu nghiêm trọng.","congNang":["Phân liệt hồn phách để một phần tinh hồn nhập vào khôi lỗi @c0965"],"nguoiTu":[{"ten":"Đại Diễn Thần Quân","tuChuong":"@c0965","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0965","loai":"thi triển","importance":"major","giaiDoan":"Phân hồn nhập khôi lỗi","text":"Đại Diễn Thần Quân thi triển liệt hồn thuật, khiến lục quang phân thành hai và một phần tinh hồn bay vào miệng khôi lỗi.","anchor":"Tiếp theo chú ngữ phát ra càng lúc càng dồn dập, lục quang dần dần trở nên chói mắt"}]},"capNhatToi":"@c0965","nguon":["@c0965"]},{"id":"van-moc-dai-tran","name":"Vạn mộc đại trận","cn":"","aliases":["Vạn Mộc đại trận"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"cổ kỳ trận","hePhai":"Mộc hệ","soHuu":["Khô trúc lão nhân"],"blurb":"Cổ kỳ trận trấn giữ Khô trúc đảo, lấy thiên tang thần thụ làm trận nhãn. Trận này uy chấn hải ngoại nhiều vạn năm, ngay cả tu sĩ Nguyên Anh hậu kỳ lọt vào cũng bị hạn chế thần thông.","detail":"Vạn mộc đại trận là chỗ dựa nổi danh của Khô trúc lão nhân trên Khô trúc đảo. Trận lấy thiên tang thần thụ làm trận nhãn, được mô tả có uy danh lớn đến mức tu sĩ Nguyên Anh hậu kỳ nếu xâm nhập cũng chỉ còn dùng được bảy phần thần thông.","thuocTinh":"Mộc hệ","uyLuc":"Áp chế thần thông của tu sĩ xâm nhập, kể cả Nguyên Anh hậu kỳ cũng bị hạn chế.","dacDiem":"Dùng thiên tang thần thụ làm trận nhãn, trấn giữ Khô trúc đảo.","congNang":["Áp chế thần thông người vào trận, Nguyên Anh hậu kỳ cũng chỉ còn dùng được bảy phần @c0965"],"tabs":{"tienTrinh":[{"chuong":"@c0965","loai":"xuất hiện","importance":"normal","giaiDoan":"Trấn đảo Khô trúc","text":"Vạn mộc đại trận được giới thiệu là cổ kỳ trận lấy thiên tang thần thụ làm trận nhãn và là một trong các chỗ dựa khiến Khô trúc lão nhân danh chấn hải ngoại.","anchor":"một thân thần thông cũng sẽ chỉ còn sử dụng được bảy phần mà thôi"}]},"capNhatToi":"@c0965","nguon":["@c0965"]},{"id":"cong-phap-dac-thu-cua-moc-linh-ve","name":"Công pháp đặc thù của mộc linh vệ","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"khong-ro","hePhai":"Khô Trúc đảo","soHuu":["Các mộc linh vệ canh mộc điện"],"blurb":"Công pháp riêng của mộc linh vệ trên Khô Trúc đảo, được tu luyện nhờ linh khí Thiên Tang Thần Thụ. Nó khiến mộc linh khí của họ tinh túy hơn tu vi biểu hiện và giúp họ am hiểu phối hợp chiến đấu.","detail":"Lão giả dẫn đường nói các mộc linh vệ do Khô Trúc tự huấn luyện, chuyên tu một loại công pháp đặc thù nhờ linh khí Thiên Tang Thần Thụ. Dù chỉ là Trúc Cơ kỳ, họ có mộc linh khí tinh túy và phối hợp chiến đấu tốt.","thuocTinh":"Mộc thuộc tính","dacDiem":"Gắn với linh khí Thiên Tang Thần Thụ và hệ thống mộc linh vệ của Khô Trúc đảo.","congNang":["Tăng độ tinh túy của mộc linh khí cho mộc linh vệ @c0967","Hỗ trợ mộc linh vệ am hiểu phối hợp chiến đấu @c0967"],"nguoiTu":[{"ten":"Các mộc linh vệ canh mộc điện","tuChuong":"@c0967","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu tại mộc điện","text":"Lão giả giới thiệu mộc linh vệ chuyên tu công pháp đặc thù nhờ linh khí Thiên Tang Thần Thụ.","anchor":"bọn chúng chuyên môn tu luyện một loại công pháp đặc thù"}]},"capNhatToi":"@c0967","nguon":["@c0967"]},{"id":"tru-nhan-thuat","name":"Trú nhan thuật","cn":"","loai":"khac","loaiLabel":"Thuật pháp","phamCap":"khong-ro","hePhai":"khong-ro","soHuu":["Khô Trúc lão nhân"],"blurb":"Thuật pháp giữ dung nhan trẻ, được Hàn Lập liên hệ khi thấy Khô Trúc lão nhân có dáng thiếu niên tóc bạc. Nó giải thích vì sao một lão quái nổi danh lại không có vẻ ngoài già nua.","detail":"Khi gặp Khô Trúc lão nhân trong mộc điện, Hàn Lập kinh ngạc vì đối phương mang diện mạo thiếu niên tóc bạc môi hồng. Chàng suy đoán với tu vi của tu sĩ Nguyên Anh, việc dùng trú nhan thuật là điều có thể xảy ra.","congNang":["Giữ dung nhan trẻ hơn tuổi thật hoặc hình dung thông thường @c0967"],"nguoiTu":[{"ten":"Khô Trúc lão nhân","tuChuong":"@c0967","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"nhắc tới","importance":"normal","giaiDoan":"Khô Trúc lộ diện","text":"Hàn Lập suy đoán Khô Trúc lão nhân có thể dùng trú nhan thuật nên giữ dung mạo thiếu niên.","anchor":"dĩ nhiên đều có khả năng sử dụng trú nhan thuật"}]},"capNhatToi":"@c0967","nguon":["@c0967"]},{"id":"kiem-tran-cua-kho-truc","name":"Kiếm trận của Khô Trúc","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"khong-ro","hePhai":"Khô Trúc đảo","soHuu":["Khô Trúc lão nhân"],"blurb":"Kiếm trận do Khô Trúc lão nhân thi triển bằng hơn trăm khẩu phi kiếm màu xanh biếc. Trận này xếp thành thế cổ quái trên đỉnh đầu, rồi phóng kiếm khí hóa thành bóng kiếm rợp trời.","detail":"Trong cuộc luận bàn với khôi lỗi Lệ đạo hữu, Khô Trúc kết quyết phóng hơn trăm đạo lục mang hóa thành phi kiếm. Các phi kiếm tự động lập thành trận, sau đó kiếm trận rung lên và bắn kiếm khí liên kết thành một mảnh hàn quang công kích đối thủ.","uyLuc":"Hơn trăm phi kiếm hợp thành kiếm trận, có thể phóng kiếm khí tạo bóng kiếm rợp trời.","dacDiem":"Dùng phi kiếm xanh biếc xếp thành thế trận cổ quái phía trên đỉnh đầu người thi triển.","congNang":["Lập trận bằng hơn trăm khẩu phi kiếm xanh biếc @c0967","Phóng kiếm khí hóa bóng kiếm rợp trời để công kích @c0967"],"nguoiTu":[{"ten":"Khô Trúc lão nhân","tuChuong":"@c0967","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"thi triển","importance":"normal","giaiDoan":"Luận bàn với khôi lỗi","text":"Khô Trúc dùng hơn trăm phi kiếm xanh biếc lập kiếm trận và phát động kiếm khí tấn công khôi lỗi.","anchor":"phi kiếm tự động xếp thành một thế trận cổ quái phía trên đỉnh đầu"}]},"capNhatToi":"@c0967","nguon":["@c0967"]},{"id":"linh-van-thuat","name":"Linh văn thuật","cn":"","loai":"khac","loaiLabel":"Thuật pháp","phamCap":"khong-ro","hePhai":"Nam Cương Độc Thánh môn","soHuu":["Nam Cương Độc Thánh môn"],"blurb":"Thuật pháp nổi danh của Nam Cương Độc Thánh môn, được Khô Trúc nhắc tới khi thấy ký hiệu đủ màu trên mặt khôi lỗi. Khôi lỗi phủ nhận có liên quan, nhưng Khô Trúc vẫn bán tín bán nghi.","detail":"Khi khôi lỗi hiện ký hiệu đủ màu và vòng bảo hộ ngũ sắc, Khô Trúc nghi đó là Linh văn thuật nổi danh của Độc Thánh môn ở Nam Cương. Sự nhầm lẫn này giúp bản chất khôi lỗi tiếp tục được che giấu.","dacDiem":"Bị liên hệ với các ký hiệu hiện trên mặt và thủ đoạn phòng hộ của khôi lỗi.","congNang":["Tạo dấu hiệu khiến Khô Trúc liên tưởng tới công pháp nổi danh của Độc Thánh môn @c0967"],"tabs":{"tienTrinh":[{"chuong":"@c0967","loai":"nhắc tới","importance":"normal","giaiDoan":"Khô Trúc nghi ngờ khôi lỗi","text":"Khô Trúc nghi khôi lỗi dùng Linh văn thuật của Nam Cương Độc Thánh môn nhưng bị phủ nhận.","anchor":"Công pháp của đạo hữu hình như là linh văn thuật nổi danh của độc Thánh môn"}]},"capNhatToi":"@c0967","nguon":["@c0967"]},{"id":"kiem-luan","name":"Kiếm luân","cn":"","loai":"than-thong","loaiLabel":"Thần thông kiếm trận","phamCap":"Không rõ","hePhai":"Khô Trúc đảo","soHuu":["Khô Trúc lão nhân"],"blurb":"Thần thông biến hóa từ kiếm trận của Khô Trúc lão nhân, gom phi kiếm thành kiếm luân lớn để phát động công kích tập trung.","detail":"Khi Khô Trúc lão nhân thúc kiếm trận, phi kiếm hội tụ thành kiếm luân đường kính lớn trên không, xoay nhanh rồi bắn cột sáng xanh biếc làm quang thuẫn của khôi lỗi lõm sâu. Đòn này vẫn bị cương thuẫn hóa giải khi khôi lỗi thu quang thuẫn và phản xạ luồng sáng.","congNang":["Tụ phi kiếm thành kiếm luân, phóng cột sáng xanh biếc công kích tập trung @c0968"],"uyLuc":"Có thể ép lõm quang thuẫn của khôi lỗi nhưng chưa phá được cương thuẫn.","nguoiTu":[{"ten":"Khô Trúc lão nhân","tuChuong":"@c0968","tangDatToi":"Thi triển trong kiếm trận","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0968","loai":"thi triển","importance":"normal","giaiDoan":"Công kích khôi lỗi","text":"Khô Trúc lão nhân dùng kiếm trận hóa thành kiếm luân, phóng cột sáng xanh biếc ép lõm quang thuẫn nhưng bị cương thuẫn phản xạ.","anchor":"Một kiếm luân đường kính trượng xuất hiện trên trời cao"}]},"capNhatToi":"@c0968","nguon":["@c0968"]},{"id":"dai-dien-bao-kinh","name":"Đại diễn bảo kinh","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp và bí thuật truyền thừa","phamCap":"truyền thừa khôi lỗi thuật của Đại Diễn Thần Quân","hePhai":"Khôi lỗi thuật","soHuu":["Đại Diễn Thần Quân","Hàn Lập"],"blurb":"Bộ kinh do Đại Diễn Thần Quân khắc trong ngọc giản, gom công pháp, bí thuật, kiến thức và kinh nghiệm cả đời. Đây là y bát chân chính để Hàn Lập truyền lại cho đệ tử tương lai.","detail":"Đại Diễn Thần Quân cho biết toàn bộ tâm huyết cả đời của lão đã được khắc thành Đại diễn bảo kinh và cất trong ngọc giản tại động phúc thiên trung. Bộ kinh được giao theo di nguyện đoạt lại Thiên trúc giáo, nhằm giúp đệ tử tương lai của Hàn Lập kế thừa khôi lỗi thuật và chấp chưởng giáo này.","nguonGoc":"Đại Diễn Thần Quân","congNang":["Truyền thừa công pháp, bí thuật, kiến thức và kinh nghiệm khôi lỗi thuật của Đại Diễn Thần Quân @c0969","Ghi chép tri thức về thi sát khí và đặc tính của Sát hồn ti @c0982"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0969","tangDatToi":"nhớ ghi chép thi sát khí","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện truyền thừa","text":"Đại Diễn Thần Quân tiết lộ Đại diễn bảo kinh là nơi lưu toàn bộ tâm huyết cả đời của lão trong ngọc giản.","anchor":"Tất cả đều khắc thành một bộ gọi là ‘ Đại diễn bảo kinh ’ lưu giữ trong ngọc giản"},{"chuong":"@c0982","loai":"nhắc tới","importance":"normal","giaiDoan":"Ghi chép thi sát khí","text":"Hàn Lập nhớ trong Đại Diễn Bảo Kinh có nhắc tới thi sát khí, từ đó nhận ra bản chất khó đối phó của Sát hồn ti.","anchor":"thấy trong Đại Diễn Bảo Kinh có nhắc tới vật ấy"}]},"capNhatToi":"@c0969","nguon":["@c0969","@c0982"],"trangThai":"được nhắc tới"},{"id":"phong-hon-chu","name":"Phong hồn chú","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Chú thuật phong hồn","phamCap":"không rõ","hePhai":"Âm La tông","soHuu":["Âm La tông","Kiền lão ma","Hàn Lập"],"blurb":"Phong hồn chú là chú thuật mà Hàn Lập cần tìm phương pháp giải trừ. Hắn xác định phải đoạt cách giải từ Âm La tông trong các mục tiêu còn lại ở Đại Tấn.","detail":"Khi tổng kết các việc chưa hoàn thành, Hàn Lập nhắc rõ một mục tiêu là đoạt được phương pháp giải trừ Phong hồn chú từ Âm La tông. Chương này chưa nêu chi tiết cách thi triển, chỉ xác định đây là chú thuật cần giải.","congNang":["Cần phương pháp giải trừ từ Âm La tông @c0969","Cần pháp quyết riêng để giải chú, khiến Hàn Lập vẫn phải tính kế Kiền lão ma @c1001"],"tabs":{"tienTrinh":[{"chuong":"@c0969","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu giải chú","text":"Hàn Lập xác định phải đoạt phương pháp giải trừ Phong hồn chú từ Âm La tông.","anchor":"từ trong Âm la tông đoạt được phương pháp giải trừ phong hồn chú"},{"chuong":"@c1001","loai":"nhắc tới","importance":"normal","giaiDoan":"Tìm pháp quyết giải chú","text":"Hàn Lập tạm bỏ lỡ cơ hội động thủ với Kiền lão ma để mưu đồ pháp quyết giải Phong Hồn chú.","anchor":"mưu đồ của với phong hồn chú giải chú pháp quyết"}]},"capNhatToi":"@c0969","nguon":["@c0969","@c1001"]},{"id":"cong-phap-nam-cuong-am-doc","name":"Công pháp Nam Cương âm độc","cn":"","loai":"cong-phap","loaiLabel":"Công pháp khu vực","phamCap":"không rõ","hePhai":"Nam Cương","soHuu":["Các tông môn Nam Cương"],"blurb":"Hệ công pháp của các tông môn Nam Cương thiên về âm độc, dụng độc, côn trùng thuật, tà thuật và bùa chú. Chương nhấn mạnh hệ này tự thành một mạch, khiến tu sĩ đồng cấp khó phòng bị khi đấu pháp.","detail":"Công pháp Nam Cương được giới thiệu như hệ pháp môn đặc thù của khu vực, khác với lối tu luyện phổ biến trong tu tiên giới Đại Tấn. Các thủ đoạn liên quan độc, côn trùng, tà thuật và bùa chú khiến Nam Cương trở thành vùng khó bị thế lực ngoài thâm nhập.","thuocTinh":"Âm độc, độc thuật, côn trùng thuật, tà thuật, bùa chú","dacDiem":"Tự thành hệ tại Nam Cương và nổi tiếng khó phòng bị trong đấu pháp đồng cấp.","congNang":["Hỗ trợ các thủ đoạn dùng độc, côn trùng, tà thuật và bùa chú của tu sĩ Nam Cương @c0970"],"nguon":["@c0970"],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu hệ pháp môn Nam Cương","text":"Chương xác lập công pháp của các tông môn Nam Cương thiên về âm độc và nhiều thủ đoạn khó phòng bị.","anchor":"Những tông môn này tu luyện công pháp đại đô thị tu tiên giới, hiếm thấy âm độc pháp môn"}]},"capNhatToi":"@c0970"},{"id":"khinh-than-thuat","name":"Khinh thân thuật","cn":"","loai":"khac","loaiLabel":"Thuật pháp di chuyển","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Mấy đồng đạo đi cùng Vương sư tỷ"],"blurb":"Khinh thân thuật được nhóm tu sĩ cấp thấp thi triển khi chạy trốn biến dị Thiết Vĩ Hạt trong chướng khí Song Hạt Sơn. Đây là thuật pháp hỗ trợ di chuyển nhanh ở cấp thấp.","detail":"Trong cảnh nhóm Vương sư tỷ bị biến dị Thiết Vĩ Hạt truy đuổi, các tu sĩ dùng khinh thân thuật để gấp rút bỏ chạy. Chương chỉ nêu tác dụng di chuyển, chưa hé lộ nguồn gốc hay cấp bậc.","congNang":["Giúp tu sĩ cấp thấp di chuyển và chạy trốn nhanh trong địa hình núi chướng khí @c0970"],"nguon":["@c0970"],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"thi triển","importance":"normal","giaiDoan":"Chạy trốn độc hạt","text":"Nhóm tu sĩ cấp thấp thi triển khinh thân thuật để chạy khỏi biến dị Thiết Vĩ Hạt.","anchor":"những người này mũi chân chĩa xuống đất đang gấp rút thi triển khinh thân thuật"}]},"capNhatToi":"@c0970"},{"id":"quang-thu-mau-xanh","name":"Quang thủ màu xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông bắt giữ","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Quang thủ màu xanh là thủ đoạn Hàn Lập dùng để bắt sống biến dị Thiết Vĩ Hạt. Bàn tay ánh sáng từ hư không chụp xuống, giam con độc hạt cấp hai khiến nó không nhúc nhích.","detail":"Khi cứu Vương sư tỷ, Hàn Lập phóng ra một bàn tay ánh sáng màu xanh chụp thẳng xuống biến dị Thiết Vĩ Hạt. Thủ đoạn này thể hiện khả năng bắt giữ nhanh và khống chế yêu thú cấp thấp trong phạm vi thần thông của hắn.","congNang":["Chụp bắt và khống chế biến dị Thiết Vĩ Hạt cấp hai @c0970"],"nguon":["@c0970"],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"thi triển","importance":"normal","giaiDoan":"Bắt biến dị Thiết Vĩ Hạt","text":"Hàn Lập dùng quang thủ màu xanh chụp bắt biến dị Thiết Vĩ Hạt đang truy đuổi nhóm Vương sư tỷ.","anchor":"một quang thủ màu xanh hiện lên hung hăng chụp xuống phía dưới"}]},"capNhatToi":"@c0970"},{"id":"thanh-ha-trong-tay-ao-han-lap","name":"Thanh hà trong tay áo Hàn Lập","cn":"","loai":"than-thong","loaiLabel":"Thần thông linh quang","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thanh hà trong tay áo là luồng hào quang màu xanh Hàn Lập phóng ra để quét chướng khí và đẩy bay tu sĩ. Trong chương, thủ đoạn này vừa mở tầm nhìn trong chướng khí vừa dùng để xua nhóm tu sĩ địa phương khỏi đỉnh núi.","detail":"Tại Song Hạt Sơn, Hàn Lập phóng thanh hà từ tay áo để quét sạch chướng khí quanh mình, sau đó dùng hào quang cuồn cuộn đẩy bảy tám tu sĩ địa phương văng xa. Chương cho thấy đây là thủ đoạn linh quang có tác dụng dọn chướng khí và áp chế tu sĩ cấp thấp.","congNang":["Quét sạch chướng khí quanh Hàn Lập @c0970","Đẩy bay nhóm tu sĩ địa phương trên đỉnh Song Hạt Sơn @c0970"],"nguon":["@c0970"],"tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"thi triển","importance":"normal","giaiDoan":"Quét chướng khí và đuổi người","text":"Hàn Lập dùng thanh hà từ tay áo quét sạch chướng khí và về sau dùng hào quang này đẩy nhóm tu sĩ địa phương khỏi đỉnh núi.","anchor":"thanh hà từ trong tay áo bay cuộn ra, hào quang nơi đi qua nơi nào thì chướng khí lập tức bị quét sạch"}]},"capNhatToi":"@c0970"},{"id":"tich-ta-than-loi","name":"Tích tà thần lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi điện","soHuu":["Hàn Lập"],"blurb":"Tích tà thần lôi là thần thông lôi điện của Hàn Lập, được dùng để dẫn và thu thiên lôi vào bình ngọc.","detail":"Trong chương này, Hàn Lập hóa Tích tà thần lôi thành kim hồ và điện mâu để hấp dẫn các đạo hồ quang bạc từ bầu trời, đưa lôi điện vào bình ngọc đặc chế. Thần thông này giúp hắn thu liên tiếp nhiều bình thiên lôi phục vụ việc chuyển hóa Lôi Hỏa luyện chế.","congNang":["Dẫn thiên lôi nhập bình ngọc @c0971"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0971","denChuong":"","cachCoDuoc":"Đã sở hữu từ trước, chương này dùng để thu thiên lôi.","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0971","loai":"thi triển","importance":"normal","giaiDoan":"Thu thiên lôi","text":"Hàn Lập dùng Tích tà thần lôi để dẫn và thu các đạo hồ quang bạc vào bình ngọc.","anchor":"lại bị Tích tà thần lôi dễ dàng thu vào bên trong bình ngọc"}]},"capNhatToi":"@c0971","nguon":["@c0971"]},{"id":"tu-linh-phap-tran","name":"Tụ linh pháp trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Trận pháp tụ linh dẫn lôi","soHuu":["Hàn Lập"],"blurb":"Tụ linh pháp trận là trận pháp Hàn Lập bố trí bằng nhiều pháp kỳ trên ngọn núi cao nhất để dẫn lôi điện vùng trời xung quanh.","detail":"Trận có đường kính hơn mười trượng, được Hàn Lập lập ra để hấp dẫn linh khí và lôi điện trong cơn mưa, khiến các đạo hồ quang liên tiếp rơi về vị trí bình ngọc thu lôi.","congNang":["Dẫn lôi điện và tụ linh khí trong phạm vi trận @c0971"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0971","denChuong":"","cachCoDuoc":"Tự bố trí bằng pháp kỳ trên ngọn núi cao nhất.","trangThai":"tam-thoi"}],"tabs":{"tienTrinh":[{"chuong":"@c0971","loai":"xuất hiện","importance":"normal","giaiDoan":"Lập trận thu lôi","text":"Hàn Lập dùng pháp kỳ bố trí tụ linh pháp trận đường kính hơn mười trượng để hấp dẫn lôi điện tới vị trí thu lôi.","anchor":"một cái tụ linh pháp trận đường kính hơn mười trượng dần dần hình thành"}]},"capNhatToi":"@c0971","nguon":["@c0971"]},{"id":"cam-che-u-hoa-xanh-tham","name":"Cấm chế u hỏa xanh thẫm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Cửu U tông","soHuu":["Lão giả họ Phú"],"blurb":"Cấm chế do lão giả họ Phú lập trước khi bàn việc Bồi Anh đan. Hơn mười đạo u hỏa xanh thẫm nổ thành sương mù rồi tạo dao động mỏng quanh khu vực.","detail":"Lão giả họ Phú phóng hơn mười đạo hỏa quang xanh thẫm để dựng một lớp cấm chế mỏng, dùng che chắn cuộc bàn bạc về Bồi Anh đan, phối phương và Âm Chi Mã huyết nhục.","dinhDanh":"goc","congNang":["Che chắn và giữ kín cuộc bàn bạc về Bồi Anh đan @c0972"],"chuHienThoi":"Lão giả họ Phú","trangThai":"đã thi triển @c0972","capNhatToi":"@c0972","tabs":{"tienTrinh":[{"chuong":"@c0972","loai":"xuất hiện","importance":"normal","giaiDoan":"Lập cấm chế trước khi nói bí mật","text":"Lão giả họ Phú phóng u hỏa xanh thẫm, tạo cấm chế mỏng quanh nhóm tu sĩ trước khi tiết lộ kế hoạch Bồi Anh đan.","anchor":"sau đó phóng ra hơn mười đạo hỏa quang mà xanh thẫm"}]},"nguon":["@c0972"]},{"id":"lam-quang-tieu-ky-phap-quyet","name":"Lam quang tiêu ký pháp quyết","cn":"","aliases":[],"loai":"khac","loaiLabel":"Ấn ký pháp thuật","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Lão giả họ Phú"],"blurb":"Pháp quyết tiêu ký do lão giả họ Phú thi triển lên Hàn Lập. Tiêu ký này được mô tả là ấn ký bình thường và sẽ tự biến mất sau nửa năm nếu Hàn Lập không rời Nam Cương.","detail":"Lão giả họ Phú kết quyết niệm chú, bắn lam quang vào người Hàn Lập để lưu tiêu ký tạm thời. Hàn Lập kiểm tra trước khi tiếp nhận và nhận thấy đây chỉ là loại ấn ký bình thường.","congNang":["Lưu tiêu ký tạm thời trên mục tiêu trong nửa năm nếu mục tiêu không rời Nam Cương @c0974"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0974","loai":"thi triển","importance":"normal","giaiDoan":"Đặt tiêu ký lên Hàn Lập","text":"Lão giả họ Phú thi triển pháp quyết lam quang để lưu tiêu ký trên người Hàn Lập trong nửa năm.","anchor":"một tay kết một đạo pháp quyết, trong miệng lẩm nhẩm chú ngữ"}]},"nguon":["@c0974"]},{"id":"cam-che-cam-khong-van-doc-coc","name":"Cấm chế cấm không Vạn Độc cốc","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Cấm chế thượng cổ","hePhai":"","soHuu":[],"blurb":"Cấm chế trong Vạn Độc cốc khiến tu sĩ không thể bay qua khu vực độc vụ.","detail":"Vạn Độc cốc có cấm chế thượng cổ và cấm không, buộc nhóm Hàn Lập phải trực tiếp đi bộ vào thay vì dùng độn quang vượt qua độc vụ.","congNang":["Cấm bay trong phạm vi Vạn Độc cốc, buộc người vào cốc phải đi bộ qua độc vụ @c0975"],"dinhDanh":"goc","trangThai":"đang tồn tại","capNhatToi":"@c0975","tabs":{"tienTrinh":[{"chuong":"@c0975","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ cấm chế trong Vạn Độc cốc","text":"Đại hán họ Nguyên nói Vạn Độc cốc có cấm chế cấm không nên cả nhóm chỉ có thể trực tiếp đi vào.","anchor":"lại có cấm chế cấm không, chúng ta chỉ có cách từ trực tiếp đi vào"}]},"nguon":["@c0975"]},{"id":"hoa-thuat-khong-che-hoa-xa","name":"Hỏa thuật khống chế hỏa xà","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"hỏa thuật","soHuu":["Hàn Lập"],"blurb":"Pháp thuật Hàn Lập dùng để biến hỏa cầu thành hỏa xà, thiêu sạch độc trùng trong Vạn Độc cốc.","detail":"Hàn Lập phóng hơn mười hỏa cầu rồi khống chế chúng hóa thành hỏa xà sống động, dùng để đốt sạch độc trùng mở đường. Màn thi triển khiến người đi cùng nhận xét khả năng khống chế pháp thuật của hắn đạt mức xuất thần nhập hóa.","congNang":["Đốt độc trùng và khống chế hỏa cầu thành hỏa xà trong Vạn Độc cốc @c0976"],"uyLuc":"Có thể nhanh chóng thiêu sạch độc trùng chắn đường trong Vạn Độc cốc.","dacDiem":"Thể hiện độ tinh tế cao trong việc điều khiển hỏa thuật.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0976","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0976","loai":"thi triển","importance":"normal","giaiDoan":"Đốt độc trùng","text":"Hàn Lập thi triển hỏa thuật, khiến hơn mười hỏa cầu hóa thành hỏa xà để thiêu sạch độc trùng.","anchor":"mấy hỏa cầu này không nổ tung mà lại hóa thành hơn mười con hỏa xà"}]},"capNhatToi":"@c0976","nguon":["@c0976"]},{"id":"kinh-phach-am-phong","name":"Kinh Phách âm phong","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hiểm tượng","phamCap":"không rõ","hePhai":"âm phong","soHuu":[],"blurb":"Loại âm phong nguy hiểm trong Âm Dương Quật, được lão giả họ Phú cảnh báo có thể uy hiếp tu sĩ Nguyên Anh kỳ nếu không phòng bị.","detail":"Kinh Phách âm phong xuất hiện khi vào sâu trong Âm Dương Quật. Theo lão giả họ Phú, loại âm phong này lớn nhỏ không đồng đều, kỳ dị và khiến tu sĩ Nguyên Anh kỳ cũng khó chống đỡ lâu nếu không có bảo vật phòng hộ.","congNang":["Uy hiếp thần hồn và thân thể tu sĩ khi vào sâu Âm Dương Quật @c0976"],"uyLuc":"Tu sĩ Nguyên Anh kỳ nếu không phòng bị cũng khó chống đỡ lâu.","dacDiem":"Ẩn trong tầng sâu Âm Dương Quật, khác với âm phong bên ngoài.","tabs":{"tienTrinh":[{"chuong":"@c0976","loai":"nhắc tới","importance":"normal","giaiDoan":"Cảnh báo trong quật","text":"Lão giả họ Phú cảnh báo vào sâu Âm Dương Quật sẽ gặp Kinh Phách âm phong, loại âm phong đủ gây nguy hiểm cho Nguyên Anh kỳ nếu không phòng bị.","anchor":"cho dù là tu sĩ Nguyên Anh kỳ cũng vô pháp chống đỡ được lâu"}]},"capNhatToi":"@c0976","nguon":["@c0976"]},{"id":"phap-tran-pha-cam-diep-gia","name":"Pháp trận phá cấm Diệp gia","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"trận pháp Diệp gia","soHuu":["Diệp gia"],"blurb":"Trận pháp Diệp gia nghiên cứu hơn trăm năm nhằm phá thượng cổ cấm chế quanh Côn Ngô sơn.","detail":"Diệp gia dựa trên nghiên cứu lâu dài về thượng cổ cấm chế để tìm ra cách mượn thiên địa chi lực, dùng trận phá trận. Pháp trận này là khâu trọng yếu trong kế hoạch mở phong ấn Côn Ngô sơn.","nguonGoc":"Do các trận pháp đại sư của Diệp gia nghiên cứu và bố trí để phá cấm Côn Ngô sơn.","congNang":["Mượn thiên địa chi lực, dùng trận phá trận để giải thượng cổ cấm chế quanh Côn Ngô sơn @c0976"],"dacDiem":"Là kết quả sau hơn trăm năm nghiên cứu thượng cổ cấm chế.","tabs":{"tienTrinh":[{"chuong":"@c0976","loai":"xuất hiện","importance":"normal","giaiDoan":"Kế hoạch phá cấm","text":"Diệp gia hé lộ việc dùng pháp trận phá cấm để giải cấm chế thượng cổ quanh Côn Ngô sơn.","anchor":"mượn thiên địa chi lực, dùng trận phá trận"}]},"capNhatToi":"@c0976","nguon":["@c0976"]},{"id":"an-nac-phap-tran-sieu-cap","name":"Ẩn nặc pháp trận siêu cấp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"trận pháp Diệp gia","soHuu":["Diệp gia"],"blurb":"Pháp trận Diệp gia dự tính dùng để che giấu thanh thế khi phá cấm Côn Ngô sơn.","detail":"Ẩn nặc pháp trận siêu cấp được Diệp gia chuẩn bị nhằm che giấu toàn bộ động tĩnh phát sinh trong lúc phá cấm. Mục đích là ngăn tiếng động truyền ra ngoài và tránh kinh động các thế lực khác.","congNang":["Che giấu toàn bộ thanh thế lúc phá trận Côn Ngô sơn @c0976"],"dacDiem":"Được dùng phối hợp với kế hoạch phá thượng cổ cấm chế.","tabs":{"tienTrinh":[{"chuong":"@c0976","loai":"xuất hiện","importance":"normal","giaiDoan":"Che giấu phá trận","text":"Diệp gia dự tính phát động pháp trận ẩn nặc siêu cấp để giấu toàn bộ thanh thế khi phá cấm Côn Ngô sơn.","anchor":"đem toàn bộ thanh thế lúc phá trận giấu vào trong"}]},"capNhatToi":"@c0976","nguon":["@c0976"]},{"id":"thuat-an-nac","name":"Thuật ẩn nặc","cn":"","aliases":["thuật ẩn thân"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"khong-ro","hePhai":"","soHuu":["Âm Chi Mã"],"blurb":"Thuật che giấu tung tích được nhắc là năng lực của Âm Chi Mã.","detail":"Lão giả họ Phú cho rằng Âm Chi Mã am hiểu thuật ẩn nặc nên nhóm truy tìm trong Âm Dương Quật không thể dễ dàng phát hiện nó.","thuocTinh":"ẩn nặc","congNang":["Che giấu tung tích, khiến người truy tìm khó phát hiện @c0977"],"nguoiTu":[{"ten":"Âm Chi Mã","tuChuong":"@c0977","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0977","loai":"nhắc tới","importance":"normal","giaiDoan":"Năng lực của Âm Chi Mã","text":"Lão giả họ Phú nêu thuật ẩn nặc là lý do Âm Chi Mã khó bị phát hiện trong động quật.","anchor":"Âm Chi Mã lại am hiểu thuật ẩn nặc (ẩn thân) sao có thể để chúng ta dễ dàng phát hiện"}]},"capNhatToi":"@c0977","nguon":["@c0977"]},{"id":"tu-u-than-quang","name":"Tử U thần quang","cn":"","aliases":["thần quang hộ thể"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"","soHuu":["Lão giả họ Phú","Hàn Lập"],"blurb":"Tử U thần quang là lớp tử quang hộ thân được lão giả họ Phú tạm cấp cho đồng đội thông qua Tử U Châu.","detail":"Trong Âm Dương Quật, lão giả họ Phú dùng tinh huyết kích phát Tử U Châu để đưa Tử U thần quang vào người các tu sĩ khác. Dưới áp lực Kinh Phách âm phong, thần quang tạm thời này chỉ duy trì được bảy tám ngày.","thuocTinh":"hộ thân","congNang":["Giảm áp lực của Kinh Phách âm phong lên người được cấp thần quang @c0977","Hỗ trợ người mang đi sâu trong Âm Dương Quật và chống chịu âm phong @c0980"],"nguoiTu":[{"ten":"Lão giả họ Phú","tuChuong":"@c0977","tangDatToi":"","trangThai":"thi triển qua Tử U Châu"}],"tabs":{"tienTrinh":[{"chuong":"@c0977","loai":"thi triển","importance":"normal","giaiDoan":"Cấp thần quang tạm thời","text":"Lão giả họ Phú dùng tinh huyết và Tử U Châu đưa Tử U thần quang vào người đồng đội trước khi chia đường.","anchor":"dưới áp lực của Kinh Phách âm phong cũng chỉ có thể duy trì được bảy tám ngày"},{"chuong":"@c0980","loai":"nhắc tới","importance":"normal","giaiDoan":"Vào sâu phong huyệt","text":"Tử u thần quang giúp Hàn Lập tiếp tục đi sâu trong khu vực âm phong, nhưng không triệt tiêu hoàn toàn hao tổn pháp lực.","anchor":"Phải biết rằng nơi âm phong mãnh liệt, âm chi mã tuyệt không cách gì sinh tồn trong đó. Hơn nữa khi đi vào sâu trong phong huyệt, dù cho có thêm Tử u thần quang và pháp lực bản thân hao tổn gấp bội"}]},"capNhatToi":"@c0977","nguon":["@c0977","@c0980"]},{"id":"ta-thuat-te-song","name":"Tà thuật tế sống","cn":"","loai":"khac","loaiLabel":"Tà thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Tà thuật dùng người sống làm tế phẩm, được Hàn Lập nhận ra qua tình trạng thây khô và pháp trận trong nhũ động.","detail":"Trong nhũ động lục quang, Hàn Lập dựa vào thây khô bị xích, bụng bị rạch và dấu vết pháp trận để kết luận nạn nhân không chết bình thường mà bị người khác dùng tà thuật tế sống.","congNang":["Dùng người sống làm tế phẩm, liên quan trực tiếp đến thây khô bị xích trên thạch trụ trong nhũ động @c0978"],"tabs":{"tienTrinh":[{"chuong":"@c0978","loai":"xuất hiện","importance":"normal","giaiDoan":"nhận định nguyên nhân cái chết","text":"Hàn Lập nhận ra thây khô trong nhũ động là nạn nhân của tà thuật tế sống.","anchor":"mà là bị người khác dùng tà thuật tế sống"}]},"capNhatToi":"@c0978","nguon":["@c0978"]},{"id":"luyen-hon-tran","name":"Luyện hồn trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"cổ trận","hePhai":"không rõ","soHuu":[],"blurb":"Pháp trận cổ trong nhũ động lục quang, được Hàn Lập nhận định là một loại luyện hồn trận.","detail":"Sau khi bụi đất bị quét sạch, nhiều pháp trận hiện ra quanh thây khô. Hàn Lập cho rằng đây là luyện hồn trận rất cổ, thậm chí có khả năng được bố trí từ thời thượng cổ và xuất hiện trước thây khô rất lâu.","nguonGoc":"có thể được bố trí từ thời thượng cổ","dacDiem":"cổ xưa, có thể tồn tại trước cả thây khô bị xích trong nhũ động","congNang":["Liên quan đến việc luyện hồn và tà thuật tế sống tại thạch trụ trong nhũ động @c0978"],"tabs":{"tienTrinh":[{"chuong":"@c0978","loai":"xuất hiện","importance":"normal","giaiDoan":"cổ trận lộ diện","text":"Hàn Lập quan sát pháp trận sau khi bụi đất bị quét sạch và nhận định đó là luyện hồn trận cổ xưa.","anchor":"Pháp trận này là một loại luyện hồn trận"}]},"capNhatToi":"@c0978","nguon":["@c0978"]},{"id":"kim-ho","name":"Kim hồ","cn":"","loai":"than-thong","loaiLabel":"Lôi pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Đạo kim sắc lôi điện được Hàn Lập bắn ra từ đầu ngón tay để công kích thây khô trên thạch trụ.","detail":"Khi sắp rời nhũ động, Hàn Lập nảy sinh cảm giác bất ổn, quay lại nhìn thây khô rồi từ đầu ngón tay bắn một đạo kim hồ đánh về phía thây khô trên thạch trụ.","congNang":["Công kích mục tiêu bằng kim sắc lôi điện bắn ra từ đầu ngón tay @c0978"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0978","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0978","loai":"thi triển","importance":"normal","giaiDoan":"đánh thây khô nghi vấn","text":"Hàn Lập thi triển kim hồ đánh về phía thây khô sau khi cảm thấy bất ổn.","anchor":"một đạo kim hồ bắn ra đánh về hướng thây khô trên thạch trụ"}]},"capNhatToi":"@c0978","nguon":["@c0978"]},{"id":"quang-thu","name":"Quang thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Thần thông tạo bàn tay phát sáng từ trên không, được Hàn Lập dùng để chặn và nghiền nát Nghiệt viên.","detail":"Trong nhũ động, Hàn Lập vung chưởng khiến quang thủ xuất hiện trên không để chặn bóng đen đánh lén. Sau khi Bạch Dao Di đóng băng Nghiệt viên, chàng tiếp tục dùng quang thủ bóp nát khối băng chứa quỷ vật.","congNang":["Khống chế, chặn đòn và nghiền nát mục tiêu bằng bàn tay phát sáng từ trên không @c0978"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0978","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0978","loai":"thi triển","importance":"normal","giaiDoan":"chặn Nghiệt viên","text":"Hàn Lập dùng quang thủ để chặn bóng đen đánh lén và sau đó bóp nát Nghiệt viên đã bị đóng băng.","anchor":"trên bầu trời xuất hiện một quang thủ"}]},"capNhatToi":"@c0978","nguon":["@c0978"]},{"id":"thu-doan-hoi-sinh-thay-kho-cua-bong-den","name":"Thủ đoạn hồi sinh thây khô của bóng đen","cn":"","loai":"bi-thuat","loaiLabel":"Quỷ thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Bóng đen trong động quật dưới cột đá"],"blurb":"Quỷ thuật dùng tro bụi và hắc khí để tái tạo thây khô đã bị phá tan.","detail":"Bóng đen gom tro bụi thành bộ xương mờ ảo, phát ra âm thanh huyền ảo rồi phóng hắc khí, khiến một thây khô giống vật đã bị Hàn Lập phá tan xuất hiện trở lại.","thuocTinh":"quỷ dị, hắc khí","uyLuc":"Có thể tái tạo thây khô từ tro bụi trong thời gian ngắn.","dacDiem":"Đi kèm âm thanh huyền ảo và hắc khí bao phủ bộ xương mờ ảo.","congNang":["Tái tạo thây khô từ tro bụi @c0979"],"nguoiTu":[{"ten":"Bóng đen trong động quật dưới cột đá","tuChuong":"@c0979","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0979","loai":"thi triển","importance":"normal","giaiDoan":"Tái tạo thây khô","text":"Bóng đen dùng tro bụi, âm thanh huyền ảo và hắc khí để phục hồi thây khô trong động quật.","anchor":"từ trong miệng bóng đen phát ra một hồi âm thanh huyền ảo"}]},"capNhatToi":"@c0979","nguon":["@c0979"]},{"id":"hac-am-phong-giai-bang","name":"Hắc âm phong giải băng","cn":"","loai":"bi-thuat","loaiLabel":"Quỷ thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Thây khô được hồi sinh"],"blurb":"Quỷ thuật do thây khô phun ra để làm tan khối băng phong giữ nghiệt viên.","detail":"Thây khô được hồi sinh phun hắc âm phong vào khối băng ở lối vào, khiến băng tan nhanh đến mức mắt thường có thể thấy rõ và giải phóng nghiệt viên.","thuocTinh":"âm phong, hắc khí","uyLuc":"Làm tan băng phong nghiệt viên rất nhanh.","congNang":["Làm tan băng phong @c0979"],"nguoiTu":[{"ten":"Thây khô được hồi sinh","tuChuong":"@c0979","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0979","loai":"thi triển","importance":"normal","giaiDoan":"Giải phong nghiệt viên","text":"Thây khô phun hắc âm phong vào khối băng chứa nghiệt viên và làm nó tan ra.","anchor":"nhắm ngay khối băng có nghiệt viên nằm bên trong ở lối vào phun ra"}]},"capNhatToi":"@c0979","nguon":["@c0979"]},{"id":"ngu-tu-dong-tam-ma","name":"Ngũ tử đồng tâm ma","cn":"","aliases":["Năm bóng trắng","Ngũ tử đồng tâm","Ngũ ma đồng tử","hóa thân ma tử của Kiền lão ma"],"loai":"than-thong","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"Âm La tông","soHuu":["Thần bí tu sĩ họ Tông"],"blurb":"Ma công gồm năm bóng trắng do Đại trưởng lão Âm La tông điều khiển. Chúng có thể hóa khô lâu, xuyên qua phòng ngự, nhập thể và thôn phệ Nguyên Anh.","detail":"Trong trận diệt Hà gia, Ngũ tử đồng tâm ma bao vây trung niên hoàng bào tu sĩ, một bóng hóa bạch sắc khô lâu hút khô hoàng mãng, bốn bóng còn lại xuyên qua cự chuyên và lam hà cổ bảo rồi nhập thể giết đối thủ, thôn phệ sạch Nguyên Anh.","thuocTinh":"ma đạo, quỷ dị","uyLuc":"Một khi xuất thủ có thể khiến đối thủ thi cốt không còn và Nguyên Anh bị thôn phệ.","dacDiem":"Biểu hiện thành năm bóng trắng, có thể hóa khô lâu, tản ra rồi chui vào thân thể mục tiêu.","congNang":["Hóa bạch sắc khô lâu để trói và hút khô linh thú @c0979","Xuyên qua phòng ngự và cổ bảo để nhập thể @c0979","Thôn phệ Nguyên Anh đối thủ @c0979"],"nguoiTu":[{"ten":"Thần bí tu sĩ họ Tông","tuChuong":"@c0979","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0979","loai":"thi triển","importance":"normal","giaiDoan":"Diệt tu sĩ Hà gia","text":"Ngũ tử đồng tâm ma được Đại trưởng lão Âm La tông dùng để giết linh mãng, phá phòng ngự và thôn phệ Nguyên Anh trung niên hoàng bào Hà gia.","anchor":"Ngũ tử đồng tâm ma một khi đã xuất thủ chính là thi cốt đều không còn"}]},"capNhatToi":"@c0979","nguon":["@c0979"]},{"id":"bach-ti-cua-bach-sac-kho-lau","name":"Bạch ti của bạch sắc khô lâu","cn":"","loai":"than-thong","loaiLabel":"Ma thuật","phamCap":"không rõ","hePhai":"Âm La tông","soHuu":["Thần bí tu sĩ họ Tông"],"blurb":"Ma thuật do một bóng trắng của Ngũ tử đồng tâm ma hóa thành bạch sắc khô lâu thi triển.","detail":"Bạch sắc khô lâu phun ra một chùm bạch ti trói hoàng mãng, sau đó dẫn luồng sáng mờ dọc theo sợi tơ để hút sạch huyết nhục, khiến thân thể hoàng mãng khô quắt rồi bị nuốt xác.","thuocTinh":"ma đạo, bạch ti","uyLuc":"Trói buộc và hút khô huyết nhục linh thú trong chốc lát.","congNang":["Trói buộc mục tiêu bằng bạch ti @c0979","Hút khô huyết nhục qua luồng sáng mờ @c0979"],"nguoiTu":[{"ten":"Thần bí tu sĩ họ Tông","tuChuong":"@c0979","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0979","loai":"thi triển","importance":"normal","giaiDoan":"Giết hoàng mãng","text":"Bạch sắc khô lâu dùng bạch ti trói hoàng mãng rồi hút khô huyết nhục của nó.","anchor":"một chùm bạch ti từ trong miệng phun ra"}]},"capNhatToi":"@c0979","nguon":["@c0979"]},{"id":"cam-che-quang-sang-vang-cua-ha-gia","name":"Cấm chế quầng sáng vàng của Hà gia","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"Hà gia","soHuu":["Hà gia"],"blurb":"Cấm chế phòng hộ bao phủ hơn nửa thôn trang Hà gia trong trận bị Âm La tông vây công.","detail":"Cấm chế tạo thành quầng sáng vàng bao phủ hơn phân nửa thôn trang, được hơn mười hoàng bào tu sĩ dùng trận kỳ truyền linh lực gia cố nhưng cuối cùng bị gần trăm hắc bào tu sĩ Âm La tông công phá.","thuocTinh":"phòng hộ","uyLuc":"Có thể che chở thôn trang trước nhiều đợt công kích nhưng không chịu nổi cuộc vây công quy mô lớn.","congNang":["Phòng hộ hơn nửa thôn trang Hà gia @c0979"],"nguoiTu":[{"ten":"Hà gia","tuChuong":"@c0979","tangDatToi":"","trangThai":"bị phá"}],"tabs":{"tienTrinh":[{"chuong":"@c0979","loai":"thi triển","importance":"normal","giaiDoan":"Bị công phá","text":"Cấm chế quầng sáng vàng của Hà gia được duy trì bằng trận kỳ nhưng bị Âm La tông đánh vỡ trong cuộc vây diệt.","anchor":"quầng sáng này đang bao phủ hơn phân nửa thôn trang vào trong"}]},"capNhatToi":"@c0979","nguon":["@c0979"]},{"id":"ich-ta-than-loi","name":"Ích Tà thần lôi","cn":"益邪神雷","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập","Nhân hình khôi lỗi của Hàn Lập"],"blurb":"Thần lôi màu vàng chuyên khắc chế quỷ vật và vật âm tà, được Hàn Lập dùng để phá bướm khổng lồ do Hắc tinh thạch biến hóa.","detail":"Trong Đại Phong Huyệt, Ích Tà thần lôi đánh nát bướm khổng lồ sinh ra từ hắc mang của Hắc tinh thạch. Chương này nhấn mạnh sự khắc chế của thần lôi khiến đám bướm âm tà gần như không có sức chống cự.","uyLuc":"Khắc chế bướm khổng lồ âm tà do Hắc tinh thạch biến hóa.","congNang":["Phá diệt quỷ vật và huyễn vật âm tà trong Âm Dương Quật @c0980","Khắc chế ma công và uy hiếp nguyên anh Kiền lão ma @c1026","Hóa thành kim võng để chặn đường bỏ chạy @c1026","Ngưng thành kim sắc điện giao dài hơn hai mươi trượng @c1063","Hủy quang cầu ma khí tinh thuần ngưng tụ @c1063"],"nguon":["@c0980","@c1026","@c1063"],"tabs":{"tienTrinh":[{"chuong":"@c0980","loai":"thi triển","importance":"normal","giaiDoan":"Đại Phong Huyệt","text":"Hàn Lập dùng Ích Tà thần lôi phá bướm khổng lồ do Hắc tinh thạch hóa ra.","anchor":"Cho dù những con bướm không lồ có gì cổ quái đi nữa, nhưng bị Ích Tà thần lôi khắc chế, nên căn bản không có chút kháng cự nào cả."},{"chuong":"@c1026","loai":"thi triển","importance":"normal","giaiDoan":"Chặn nguyên anh Kiền lão ma","text":"Ích tà thần lôi được ẩn trong mũi tên xanh biếc của khôi lỗi và được Hàn Lập hóa thành kim võng để chặn nguyên anh Kiền lão ma.","anchor":"Trong đạo thuý mang đó lại ẩn chứa Ích tà thần lôi chuyên khắc chế ma công"},{"chuong":"@c1063","loai":"thi triển","importance":"major","giaiDoan":"Toàn lực kích phát lần đầu","text":"Hàn Lập kích phát toàn bộ Ích Tà Thần Lôi trong Thanh Trúc Phong Vân Kiếm, ngưng thành kim sắc điện giao dài hơn hai mươi trượng, đánh tan quang cầu ma khí. Linh Lung dung hợp nguyên thần Ngân Nguyệt mà cũng lần đầu thấy Ích Tà Thần Lôi phát toàn lực, kinh ngạc.","anchor":"hồ quang nháy mắt ngưng tụ thành hình, hoá thành một con kim sắc điện giao dài hơn hai mươi trượng"}]},"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1026","tangDatToi":"Toàn lực kích phát","trangThai":"dang-tu"},{"ten":"Nhân hình khôi lỗi của Hàn Lập","tuChuong":"@c1026","tangDatToi":"","trangThai":"được gắn trong mũi tên"}]},{"id":"han-lap-lam-quang-thi-luc","name":"Lam quang thị lực của Hàn Lập","cn":"","loai":"than-thong","loaiLabel":"Thần thông nhãn lực","phamCap":"khong-ro","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Lam quang thị lực giúp Hàn Lập nhìn xa qua âm phong trong thông đạo.","detail":"Hàn Lập dùng hai mắt lóe lam quang để thấy quỷ vật ngoài trăm trượng trong lúc những người khác bị âm phong che tầm nhìn, nhờ đó sớm phát hiện thi lang và Âm Chi Mã.","thuocTinh":"nhãn lực","uyLuc":"Có thể nhìn xuyên âm phong tới ngoài trăm trượng trong hoàn cảnh thông đạo bị che phủ.","dacDiem":"Biểu hiện bằng lam quang thoáng hiện trong hai mắt.","congNang":["Nhìn xuyên âm phong và phát hiện mục tiêu ở xa @c0981"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0981","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0981","loai":"thi triển","importance":"normal","giaiDoan":"Phát hiện thi lang","text":"Hàn Lập dùng lam quang thị lực nhìn xuyên âm phong, thấy trước thi lang cùng Âm Chi Mã ở ngoài trăm trượng.","anchor":"hai mắt Hàn Lập sớm đã thoáng hiện lam quang, thoáng cái thấy được ngoài trăm trượng có một con quỷ vật"}]},"capNhatToi":"@c0981","nguon":["@c0981"]},{"id":"thi-hoa-xanh-biec-cua-thi-lang","name":"Thi hỏa xanh biếc của thi lang","cn":"","loai":"than-thong","loaiLabel":"Thần thông quỷ hỏa","phamCap":"khong-ro","hePhai":"","soHuu":["Thi lang"],"blurb":"Thi hỏa xanh biếc là quỷ hỏa do thi lang phun ra, có sức ăn mòn và ngăn pháp bảo mạnh.","detail":"Thi lang phun lửa xanh biếc làm vách băng bị ăn mòn, sau đó hóa thành sóng lửa ngăn pháp bảo của năm tu sĩ Nguyên Anh và thiêu bò cạp có cánh thành khói xanh.","thuocTinh":"quỷ hỏa","uyLuc":"Ăn mòn băng, chặn nhiều pháp bảo Nguyên Anh và không lép vế trước băng hệ thần thông khắc chế.","dacDiem":"Lửa màu xanh biếc, có thể phun thành sóng hỏa diễm để phòng thủ diện rộng.","congNang":["Ăn mòn vách băng trong thông đạo @c0981","Ngăn phi kiếm, lưới tơ tằm và nhiều pháp bảo cùng lúc @c0981","Thiêu bò cạp có cánh thành khói xanh @c0981"],"nguoiTu":[{"ten":"Thi lang","tuChuong":"@c0981","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0981","loai":"thi triển","importance":"normal","giaiDoan":"Chặn pháp bảo Nguyên Anh","text":"Thi lang phun thi hỏa xanh biếc, vừa ăn mòn băng vừa chặn toàn bộ đợt pháp bảo đầu của năm tu sĩ.","anchor":"một đoàn thi hỏa màu xanh biếc thỉnh thoảng phun ra"}]},"capNhatToi":"@c0981","nguon":["@c0981"]},{"id":"bach-dao-di-han-he-than-thong","name":"Hàn hệ thần thông của Bạch Dao Di","cn":"","loai":"than-thong","loaiLabel":"Thần thông hàn hệ","phamCap":"khong-ro","hePhai":"Bắc Dạ Tiểu Cực Cung","soHuu":["Bạch Dao Di"],"blurb":"Hàn hệ thần thông của Bạch Dao Di khiến hàn khí trắng bùng phát, phối hợp với pháp bảo băng thuộc tính.","detail":"Bạch Dao Di vận hàn khí trắng khiến nhiệt độ xung quanh giảm mạnh, rồi phối hợp quạt băng để đối kháng thi hỏa xanh biếc của thi lang.","thuocTinh":"hàn thuộc tính","uyLuc":"Làm nhiệt độ xung quanh chợt giảm mạnh và gia trì cho quạt băng.","dacDiem":"Phù hợp truyền thừa hàn thuộc tính của Bắc Dạ Tiểu Cực Cung.","congNang":["Phóng hàn khí trắng làm giảm nhiệt độ xung quanh @c0981","Gia trì quạt băng để đối kháng thi hỏa @c0981"],"nguoiTu":[{"ten":"Bạch Dao Di","tuChuong":"@c0981","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0981","loai":"thi triển","importance":"normal","giaiDoan":"Gia trì quạt băng","text":"Bạch Dao Di vận hàn khí trắng trước khi phun quạt băng ra đối kháng thi hỏa.","anchor":"trên người chợt linh quang đại phóng, một tầng hàn khí màu trắng toát ra ngoài"}]},"capNhatToi":"@c0981","nguon":["@c0981"]},{"id":"cot-tuyet-phong","name":"Cốt tuyết phong","cn":"","loai":"than-thong","loaiLabel":"Thần thông từ quạt băng","phamCap":"khong-ro","hePhai":"Bắc Dạ Tiểu Cực Cung","soHuu":["Bạch Dao Di"],"blurb":"Cốt tuyết phong là luồng gió trắng sắc lạnh do quạt băng của Bạch Dao Di tạo ra.","detail":"Trong trận với thi lang, Bạch Dao Di không quạt hoàng phong như trước mà tạo cốt tuyết phong bay toán loạn để trực tiếp đối kháng thi hỏa xanh biếc.","thuocTinh":"băng phong","uyLuc":"Có thể đối đầu thi hỏa, dù chưa áp đảo được thi hỏa biến dị của thi lang.","dacDiem":"Gió trắng lạnh buốt phát ra từ quạt băng.","congNang":["Đối kháng thi hỏa bằng băng phong @c0981"],"nguoiTu":[{"ten":"Bạch Dao Di","tuChuong":"@c0981","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0981","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng thi hỏa","text":"Bạch Dao Di dùng quạt băng tạo cốt tuyết phong thổi thẳng vào thi hỏa xanh biếc.","anchor":"mà là thứ cốt tuyết phong bay toán loạn hướng đối diện thổi tới"}]},"capNhatToi":"@c0981","nguon":["@c0981"]},{"id":"luc-mang-tu-long-lung-thi-lang","name":"Lục mang từ lông lưng thi lang","cn":"","loai":"than-thong","loaiLabel":"Thần thông quỷ vật","phamCap":"khong-ro","hePhai":"","soHuu":["Thi lang"],"blurb":"Lục mang từ lông lưng thi lang là đòn phản kích diện rộng dùng để trì hoãn đối thủ.","detail":"Khi bị nhiều pháp bảo áp chế, thi lang thu nhỏ thân hình, dựng lông lưng và bắn ra một chùm lục mang dày đặc bao vây năm tu sĩ, nhờ đó thừa cơ bỏ chạy.","thuocTinh":"quỷ vật","uyLuc":"Có thể bao vây cả năm tu sĩ trong khoảnh khắc và làm thế công của họ chậm lại.","dacDiem":"Phát ra từ lông lưng dựng đứng của thi lang.","congNang":["Phản kích diện rộng để trì hoãn đối thủ @c0981"],"nguoiTu":[{"ten":"Thi lang","tuChuong":"@c0981","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0981","loai":"thi triển","importance":"normal","giaiDoan":"Mở đường bỏ chạy","text":"Thi lang bắn lục mang dày đặc từ lông lưng để buộc năm tu sĩ phòng thủ rồi quay đầu bỏ chạy.","anchor":"một chùm lục mang dày đặc bắn nhanh ra, bao vây tất cả năm người lại"}]},"capNhatToi":"@c0981","nguon":["@c0981"]},{"id":"sat-hon-ti","name":"Sát hồn ti","aliases":["Hồn ti","Sát hồn ti"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông quỷ đạo","phamCap":"cao cấp","hePhai":"Quỷ đạo","soHuu":["tam thi","Ngân Sí Dạ Xoa"],"blurb":"Sát hồn ti là sợi tơ màu tro do thi sát khí ngưng thành, lần đầu lộ rõ uy lực khi ba thây khô vây công Hàn Lập và Hắc y mỹ phụ. Nó có thể hấp thu linh lực, quấn và làm ô uế pháp bảo, đồng thời tái ngưng kết sau khi bị đánh tan.","detail":"Sát hồn ti xuyên thủng hỏa cầu, làm kiếm khí đỏ biến mất, quấn chặt cự kiếm màu hồng của Hắc y mỹ phụ và khiến pháp bảo bị u quang ô uế. Tịch tà thần lôi có thể đánh đứt sợi tơ trong chốc lát, nhưng thi sát khí vẫn có thể ngưng tụ trở lại, khiến đối thủ khó diệt tận gốc.","thuocTinh":"thi sát khí, quỷ đạo","uyLuc":"Xuyên pháp thuật, hấp thu linh lực, ô uế pháp bảo và tái ngưng kết sau khi bị đánh tan.","dacDiem":"Bị công pháp Phật môn và Tịch tà thần lôi tạm thời khắc chế nhưng chưa bị diệt tận gốc.","congNang":["Hấp thu linh lực và hỏa quang của pháp thuật đối phương @c0982","Quấn giữ và làm ô uế pháp bảo @c0982","Sau khi bị Tịch tà thần lôi đánh tan có thể ngưng kết trở lại @c0982","Tấn công và áp chế đối thủ bằng vô số sợi tơ khó phòng."],"nguoiTu":[{"ten":"tam thi","tuChuong":"@c0982","tangDatToi":"thi triển Sát hồn ti","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0982","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ tên và uy lực","text":"Sát hồn ti được Hắc y mỹ phụ nhận ra khi ba thây khô dùng sợi tơ màu tro vây công, thể hiện khả năng xuyên pháp thuật, hấp thu linh lực, ô uế pháp bảo và tái ngưng kết.","anchor":"Sát hồn ti! Mấy thứ này đều không phải thi khí, là thi sát khí"},{"chuong":"@c1047","loai":"thi triển","importance":"normal","giaiDoan":"Phục kích ngoài chướng bích","text":"Ngân Sí Dạ Xoa dùng vô số Sát Hồn Ti công kích Lâm Ngân Bình giữa không trung.","anchor":"đang bị Ngân Sí Dạ Xoa thả ra vô số Sát Hồn Ti công kích"}]},"trangThai":"đang xuất hiện","capNhatToi":"@c0982","nguon":["@c0982","@c1047"]},{"id":"thi-sat-khi","name":"Thi sát khí","cn":"","loai":"than-thong","loaiLabel":"Căn nguyên quỷ đạo","phamCap":"cao cấp","hePhai":"Quỷ đạo","soHuu":["tam thi"],"blurb":"Thi sát khí là căn nguyên tạo nên Sát hồn ti, được Hàn Lập nhớ lại từ ghi chép trong Đại Diễn Bảo Kinh. Nó hình thành cực khó, có khả năng bất tử bất diệt, hấp thu linh khí ngũ hành và chuyên ô uế pháp bảo pháp khí.","detail":"Trong chương này, thi sát khí được giải thích là sát khí người chết kết hợp thi khí, khó thành hình nhưng khi đã thành thì cực kỳ khó đối phó. Sát hồn ti do ba thây khô phun ra chính là biểu hiện trực tiếp của loại thi sát khí này.","thuocTinh":"thi khí, sát khí, quỷ đạo","uyLuc":"Có khả năng bất tử bất diệt, hấp thu linh khí ngũ hành và ô uế pháp bảo pháp khí.","dacDiem":"Hình thành rất khó nhưng khi đã ngưng thành thì khó diệt tận gốc.","congNang":["Tạo thành Sát hồn ti để công kích và vây khốn đối thủ @c0982","Hấp thu linh khí ngũ hành @c0982","Làm ô uế pháp bảo pháp khí @c0982"],"tabs":{"tienTrinh":[{"chuong":"@c0982","loai":"xuất hiện","importance":"major","giaiDoan":"Được giải thích căn nguyên","text":"Hắc y mỹ phụ xác nhận Sát hồn ti là thi sát khí, còn Hàn Lập nhớ lại ghi chép trong Đại Diễn Bảo Kinh về khả năng bất tử bất diệt, hấp thu ngũ hành và ô uế pháp bảo của nó.","anchor":"có khả năng bất tử bất diệt, hơn nữa còn có thể hấp thu linh khí ngũ hành"}]},"trangThai":"đang xuất hiện","capNhatToi":"@c0982","nguon":["@c0982"]},{"id":"cong-phap-phat-mon","name":"Công pháp Phật môn","cn":"","loai":"cong-phap","loaiLabel":"Công pháp khắc chế quỷ đạo","phamCap":"không rõ","hePhai":"Phật môn","soHuu":["Hắc y mỹ phụ"],"blurb":"Công pháp Phật môn được Hàn Lập nhận định là hệ công pháp chuyên khắc chế Quỷ đạo thần thông. Trong chương này, linh quang bảy màu từ pháp luân Phật môn tạm thời ngăn Sát hồn ti xuyên qua.","detail":"Dù Hắc y mỹ phụ là trưởng lão ma môn, pháp bảo Phật môn của nàng lại phóng ra linh quang có hiệu quả khắc chế Sát hồn ti. Điều này khiến Hàn Lập ngạc nhiên và cho thấy Phật môn pháp lực có thể chống lại loại quỷ đạo thần thông này trong chốc lát.","thuocTinh":"Phật môn, khắc chế quỷ đạo","congNang":["Khắc chế Quỷ đạo thần thông và giúp linh quang bảy màu tạm ngăn Sát hồn ti @c0982"],"tabs":{"tienTrinh":[{"chuong":"@c0982","loai":"nhắc tới","importance":"normal","giaiDoan":"Khắc chế Sát hồn ti","text":"Hàn Lập nhận định công pháp Phật môn vốn chuyên khắc chế Quỷ đạo thần thông, nên linh quang bảy màu từ pháp luân mới có thể tạm chắn Sát hồn ti.","anchor":"công pháp Phật môn nguyên bản chuyên khắc chế Quỷ đạo thần thông"}]},"trangThai":"được nhắc tới","capNhatToi":"@c0982","nguon":["@c0982"]},{"id":"that-sac-linh-quang","name":"Thất sắc linh quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Hộ thể linh quang bảy màu của Hàn Lập, dùng để chặn Hồn ti trong lúc tam thi tấn công.","detail":"Trong chương 983, Hàn Lập phát ra một tầng thất sắc quang mang khiến bụi tơ xám đang quấn tới bị ngăn lại, giúp hắn thoát khỏi đòn Hồn ti của tam thi.","congNang":["Chặn Hồn ti đang quấn tới người Hàn Lập @c0983"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0983","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0983","loai":"thi triển","importance":"normal","giaiDoan":"chặn Hồn ti","text":"Hàn Lập dùng thất sắc linh quang ngăn tơ xám ngay trước khi bị quấn lấy.","anchor":"một tầng thất sắc quang mang hiện ra, bụi ti đụng trúng quầng sáng này nhất thời bị ngăn lại"}]},"capNhatToi":"@c0983","nguon":["@c0983"]},{"id":"than-thong-can-nuot-quy-vat-cua-de-hon-thu","name":"Thần thông cắn nuốt quỷ vật của Đề Hồn thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"thiên phú linh thú","soHuu":["Đề Hồn thú"],"blurb":"Thiên phú của Đề Hồn thú có thể dùng hà quang từ mũi thu nuốt quỷ vật và sát khí.","detail":"Đề Hồn thú phóng hà quang từ mũi, thu cả kim hồ lẫn hắc khí sát thi của tam thi vào trong, khiến hắc y mỹ phụ kinh ngạc vì năng lực nuốt sát khí quỷ vật quá dễ dàng.","thuocTinh":"nuốt quỷ vật và sát khí","congNang":["Thu nuốt kim hồ cùng hắc khí sát thi của tam thi @c0983"],"nguoiTu":[{"ten":"Đề Hồn thú","tuChuong":"@c0983","tangDatToi":"","trangThai":"thiên phú"}],"tabs":{"tienTrinh":[{"chuong":"@c0983","loai":"thi triển","importance":"normal","giaiDoan":"nuốt tam thi","text":"Đề Hồn thú dùng hà quang từ mũi thu sạch kim hồ và hắc khí của tam thi.","anchor":"Nhất thời một đạo hà quang từ mũi phóng xuất ra"}]},"capNhatToi":"@c0983","nguon":["@c0983"]},{"id":"ngan-si-phi-thien-va-phong-tho-than-thong","name":"Ngân sí phi thiên và phong-thổ thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"thiên phú Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thiên phú của Ngân Sí Dạ Xoa gồm đôi cánh bạc cùng hai loại thần thông phong và thổ.","detail":"Theo nhận thức của Hàn Lập, Ngân Sí Dạ Xoa có ngân sí để phi thiên hoặc xuống hoàng tuyền âm giới, đồng thời trời sinh hai loại thần thông phong và thổ.","thuocTinh":"phong, thổ, phi độn","congNang":["Dùng ngân sí để phi thiên hoặc xuống hoàng tuyền âm giới @c0983","Có thiên phú hai loại thần thông phong và thổ @c0983"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0983","tangDatToi":"","trangThai":"thiên phú"}],"tabs":{"tienTrinh":[{"chuong":"@c0983","loai":"xuất hiện","importance":"normal","giaiDoan":"lộ thiên phú","text":"Ngân Sí Dạ Xoa được mô tả có ngân sí và hai loại thần thông phong, thổ.","anchor":"lại được trời cho hai loại thần thông phong, thổ"}]},"capNhatToi":"@c0983","nguon":["@c0983"]},{"id":"vo-dong-ngan-muc","name":"Vô đồng ngân mục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"thiên phú Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Đôi mắt bạc không tròng của Ngân Sí Dạ Xoa có năng lực mê hoặc thần thức.","detail":"Vô đồng ngân mục có thể mê hoặc tu sĩ thần thức không đủ mạnh, khiến đối phương ngoan ngoãn chịu lệnh mà không tự biết.","thuocTinh":"ảo thuật, mê hoặc thần thức","congNang":["Mê hoặc tu sĩ thần thức không đủ mạnh @c0983"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0983","tangDatToi":"","trangThai":"thiên phú"}],"tabs":{"tienTrinh":[{"chuong":"@c0983","loai":"xuất hiện","importance":"normal","giaiDoan":"hé lộ năng lực mắt bạc","text":"Hàn Lập nhớ ra mắt bạc không tròng của Ngân Sí Dạ Xoa có thể mê hoặc tu sĩ thần thức yếu.","anchor":"có thể khiến tu sĩ thần thức không đủ mạnh bị mê hoặc"}]},"capNhatToi":"@c0983","nguon":["@c0983"]},{"id":"cu-tran-duoi-thuy-luc-cu-truc","name":"Cự trận dưới thúy lục cự trúc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Cự trận gần như trải khắp quảng trường dưới thúy lục cự trúc, gắn với các cột đá trói hắc kiền thi.","detail":"Tại quảng trường dưới lòng đất, phía dưới thúy lục cự trúc có một cự trận phủ gần khắp quảng trường, xung quanh còn có hơn mười lăm cột đá trói hắc kiền thi bị mổ bụng. Công dụng cụ thể chưa được giải thích trong chương này.","dacDiem":"phủ gần khắp quảng trường và liên quan các hắc kiền thi bị trói trên cột đá","congNang":["Bố trí bao phủ khu quảng trường dưới thúy lục cự trúc @c0983"],"tabs":{"tienTrinh":[{"chuong":"@c0983","loai":"xuất hiện","importance":"normal","giaiDoan":"lộ trận ở quảng trường","text":"Hàn Lập và hắc y mỹ phụ phát hiện cự trận gần như trải khắp quảng trường dưới thúy lục cự trúc.","anchor":"phía dưới lại bố trí một cự trận cơ hồ trải khắp quảng trường"}]},"capNhatToi":"@c0983","nguon":["@c0983"]},{"id":"ngan-dong-huyen-thuat","name":"Ngân Đồng Huyễn Thuật","cn":"","aliases":["ngân đồng ảo thuật"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Ảo thuật đồng thuật của Ngân Sí Dạ Xoa, được Tà Nguyệt Huyễn Kính tăng cường trong trận ở quảng trường dưới lòng đất.","detail":"Ngân Sí Dạ Xoa dùng ngân nhãn phối hợp hắc kính kéo Hàn Lập và hắc y mỹ phụ vào không gian sương mù, che lấp quảng trường, kén xám và vị trí thật của nó. Trong ảo cảnh, thuật tạo ngân nhãn khổng lồ, trăng lưỡi liềm và ngân quang có thể xóa sạch công kích mô phỏng của đối phương.","thuocTinh":"Ảo thuật đồng thuật","uyLuc":"Khi có Tà Nguyệt Huyễn Kính phụ trợ, uy lực tăng mạnh và có thể che giấu vị trí thật của người thi triển.","dacDiem":"Dựa vào ngân nhãn phát động, kéo mục tiêu vào huyễn cảnh quy mô lớn.","congNang":["Tạo ảo cảnh sương mù khiến quảng trường và kén xám biến mất @c0984","Che giấu vị trí thật của Ngân Sí Dạ Xoa trong lúc giao chiến @c0984","Tạo ngân nhãn và ngân quang trong ảo cảnh để xóa sạch công kích của đối thủ @c0984"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0984","tangDatToi":"Chưa rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0984","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trước Hàn Lập và hắc y mỹ phụ","text":"Ngân Sí Dạ Xoa dùng ngân nhãn phối hợp Tà Nguyệt Huyễn Kính thi triển ảo thuật, kéo Hàn Lập và hắc y mỹ phụ vào một không gian sương mù đầy ngân nhãn.","anchor":"Ngân đồng ảo thuật uy lực tối thiểu cũng cường hãn hơn phân nửa"}]},"dinhDanh":"goc","trangThai":"đang dùng","capNhatToi":"@c0984","nguon":["@c0984"]},{"id":"hoang-ha-cua-de-hon-thu","name":"Hoàng hà của Đề Hồn thú","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đề Hồn thú","soHuu":["Đề Hồn thú"],"blurb":"Luồng khí vàng do Đề Hồn thú phun ra để truy kích và khắc chế quỷ vật.","detail":"Trong trận với Ngân Sí Dạ Xoa, hoàng hà tiếp tục truy kích đối phương nhưng bị ngân mang từ đôi cánh chống đỡ, cho thấy khả năng khắc chế không tuyệt đối trước loại quỷ vật đặc biệt này.","congNang":["Truy kích và khắc chế quỷ vật, nhưng ở @c0985 bị ngân mang của Ngân Sí Dạ Xoa chống lại."],"tabs":{"tienTrinh":[{"chuong":"@c0985","loai":"thi triển","importance":"normal","giaiDoan":"Truy kích Ngân Sí Dạ Xoa","text":"Đề Hồn thú phun hoàng hà truy đuổi Ngân Sí Dạ Xoa nhưng bị ngân mang chống lại.","anchor":"không ngờ bị mấy cái Ngân mang lại có khả năng chống lại"}]},"capNhatToi":"@c0985","nguon":["@c0985"]},{"id":"thi-khi-hac-sac-cua-ngan-si-da-xoa","name":"Thi khí hắc sắc của Ngân Sí Dạ Xoa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"thi khí","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thi khí hắc sắc âm hàn, mang thi độc mạnh của Ngân Sí Dạ Xoa.","detail":"Ngân Sí Dạ Xoa phun cột sáng hắc sắc chứa thi khí âm hàn và thi độc, làm Phệ kim trùng rơi xuống như mưa và tổn thất khoảng một phần ba trong thoáng chốc.","thuocTinh":"âm hàn, thi độc","uyLuc":"Có thể làm suy yếu mạnh đàn Phệ kim trùng vốn thân thể cứng rắn.","dacDiem":"Hôi thối, âm hàn và chứa thi độc lợi hại.","congNang":["Đánh rơi và làm tổn thất khoảng một phần ba Phệ kim trùng trong trận @c0985."],"tabs":{"tienTrinh":[{"chuong":"@c0985","loai":"thi triển","importance":"normal","giaiDoan":"Khắc chế Phệ kim trùng","text":"Ngân Sí Dạ Xoa phun thi khí hắc sắc khiến Phệ kim trùng rơi rụng và mất khoảng một phần ba đàn.","anchor":"chẳng những hôi thối còn mang tính âm hàn cùng thi độc lợi hại cực kỳ"}]},"capNhatToi":"@c0985","nguon":["@c0985"]},{"id":"phong-giao-phong-long-cua-bach-ngoc-ho-diep","name":"Phong giao / Phong long của bạch ngọc hồ điệp","cn":"","aliases":["Phong giao của bạch ngọc hồ điệp","Phong long của bạch ngọc hồ điệp"],"loai":"than-thong","loaiLabel":"Pháp thuật biến hóa","phamCap":"không rõ","hePhai":"pháp bảo bạch ngọc hồ điệp","soHuu":["Hắc y mỹ phụ"],"blurb":"Biến hóa công kích từ hai bạch ngọc hồ điệp của hắc y mỹ phụ.","detail":"Hắc y mỹ phụ biến hai phong thuẫn do bạch ngọc hồ điệp hóa ra thành hai phong giao, sau đó dùng phong long phun phong nhận phá nhỏ quang cầu quanh Ngân Sí Dạ Xoa.","congNang":["Hóa thành phong giao hoặc phong long để công kích bằng phong nhận ở @c0985."],"tabs":{"tienTrinh":[{"chuong":"@c0985","loai":"thi triển","importance":"normal","giaiDoan":"Công kích quang cầu","text":"Hắc y mỹ phụ biến phong thuẫn thành hai bạch sắc phong giao để cùng Hàn Lập công kích Ngân Sí Dạ Xoa.","anchor":"lúc này phong thuẫn lại một lần nữa hoá thành hai con bạch sắc phong giao"}]},"capNhatToi":"@c0985","nguon":["@c0985"]},{"id":"hang-linh-phu-phu-the","name":"Hàng linh phù phụ thể","cn":"","loai":"bi-thuat","loaiLabel":"Phù thuật tăng pháp lực","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Hàng linh phù phụ thể là thủ đoạn Hàn Lập kích hoạt phù lục để mượn giao long hư ảnh nhập thể, tạm tăng mạnh pháp lực.","detail":"Khi thi triển, sau lưng Hàn Lập hiện giao long hư ảnh, thân thể chuyển sang trạng thái nửa người nửa thú và pháp lực tăng tới đỉnh Nguyên Anh trung kỳ. Chương này thủ đoạn được dùng làm nền cho một kích phá quang cầu huyễn thuật của Ngân Sí Dạ Xoa.","thuocTinh":"Phù thuật phụ thể","uyLuc":"Tạm thời đẩy pháp lực của Hàn Lập lên tới đỉnh Nguyên Anh trung kỳ.","dacDiem":"Gắn với giao long hư ảnh và biến hóa thân thể nửa người nửa thú.","congNang":["Tăng mạnh pháp lực trong thời gian thi triển @c0986"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0986","tangDatToi":"Thi triển phụ thể","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0986","loai":"thi triển","importance":"normal","giaiDoan":"Phụ thể tăng pháp lực","text":"Hàn Lập kích hoạt Hàng linh phù, khiến giao long hư ảnh phụ thể và pháp lực tăng tới đỉnh Nguyên Anh trung kỳ.","anchor":"Một hình ảnh giao long hư ảo một lần nữa ở sau lưng hiện ra"}]},"capNhatToi":"@c0986","nguon":["@c0986"]},{"id":"than-thong-quang-cau-huyen-thuat-cua-ngan-si-da-xoa","name":"Thần thông quang cầu huyễn thuật của Ngân Sí Dạ Xoa","cn":"","loai":"than-thong","loaiLabel":"Huyễn thuật cấm chế","phamCap":"Không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thần thông này phối hợp với Tà Nguyệt Huyễn Kính tạo ra quang cầu có khả năng tự dung hợp và mở rộng trong ô quang.","detail":"Quang cầu bị phong nhận đánh nát thành nhiều mảnh nhưng nhanh chóng dung hợp lại, khiến phong giao tiêu hao mà không phá được thế cục. Hàn Lập nhận ra tính chất vặn không gian tương tự thủ đoạn từng gặp ở Loạn Tinh hải và dùng cự kiếm lôi hỏa cưỡng ép phá hủy.","thuocTinh":"Huyễn thuật và cấm chế không gian","uyLuc":"Có thể tiêu hao công kích của phong giao và mở rộng phạm vi uy hiếp trong pháp trận.","dacDiem":"Dựa vào Tà Nguyệt Huyễn Kính để duy trì, khi bảo kính ngừng phun xuất thì công pháp bị phá.","congNang":["Tạo quang cầu tự dung hợp sau khi bị đánh nát @c0986","Mở rộng không gian uy hiếp trong ô quang @c0986"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0986","tangDatToi":"Thi triển trong pháp trận","trangThai":"bị phá"}],"tabs":{"tienTrinh":[{"chuong":"@c0986","loai":"thi triển","importance":"normal","giaiDoan":"Quang cầu bị phá","text":"Ngân Sí Dạ Xoa dùng Tà Nguyệt Huyễn Kính duy trì quang cầu huyễn thuật, nhưng bị cự kiếm của Hàn Lập cưỡng ép phá vỡ.","anchor":"Mà quang cầu bị phong nhận đánh cho thành rất nhiều mảnh nhỏ"}]},"capNhatToi":"@c0986","nguon":["@c0986"]},{"id":"sat-hon-ti-cu-chuong","name":"Sát hồn ti cự chưởng","cn":"","loai":"than-thong","loaiLabel":"Thần thông công phòng","phamCap":"Không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Sát hồn ti cự chưởng là biến hóa Ngân Sí Dạ Xoa dùng để hóa sát hồn ti thành hai bàn tay lớn chống cự cự kiếm.","detail":"Sau khi né một kích phá pháp, Ngân Sí Dạ Xoa hóa sát hồn ti thành hai cự chưởng để thử uy lực cự kiếm của Hàn Lập. Một cự chưởng bị chém tan, chưởng còn lại giao phong ngang sức với kiếm quang đã suy yếu.","thuocTinh":"Sát hồn ti biến hóa","uyLuc":"Có thể trực diện ngăn cản cự kiếm đã suy giảm uy lực.","dacDiem":"Dùng sát hồn ti ngưng tụ thành cự chưởng để công thủ trong cự ly gần.","congNang":["Hóa sát hồn ti thành cự chưởng để chặn cự kiếm @c0986"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0986","tangDatToi":"Thi triển cự chưởng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0986","loai":"thi triển","importance":"normal","giaiDoan":"Chặn cự kiếm","text":"Ngân Sí Dạ Xoa hóa sát hồn ti thành hai cự chưởng để chống cự cự kiếm của Hàn Lập.","anchor":"xuất hiện hai cái cự chưởng do sát hồn ti biến hoá thành"}]},"capNhatToi":"@c0986","nguon":["@c0986"]},{"id":"tho-don-cua-ngan-si-da-xoa-va-thi-lang","name":"Thổ độn của Ngân Sí Dạ Xoa và Thi lang","cn":"","loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"Không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa","Thi lang"],"blurb":"Độn thuật này cho phép Ngân Sí Dạ Xoa và Thi lang cùng chìm xuống lòng đất để đổi chiến trường trong pháp trận.","detail":"Sau khi Tà Nguyệt Huyễn Kính bị phá, Ngân Sí Dạ Xoa đáp lên đầu Thi lang rồi cả hai đồng thời độn xuống đất. Hành động này kéo theo rung chuyển pháp trận, hoàng quang và hắc khí bốc lên từ lòng đất.","thuocTinh":"Thổ độn","uyLuc":"Có thể giúp người và lang biến mất xuống lòng đất trong im lặng.","dacDiem":"Được thi triển đồng thời bởi Ngân Sí Dạ Xoa và Thi lang.","congNang":["Ẩn độn xuống lòng đất cùng Thi lang @c0986"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0986","tangDatToi":"Thi triển","trangThai":"đang dùng"},{"ten":"Thi lang","tuChuong":"@c0986","tangDatToi":"Thi triển cùng chủ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0986","loai":"thi triển","importance":"normal","giaiDoan":"Độn xuống đất","text":"Ngân Sí Dạ Xoa cùng Thi lang thổ độn xuống lòng đất, khiến pháp trận rung chuyển.","anchor":"Tiếp theo người và lang đồng thời hướng xuống lòng đất"}]},"capNhatToi":"@c0986","nguon":["@c0986"]},{"id":"minh-thanh-linh-muc","name":"Minh Thanh linh mục","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông quan sát","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông linh mục giúp Hàn Lập quan sát và nhìn phá thủ đoạn ẩn giấu tinh vi.","detail":"Trong cuộc đối đầu với Ngân Sí Dạ Xoa, Minh Thanh linh mục giúp Hàn Lập phát hiện ti võng lớn bị ảo thuật che giấu trên cao, nhờ đó hắn không lao vào bẫy khi Nguyên Anh Hắc y mỹ phụ kêu cứu.","thuocTinh":"linh mục, quan sát, phá ảo thuật","congNang":["Nhìn ra ảo thuật che giấu cự võng của Ngân Sí Dạ Xoa @c0987"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0987","tangDatToi":"có chút hỏa hầu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0987","loai":"thi triển","importance":"normal","giaiDoan":"Nhìn phá cự võng","text":"Hàn Lập dùng Minh Thanh linh mục phát hiện tấm ti võng lớn được Ngân Sí Dạ Xoa che giấu trên cao, tránh rơi vào bẫy cứu người.","anchor":"Nếu không phải Minh Thanh linh mục của Hàn Lập có chút hoả hầu"}]},"capNhatToi":"@c0987","nguon":["@c0987"]},{"id":"phong-don-thuat-cua-ngan-si-da-xoa","name":"Phong độn thuật của Ngân Sí Dạ Xoa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Độn thuật bằng gió của Ngân Sí Dạ Xoa, gần đạt cảnh giới theo gió ẩn hình.","detail":"Sau khi biến đổi hình thái, Ngân Sí Dạ Xoa dùng phong độn thuật truy sát Hàn Lập, khiến lôi độn thuật của Hàn Lập bị đánh giá là kém hơn trong cuộc đuổi bắt.","thuocTinh":"phong, độn thuật, truy kích","congNang":["Ẩn hình theo gió và rút ngắn khoảng cách khi truy sát đối thủ @c0987"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0987","tangDatToi":"gần cảnh giới theo gió ẩn hình","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0987","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Hàn Lập","text":"Ngân Sí Dạ Xoa dùng phong độn thuật gần như theo gió ẩn hình để đuổi sát Hàn Lập, khiến khoảng cách giữa hai bên ngày càng bị rút ngắn.","anchor":"Cơ hồ đã tới cảnh giới “theo gió ẩn hình”."}]},"capNhatToi":"@c0987","nguon":["@c0987"]},{"id":"ao-thuat-che-giau-cu-vong","name":"Ảo thuật che giấu cự võng","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Ẩn giấu bẫy","phamCap":"không rõ","hePhai":"","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thủ đoạn che giấu cự võng trên cao để dụ đối thủ lao vào bẫy.","detail":"Ngân Sí Dạ Xoa dùng ảo thuật che một tấm ti võng lớn phía trên Hàn Lập, định lợi dụng tiếng kêu cứu của Hắc y mỹ phụ để dụ hắn dùng lôi độn lao tới.","thuocTinh":"ảo thuật, ẩn giấu, bẫy bắt","congNang":["Che giấu cự võng lớn để mai phục người lao vào cứu viện @c0987"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0987","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0987","loai":"thi triển","importance":"normal","giaiDoan":"Giấu đại võng","text":"Ngân Sí Dạ Xoa che giấu một cự võng phía trên để chờ Hàn Lập mắc bẫy, nhưng bị Minh Thanh linh mục nhìn ra.","anchor":"không ngờ có thể đem như thế một cái cự võng che dấu"}]},"capNhatToi":"@c0987","nguon":["@c0987"]},{"id":"than-quang-mau-vang-cua-de-hon-thu","name":"Thần quang màu vàng của Đề Hồn thú","cn":"","aliases":["hoàng quang của Đề Hồn thú"],"loai":"than-thong","loaiLabel":"Thần thông khắc thi quỷ","phamCap":"không rõ","hePhai":"","soHuu":["Đề Hồn thú"],"blurb":"Dòng thần quang màu vàng do Đề Hồn thú phun ra, có tác dụng áp chế thi lang và đối kháng thi hỏa.","detail":"Trong trận giằng co với thi lang, Đề Hồn thú phun dòng khí vàng và thần quang khiến thi lang không dám áp sát, đồng thời hình thành tầng ánh sáng bảo vệ thân thể.","thuocTinh":"khắc thi quỷ, phòng hộ, áp chế","congNang":["Đối kháng thi hỏa và khiến thi lang kiêng sợ không dám tiếp cận @c0987"],"nguoiTu":[{"ten":"Đề Hồn thú","tuChuong":"@c0987","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0987","loai":"thi triển","importance":"normal","giaiDoan":"Giằng co thi lang","text":"Đề Hồn thú phun thần quang màu vàng để chống thi hỏa và ép thi lang phải né tránh trong lúc giao chiến.","anchor":"liên tiếp từ trong mũi phun ra thần quang khiến cho dòng khí màu vàng"}]},"capNhatToi":"@c0987","nguon":["@c0987"]},{"id":"thanh-minh-linh-muc","name":"Thanh Minh Linh mục","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông linh mục","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông linh mục giúp Hàn Lập nhìn rõ tình hình trong kim sắc quang mang.","detail":"Ở chương này, Hàn Lập dùng Thanh Minh Linh mục để quan sát kim tráo của Ngân Sí Dạ Xoa, thấy phi kiếm bị tá lực đánh bật, Tịch Tà Thần Lôi chỉ làm hào quang nhoáng lên, còn tử sắc hỏa diễm có thể đóng băng kim tráo.","thuocTinh":"Linh mục quan sát","congNang":["Quan sát xuyên qua kim sắc quang mang và nhận rõ biến hóa bên trong @c0988"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0988","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0988","loai":"thi triển","importance":"normal","giaiDoan":"Quan sát kim tráo","text":"Hàn Lập dùng Thanh Minh Linh mục để nhìn rõ tình hình bên trong kim sắc quang mang của Ngân Sí Dạ Xoa.","anchor":"Dưới Thanh Minh Linh mục, hắn nhìn rất rõ ràng tình hình bên trong quang mang."}]},"capNhatToi":"@c0988","nguon":["@c0988"]},{"id":"kim-don-thuat","name":"Kim độn thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"Không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Độn thuật theo kim thuộc tính mà Ngân Sí Dạ Xoa có thể sử dụng trong lúc đang tiến giai.","detail":"Hàn Lập xác nhận Ngân Sí Dạ Xoa ngoài thổ, phong độn còn có thể dùng kim độn thuật, nhưng suy đoán đối phương mới nắm một phần do tiến giai Kim Thân Nguyệt Thi chưa hoàn tất và bị hạn chế bởi vật có kim khí tài liệu quý hiếm.","thuocTinh":"Kim thuộc tính","yeuCau":"Liên quan đến tiến giai Kim Thân Nguyệt Thi","congNang":["Giúp người thi triển mượn kim thuộc tính để độn hình @c0988"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0988","tangDatToi":"Một phần","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0988","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Hàn Lập nhận ra","text":"Hàn Lập nhận ra Ngân Sí Dạ Xoa không chỉ có thổ, phong độn mà còn dùng được kim độn thuật.","anchor":"ngoài trừ ra thổ phong hai loại độn hình, ngươi còn có thể sử dụng kim độn thuật"}]},"capNhatToi":"@c0988","nguon":["@c0988"]},{"id":"tho-phong-hai-loai-don-hinh","name":"Thổ phong hai loại độn hình","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"Không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Hai loại độn hình theo thổ và phong mà Ngân Sí Dạ Xoa đã thể hiện trước khi bị Hàn Lập nhận ra thêm kim độn.","detail":"Chương này nhắc thổ phong hai loại độn hình như cơ sở đối chiếu để Hàn Lập xác định Ngân Sí Dạ Xoa còn có thể sử dụng kim độn thuật.","thuocTinh":"Thổ và phong","congNang":["Độn hình theo thổ, phong thuộc tính @c0988"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0988","tangDatToi":"Không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0988","loai":"nhắc tới","importance":"bridge","giaiDoan":"Làm nền cho kim độn","text":"Hàn Lập nhắc Ngân Sí Dạ Xoa đã có thổ, phong độn khi chỉ ra thêm kim độn thuật.","anchor":"ngoài trừ ra thổ phong hai loại độn hình, ngươi còn có thể sử dụng kim độn thuật"}]},"capNhatToi":"@c0988","nguon":["@c0988"]},{"id":"bang-diem","name":"Băng diễm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Biến hóa băng hàn","phamCap":"Không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Biến hóa băng hàn do Hàn Lập dùng Tuyết Phát hoàn, Tuyết Tinh Châu và tinh huyết thúc phát từ hàn khí Tử La Thiên Hỏa.","detail":"Băng diễm không còn là Tử La Thiên Hỏa đơn thuần ban đầu mà là hàn khí được ngưng tụ mạnh hơn nhờ Tuyết Phát hoàn, Tuyết Tinh Châu và tinh huyết của Hàn Lập, tạo thành tường băng tím chống lại phi châm kim khí của Ngân Sí Dạ Xoa.","thuocTinh":"Băng hàn, tử diễm","nguonGoc":"Từ hàn khí Tử La Thiên Hỏa được Tuyết Phát hoàn và Tuyết Tinh Châu ngưng tụ","yeuCau":"Hàn Lập phải dùng tinh huyết khi pháp lực hao hụt","congNang":["Tạo tường băng tím phòng ngự phi châm kim khí @c0988"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0988","tangDatToi":"Có thể thúc phát bằng Tuyết Tinh Châu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0988","loai":"xuất hiện","importance":"normal","giaiDoan":"Tạo tường băng tím","text":"Hàn Lập dùng Tuyết Phát hoàn, Tuyết Tinh Châu và tinh huyết để tạo băng diễm ngưng tụ hàn khí Tử La Thiên Hỏa, nhờ đó ngăn phi châm kim khí.","anchor":"Mà sau khi dùng Tuyết Phát hoàn lại mượn lực Tuyết Tinh châu kết hợp, từ đó mới tạo ra băng diễm này."}]},"capNhatToi":"@c0988","nguon":["@c0988"]},{"id":"thi-sat-ti-vong","name":"Thi sát ti võng","cn":"","aliases":["hôi sắc cự võng"],"loai":"than-thong","loaiLabel":"Thần thông thi sát","phamCap":"Không rõ","hePhai":"Thi đạo","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thần thông do Ngân Sí Dạ Xoa dùng gần như toàn bộ thi sát chi khí ngưng tụ thành hôi sắc cự võng. Trong chương này, nó bị tam sắc quang luân của Tam Diễm Phiến cuốn vào rồi tiêu tán hoàn toàn.","detail":"Thi sát ti võng là lưới lớn màu xám do Ngân Sí Dạ Xoa ngưng tụ gần như toàn bộ thi sát chi khí mà thành, dùng để vây khóa đối thủ. Khi đối đầu Tam Diễm Phiến, cự võng bị quang luân tam sắc bao lấy và cùng quang luân biến mất, khiến Ngân Sí Dạ Xoa kinh hãi.","congNang":["Vây khóa mục tiêu bằng thi sát chi khí @c0989"],"uyLuc":"Từng được Ngân Sí Dạ Xoa dốc gần như toàn bộ thi sát chi khí ngưng tụ nhưng vẫn bị Tam Diễm Phiến phá tan.","dacDiem":"Hiện thành hôi sắc cự võng, bản chất là thi sát chi khí ngưng tụ.","nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0989","tangDatToi":"Có thể ngưng tụ thành cự võng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0989","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Tam Diễm Phiến","text":"Ngân Sí Dạ Xoa dùng thi sát ti võng vây khóa nhưng bị Tam Diễm Phiến phá tan.","anchor":"ti võng kia là do hắn ngưng tụ gần như toàn bộ thi sát chi khí mà thành"}]},"capNhatToi":"@c0989","nguon":["@c0989"]},{"id":"huyet-te-phap-luyen-che-thi-sat-hoa-than","name":"Huyết tế pháp luyện chế thi sát hóa thân","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Tà pháp luyện hóa","phamCap":"Không rõ","hePhai":"Thi đạo","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Tà pháp mà Ngân Sí Dạ Xoa từng dùng để luyện thi thể tu sĩ xâm nhập thành thi sát hóa thân. Chi tiết này cho thấy hắn từng tạo hóa thân để bù lại việc thân thể bị pháp trận hạn chế.","detail":"Ngân Sí Dạ Xoa vì bị pháp trận giam hãm, hành động bị hạn chế nên sau khi giết những tu sĩ tiến vào, đã mượn thi thể họ dùng huyết tế pháp luyện chế thành thi sát hóa thân. Đây là thủ đoạn luyện hóa thi thể bằng huyết tế, phục vụ thi đạo của hắn.","congNang":["Luyện thi thể tu sĩ thành thi sát hóa thân @c0989"],"dacDiem":"Gắn với huyết tế và thi sát chi khí.","nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0989","tangDatToi":"Từng dùng để luyện thi sát hóa thân","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0989","loai":"nhắc tới","importance":"normal","giaiDoan":"Quá khứ trong pháp trận","text":"Ngân Sí Dạ Xoa từng dùng huyết tế pháp luyện thi thể tu sĩ thành thi sát hóa thân.","anchor":"mượn thi thể họ, dùng huyết tế pháp luyện chế thành thi sát hóa thân"}]},"capNhatToi":"@c0989","nguon":["@c0989"]},{"id":"truyen-tong-tran-cuc-lon","name":"Truyền Tống Trận cực lớn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"Không rõ","hePhai":"Trận pháp","soHuu":[],"blurb":"Trận pháp truyền tống khổng lồ đột ngột hiện ra từ dưới đất trong khu vực Hàn Lập và Ngân Sí Dạ Xoa giao chiến. Nó dung hợp với trận pháp sẵn có rồi truyền tống cả hai cùng mọi thứ đi mất.","detail":"Truyền Tống Trận cực lớn xuất hiện khi mặt đất rạn nứt, một đạo linh mang khảm hơn trăm viên linh thạch bắn lên và hợp với trận pháp bên trong. Trận pháp nhanh chóng kích phát, khiến Hàn Lập không kịp dùng lôi độn thoát ra, đồng thời còn có ba địa phương khác ở Đại Tấn phát sinh dị biến tương tự.","congNang":["Truyền tống nhiều đối tượng khỏi nơi phong ấn @c0989","Kích phát đồng bộ với ba địa điểm khác ở Đại Tấn @c0989"],"uyLuc":"Có thể cuốn cả Hàn Lập, Ngân Sí Dạ Xoa và mọi thứ trong phạm vi biến mất vô tung.","dacDiem":"Linh mang cấu thành trận có khảm hơn trăm viên linh thạch.","tabs":{"tienTrinh":[{"chuong":"@c0989","loai":"xuất hiện","importance":"major","giaiDoan":"Dị biến dưới đất","text":"Truyền Tống Trận cực lớn hiện ra, dung hợp với trận pháp bên trong và cuốn Hàn Lập cùng Ngân Sí Dạ Xoa đi mất.","anchor":"Đây rõ ràng là một Truyền Tống Trận cực lớn"}]},"capNhatToi":"@c0989","nguon":["@c0989"]},{"id":"an-nac-phap-tran-cua-diep-gia","name":"Ẩn nặc pháp trận của Diệp gia","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp che giấu thiên tượng","phamCap":"Không rõ","hePhai":"Trận pháp Diệp gia","soHuu":["Diệp gia"],"blurb":"Trận pháp được Diệp gia bố trí quanh tiểu hồ Nam Cương để che giấu thiên tượng khi giải phong ấn Côn Ngô sơn. Cuối chương, nó bị phát hiện đã bị người khác phá hoại, khiến kế hoạch Diệp gia lộ ra nguy cơ lớn.","detail":"Ẩn nặc pháp trận của Diệp gia vốn dùng để che đậy bạch sắc quang trụ và các quang trụ phụ khi phong ấn Côn Ngô sơn bị giải trừ. Khi thiên tượng hiện rõ, đại trưởng lão phái người kiểm tra và nhận tin các pháp trận đã bị phá hoại, còn đệ tử bên trong đều biến mất.","trangThai":"bị phá hoại","congNang":["Che giấu thiên tượng khi giải phong ấn Côn Ngô sơn @c0989"],"dacDiem":"Bị phá hoại trước khi che được dị tượng quang trụ trên tiểu hồ.","tabs":{"tienTrinh":[{"chuong":"@c0989","loai":"nhắc tới","importance":"major","giaiDoan":"Bị phá hoại","text":"Ẩn nặc pháp trận không che được thiên tượng và được xác nhận đã bị người khác phá hoại.","anchor":"Ta đã tra xét các pháp trận kia, rõ ràng đã bị người khác phá hoại"}]},"capNhatToi":"@c0989","nguon":["@c0989"]},{"id":"phong-an-con-ngo-son","name":"Phong ấn Côn Ngô sơn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Phong ấn đại trận","phamCap":"Không rõ","hePhai":"Thượng cổ phong ấn","soHuu":["Hóa Tiên tông","Côn Ngô nhị lão"],"blurb":"Đại phong ấn bao phủ Côn Ngô sơn, đang bị Diệp gia bí mật giải trừ tại tiểu hồ Nam Cương. Bạch phát lão giả xác nhận phong ấn đã mở một khe nhỏ và khoảng một năm nữa sẽ hoàn toàn biến mất.","detail":"Phong ấn Côn Ngô sơn là mục tiêu kế hoạch bí mật của Diệp gia. Trong chương này, bạch phát lão giả phụ trách giải phong ấn báo rằng phong ấn đã được mở một khe nhỏ, hiện rất yếu, dù còn chưa thể lập tức triệt bỏ nhưng dự kiến khoảng một năm nữa sẽ hoàn toàn biến mất.","trangThai":"phá huỷ hoàn toàn","congNang":["Phong cấm Côn Ngô sơn @c0989","Phong ấn người có thân phận đặc thù trong Côn Ngô Sơn @c1014","Có thể được gia cố bằng Hóa long tỳ và liên quan hậu thủ Thiên tinh bi @c1014","Trấn áp ma khí và ma vật bên trong Côn Ngô Sơn","Có thể được khởi động lại bằng Hoá Long Tỳ hoặc pháp trận dự phòng"],"dacDiem":"Sau khi bị mở khe nhỏ, phong ấn trở nên rất yếu và có mốc khoảng một năm trước khi biến mất.","tabs":{"tienTrinh":[{"chuong":"@c0989","loai":"nhắc tới","importance":"major","giaiDoan":"Mở khe nhỏ","text":"Diệp gia đã mở một khe nhỏ trên phong ấn Côn Ngô sơn và dự đoán khoảng một năm nữa phong ấn biến mất.","anchor":"Phong ấn tại Côn Ngô sơn đã được mở ra một khe nhỏ"},{"chuong":"@c1014","loai":"nhắc tới","importance":"major","giaiDoan":"Cơ chế phong ấn hé lộ","text":"Mộc phu nhân nói Trấn Ma tháp là trận nhãn chân chính khống chế phong ấn và muốn gia cố phải dùng Hóa long tỳ trong Côn Ngô điện.","anchor":"Trấn Ma tháp mới là trận nhãn chân chính khống chế phong ấn"},{"chuong":"@c1065","loai":"nhắc tới","importance":"major","giaiDoan":"Phong ấn bị phá hoàn toàn","text":"Cột đá bốn phía đại bộ phận bị phá, Tế Đàn bị Hắc Lang phát tiếng rít làm vỡ vụn sụp đổ, ma khí đen như mực tràn ra bốn phía. Hoá Long Tỳ đã bị ma vật bóp nát, mất phương tiện khống chế.","anchor":"pháp trận đã bị phá huỷ hoàn toàn"}]},"capNhatToi":"@c0989","nguon":["@c0989","@c1014","@c1065"]},{"id":"phong-don","name":"Phong độn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Độn thuật theo gió được Ngân Sí Dạ Xoa dùng khi thoát khỏi nơi truyền tống. Nó giúp hắn rời đi nhanh chóng thay vì liều mạng với Hàn Lập.","detail":"Sau khi pháp khí giam cầm bị phá và có cơ hội tự do, Ngân Sí Dạ Xoa thi triển phong độn, nương theo gió rời khỏi nơi có cự đại truyền tống trận.","congNang":["Thoát ly nhanh theo gió @c0990"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c0990","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"thi triển","importance":"normal","giaiDoan":"Rời nơi truyền tống","text":"Ngân Sí Dạ Xoa dùng phong độn để rời đi sau khi thoát giam cầm.","anchor":"hắn nhân có hội thi triển phong độn, nương theo gió ly khai khỏi nơi này"}]},"nguon":["@c0990"]},{"id":"tho-don-thuat-cua-cu-hinh-ngo-cong","name":"Thổ độn thuật của cự hình ngô công","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Độn thuật yêu thú","phamCap":"không rõ","hePhai":"Diệp gia","soHuu":["Đạo cô Cửu muội Diệp gia"],"blurb":"Thổ độn thuật của linh thú ngô công mà Cửu muội Diệp gia thả ra. Nó chở nhóm trưởng lão Diệp gia lặng lẽ chìm xuống lòng đất để tiếp cận khe phong ấn.","detail":"Cự hình ngô công của Cửu muội vừa tiếp xúc mặt đất đã vô thanh vô tức chìm xuống, cho thấy yêu thú này tinh thông thổ độn và đủ sức mang cả nhóm tu sĩ Diệp gia đi xuống sâu.","congNang":["Đưa đoàn tu sĩ Diệp gia xuống lòng đất @c0990"],"tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"thi triển","importance":"normal","giaiDoan":"Xuống khe phong ấn","text":"Cự hình ngô công dùng thổ độn đưa các trưởng lão Diệp gia chìm xuống đất.","anchor":"Thật không ngờ, đây lại là một yêu thú tinh tông thổ độn thuật"}]},"nguon":["@c0990"]},{"id":"phap-tran-tim-khe-phong-an","name":"Pháp trận tìm khe phong ấn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp dò tìm","phamCap":"không rõ","hePhai":"Diệp gia","soHuu":["Diệp gia"],"blurb":"Pháp trận được Diệp gia dùng để xác định khe phong ấn ở phía bắc tiểu hồ. Nó giúp nhóm trưởng lão tìm đúng vị trí dưới mặt đất ngàn trượng.","detail":"Bạch phát lão giả báo đã dùng pháp trận tìm ra khe phong ấn ở phương bắc cách hơn hai mươi dặm, sâu dưới mặt đất ngàn trượng.","congNang":["Xác định vị trí khe phong ấn @c0990"],"tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"xuất hiện","importance":"normal","giaiDoan":"Tìm đường vào Côn Ngô","text":"Diệp gia dùng pháp trận tìm được khe phong ấn phía bắc tiểu hồ.","anchor":"Đã dùng pháp trận tìm được rồi, tại phương Bắc cách nơi này hơn hai mươi dặm"}]},"nguon":["@c0990"]},{"id":"cac-phap-tran-che-giau-quanh-tieu-ho","name":"Các pháp trận che giấu quanh tiểu hồ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp che giấu","phamCap":"không rõ","hePhai":"Diệp gia","soHuu":["Diệp gia"],"trangThai":"bị hủy @c0990","blurb":"Hệ thống pháp trận che giấu quanh tiểu hồ do Diệp gia bố trí. Chúng bị phá hủy đồng loạt, khiến hành tung Diệp gia lộ ra và buộc đội ngũ phải tiến vào Côn Ngô sơn gấp.","detail":"Các tu sĩ Diệp gia đi kiểm tra đều báo pháp trận bị hủy và đệ tử thao túng biến mất không thấy, làm dấy lên nghi vấn nội bộ và nguy cơ mưu đồ Côn Ngô sơn bị lộ.","congNang":["Che giấu hành động của Diệp gia quanh tiểu hồ trước khi bị phá @c0990"],"tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị phá từ bên trong","text":"Hệ thống pháp trận quanh tiểu hồ bị phá và người thao túng mất tích.","anchor":"đều là trận bị hủy, đệ tử thao túng pháp trận biến mất không thấy"}]},"nguon":["@c0990"]},{"id":"cu-hinh-truyen-tong-tran-mot-chieu","name":"Cự hình truyền tống trận một chiều","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp trong sơn động nơi nhóm Hàn Lập bị truyền tống tới, chỉ có chiều đến mà không thể đưa họ quay lại chỗ cũ.","detail":"Hàn Lập quan sát bằng tạo nghệ trận pháp và nhận ra đây là truyền tống trận một chiều. Điều này khiến nhóm bị khóa đường lui tại khu vực cự sơn, buộc phải tìm lối thoát khác.","dinhDanh":"goc","congNang":["Truyền tống một chiều đến sơn động, không thể dùng để quay lại nơi cũ @c0991"],"trangThai":"đang tồn tại","capNhatToi":"@c0991","tabs":{"tienTrinh":[{"chuong":"@c0991","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị nhận ra là trận một chiều","text":"Hàn Lập nhận ra pháp trận trong sơn động chỉ đưa người đến đây và không thể truyền tống trở về chỗ cũ.","anchor":"rõ ràng chính là một cái truyền tống trận một chiều"}]},"nguon":["@c0991"]},{"id":"cam-che-bach-quang-bao-phu-cu-son","name":"Cấm chế bạch quang bao phủ cự sơn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Thượng cổ cấm chế","hePhai":"Thượng cổ tu sĩ","soHuu":[],"blurb":"Màn bạch quang khổng lồ phủ kín Kình Thiên cự sơn, chứa linh lực cực kỳ đáng sợ.","detail":"Cấm chế này bao phủ toàn bộ cự sơn bằng bạch quang vô tận. Hàn Lập cảm nhận uy năng của bích chướng và cho rằng ngay cả tu sĩ Hóa Thần kỳ cũng khó cưỡng ép phá bỏ bằng sức mạnh.","dinhDanh":"goc","uyLuc":"Ngay cả tu sĩ Hóa Thần kỳ cũng khó cưỡng ép bài trừ bằng sức mạnh đã thấy ở chương này.","congNang":["Bao phủ và ngăn cách toàn bộ Kình Thiên cự sơn bằng bạch quang vô tận @c0991","Tạo bích chướng chứa linh lực đáng sợ, khó dùng sức mạnh cưỡng ép phá bỏ @c0991"],"trangThai":"đang bao phủ cự sơn","capNhatToi":"@c0991","tabs":{"tienTrinh":[{"chuong":"@c0991","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ bích chướng cự sơn","text":"Hàn Lập phát hiện bạch quang phủ kín cự sơn và đánh giá uy lực cấm chế vượt xa khả năng cưỡng ép phá bỏ của hắn.","anchor":"cho dù một Hóa thần kì tu sĩ, cũng vô pháp cậy sức mạnh mẽ bài trừ bích chướng này"}]},"nguon":["@c0991"]},{"id":"phap-tran-an-nau-canh-bao-cua-han-lap","name":"Pháp trận ẩn náu cảnh báo của Hàn Lập","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp trận Hàn Lập bố trí trong sơn động để che giấu phạm vi bên trong và cảnh báo khi có địch xâm nhập.","detail":"Trong lúc lão giả họ Phú và Bạch Dao Di điều tức, Hàn Lập lấy trận bàn triển khai một pháp trận đơn giản trong sơn động. Trận này bao phủ phạm vi trong động, có tác dụng ẩn náu, đồng thời phát tín hiệu cảnh báo nếu có địch nhân xâm nhập.","nguon":["@c0992"]},{"id":"an-nac-don-thuat-cua-su-cam-thu","name":"Ẩn nặc độn thuật của Sư cầm thú","cn":"","aliases":[],"loai":"khac","loaiLabel":"Độn thuật","phamCap":"","hePhai":"","soHuu":["Sư cầm thú"],"blurb":"Độn thuật giúp Sư cầm thú ẩn mình trong tử vụ và biến mất khỏi tầm nhìn đối thủ.","detail":"Sư cầm thú được nhận định là tinh thông ẩn nặc độn thuật. Trong hoàn cảnh thần thức bị áp chế, năng lực này khiến nó có thể ẩn trong tử vụ, bất ngờ tập kích và gây khó khăn lớn cho nhóm Diệp gia khi giao chiến.","nguon":["@c0992"]},{"id":"song-am-mau-vang-cua-su-cam-thu","name":"Sóng âm màu vàng của Sư cầm thú","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Sư cầm thú"],"blurb":"Thần thông sóng âm màu vàng gần như trong suốt do Sư cầm thú phun ra để đánh bật pháp bảo.","detail":"Sau khi bị hắc hồng phi đao làm trọng thương, Sư cầm thú há miệng phun ra một làn sóng màu vàng gần như trong suốt. Đòn này đánh bật hắc hồng phi đao, đồng thời khiến phi đao của Diệp gia Thất thúc tán loạn, tạo cơ hội cho hung cầm thi triển lôi độn bỏ chạy.","nguon":["@c0992"]},{"id":"cam-che-son-dong-cua-han-lap","name":"Cấm chế sơn động của Hàn Lập","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Các cấm chế Hàn Lập bố trí trong sơn động để phòng hộ nơi luyện đan.","detail":"Khi sơn động rung chuyển và ba người chuẩn bị rời đi, Hàn Lập phất tay áo khiến thanh hà quét ra bốn phía, giải khai hoàn toàn những cấm chế trong sơn động.","congNang":["Phong hộ nơi luyện đan và có thể được Hàn Lập chủ động giải khai khi rời đi @c0993"],"trangThai":"đã giải khai","capNhatToi":"@c0993","tabs":{"tienTrinh":[{"chuong":"@c0993","loai":"nhắc tới","importance":"normal","giaiDoan":"Rời sơn động luyện đan","text":"Hàn Lập giải khai toàn bộ cấm chế trong sơn động trước khi dẫn Bạch Dao Di và lão giả họ Phú rời đi.","anchor":"Ánh sáng lướt qua những cấm chế trong sơn động hoàn toàn giải khai"}]},"nguon":["@c0993"]},{"id":"phap-thuat-an-than-cua-lao-gia-ho-phu","name":"Pháp thuật ẩn thân của Lão giả họ Phú","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật ẩn nặc","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lão giả họ Phú"],"blurb":"Pháp thuật ẩn nấp bằng lục quang của Lão giả họ Phú. Khi thi triển, thân hình ông mờ dần thành bóng xanh khó phát hiện.","detail":"Lão giả họ Phú kháp tay gọi lục quang, khiến thân hình mờ đi rồi biến thành một bóng xanh mờ. Thủ đoạn này được dùng khi nhóm Hàn Lập quyết định che giấu hành tung để tới nơi phát ra tiếng động trong Côn Ngô sơn.","congNang":["Ẩn nấp thân hình, khiến người thi triển hóa thành bóng xanh mờ trong hoàn cảnh thần thức bị áp chế @c0994"],"nguoiTu":[{"ten":"Lão giả họ Phú","tuChuong":"@c0994","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn nấp dò xét","text":"Lão giả họ Phú thi triển pháp thuật lục quang để che giấu hành tung trước khi cùng nhóm bay lên phía tiếng nổ.","anchor":"thân hình lão giả cũng mờ theo cuối cùng biến thành một cái bóng xanh mờ mờ"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"phap-thuat-an-than-bang-lenh-bai-cua-bach-dao-di","name":"Pháp thuật ẩn thân bằng lệnh bài của Bạch Dao Di","cn":"","loai":"than-thong","loaiLabel":"Pháp thuật ẩn nặc","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Bạch Dao Di"],"blurb":"Thủ đoạn ẩn thân Bạch Dao Di thi triển bằng một lệnh bài trong suốt như băng tinh. Lệnh bài phóng ra dải ngân hà bao phủ toàn thân nàng rồi khiến nàng biến mất.","detail":"Bạch Dao Di lấy ra lệnh bài trong suốt, niệm chú và phun sương vào đó. Từ lệnh bài bắn ra một dải ngân hà bao phủ toàn thân, giúp nàng ẩn giấu hành tung khi nhóm tiến vào vùng lạ của Côn Ngô sơn.","congNang":["Ẩn nấp thân hình bằng dải ngân hà phát ra từ lệnh bài trong suốt @c0994"],"nguoiTu":[{"ten":"Bạch Dao Di","tuChuong":"@c0994","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn nấp dò xét","text":"Bạch Dao Di dùng lệnh bài băng tinh thi triển pháp thuật ẩn thân trước khi cùng nhóm rời đi dò xét.","anchor":"từ trong lệnh bày bắn ra một dải ngân hà, bao phủ lấy toàn thân nàng"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"an-than-phu","name":"Ẩn thân phù","cn":"","loai":"bi-thuat","loaiLabel":"Phù lục ẩn thân","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Phù lục Hàn Lập dùng để che giấu thân hình. Trong Côn Ngô sơn, hiệu quả của phù khiến Lão giả họ Phú và Bạch Dao Di gần như không cảm ứng được tung tích hắn bằng thần thức.","detail":"Hàn Lập dán ẩn thân phù lên người sau khi hai đồng hành đã thi pháp che giấu hành tung. Dù ở gần nhau, Lão giả họ Phú và Bạch Dao Di dùng thần thức vẫn khó phát hiện tung tích của hắn trong không gian áp chế thần thức.","congNang":["Ẩn thân và che giấu tung tích đến mức người đứng gần khó phát hiện bằng thần thức @c0994"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0994","tangDatToi":"không rõ","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn nấp dò xét","text":"Hàn Lập dùng Ẩn thân phù để che giấu hành tung khi nhóm tiến về nơi phát ra tiếng động.","anchor":"ngay cả dùng thần thức cảm ứng cũng không phát hiện ra tung tích của Hàn Lập"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"linh-nhan","name":"Linh nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông quan sát","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Thần thông quan sát khiến hai mắt Hàn Lập hiện lam quang. Hắn dùng nó để nhìn vào vùng sương trắng và kiểm tra bia đá trong Côn Ngô sơn.","detail":"Khi phát hiện vùng sương trắng có điều hữu dụng, Hàn Lập vận dụng linh nhãn, hai mắt hiện lam quang để quan sát. Sau đó hắn cũng dùng thủ đoạn này xem xét bia đá nhưng không nhìn ra điểm khác thường rõ rệt.","congNang":["Quan sát dị thường trong sương trắng và xem xét bia đá @c0994"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0994","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"thi triển","importance":"normal","giaiDoan":"Quan sát sương trắng","text":"Hàn Lập dùng linh nhãn để quan sát vùng sương trắng và phát hiện dấu hiệu dẫn tới bia đá Côn Ngô.","anchor":"Hai mắt Hàn Lập lam quang hiện ra chăm chú xem xét"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"co-truyen-tong-tran-tran-phap","name":"Cổ truyền tống trận","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Trận pháp truyền tống cổ xưa được Lão giả họ Phú nhắc tới trong suy đoán về việc nhóm bị đưa vào Côn Ngô sơn. Nó có thể đã bị cấm chế khởi động khi nhóm vô tình chạm vào.","detail":"Sau khi nhận ra nơi này là Côn Ngô sơn, Lão giả họ Phú suy đoán nhóm họ vô tình khiến cấm chế khởi động cổ truyền tống trận nên bị đưa tới linh sơn bị phong ấn. Đây là lời giải thích cho việc cả nhóm đột ngột xuất hiện trong không gian thượng cổ này.","congNang":["Truyền tống người vào Côn Ngô sơn bị phong ấn theo suy đoán của Lão giả họ Phú @c0994"],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"nhắc tới","importance":"normal","giaiDoan":"Suy đoán lai lịch","text":"Lão giả họ Phú suy đoán cổ truyền tống trận đã bị cấm chế khởi động và đưa nhóm vào Côn Ngô sơn.","anchor":"chúng ta vô tình làm cho cấm chế khởi động cổ truyền tống trận và bị đưa đến đây"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"cam-che-con-ngo-son","name":"Cấm chế Côn Ngô sơn","cn":"","loai":"khac","loaiLabel":"Cấm chế phong ấn","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Cấm chế bao phủ cả Côn Ngô sơn, khiến linh sơn thượng cổ trở thành một không gian bị phong bế. Hàn Lập nhận định đây là nguyên nhân không nên tùy tiện ở lại tu luyện.","detail":"Hàn Lập nhận ra cả tòa linh sơn bị cấm chế bao phủ, trong khi nơi này linh khí sung túc nhưng không có sinh vật hay linh thảo. Lão giả họ Phú cũng suy đoán Côn Ngô sơn vì nguyên nhân nào đó đã bị phong ấn, khiến nhóm bị đưa vào đây qua cổ truyền tống trận.","congNang":["Phong bế hoặc bao phủ toàn bộ Côn Ngô sơn, tạo thành hoàn cảnh lạ không thể tùy tiện rời ở @c0994"],"tabs":{"tienTrinh":[{"chuong":"@c0994","loai":"nhắc tới","importance":"normal","giaiDoan":"Nhận định phong ấn","text":"Hàn Lập nhận định cả Côn Ngô sơn bị cấm chế bao phủ khi thấy linh khí dày đặc nhưng hoàn cảnh quá bất thường.","anchor":"cả tòa linh sơn này đều bị cấm chế bao phủ lên"}]},"capNhatToi":"@c0994","nguon":["@c0994"]},{"id":"thanh-sac-kiem-khi","name":"Thanh sắc kiếm khí","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm khí","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Kiếm khí màu xanh do Hàn Lập bắn ra từ mười đầu ngón tay. Trong chương này, nó được dùng để cắt gọt lớp đá ngoài tấm bia.","detail":"Hàn Lập bắn hơn mười đạo thanh sắc kiếm khí để gọt bỏ lớp đá bọc ngoài tấm bia, khiến đá vụn bay loạn và làm lộ lam sắc tinh bi bên trong.","congNang":["Cắt gọt bia đá và bóc lớp đá bên ngoài để lộ vật ẩn bên trong @c0995"],"uyLuc":"Có thể cắt gọt lớp đá ngoài tấm bia thành đá vụn.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0995","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0995","loai":"thi triển","importance":"normal","giaiDoan":"Gọt tấm bia đá","text":"Hàn Lập thi triển hơn mười đạo thanh sắc kiếm khí để cắt gọt lớp đá ngoài tấm bia.","anchor":"mười đầu ngón tay của hắn bắn ra hơn mười đạo thanh sắc kiếm khí"}]},"capNhatToi":"@c0995","nguon":["@c0995"]},{"id":"van-tu-chi-mon","name":"Vạn Tu chi môn","cn":"","loai":"khac","loaiLabel":"Cấm chế cổng","phamCap":"không rõ","hePhai":"Côn Ngô Sơn","soHuu":[],"blurb":"Cổng lớn có cấm chế trên thềm đá Côn Ngô Sơn. Nó tự thả vạn đạo quang hà đỡ các đợt công kích của Diệp gia.","detail":"Vạn Tu chi môn nằm trên đoạn thềm đá nơi Diệp gia bày trận phá cấm. Cổng tự phóng vạn đạo quang hà tiếp đỡ pháp bảo và trận pháp công kích, khiến Diệp gia dự tính còn cần khoảng một ngày một đêm mới phá được.","congNang":["Tự động thả vạn đạo quang hà để chống đỡ các công kích phá cấm @c0995"],"dacDiem":"Cấm chế phòng hộ mạnh, có thể tự phản ứng trước công kích.","tabs":{"tienTrinh":[{"chuong":"@c0995","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Diệp gia phá cấm","text":"Vạn Tu chi môn tự thả vạn đạo quang hà chống đỡ pháp bảo và trận pháp của Diệp gia.","anchor":"Cái cổng này tự thân nó có thể tự động thả ra vạn đạo quang hà"}]},"capNhatToi":"@c0995","nguon":["@c0995"]},{"id":"huyet-xa-chan-quyet","name":"Huyết Xa Chân Quyết","cn":"","loai":"than-thong","loaiLabel":"Công pháp cảm ứng","phamCap":"không rõ","hePhai":"","soHuu":["Quái nhân Diệp gia"],"blurb":"Pháp quyết mà Quái nhân Diệp gia từng tu luyện. Nó giúp lão có cảm ứng thi khí rất linh mẫn.","detail":"Nhờ từng tu luyện Huyết Xa Chân Quyết, Quái nhân Diệp gia có loại thần thông cảm ứng thi khí linh mẫn, qua đó phát hiện Ngân Sí Dạ Xoa đang ẩn nấp gần nơi Diệp gia phá Vạn Tu chi môn.","congNang":["Tăng khả năng cảm ứng thi khí, giúp phát hiện Ngân Sí Dạ Xoa đang ẩn nấp @c0995"],"nguoiTu":[{"ten":"Quái nhân Diệp gia","tuChuong":"@c0995","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0995","loai":"thi triển","importance":"normal","giaiDoan":"Cảm ứng thi khí","text":"Quái nhân Diệp gia dựa vào Huyết Xa Chân Quyết để phát hiện Ngân Sí Dạ Xoa.","anchor":"Thất thúc tu luyện qua Huyết Xa Chân Quyết, mới có thể tu luyện ra loại thần thông linh mẫn"}]},"capNhatToi":"@c0995","nguon":["@c0995"]},{"id":"cam-che-cuoi-cua-con-ngo-tam-lao","name":"Cấm chế cuối của Côn Ngô Tam Lão","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Côn Ngô Sơn","soHuu":["Côn Ngô Tam Lão"],"blurb":"Tầng cấm chế cuối do Côn Ngô Tam Lão bố trí năm xưa. Nữ tử bí ẩn nói một mình nàng không thể xé bỏ tầng cấm chế này.","detail":"Theo lời Nữ tử bí ẩn, Côn Ngô Tam Lão từng dùng vạn nhân chi lực bố trí tầng cấm chế cuối. Chính tầng cấm chế này khiến nàng dù đã ra từ rất lâu vẫn chưa thể hoàn toàn rời khỏi nơi bị phong tỏa.","congNang":["Phong tỏa Nữ tử bí ẩn, khiến nàng không thể tự mình xé bỏ để rời đi @c0995"],"nguonGoc":"Do Côn Ngô Tam Lão dùng vạn nhân chi lực bố trí.","tabs":{"tienTrinh":[{"chuong":"@c0995","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ qua lời Nữ tử bí ẩn","text":"Nữ tử bí ẩn nói tầng cấm chế cuối của Côn Ngô Tam Lão là nguyên nhân khiến nàng chưa thể thoát ra.","anchor":"Côn Ngô Tam Lão dùng tới vạn nhân chi lực, bố trí cuối cùng một tầng cấm chế"}]},"capNhatToi":"@c0995","nguon":["@c0995"]},{"id":"cuu-chan-phuc-ma-tran","name":"Cửu chân phục ma trận","cn":"","loai":"khac","loaiLabel":"Trận pháp phong ấn","phamCap":"không rõ","hePhai":"liên quan Côn Ngô Tam Lão","soHuu":["Côn Ngô Tam Lão"],"blurb":"Đại trận phong ấn đang trấn áp nữ tử thần bí trong Côn Ngô sơn. Chân thân nàng vẫn chưa thoát khỏi trận này.","detail":"Cửu chân phục ma trận được nhắc cùng hai kiện Thông thiên linh bảo như cơ chế phong ấn khiến nữ tử thần bí chưa thể thật sự thoát khốn. Hướng Chi Lễ nhận ra trận pháp này và nữ tử cũng xác nhận chân thân vẫn còn bị khống chế.","dinhDanh":"goc","nguonGoc":"Côn Ngô Tam Lão","congNang":["Trấn áp và phong ấn nữ tử thần bí trong Côn Ngô sơn @c0996","Phục ma và trảm cổ ma bằng kim sắc đao quang @c1037"],"trangThai":"đang trấn áp nữ tử thần bí","capNhatToi":"@c0996","tabs":{"tienTrinh":[{"chuong":"@c0996","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ cơ chế phong ấn","text":"Trận pháp được xác nhận là một phần cốt lõi đang giam chân thân nữ tử thần bí, có liên hệ trực tiếp với hai kiện Thông thiên linh bảo và Côn Ngô Tam Lão.","anchor":"Bản phi chân thân còn chưa có thoát khốn"},{"chuong":"@c1037","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện trận phong ma","text":"Bát Linh Xích bị kích phát khiến Cửu Chân Phục Ma Trận hiện ra với chín tế đàn và chín cự nhận kim quang. Trận lập tức phát kim sắc đao quang trảm Ma Ảnh hai đầu bốn tay.","anchor":"Bát Linh Xích bỗng nhiên phát ra âm thanh vù vù chói tai."}]},"nguon":["@c0996","@c1037"]},{"id":"huyen-dieu-thien-tuong","name":"Huyễn diệu thiên tượng","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyễn thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Nữ tử thần bí tự xưng Bản phi","Tân hồn trong thân Ngân Nguyệt"],"blurb":"Thần thông do nữ tử thần bí thi triển bằng lốc xoáy bạch sắc và ngũ sắc hà quang. Nó hút Hướng Chi Lễ biến mất dù hắn định độn chạy.","detail":"Huyễn diệu thiên tượng tạo dị tượng trên không, dùng ngũ sắc hà quang bao trùm và sinh hấp lực hư không. Trong chương này, thần thông đủ sức giam giữ Hướng Chi Lễ, khiến hắn biến mất khỏi chỗ cũ trong khoảnh khắc.","dinhDanh":"goc","thuocTinh":"huyễn thuật, không gian, giam giữ","uyLuc":"Có thể khống chế và hút biến mất Hướng Chi Lễ trong phạm vi dị tượng.","congNang":["Tạo lốc xoáy bạch sắc và ngũ sắc hà quang để giam giữ mục tiêu @c0996","Hút mục tiêu biến mất khỏi vị trí ban đầu @c0996","Kéo tu sĩ Hóa Thần vào huyễn tượng và có thể gây tổn hao thần thức cho tân hồn đã thi triển @c1017"],"nguoiTu":[{"ten":"Nữ tử thần bí tự xưng Bản phi","tuChuong":"@c0996","tangDatToi":"không rõ","trangThai":"đang dùng"}],"capNhatToi":"@c0996","tabs":{"tienTrinh":[{"chuong":"@c0996","loai":"thi triển","importance":"major","giaiDoan":"Phong khốn Hướng Chi Lễ","text":"Nữ tử thần bí thi triển Huyễn diệu thiên tượng khi Hướng Chi Lễ định rời đi, khiến hắn sắc mặt đại biến rồi bị quang hà hút biến mất.","anchor":"Huyễn diệu thiên tượng!” Hướng Chi Lễ nhìn thấy cảnh này, sắc mặt đại biến"},{"chuong":"@c1017","loai":"nhắc tới","importance":"normal","giaiDoan":"Tân hồn phân liệt","text":"Huyễn Diệu Thiên Tượng được nhắc là nguyên nhân khiến tân hồn tổn hao thần thức và hai tinh hồn lại tách ra.","anchor":"tân hồn vì đem một gã Hoá thần tu sĩ lén trộm tới đây kéo vào trong Huyễn Diệu Thiên Tượng"}]},"nguon":["@c0996","@c1017"]},{"id":"ao-tran-che-giau-cua-vao-phong-an","name":"Ảo trận che giấu cửa vào phong ấn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Ảo trận dưới lòng đất cách tiểu hồ hơn hai mươi dặm, che giấu manh mối cửa vào phong ấn. Đệ tử Độc Thánh môn phát hiện và đang phá cấm tại khu vực này.","detail":"Ảo trận này được nhận định do người tinh thông trận pháp cố ý bố trí để che giấu thứ gì đó dưới lòng đất. Việc Độc Thánh môn phát hiện và phá giải nó dẫn tới bí mật cửa vào phong ấn bị bại lộ trước đông đảo tu sĩ.","dinhDanh":"goc","congNang":["Che giấu manh mối hoặc cửa vào phong ấn dưới lòng đất @c0996"],"trangThai":"đang bị Độc Thánh môn phá giải","capNhatToi":"@c0996","tabs":{"tienTrinh":[{"chuong":"@c0996","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Độc Thánh môn phát hiện","text":"Đệ tử Độc Thánh môn phát hiện nơi dưới lòng đất bị ảo trận cố ý che giấu và báo lại cho Hoa Thiên Kỳ.","anchor":"nơi đó bị người cố ý dùng một cái ảo trận che dấu cái gì đó"}]},"nguon":["@c0996"]},{"id":"ao-tran-trong-phong-an","name":"Ảo trận trong phong ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Trận pháp / cấm chế","phamCap":"Thượng cổ kỳ trận","hePhai":"Côn Ngô sơn","soHuu":[],"blurb":"Ảo trận che lối vào khu vực phong ấn, đưa người lọt vào một không gian thải vân không thấy trời đất. Ngay cả Hàn Lập dùng linh mục, phi kiếm và pháp bảo công kích cũng chưa thể phá ra ngay.","detail":"Trận pháp tạo ra cảnh tượng như mộng ảo với thải vân đủ màu, khiến người bên trong bay mãi không thấy điểm cuối và các đòn công kích tán loạn mà không chạm được mục tiêu thật. Hàn Lập phải suy xét các thượng cổ kỳ trận từng biết mới dường như nhận ra mấu chốt.","congNang":["Vây khốn và mê hoặc không gian, khiến người vào bị lạc trong thải vân @c0997","Che giấu mục tiêu thật, làm linh mục và công kích pháp bảo khó phát hiện điểm phá trận @c0997"],"trangThai":"đang vận hành","capNhatToi":"@c0997","tabs":{"tienTrinh":[{"chuong":"@c0997","loai":"xuất hiện","importance":"major","giaiDoan":"Lối vào phong ấn","text":"Ảo trận trong phong ấn nuốt Kiền lão ma, nhóm Độc Thánh môn, các tán tu Nguyên Anh và đang vây Hàn Lập trong không gian thải vân.","anchor":"Hiện giờ. hắn như đang trong một không gian mộng ả, bốn phía tất cả đều là thải vân đủ màu"}]},"nguon":["@c0997"]},{"id":"thanh-sac-dai-thu","name":"Thanh sắc đại thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông hóa ra bàn tay lớn màu xanh từ hư vô để bắt giữ các đóa vân hà trong ảo cấm.","detail":"Hàn Lập dùng thanh sắc đại thủ bắt giữ hồng vân trong thượng cổ ảo thuật cấm chế tại cự thạch, tạo điều kiện luyện hóa vật ẩn trong mây thành viên châu phá cấm.","congNang":["Bắt giữ vân hà trong ảo thuật cấm chế @c0998"],"tabs":{"tienTrinh":[{"chuong":"@c0998","loai":"thi triển","importance":"normal","giaiDoan":"Phá ảo cấm cự thạch","text":"Hàn Lập hóa ra thanh sắc đại thủ từ hư vô để chộp lấy vân hà trong cấm chế.","anchor":"Thanh sắc đại thủ từ hư vô biến ảo mà ra"}]},"nguon":["@c0998"]},{"id":"thanh-sac-anh-hoa","name":"Thanh sắc anh hỏa","cn":"","loai":"than-thong","loaiLabel":"Anh hỏa","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Anh hỏa màu xanh do Hàn Lập phun ra, dùng để luyện hóa quang cầu và vân hà trong cấm chế.","detail":"Trong ảo thuật cấm chế tại cự thạch, Hàn Lập phun thanh sắc anh hỏa bao phủ quang cầu, luyện hóa mây hư ảo thành viên châu hoặc khiến mây tan biến.","congNang":["Luyện hóa vật ẩn trong ảo cấm thành viên châu phá trận @c0998"],"tabs":{"tienTrinh":[{"chuong":"@c0998","loai":"thi triển","importance":"normal","giaiDoan":"Luyện hóa vân hà","text":"Hàn Lập phun thanh sắc anh hỏa để luyện hóa quang cầu trong ảo cấm.","anchor":"một đoàn thanh sắc anh hỏa phún xuất ra"}]},"nguon":["@c0998"]},{"id":"tang-vat-hoa-hinh","name":"Tàng vật hóa hình","cn":"","loai":"bi-thuat","loaiLabel":"Thủ đoạn cấm pháp","phamCap":"thượng cổ","hePhai":"Thượng cổ tu sĩ","soHuu":["Thượng cổ tu sĩ Côn Ngô sơn"],"blurb":"Thủ đoạn giấu vật thành hình cực tinh vi, khiến vật thật bị biến hóa trong ảo cấm.","detail":"Hàn Lập nhận định thủ đoạn giấu vật thành hình trong cấm chế ở cự thạch rất cao minh, chỉ thượng cổ tu sĩ mới có thể sở hữu, liên quan trực tiếp tới các đóa mây hóa thành châu phá trận.","dacDiem":"Thủ đoạn thượng cổ, dùng để che giấu vật thật dưới hình thái biến ảo.","congNang":["Giấu vật thật dưới hình thái biến hóa trong ảo thuật cấm chế @c0998"],"tabs":{"tienTrinh":[{"chuong":"@c0998","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhận diện thủ đoạn phá cấm","text":"Hàn Lập nhận ra cấm chế dùng thủ đoạn tàng vật hóa hình rất cao minh của thượng cổ tu sĩ.","anchor":"Thủ đoạn tàng vật hóa hình cao minh bậc này"}]},"nguon":["@c0998"]},{"id":"dinh-giai-huyen-hoa-chi-thuat","name":"Đỉnh giai Huyễn Hóa Chi Thuật","cn":"","loai":"than-thong","loaiLabel":"Ảo thuật cấm chế","phamCap":"đỉnh giai","hePhai":"Thượng cổ cấm chế","soHuu":["Thượng cổ tu sĩ Côn Ngô sơn"],"blurb":"Loại huyễn thuật cấp cao mà linh mục hiện tại của Hàn Lập chưa thể nhìn thấu trực tiếp.","detail":"Hàn Lập tự xét nếu tiếp tục tăng cường linh mục bằng minh thanh linh dịch hơn trăm năm nữa thì có thể khám phá loại đỉnh giai Huyễn Hóa Chi Thuật này.","dacDiem":"Cần linh mục rất mạnh mới có thể nhìn thấu.","congNang":["Che giấu chân tướng cấm chế đến mức linh mục hiện tại của Hàn Lập chưa đủ khám phá @c0998"],"tabs":{"tienTrinh":[{"chuong":"@c0998","loai":"nhắc tới","importance":"normal","giaiDoan":"Đánh giá ảo thuật cấm chế","text":"Hàn Lập cho rằng linh mục nếu được tăng cường lâu dài mới có thể khám phá loại đỉnh giai Huyễn Hóa Chi Thuật này.","anchor":"cũng có thể khám phá loại đỉnh giai Huyễn Hóa Chi Thuật này rồi"}]},"nguon":["@c0998"]},{"id":"thuong-co-ao-thuat-cam-che-tai-cu-thach","name":"Thượng cổ ảo thuật cấm chế tại cự thạch","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"thượng cổ","hePhai":"Côn Ngô Sơn","soHuu":["Thượng cổ tu sĩ Côn Ngô sơn"],"blurb":"Ảo thuật cấm chế vây khốn nhóm Hàn Lập khi tiến gần cự thạch có linh thảo.","detail":"Cấm chế khiến ba người rơi vào ảo cảnh từ lúc tới gần cự thạch; hành động hái linh thảo giả kích phát phần pháp trận lợi hại nhất. Hàn Lập chỉ tạm bài trừ chứ chưa phá hủy hoàn toàn.","congNang":["Vây khốn tu sĩ trong ảo cảnh @c0998","Biến ảo pháp khí thành linh thảo giả để dẫn dụ người chạm bẫy @c0998"],"tabs":{"tienTrinh":[{"chuong":"@c0998","loai":"xuất hiện","importance":"normal","giaiDoan":"Vây khốn và bị tạm phá","text":"Cấm chế tại cự thạch vây khốn ba người Hàn Lập và bị hắn tạm phá bằng năm viên châu ngũ sắc.","anchor":"cũng đã bước vào một loại ảo thuật cấm chế rồi"}]},"nguon":["@c0998"]},{"id":"nghich-tinh-doan-thien","name":"Nghịch Tình Đoạn Thiên","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"Âm La tông","soHuu":["Kiền lão ma"],"blurb":"Ma công Kiền lão ma tu luyện, được Phú lão giả nhận ra trong lúc lão ma bị kích động sát khí.","detail":"Công pháp này chú trọng thuận theo tình tính, khiến lời uy hiếp của Phú lão giả và Bạch Dao Di có thể phản tác dụng, làm Kiền lão ma càng bị kích phát sát ý khi đối đầu Hàn Lập.","thuocTinh":"ma đạo","dacDiem":"Chú trọng dẫn động tình tính, có thể khiến người luyện càng dễ bị kích phát khi bị chọc giận.","nguoiTu":[{"ten":"Kiền lão ma","tuChuong":"@c0999","tangDatToi":"không rõ","trangThai":"đang tu luyện"}],"congNang":["Kích phát hoặc thuận theo tình tính của người luyện, khiến sát khí Kiền lão ma bùng lên khi bị uy hiếp @c0999"],"tabs":{"tienTrinh":[{"chuong":"@c0999","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Phú lão giả nhận ra","text":"Phú lão giả nhận ra Kiền lão ma luyện Nghịch Tình Đoạn Thiên, nên lời uy hiếp trước đó đã phản tác dụng và làm lão ma nổi sát khí.","anchor":"Công pháp này tối chú ý dẫn suất tính nhi vi"}]},"capNhatToi":"@c0999","nguon":["@c0999"]},{"id":"khoi-loi-dai-tran","name":"Khôi lỗi đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp khôi lỗi","phamCap":"","hePhai":"","soHuu":["Cổ ma Hàn Lập"],"blurb":"Khôi lỗi đại trận là trận pháp khôi lỗi được Cổ ma Hàn Lập nhận ra qua ghi chép cổ, có thể liên tục phóng xuất khôi lỗi để tiêu hao địch thủ.","detail":"Trong cự điện Côn Ngô sơn, trận này khiến các khôi lỗi thú cầm từ hành lang liên tục tràn ra, thân cứng và còn có thể phun pháp thuật đơn giản. Cổ ma Hàn Lập chỉ điểm Diệp gia phá các then chốt tại thiên điện, nhờ đó cắt nguồn khôi lỗi; nếu cố thủ tại chỗ, người trong trận sẽ dần bị tiêu hao pháp lực đến chết.","nguon":["@c1000"]},{"id":"cam-khong-cam-che-con-ngo-son","name":"Cấm không cấm chế","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"","hePhai":"Côn Ngô sơn","soHuu":[],"blurb":"Cấm không cấm chế xuất hiện tại khu gần trung tâm Côn Ngô sơn, chuyên ngăn tu sĩ phi hành.","detail":"Khi đội Diệp gia định bay lên quảng trường bạch ngọc để quan sát các lối rẽ, cấm chế này lập tức phát tác khiến mọi người rơi xuống. Sự tồn tại của nó vừa làm chậm bước tiến của Diệp gia, vừa cho thấy họ đã thật sự bước vào khu vực trọng yếu của Côn Ngô sơn.","nguon":["@c1000"]},{"id":"ao-tran-tu-bao-phong-an-loi-ra","name":"Ảo trận tự bạo phong ấn lối ra","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Côn Ngô sơn","soHuu":[],"blurb":"Ảo trận tự bạo phong ấn lối ra là cấm chế khiến thông đạo ra vào bị hủy trong ngắn hạn. Biến cố này buộc các nhóm tu sĩ tiếp tục tiến sâu trong Côn Ngô sơn.","detail":"Sau khi ảo trận tự bạo, phong ấn lối ra bị phá hủy khiến thông đạo tạm thời không thể ra vào. Hàn Lập tự kiểm tra ngân quang và xác nhận tình trạng không thể thông hành.","congNang":["Phong tỏa thông đạo ra vào trong thời gian ngắn sau khi tự bạo @c1001"],"tabs":{"tienTrinh":[{"chuong":"@c1001","loai":"xuất hiện","importance":"normal","giaiDoan":"Lối ra bị khóa","text":"Ảo trận tự bạo làm phong ấn lối ra bị hủy, khiến thông đạo trong thời gian ngắn không thể ra vào.","anchor":"ảo trận tự bạo phong ấn lối ra bị hủy"}]},"nguon":["@c1001"]},{"id":"tu-vi-that-tinh-dai-tran","name":"Tử Vi Thất Tinh đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"đắt giá","hePhai":"Diệp gia","soHuu":["Diệp gia","Đại trưởng lão Diệp gia","Phong Thiên Hành"],"blurb":"Bộ trận pháp đắt giá còn lại của Diệp gia khi các khí cụ bố trận khác đã dùng hết. Ở Côn Ngô Sơn, nó được bố trí tại quảng trường để chặn truy binh.","detail":"Nho sinh Diệp gia sai lão giả họ Phong đem Tử Vi Thất Tinh trận bày tại quảng trường, đồng thời thả đầu hổ phong và hai hấp huyết bức vào trong trận để tăng khả năng chặn hậu.","nguon":["@c1002"],"congNang":["Chặn truy binh khi phối hợp đầu hổ phong và hấp huyết bức @c1002"],"trangThai":"được bố trí tại quảng trường @c1002","capNhatToi":"@c1002","tabs":{"tienTrinh":[{"chuong":"@c1002","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí chặn hậu","text":"Diệp gia dùng bộ trận còn lại này đặt tại quảng trường để cản nhóm truy kích.","anchor":"vậy đem bộ Tử Vi Thất Tinh trận bày bố tại đây đi"}]}},{"id":"ao-tran-diep-gia-o-van-tu-chi-mon","name":"Ảo trận Diệp gia ở Vạn Tu chi môn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"có thể vây Kết Đan kỳ vài ngày","hePhai":"Diệp gia","soHuu":["Diệp gia"],"blurb":"Ảo trận Diệp gia bố trí tại eo núi sau Vạn Tu chi môn. Trận đủ vây Kết Đan kỳ vài ngày nhưng bị nhiều Nguyên Anh tu sĩ phá rất nhanh.","detail":"Đoàn Hàn Lập xuyên qua Vạn Tu chi môn thì gặp ảo trận Diệp gia. Vì có nhiều tu sĩ Nguyên Anh liên thủ, trận này bị phá gần như tức thì, khiến truy binh tiếp tục lên núi.","nguon":["@c1002"],"congNang":["Vây khốn tu sĩ Kết Đan kỳ trong vài ngày nếu không có nhiều Nguyên Anh liên thủ @c1002"],"trangThai":"đã bị phá @c1002","capNhatToi":"@c1002","tabs":{"tienTrinh":[{"chuong":"@c1002","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phá khi truy kích","text":"Ảo trận tại eo núi bị nhóm Nguyên Anh tu sĩ phá nhanh sau khi họ vượt Vạn Tu chi môn.","anchor":"tối thiểu cũng có thể vây khốn vài ngày"}]}},{"id":"bi-thuat-thach-linh-thuong-co","name":"Bí thuật thạch linh thượng cổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"thượng cổ thất truyền","hePhai":"Thượng cổ tu sĩ","soHuu":[],"blurb":"Bí thuật thượng cổ dùng để nhốt tinh hồn yêu thú vào thạch tượng đặc chế. Hàn Lập cho rằng các mảnh vụn trong thạch điện có thể liên quan đến bí thuật này.","detail":"Theo Hàn Lập, thạch linh không phải thạch khôi lỗi thông thường, trọng yếu nằm ở việc dùng bí thuật cưỡng ép tinh hồn yêu thú vào thạch tượng, phối hợp ký hiệu pháp trận trên mảnh đá để thành vật có thể hoạt động.","nguon":["@c1002"],"thuocTinh":"khôi lỗi thuật thượng cổ","nguonGoc":"Thời thượng cổ @c1002","congNang":["Cưỡng ép tinh hồn yêu thú vào thạch tượng đặc chế để tạo thạch linh @c1002"],"trangThai":"thất truyền @c1002","capNhatToi":"@c1002","tabs":{"tienTrinh":[{"chuong":"@c1002","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập nhận định","text":"Hàn Lập giải thích mảnh vụn trong thạch điện có thể là dấu vết của bí thuật tạo thạch linh thời thượng cổ.","anchor":"dùng một bí thuật nào đó cường hành nhốt vào trong một ít thạch tượng"}]}},{"id":"khon-linh-tran","name":"Khốn Linh trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Côn Ngô Sơn","soHuu":["Ba hậu nhân Côn Ngô"],"blurb":"Trận pháp từng được ba hậu nhân Côn Ngô dùng để giam giữ các yêu vật trong núi. Dù các yêu vật đã thoát khỏi trận, ràng buộc với bổn mệnh bài vẫn khiến chúng chưa thể rời Côn Ngô Sơn.","detail":"Phụ nhân áo đen nói ba hậu nhân Côn Ngô từng dùng Khốn Linh trận giam chúng để bắt bảo hộ núi. Ngân Sí Dạ Xoa bổ sung rằng nếu không thu hồi bổn mệnh bài, chúng dù thoát trận cũng không thể rời Côn Ngô Sơn.","nguon":["@c1002"],"congNang":["Giam giữ và ràng buộc các yêu vật với Côn Ngô Sơn @c1002"],"trangThai":"các yêu vật đã thoát trận nhưng còn bị bổn mệnh bài ràng buộc @c1002","capNhatToi":"@c1002","tabs":{"tienTrinh":[{"chuong":"@c1002","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ ràng buộc yêu vật","text":"Phụ nhân áo đen và Ngân Sí Dạ Xoa nhắc việc Khốn Linh trận từng giam giữ chúng tại Côn Ngô Sơn.","anchor":"chúng ta mặc dù thoát ra khỏi Khốn Linh trận"}]}},{"id":"bao-huyet-chu","name":"Bạo huyết chú","cn":"","loai":"bi-thuat","loaiLabel":"Chú thuật","phamCap":"Cổ tu chú thuật","hePhai":"Đám cổ tu năm xưa","soHuu":["Đám cổ tu năm xưa"],"blurb":"Bạo huyết chú là chú thuật từng được đám cổ tu hạ lên nhóm yêu vật bị phong ấn trong Côn Ngô sơn. Nó hủy hoại thần trí, khiến nạn nhân biến thành cuồng vật khát máu nếu không có Thanh Hư đan bảo trì.","detail":"Trong lời Ngân Sí Dạ Xoa, bạo huyết chú là nguyên nhân khiến các yêu vật bị phong ấn năm xưa có nguy cơ mất thần trí. Xú phụ nhân nhờ nửa viên Thanh Hư đan nên tránh được kết cục hóa thành kẻ điên khát máu.","thuocTinh":"Chú thuật hại thần trí","nguonGoc":"Đám cổ tu năm xưa","congNang":["Hủy hoại thần trí của người trúng chú, có thể khiến nạn nhân biến thành cuồng vật khát máu @c1003"],"uyLuc":"Đủ khiến các yêu vật bị phong ấn mất thần trí nếu không có Thanh Hư đan bảo trì.","dinhDanh":"goc","capNhatToi":"@c1003","tabs":{"tienTrinh":[{"chuong":"@c1003","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ quá khứ phong ấn","text":"Ngân Sí Dạ Xoa nhắc lại việc đám cổ tu năm xưa hạ bạo huyết chú lên nhóm yêu vật, khiến thần trí họ có nguy cơ hóa ngu ngốc và khát máu.","anchor":"Năm đó đám cổ tu kia đã hạ bạo huyết chú trên người chúng ta"}]},"nguon":["@c1003"]},{"id":"tran-tu-truc-lam-con-ngo","name":"Trận tử trúc lâm Côn Ngô","cn":"","aliases":["Trận tử trúc lâm Côn Ngô chưa rõ tên"],"loai":"khac","loaiLabel":"Cấm chế pháp trận","phamCap":"Cấm chế Côn Ngô sơn","hePhai":"Côn Ngô sơn","soHuu":[],"blurb":"Trận tử trúc lâm Côn Ngô là cấm chế chặn đường tại trọng địa Côn Ngô sơn. Rừng tử trúc che kín quảng trường bạch ngọc, tỏa tử khí và linh áp kinh người, có thể phản kích khi bị công phá.","detail":"Pháp trận hiện dưới dạng rừng tử trúc lớn cỡ vòng tay ôm, trải khắp tầm mắt và che khuất quảng trường bạch ngọc. Khi bị Kiền lão ma cùng nhóm tu sĩ công kích, trận phóng bảy đạo tử sắc quang trụ, hóa tử khí thành sóng tím chống lại hàn khí xám và các bảo vật.","thuocTinh":"Tử khí, cấm chế phòng hộ","nguonGoc":"Cấm chế ở trọng địa Côn Ngô sơn","congNang":["Chặn đường vào quảng trường bạch ngọc ở trọng địa Côn Ngô sơn @c1003","Phản kích bằng tử sắc quang trụ và sóng tử khí khi bị công phá @c1003"],"uyLuc":"Được Hoa Thiên Kỳ nhận định lợi hại hơn Băng Diễm Lưỡng Cực trận.","dinhDanh":"goc","capNhatToi":"@c1003","tabs":{"tienTrinh":[{"chuong":"@c1003","loai":"xuất hiện","importance":"normal","giaiDoan":"Chặn đường trọng địa","text":"Trận tử trúc lâm hiện ra trước nhóm Hàn Lập, che kín quảng trường bạch ngọc và buộc nhóm tu sĩ phải hợp lực công phá.","anchor":"Cả mảng rừng đều là tử trúc (trúc tím) lớn cỡ một vòng tay người ôm"}]},"nguon":["@c1003"]},{"id":"ao-tran-tu-bao","name":"Ảo trận tự bạo","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp tự bạo làm lộ khe nứt rộng mấy trượng trước mặt các tu sĩ, đồng thời khiến thông đạo phong ấn trở nên nguy hiểm hơn.","detail":"Sau khi ảo trận tự bạo, lối vào phong ấn dưới lòng đất phương bắc hiện ra thành khe nứt rộng mấy trượng. Biến cố này mở đường cho các phe lớn tiếp cận phong ấn, nhưng ngân quang và dao động cấm chế quanh khe nứt cũng khiến tán tu và thế lực nhỏ phải tránh xa.","nguon":["@c1004"]},{"id":"tro-chu-hoa-tien-tong","name":"Trớ chú Hóa Tiên tông","cn":"","loai":"cong-phap","loaiLabel":"Pháp chú","phamCap":"","hePhai":"Hóa Tiên tông","soHuu":["Mộc phu nhân","Hóa Tiên tông"],"blurb":"Trớ chú âm độc nổi danh của Hóa Tiên tông, được nhắc là có thể cách xa ngoài ngàn dặm giết người vô hình.","detail":"Hóa Tiên tông ở Nam Cương nổi tiếng nhờ công pháp và trớ chú khó phòng. Mộc phu nhân từng có truyền thuyết dùng pháp chú giết ba tu sĩ cùng cấp ở các nơi khác nhau trong một ngày, khiến danh tiếng loại trớ chú này trở thành uy hiếp lớn đối với tu sĩ đồng giai.","nguon":["@c1004"]},{"id":"ngu-sac-linh-quang-linh-te-khong-tuoc","name":"Ngũ sắc linh quang của Linh Tê khổng tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông linh cầm","phamCap":"","hePhai":"Thiên Lan thảo nguyên","soHuu":["Đại tiên sư họ Từ","Linh Tê khổng tước"],"blurb":"Linh quang trời sinh của Linh Tê khổng tước, có khả năng ngăn cách thiên địa linh khí để mở đường qua khe nứt phong ấn.","detail":"Đại tiên sư họ Từ thả Linh Tê khổng tước ra từ túi linh thú, dùng ngũ sắc linh quang của linh cầm làm lớp mở đường trước ngân sắc hà quang. Nhờ khả năng ngăn cách thiên địa linh khí, nhóm Nguyên Anh của Âm La tông và Thiên Lan có thể cưỡng vượt khe nứt tiến vào phong ấn.","nguon":["@c1004"]},{"id":"tu-vi-tinh-tran","name":"Tử Vi Tinh trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Côn Ngô sơn","soHuu":[],"blurb":"Đại trận trong Côn Ngô sơn với tử vụ, ảo ảnh và nhiều quang trụ làm mắt trận. Chương này bị nhóm Hàn Lập liên thủ phá trừ.","detail":"Tử Vi Tinh trận dùng tử sắc quang trụ, tử vụ, linh trùng linh thú bị bồi dưỡng và ảo thuật cấm chế để ngăn người xâm nhập. Khi các quang trụ lần lượt bị phá, toàn bộ đại trận tan đi.","trangThai":"bị phá","capNhatToi":"@c1005","congNang":["Tạo tử vụ, ảo ảnh và cấm chế che giấu lối đi trong Côn Ngô sơn @c1005","Dùng các quang trụ làm mắt trận; khi quang trụ bị phá, đại trận suy sụp @c1005"],"tabs":{"tienTrinh":[{"chuong":"@c1005","loai":"nhắc tới","importance":"major","giaiDoan":"Bị phá trừ","text":"Nhóm Hàn Lập liên thủ phá hủy các tử sắc quang trụ khiến Tử Vi Tinh trận tan hoàn toàn.","anchor":"tòa đại trận này có thể xưng là thần diệu rốt cuộc bị bọn họ liên thủ phá trừ"}]},"nguon":["@c1005"]},{"id":"linh-muc-lam-mang-cua-han-lap","name":"Linh mục lam mang của Hàn Lập","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông phá ảo","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông linh mục khiến mắt Hàn Lập lóe lam mang để nhìn xuyên huyễn thuật. Trong Tử Vi Tinh trận, nó giúp hắn xác định vị trí thật của quang trụ.","detail":"Khi tử sắc cự trúc và trúc ảnh chồng lớp che giấu quang trụ, Hàn Lập vận lam mang trong mắt để nhìn phá ảo thuật cấm chế, từ đó khóa đúng mục tiêu phá trận.","thuocTinh":"phá ảo","congNang":["Nhìn xuyên ảo thuật cấm chế quanh quang trụ trong Tử Vi Tinh trận @c1005"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1005","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1005","loai":"thi triển","importance":"normal","giaiDoan":"Phá ảo quang trụ","text":"Hàn Lập thi triển linh mục lam mang để nhìn phá tử trúc huyễn thuật che giấu quang trụ.","anchor":"Hàn Lập không chút nghĩ ngợi lam mang trong mắt chớp động"}]},"nguon":["@c1005"]},{"id":"ao-thuat-cam-che-quanh-quang-tru","name":"Ảo thuật cấm chế quanh quang trụ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế huyễn thuật","phamCap":"không rõ","hePhai":"Tử Vi Tinh trận","soHuu":[],"blurb":"Lớp huyễn thuật xuất hiện khi Hàn Lập tới gần quang trụ trong Tử Vi Tinh trận. Tử sắc cự trúc và trúc ảnh trùng điệp dùng để che giấu vị trí thật của quang trụ.","detail":"Cấm chế khiến tử sắc cự trúc hiện lại quanh quang trụ, tạo nhiều trúc ảnh đan xen làm người phá trận khó xác định mục tiêu. Hàn Lập dùng linh mục lam mang nhìn xuyên và phá giải.","thuocTinh":"huyễn thuật","congNang":["Che giấu vị trí thật của quang trụ bằng tử sắc cự trúc và trúc ảnh @c1005"],"tabs":{"tienTrinh":[{"chuong":"@c1005","loai":"xuất hiện","importance":"normal","giaiDoan":"Che quang trụ","text":"Ảo thuật cấm chế quanh quang trụ hiện ra để cản Hàn Lập phá trận nhưng bị linh mục nhìn phá.","anchor":"tử sắc cự trúc vốn đã biến mất sau khi hắn tiến vào trận chợt ở xunh quanh quang trụ xuất hiện"}]},"nguon":["@c1005"]},{"id":"hoang-quang-phap-tran-tu-guong-dong","name":"Hoàng quang pháp trận từ gương đồng","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp trấn áp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Pháp trận kỳ quái do gương đồng gần cự vật phóng ra. Các cột hoàng quang đan xen để trấn áp tồn tại khổng lồ bị xiềng xích và cấm phù vây nhốt.","detail":"Trong không gian giam cự vật, gương đồng nhỏ phóng từng đạo hoàng quang trụ tạo thành pháp trận. Pháp trận này cùng cấm phù, xiềng xích và nhiều tầng cấm chế khóa chặt cự vật.","thuocTinh":"trấn áp","congNang":["Dùng các cột hoàng quang tạo pháp trận kỳ quái để nhốt cự vật @c1005"],"tabs":{"tienTrinh":[{"chuong":"@c1005","loai":"xuất hiện","importance":"normal","giaiDoan":"Trấn áp cự vật","text":"Hoàng quang pháp trận từ gương đồng được hé lộ trong không gian giam cự vật.","anchor":"phóng ra từng đạo hoàng quang trụ (cột ánh sáng màu vàng) tạo thành một pháp trận kỳ quái"}]},"nguon":["@c1005"]},{"id":"dai-phap-tran-quanh-cung-dien","name":"Đại pháp trận quanh cung điện","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp kiến trúc","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Đại pháp trận lấy cung điện thần bí làm trung tâm. Xung quanh pháp trận có tám mươi mốt tế đàn nhỏ thờ bạch ngọc thạch nhân mặc kim giáp.","detail":"Cung điện trong không gian linh khí sung mãn được xây ngay tại trung tâm một pháp trận lớn, tạo bố cục cổ xưa và quỷ dị. Các tế đàn quanh đó khiến nơi này giống một trung tâm nghi thức hoặc cơ quan cổ.","thuocTinh":"bố trí kiến trúc cổ","congNang":["Đặt cung điện thần bí vào trung tâm bố cục pháp trận lớn @c1005"],"tabs":{"tienTrinh":[{"chuong":"@c1005","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ bố cục","text":"Đại pháp trận quanh cung điện được hé lộ cùng tám mươi mốt tế đàn nhỏ.","anchor":"cung điện này không ngờ lại được xây tại trung tâm của một tòa pháp trận to lớn"}]},"nguon":["@c1005"]},{"id":"an-nac-thuat-cua-ngan-si-da-xoa","name":"Ẩn nặc thuật của Ngân Sí Dạ Xoa","cn":"","loai":"than-thong","loaiLabel":"Thần thông ẩn thân","phamCap":"Không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thần thông che giấu thân hình do Ngân Sí Dạ Xoa thi triển.","detail":"Xú phụ nhân đánh giá trong ba yêu vật thì ẩn nặc thuật của Ngân Sí Dạ Xoa cao minh nhất. Hắn rung cánh phóng ngân hà cuốn cả ba yêu vật vào trong, giúp cả nhóm biến mất khỏi tầm mắt.","congNang":["Ẩn giấu cả nhóm ba yêu vật bằng ngân hà từ cánh @c1006"],"tabs":{"tienTrinh":[{"chuong":"@c1006","loai":"thi triển","importance":"normal","giaiDoan":"Che giấu nhóm yêu vật","text":"Ngân Sí Dạ Xoa dùng ngân hà từ cánh cuốn cả ba yêu vật, khiến chúng biến mất khỏi quảng trường.","anchor":"trong ba người chúng ta, ẩn nặc thuật của ngươi là cao minh nhất"}]},"nguon":["@c1006"]},{"id":"cam-che-bach-sac-quang-mac-cua-chu-linh-duong","name":"Cấm chế bạch sắc quang mạc của Chú Linh đường","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Côn Ngô Sơn","soHuu":[],"blurb":"Cấm chế quang mạc trắng bao quanh khu Chú Linh đường.","detail":"Quang mạc trắng bao kín trang viên Chú Linh đường. Phi kiếm của Hàn Lập chỉ chém sâu mấy thước rồi quang mạc tự khôi phục, buộc hắn phải dùng Tam Diễm Phiến mở lối.","congNang":["Tự khôi phục sau khi bị phi kiếm chém vào @c1006"],"tabs":{"tienTrinh":[{"chuong":"@c1006","loai":"xuất hiện","importance":"normal","giaiDoan":"Cản lối vào Chú Linh đường","text":"Cấm chế bạch sắc quang mạc ngăn Hàn Lập tiến vào Chú Linh đường và tự khôi phục sau đòn thử bằng phi kiếm.","anchor":"Bạch sắc quang mạc bị phá vỡ một chút, nhưng liền khôi phục lại bộ dáng ban đầu"}]},"nguon":["@c1006"]},{"id":"phap-tran-khong-che-hoa-tru-trong-dai-dien","name":"Pháp trận khống chế hỏa trụ trong đại điện","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Pháp trận cỡ trung nằm dưới nền đại điện, duy trì các hỏa trụ phun hồng hà nung luyện cự đỉnh.","detail":"Trận pháp này khống chế mười mấy hỏa trụ trong đại điện, khiến các cột lửa liên tục phun hồng hà về phía cự đỉnh ở trung tâm. Trận nhãn là một trận bàn chôn ở góc điện; khi Hàn Lập dùng kim sắc tiểu kiếm phá hủy trận bàn, hỏa trụ ngừng phun hồng hà và pháp trận dưới đất cũng đình chỉ vận chuyển.","nguon":["@c1007"]},{"id":"vong-bao-ho-thuy-thuoc-tinh","name":"Vòng bảo hộ thủy thuộc tính","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Vòng bảo hộ màu lam do Hàn Lập dùng lam sắc trận kỳ bố trí, có tác dụng thu liễm khí nóng trong đại điện.","detail":"Trước khi mở cự đỉnh, Hàn Lập cắm một sấp lam sắc trận kỳ vào các góc đại điện rồi khởi chú, tạo ra một tầng vòng bảo hộ màu lam bao lấy cả hắn và cự đỉnh. Vòng bảo hộ này làm khí tức nóng rực trong điện bị thu liễm bớt, hỗ trợ hắn chuẩn bị đối phó biến hóa khi mở đỉnh.","nguon":["@c1007"]},{"id":"bach-sac-han-khi-cua-luc-duc-suong-cong","name":"Bạch sắc hàn khí của Lục dực sương công","cn":"","loai":"than-thong","loaiLabel":"Thần thông linh trùng","phamCap":"","hePhai":"","soHuu":["Lục dực sương công"],"blurb":"Hàn khí màu trắng do Lục dực sương công phun ra, dùng để áp chế hỏa diễm của cự đỉnh.","detail":"Một đôi Lục dực sương công đã tiến hóa được Hàn Lập thả ra canh giữ phía trên cự đỉnh. Khi xích hồng hỏa điểu hiện ra chống lại Tử La Cực Hỏa, chúng phun bạch sắc hàn khí từ không trung bao phủ hỏa điểu và thân đỉnh, phối hợp với bàn tay tím bóp nát hỏa điểu, đồng thời khiến cự đỉnh bị đông thành một khối băng.","nguon":["@c1007"]},{"id":"thai-am-chan-hoa","name":"Thái Âm Chân Hỏa","cn":"太阴真火","loai":"than-thong","loaiLabel":"Chân linh chi hỏa","phamCap":"Một trong tam đại chân linh chi hỏa ở nhân giới","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Chân hỏa thoát ra từ cự đỉnh, ban đầu bị Hàn Lập nhận lầm là Thái Dương Tinh Hỏa.","detail":"Sau khi nắp cự đỉnh bị mở, một đạo xích mang kèm tiếng chim hót khó nghe bắn ra và toan xuyên thủng lam sắc quang mạc. Hàn Lập dùng thanh sắc kiếm khí làm nó suy yếu rồi bắt giữ bằng bàn tay tím. Một giọng nói trong thần thức cải chính nhận định của hắn, nói vật này không phải Thái Dương Tinh Hỏa mà là Thái Âm Chân Hỏa, nổi danh cùng Thái Dương Tinh Hỏa và thuộc một trong tam đại chân linh chi hỏa ở nhân giới.","nguon":["@c1007","@c1008","@c1089"],"tabs":{"tienTrinh":[{"chuong":"@c1008","loai":"xuất hiện","importance":"major","giaiDoan":"Được nhận diện và phong cấm","text":"Ngân Nguyệt xác nhận đoàn hỏa diễm đỏ là âm hỏa chi tinh cấp thấp của Thái Âm Chân Hỏa, còn Hàn Lập dùng tử diễm và kim sắc hồ quang phong thành kim cầu rồi thu vào xích hồng ngọc hạp.","anchor":"cùng thái dương tinh hỏa nổi danh, cùng liệt vào nhân giới tam đại chân linh chi hỏa"},{"chuong":"@c1089","loai":"thi triển","importance":"major","giaiDoan":"Thử nghiệm thành công trong Huyền Ngọc Động","text":"Hàn Lập bí mật bắn xích hồng hoả diễm vào nhũ bạch sắc hàn quang, Thái Âm chân hoả hấp thu hàn quang nhanh chóng như nước hoà sữa, chứng minh khắc chế được hàn khí thông linh mà Tử La Cực Hoả bất lực. Được xác nhận là một trong tam đại chân linh chi hoả.","anchor":"Luồng xích hồng hoả diễm này cùng luồng nhũ bạch sắc hàn quang vừa tiếp xúc, nhất thời nhanh chóng hấp thu hàn quang, giống như nước với sữa hoà tan"}]},"trangThai":"bị Hàn Lập phong cấm thu giữ","aliases":["âm hỏa chi tinh"],"congNang":["Có thể được bồi dưỡng làm chân hỏa chí âm chí hàn có linh tính @c1008","Có khả năng phối hợp hoặc dẫn tới hướng bắt giữ Thái Dương Tinh Hỏa @c1008","Khắc chế hàn khí thông linh Huyền Ngọc Động, hấp thu hàn quang cực nhanh"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1008","tangDatToi":"Mới có một tia linh tính","trangThai":"dang-tu-luyen"}]},{"id":"thai-duong-tinh-hoa","name":"Thái Dương Tinh Hỏa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Chân linh chi hỏa","phamCap":"Nhân giới tam đại chân linh chi hỏa","hePhai":"","soHuu":[],"blurb":"Chân hỏa được Ngân Nguyệt nhắc cùng Thái Âm Chân Hỏa trong chương này. Hai loại chân hỏa tương sinh tương khắc, có thể liên quan đến hướng tăng uy lực âm dương giao hội.","detail":"Ngân Nguyệt cho rằng Thái Âm Chân Hỏa và Thái Dương Tinh Hỏa tương sinh tương khắc, nếu có thể hấp thu thêm Thái Dương Tinh Hỏa thì uy lực về sau khó tưởng tượng. Hàn Lập nhớ Đại Diễn Thần Quân từng nói tu sĩ giới này khó bắt giữ loại tinh hỏa ấy.","thuocTinh":"chí dương","dacDiem":"Tương sinh tương khắc với Thái Âm Chân Hỏa.","trangThai":"được nhắc tới","capNhatToi":"@c1008","congNang":["Có thể cùng Thái Âm Chân Hỏa tạo thành hướng âm dương giao hội tăng uy lực @c1008"],"tabs":{"tienTrinh":[{"chuong":"@c1008","loai":"nhắc tới","importance":"normal","giaiDoan":"Khả năng âm dương giao hội","text":"Ngân Nguyệt nêu khả năng dùng Thái Âm Chân Hỏa để bắt giữ Thái Dương Tinh Hỏa, nhưng Hàn Lập tạm gác vì hiện chưa luyện hóa được chân hỏa vừa thu.","anchor":"thái âm chân hỏa này cùng thái dương tinh hỏa tương sinh tương khắc"}]},"nguon":["@c1008"]},{"id":"am-phach-ngung-hinh","name":"Âm Phách Ngưng Hình","cn":"","loai":"khac","loaiLabel":"Cảnh giới quỷ đạo","phamCap":"","hePhai":"Quỷ đạo","soHuu":["Ác quỷ trong Trấn Ma tháp"],"blurb":"Trạng thái tu luyện của ác quỷ trong Trấn Ma tháp sau nhiều vạn năm hấp thu âm khí, khiến chúng khó bị pháp thuật và pháp bảo bình thường tiêu diệt triệt để.","detail":"Các ác quỷ tóc đỏ trong Trấn Ma tháp đã đạt cảnh giới âm phách ngưng hình. Khi bị pháp bảo đánh nát thân thể, chúng vẫn có thể nhờ âm khí trong tháp hồi phục, làm nhóm Diệp gia khó xử lý bằng thủ đoạn thông thường.","nguon":["@c1009"]},{"id":"chi-duong-than-thong","name":"Chí Dương thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Minh Lễ hiền chất"],"blurb":"Thần thông thiên về chí dương của Minh Lễ, được nhắc là thích hợp dùng để đối phó ác quỷ âm khí trong Trấn Ma tháp.","detail":"Lão giả Diệp gia tiếc rằng Minh Lễ đã mất thân thể ở tầng trước, vì Chí Dương thần thông do Minh Lễ tu luyện vốn có thể khắc chế đám ác quỷ đã ngưng tụ âm phách trong tháp.","nguon":["@c1009"]},{"id":"am-anh-phun-sa-cua-o-anh-xa","name":"Ám ảnh phún sa của Ô ảnh xà","cn":"","loai":"khac","loaiLabel":"Yêu thuật","phamCap":"","hePhai":"","soHuu":["Ô ảnh xà"],"blurb":"Yêu thuật đánh lén của Ô ảnh xà, từng khiến Minh Lễ mất thân thể ở tầng trước Trấn Ma tháp.","detail":"Ô ảnh xà dùng ám ảnh phún sa từ trong bóng để tập kích Minh Lễ. Đòn này làm thân thể Minh Lễ nhanh chóng thối nát, cuối cùng chỉ còn Nguyên Anh thoát ra.","nguon":["@c1009"]},{"id":"kha-nang-tron-vao-bong-cua-o-anh-xa","name":"Khả năng trốn vào bóng của Ô ảnh xà","cn":"","loai":"khac","loaiLabel":"Yêu thuật","phamCap":"","hePhai":"","soHuu":["Ô ảnh xà"],"blurb":"Năng lực ẩn nấp của Ô ảnh xà, cho phép nó trốn trong cái bóng rồi bất ngờ phát động tập kích.","detail":"Diệp Nguyệt Thánh nói Ô ảnh xà có thể trốn vào trong bóng, nhờ vậy bất ngờ từ bóng của Minh Lễ đánh lén khiến cả ông cũng không kịp cứu viện.","nguon":["@c1009"]},{"id":"hai-truyen-tong-tran-den-trang","name":"Hai truyền tống trận đen trắng","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Độc Thánh môn"],"blurb":"Hai truyền tống trận một đen một trắng xuất hiện trong thạch thất dưới tầng, được Miêu sư đệ xác định là truyền tống trận cự ly ngắn.","detail":"Trong thạch thất nhỏ sau khi nhóm Hoa Thiên Kỳ đi xuống hơn mười trượng có hai pháp trận một đen một trắng. Miêu sư đệ kiểm tra và xác nhận chúng là truyền tống trận cự ly ngắn, khoảng cách không vượt quá trăm dặm; hắc trận đem lại cảm giác bất an nên Hoa Thiên Kỳ chọn bạch trận để đi tiếp.","nguon":["@c1010"]},{"id":"phap-tran-sieu-dai-duoi-cung-dien","name":"Pháp trận siêu đại dưới cung điện","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Pháp trận cực lớn nâng đỡ một cung điện kim bích cỡ nhỏ tại không gian như bồng lai tiên cảnh.","detail":"Sau khi đi qua bạch truyền tống trận, nhóm Hoa Thiên Kỳ tới một không gian linh khí nồng đậm, nơi có cung điện kim bích cỡ nhỏ tọa lạc trên một pháp trận siêu đại. Chung quanh pháp trận còn có nhiều tế đàn và các thạch nhân cầm kim sắc cự nhận, tạo nên bố cục kỳ dị tại điểm đến này.","nguon":["@c1010"]},{"id":"than-phap-quy-di-cua-thanh-nien-ho-tu","name":"Thân pháp quỷ dị của thanh niên họ Từ","cn":"","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"không rõ","hePhai":"Thiên Lan","soHuu":["Bạch bào thanh niên họ Từ"],"blurb":"Thân pháp tốc độ cao của bạch bào thanh niên họ Từ. Một bước có thể vượt xa, giúp hắn truy bám Hàn Lập trong lúc đối phương dùng Lôi độn.","detail":"Trong cuộc giao chiến trên bạch ngọc quảng trường, thanh niên họ Từ chỉ bước một bước đã xuất hiện ngoài mười trượng, tốc độ bám đuổi không kém Lôi độn của Hàn Lập. Thân pháp này được dùng để truy kích khi Hàn Lập lùi lên thềm đá.","thuocTinh":"độn pháp tốc độ cao","congNang":["Truy kích tốc độ cao trong chiến đấu @c1011"],"nguoiTu":[{"ten":"Bạch bào thanh niên họ Từ","tuChuong":"@c1011","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1011","loai":"thi triển","importance":"normal","giaiDoan":"Truy kích Hàn Lập","text":"Thanh niên họ Từ thi triển thân pháp một bước vượt hơn mười trượng, bám theo Hàn Lập khi hắn dùng Lôi độn.","anchor":"dáng vẻ không mảy may chậm hơn so với lôi độn của Hàn Lập"}]},"capNhatToi":"@c1011","nguon":["@c1011"]},{"id":"minh-linh-muc","name":"Minh Linh mục","cn":"","aliases":["Linh mục lam mang của Hàn Lập"],"loai":"than-thong","loaiLabel":"Thần thông linh mục","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Thần thông linh mục giúp Hàn Lập dùng lam mang trong mắt để nhìn thấu chỗ ẩn nấp. Tại đài cao trước sơn môn, nó giúp hắn phát hiện Ngân Sí Dạ Xoa cùng các bóng mờ sau thạch đôn.","detail":"Hàn Lập vận lam mang trong mắt để dò xét linh ba dị thường sau thạch đôn. Nhờ uy năng linh mục tăng mạnh, hắn nhìn ra hồng mục của Ngân Sí Dạ Xoa và các bóng mờ đang ẩn nấp cạnh chiến trường.","thuocTinh":"linh mục quan sát","uyLuc":"Có thể phát hiện kẻ ẩn nấp sau thạch đôn gần chiến trường.","dacDiem":"Lam mang lóe lên trong mắt khi thi triển.","congNang":["Phát hiện ẩn nấp và nhìn ra yêu mục cùng bóng mờ sau vật che khuất @c1012"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1012","tangDatToi":"dùng để phát hiện ẩn nấp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1012","loai":"thi triển","importance":"normal","giaiDoan":"Dò xét thạch đôn","text":"Hàn Lập dùng Minh Linh mục để kiểm tra linh ba bất thường và phát hiện Ngân Sí Dạ Xoa cùng hai bóng mờ ẩn nấp.","anchor":"trong mắt hắn nhất thời lam mang chợt lóe"}]},"capNhatToi":"@c1012","nguon":["@c1012"]},{"id":"vo-danh-liem-tuc-thuat","name":"Vô danh liễm tức thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Liễm tức ẩn nấp","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Bí thuật liễm tức giúp Hàn Lập che giấu khí tức khi tiếp cận chiến trường. Ngân Sí Dạ Xoa tới trước cũng chưa phát hiện ra hắn.","detail":"Hàn Lập dựa vào vô danh liễm tức thuật để thu liễm khí tức khi ẩn thân gần quảng trường bạch ngọc. Thuật này khiến yêu vật ẩn nấp như Ngân Sí Dạ Xoa cũng không nhận ra hắn ngay từ đầu.","thuocTinh":"ẩn nấp liễm tức","uyLuc":"Giúp tránh bị yêu vật phát hiện khi tiếp cận gần đài cao.","dacDiem":"Không nêu tên truyền thừa, chỉ cho thấy hiệu quả liễm tức cao minh.","congNang":["Thu liễm khí tức để tránh bị Ngân Sí Dạ Xoa phát hiện @c1012"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1012","tangDatToi":"thi triển khi ẩn nấp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1012","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn thân tiếp cận","text":"Hàn Lập nhờ vô danh liễm tức thuật cao minh nên chưa bị Ngân Sí Dạ Xoa phát hiện khi tới gần đài cao.","anchor":"Hàn Lập có vô danh liễm tức thuật thật cao minh"}]},"capNhatToi":"@c1012","nguon":["@c1012"]},{"id":"cam-che-dai-tran-thach-lam","name":"Cấm chế đại trận thạch lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"Côn Ngô điện","soHuu":[],"blurb":"Cấm chế đại trận đặt trong khu thạch lâm trước Côn Ngô điện. Đến khi Hàn Lập đi qua, nơi này đã bị phá hoại nghiêm trọng.","detail":"Thạch lâm gồm các cột đá có điêu khắc, văn phù và linh quang pháp chú, vốn là một cấm chế đại trận. Tuy nhiên phần lớn trận đã bị người khác dùng sức mạnh phá hủy, để lại đá vụn và hố đá rải rác.","thuocTinh":"cấm chế trận pháp","trangThai":"bị phá hủy @c1012","dacDiem":"Dấu tích cột đá, văn phù và linh quang pháp chú còn sót lại trong thạch lâm.","congNang":["Tạo khu cấm chế trước Côn Ngô điện, nhưng hiện đã bị phá hủy nặng @c1012"],"tabs":{"tienTrinh":[{"chuong":"@c1012","loai":"nhắc tới","importance":"normal","giaiDoan":"Dấu tích bị phá","text":"Hàn Lập đi qua thạch lâm và nhận ra nơi này vốn là cấm chế đại trận đã bị phá hỏng nghiêm trọng.","anchor":"Hiển nhiên thạch lâm là một cấm chế đại trận"}]},"capNhatToi":"@c1012","nguon":["@c1012"]},{"id":"quang-mac-dien-ho-tren-dai-cao","name":"Quang mạc điện hồ trên đài cao","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế quang mạc","phamCap":"không rõ","hePhai":"Côn Ngô điện","soHuu":[],"blurb":"Màng sáng lớn bao phủ khu chiến đấu trên đài cao trước sơn môn. Bề mặt có ngân sắc điện hồ, tự kích phát sấm sét khi bị tiếp cận hoặc công kích.","detail":"Quang mạc gần như phủ kín đài cao, bên trong đang diễn ra trận hỗn chiến giữa ngũ tử ma, trung niên tu sĩ và hai thanh đồng cự sư. Khi Hàn Lập dùng Tam Diễm phiến chém vào, quang mạc vang sấm sét và bộc phát điện hồ dày đặc.","thuocTinh":"lôi điện cấm chế","uyLuc":"Điện hồ tự động công kích và tạo trở ngại trước lối vào sơn môn.","dacDiem":"Mặt ngoài hiện ngân sắc điện hồ và phản ứng dữ dội khi bị tam sắc hỏa diễm đánh trúng.","congNang":["Bao phủ đài cao và dùng điện hồ cản người vượt qua @c1012"],"tabs":{"tienTrinh":[{"chuong":"@c1012","loai":"xuất hiện","importance":"normal","giaiDoan":"Chặn lối sơn môn","text":"Quang mạc điện hồ bao phủ khu đài cao và bị Hàn Lập dùng Tam Diễm phiến phá mở một lỗ hổng để xông vào.","anchor":"trên quang mạc lập tức vang lên tiếng sấm sét"}]},"capNhatToi":"@c1012","nguon":["@c1012"]},{"id":"cam-khong-cam-che-tren-dai-cao","name":"Cấm không cấm chế trên đài cao","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế hạn chế phi độn","phamCap":"không rõ","hePhai":"Côn Ngô điện","soHuu":[],"blurb":"Cấm chế trên khu đài cao khiến người xông qua phải chịu hạn chế khi phi độn. Hàn Lập phải dùng pháp lực mạnh mẽ đối kháng để vượt qua.","detail":"Sau khi phá quang mạc, Hàn Lập hóa thành độn quang lao qua đài cao nhưng bị cấm không cấm chế áp chế. Hắn dựa vào pháp lực mạnh mẽ để cưỡng ép đối kháng và tiếp tục tiến về phía bên kia quang mạc.","thuocTinh":"cấm không","uyLuc":"Hạn chế phi độn trên đài cao trước sơn môn.","congNang":["Áp chế người phi độn qua đài cao, buộc Hàn Lập dùng pháp lực đối kháng @c1012"],"tabs":{"tienTrinh":[{"chuong":"@c1012","loai":"xuất hiện","importance":"normal","giaiDoan":"Cản độn quang","text":"Cấm không cấm chế trên đài cao bị Hàn Lập dùng pháp lực mạnh mẽ cưỡng ép đối kháng khi hắn xông qua.","anchor":"Dùng pháp lực mạnh mẽ đối kháng cấm không cấm chế"}]},"capNhatToi":"@c1012","nguon":["@c1012"]},{"id":"thuat-tuy-phong-yem-hinh","name":"Thuật tùy phong yểm hình","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ẩn nấp","phamCap":"không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thuật ẩn hình của Ngân Sí Dạ Xoa, dùng để che giấu hành tung theo gió. Trong chương này, thuật bị Hàn Lập nhìn thấu và dùng kim hồ ép lộ cả nhóm yêu vật.","detail":"Ngân Sí Dạ Xoa tức giận vì Hàn Lập nhiều lần nhìn ra thuật tùy phong yểm hình. Lần này, Hàn Lập bắn kim hồ về phía thạch đôn khiến Ngân Sí Dạ Xoa, sư cầm thú và xú phụ phải hiện hình trước các tu sĩ.","dinhDanh":"goc","thuocTinh":"ẩn nấp","congNang":["Ẩn giấu hành tung của người thi triển nhưng vẫn có thể bị Hàn Lập nhìn thấu trong @c1013."],"tabs":{"tienTrinh":[{"chuong":"@c1013","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá ẩn nấp","text":"Thuật tùy phong yểm hình bị Hàn Lập nhìn ra, khiến nhóm Ngân Sí Dạ Xoa không thể tiếp tục ẩn mình.","anchor":"đối phương vì sao có thể nhiều lần nhìn ra được thuật tùy phong yểm hình"}]},"capNhatToi":"@c1013","nguon":["@c1013"]},{"id":"cam-che-trong-ap-tren-duong-da-trang","name":"Cấm chế trọng áp trên đường đá trắng","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Côn Ngô điện","soHuu":[],"blurb":"Cấm chế vô hình nằm trên đường đá trắng dẫn vào Côn Ngô điện. Nó không lộ dao động khi bị thần thức dò xét nhưng lập tức tạo trọng áp khi có người bước vào.","detail":"Hàn Lập đã kiểm tra sơn môn và khu vực xung quanh bằng thần thức mà không phát hiện dấu hiệu cấm chế. Khi đi được hơn mười trượng trên đường đá trắng, hắn bị trọng áp ép quỳ, càng cố chống lại thì trọng lực càng tăng mạnh.","dinhDanh":"goc","thuocTinh":"trọng áp","congNang":["Tạo trọng áp vạn cân lên người bước vào đường đá trắng trong @c1013.","Càng chống cự, trọng lực trên người càng tăng vọt trong @c1013."],"tabs":{"tienTrinh":[{"chuong":"@c1013","loai":"xuất hiện","importance":"normal","giaiDoan":"Ép Hàn Lập quỳ xuống","text":"Cấm chế trọng áp phát động khi Hàn Lập bước lên đường đá trắng, khiến hắn bị ép quỳ và khó đứng dậy.","anchor":"vừa đứng thẳng được một nửa, lại cảm thấy trọng lực trên người đột nhiên tăng vọt"}]},"capNhatToi":"@c1013","nguon":["@c1013"]},{"id":"cam-che-con-ngo-dien","name":"Cấm chế Côn Ngô điện","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Côn Ngô điện","soHuu":[],"blurb":"Cấm chế bảo vệ khu vực Côn Ngô điện, được Kiền lão ma nhận định không dễ phá trừ. Nó trở thành lý do khiến Kiền lão ma đề nghị trưởng lão Diệp gia tạm hợp lực.","detail":"Sau khi thấy Hàn Lập đi trước về phía Côn Ngô điện, Kiền lão ma cho rằng cấm chế nơi này không thể dễ dàng bị phá. Hắn đề nghị Diệp gia trưởng lão cùng phá cấm trước, chờ vào điện rồi mới dựa vào thủ đoạn của từng bên để đoạt bảo.","dinhDanh":"goc","thuocTinh":"phòng hộ","congNang":["Ngăn cản đường tiến vào Côn Ngô điện và buộc các phe phải cân nhắc hợp lực phá cấm trong @c1013."],"tabs":{"tienTrinh":[{"chuong":"@c1013","loai":"nhắc tới","importance":"normal","giaiDoan":"Thành mục tiêu hợp lực phá trừ","text":"Kiền lão ma lấy độ khó của cấm chế Côn Ngô điện làm lý do để đề nghị Diệp gia trưởng lão tạm hợp lực.","anchor":"Nếu cấm chế của Côn Ngô điện dễ phá trừ như thế"}]},"capNhatToi":"@c1013","nguon":["@c1013"]},{"id":"chu-thuat-hoa-tien-tong","name":"Chú thuật Hóa Tiên tông","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Hóa Tiên tông","soHuu":["Mộc phu nhân"],"blurb":"Bí thuật yểm chú của Hóa Tiên tông, được Mộc phu nhân nói có thể âm thầm trọng thương Kiền lão ma nếu lấy được tinh huyết mục tiêu.","detail":"Mộc phu nhân cho biết công pháp Hóa Tiên tông không thiện chính diện đối địch, nhưng nếu có chút tinh huyết của Kiền lão ma rồi lặng lẽ thi triển chú thuật thì bà có bảy tám phần nắm chắc khiến lão trọng thương.","congNang":["Dùng tinh huyết yểm chú để âm thầm trọng thương mục tiêu @c1014"],"nguoiTu":[{"ten":"Mộc phu nhân","tuChuong":"@c1014","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1014","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ công dụng","text":"Mộc phu nhân nêu chú thuật như thủ đoạn có thể trọng thương Kiền lão ma nếu lấy được tinh huyết của lão.","anchor":"lặng lẻ thi triển chú thuật, ta có bảy tám phần nắm chắc"}]},"nguon":["@c1014"]},{"id":"kim-tu-trong-quang","name":"Kim từ trọng quang","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế thiên nhiên","phamCap":"thượng cổ liên quan kim từ linh mộc","hePhai":"Côn Ngô Sơn","soHuu":[],"blurb":"Kim từ trọng quang là cấm chế do hai hàng kim từ linh mộc hai bên đường trước Côn Ngô điện sinh ra. Nó tạo trọng lực cực mạnh và khắc chế pháp bảo chứa kim chúc tính.","detail":"Bất kỳ người hoặc vật nào bước vào phạm vi ảnh hưởng của kim từ linh mộc đều bị trọng lực áp thân, khiến nửa bước khó đi. Pháp bảo kim chúc tính như trường giáo đỏ của Cát Thiên Hào bị kéo rơi xuống đất và khó thu hồi.","thuocTinh":"kim từ trọng lực","uyLuc":"Có thể khiến tu sĩ mạnh cũng khó di chuyển, còn linh xà thân thể cứng cỏi bị ép nát trong thời gian rất ngắn.","dacDiem":"Do hai hàng kim từ linh mộc tạo ra, có khả năng chồng chất trọng lực trong phạm vi nhiều cây.","congNang":["Tạo trọng lực áp thân khiến người bước vào phạm vi nửa bước khó đi @c1015","Kéo rơi và khắc chế pháp bảo chứa kim chúc tính @c1015"],"trangThai":"đang vận hành trước Côn Ngô điện","capNhatToi":"@c1015","tabs":{"tienTrinh":[{"chuong":"@c1015","loai":"xuất hiện","importance":"major","giaiDoan":"Cấm chế trước Côn Ngô điện","text":"Kim từ trọng quang được Ngân Sí Dạ Xoa nhận ra là cấm chế do hai hàng kim từ linh mộc sinh ra, ép Hàn Lập di chuyển từng bước nặng nề và kéo rơi pháp bảo kim chúc tính của Cát Thiên Hào.","anchor":"Bất luận kẻ nào bước một bước vào phạm vi ảnh hưởng của mấy cái linh mộc này"}]},"nguon":["@c1015"]},{"id":"minh-an-dai-quang-luan-hang-ma-chu","name":"Minh ấn đại quang luân hàng ma chú","cn":"","aliases":[],"loai":"khac","loaiLabel":"Phù chú thượng cổ","phamCap":"thượng cổ","hePhai":"không rõ","soHuu":[],"blurb":"Minh ấn đại quang luân hàng ma chú là phù chú thượng cổ được khắc trong mỗi cây kim từ linh mộc trước Côn Ngô điện. Hàn Lập và Ngân Nguyệt phát hiện điều này khi nhóm phía sau chuẩn bị đốn cây.","detail":"Phù chú nằm trong thân kim từ linh mộc nên nhóm Kiền lão ma không nhận ra nếu không có nhãn thuật đặc biệt. Việc đốn cây có thể tạo cơ hội cho ba yêu vật, khiến Hàn Lập cố ý không cảnh báo các phe phía sau.","nguonGoc":"thượng cổ","dacDiem":"Khắc ấn bên trong mỗi cây kim từ linh mộc.","congNang":["Ẩn trong kim từ linh mộc và liên quan tới hàng ma chú thượng cổ @c1015"],"trangThai":"ẩn trong hai hàng kim từ linh mộc","capNhatToi":"@c1015","tabs":{"tienTrinh":[{"chuong":"@c1015","loai":"xuất hiện","importance":"major","giaiDoan":"Bị Hàn Lập và Ngân Nguyệt phát hiện","text":"Hàn Lập nhờ Minh Thanh Linh Nhãn và lời nhắc của Ngân Nguyệt biết trong mỗi cây kim từ linh mộc có Minh ấn đại quang luân hàng ma chú, nhưng quyết định không cảnh báo nhóm phía sau.","anchor":"trong mỗi một cây đều có Minh ấn đại quang luân hàng ma chú của thời thượng cổ"}]},"nguon":["@c1015"]},{"id":"bi-thuat-quan-chu-ma-khi","name":"Bí thuật quán chú ma khí","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ma đạo","phamCap":"không rõ","hePhai":"Thánh tộc","soHuu":["Nguyên Sát thánh tổ hóa thân","Cổ ma"],"blurb":"Bí thuật ma đạo được cổ ma dùng làm điều kiện dụ Diệp Nguyệt Thánh phản bội Diệp gia. Nếu thành công, người được thi triển có thể chuyển hóa theo ma khí và tăng cơ hội tiến giai Hóa Thần kỳ.","detail":"Cổ ma hứa khi thánh tổ thoát khốn sẽ giúp Diệp Nguyệt Thánh thi triển bí thuật này, khiến đối phương về sau trở thành một thành viên của thánh tộc và có hi vọng tiến giai Hóa Thần.","thuocTinh":"Ma khí","uyLuc":"Có thể tạo cơ hội chuyển hóa và tiến giai Hóa Thần kỳ cho tu sĩ nhân giới theo lời cổ ma.","dacDiem":"Là điều kiện trao đổi khiến Diệp Nguyệt Thánh chấp nhận phản bội Diệp gia.","congNang":["Quán chú ma khí để tăng cơ hội tiến giai Hóa Thần kỳ @c1016"],"nguon":["@c1016"],"capNhatToi":"@c1016","tabs":{"tienTrinh":[{"chuong":"@c1016","loai":"nhắc tới","importance":"normal","giaiDoan":"Lời hứa của cổ ma","text":"Cổ ma dùng bí thuật quán chú ma khí làm điều kiện dụ Diệp Nguyệt Thánh phản bội Diệp gia.","anchor":"thánh tổ liền có thể giúp cho các hạ thi triển bí thuật quán chú ma khí"}]}},{"id":"bi-thuat-cau-thong-than-hon-thanh-to","name":"Bí thuật câu thông thần hồn thánh tổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ma đạo","phamCap":"không rõ","hePhai":"Thánh tộc","soHuu":["Cổ ma"],"blurb":"Bí thuật cổ ma dùng để câu thông thần hồn Nguyên Sát thánh tổ hóa thân trong phong ấn. Nghi thức dùng ma ảnh hai đầu bốn tay, tinh huyết, pháp quyết và huyết văn.","detail":"Tại không gian phong ấn song thủ ngân lang, cổ ma thi triển bí thuật này trước khi phá phong ấn hoàn toàn. Huyết văn do hắn tạo ra khiến hắc sắc lang thủ của hóa thân Nguyên Sát mở mắt.","thuocTinh":"Ma đạo, huyết thuật","uyLuc":"Có thể đánh thức hắc sắc lang thủ của hóa thân Nguyên Sát thánh tổ đang bị phong ấn.","dacDiem":"Cần tinh huyết và pháp quyết liên tục để hình thành huyết văn câu thông.","congNang":["Câu thông hoặc đánh thức thần hồn thánh tổ bị phong ấn @c1016"],"nguon":["@c1016"],"capNhatToi":"@c1016","tabs":{"tienTrinh":[{"chuong":"@c1016","loai":"thi triển","importance":"normal","giaiDoan":"Đánh thức hắc sắc lang thủ","text":"Cổ ma thi triển bí thuật câu thông thần hồn thánh tổ, dùng huyết văn khiến hắc sắc lang thủ mở mắt.","anchor":"Ta trước tiên thi triển bí thuật câu thông với thần hồn của thánh rồi nói sau"}]}},{"id":"hac-sac-ma-diem","name":"Hắc sắc ma diễm","cn":"","loai":"than-thong","loaiLabel":"Ma diễm","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Ma diễm màu đen của cổ ma dùng để diệt sát trưởng lão Diệp gia. Ngọn lửa này thiêu hủy thân thể và cả nguyên anh đang được ngọc xích bảo hộ.","detail":"Sau khi bóp nát đầu trưởng lão Diệp gia, cổ ma thả hắc sắc ma diễm bao phủ thi thể và nguyên anh. Quang tráo do bạch sắc ngọc xích tạo ra bị phá, nguyên anh cuối cùng hóa thành hư vô.","thuocTinh":"Ma hỏa","uyLuc":"Có thể hủy diệt nguyên anh của tu sĩ Nguyên Anh kỳ sau khi phá lớp quang tráo hộ thân.","dacDiem":"Bám giết liên tục từ thân thể tới nguyên anh.","congNang":["Thiêu hủy thân thể và nguyên anh mục tiêu @c1016"],"nguon":["@c1016"],"capNhatToi":"@c1016","tabs":{"tienTrinh":[{"chuong":"@c1016","loai":"thi triển","importance":"normal","giaiDoan":"Diệt nguyên anh Diệp gia","text":"Cổ ma dùng hắc sắc ma diễm đốt thân thể và nguyên anh trưởng lão Diệp gia cho tới khi hư vô.","anchor":"nguyên anh của lão giả đã bị hắc sắc ma diễm biến thành hư vô"}]}},{"id":"dung-hon","name":"Dung hồn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"hồn phách","soHuu":["Hắc sắc lang thủ"],"blurb":"Bí pháp hồn phách hắc sắc lang thủ dùng để đối kháng lang hồn thứ hai của Ngân Nguyệt. Pháp này hợp hai tinh hồn thành tân hồn, lấy thần thức Ngân Nguyệt làm chính và ý thức thánh tổ làm phụ.","detail":"Hắc sắc lang thủ trong thân ngân lang hai đầu nói nàng buộc phải dùng phương pháp Dung hồn để đối kháng lang hồn thứ hai. Kết quả là hai tinh hồn hợp thành một tân hồn, nhưng tân hồn này không được cổ tu thừa nhận để cởi bỏ phong ấn.","thuocTinh":"hồn phách","congNang":["Hợp hai tinh hồn thành một tân hồn, trong đó một bên làm chính và một bên làm phụ @c1017"],"nguoiTu":[{"ten":"Hắc sắc lang thủ","tuChuong":"@c1017","tangDatToi":"đã thi triển để tạo tân hồn","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1017","loai":"xuất hiện","importance":"normal","giaiDoan":"Hợp hồn đối kháng","text":"Hắc sắc lang thủ nói mình bất đắc dĩ dùng Dung hồn để đối kháng lang hồn thứ hai của Ngân Nguyệt.","anchor":"Ta bất đắc dĩ phải sử dụng phương pháp Dung hồn để đối kháng nàng"}]},"capNhatToi":"@c1017","nguon":["@c1017"]},{"id":"khong-gian-cam-che-ngan-lang-hai-dau","name":"Không gian cấm chế ngân lang hai đầu","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"phong ấn","soHuu":[],"blurb":"Không gian cách ly do thông thiên linh bảo mở ra quanh khu vực tầng tám. Đây là nơi Huyết Diễm và quái nhân Diệp gia bị truyền vào, đồng thời giam thân thể ngân lang hai đầu cùng hắc sắc lang thủ.","detail":"Hắc sắc lang thủ giải thích khu vực này không phải không gian tự nhiên mà do một kiện thông thiên linh bảo dựa vào uy năng mở ra để cách ly tầng thứ tám. Chỉ cần có dị động, bảo vật sẽ phát động và truyền kẻ xâm nhập vào trong không gian đang phong ấn ngân lang hai đầu.","thuocTinh":"không gian phong ấn","congNang":["Cách ly khu vực tầng thứ tám và truyền kẻ xâm nhập vào nơi phong ấn khi có dị động @c1017"],"tabs":{"tienTrinh":[{"chuong":"@c1017","loai":"xuất hiện","importance":"normal","giaiDoan":"Không gian phong ấn","text":"Không gian cấm chế ngân lang hai đầu được xác nhận là khu vực cách ly do thông thiên linh bảo mở ra.","anchor":"Đây chẳng qua là do một kiện thông thiên linh bảo dựa vào uy năng của nó làm phép mở ra đem cách ly khu vực tầng thứ tám"}]},"capNhatToi":"@c1017","nguon":["@c1017"]},{"id":"quan-ma-nhap-the","name":"Quán ma nhập thể","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Ma pháp nghi thức","hePhai":"Thánh tộc","soHuu":["Lang thủ màu đen"],"blurb":"Ma pháp nghi thức được Lang thủ màu đen hứa thi triển để giúp Quái nhân đầu to có cơ hội tiến giai và tăng thọ nguyên.","detail":"Lang thủ màu đen dùng Quán ma nhập thể làm điều kiện trao đổi với Quái nhân đầu to. Theo lời hắn, với tình trạng thân thể hiện nay của Quái nhân đầu to, sau khi nhập ma chỉ có khoảng nửa phần cơ hội giúp tiến giai, nhưng cơ hội này vẫn đủ khiến Quái nhân chấp nhận mạo hiểm.","nguon":["@c1018"]},{"id":"diet-tuyet-dai-tran","name":"Diệt Tuyệt Đại Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng cổ trận pháp","hePhai":"Côn Ngô tam lão","soHuu":["Côn Ngô tam lão"],"blurb":"Trận pháp do Côn Ngô tam lão bố trí tại nơi Ngân Nguyệt lang hồn ngủ say, chuyên diệt kẻ mang ma khí tới gần.","detail":"Diệt Tuyệt Đại Trận được bố trí ở cung điện an trí lang hồn Ngân Nguyệt. Trận này dùng tám mươi mốt khẩu Tru Ma Đao hợp thành, có khả năng chém nát người mang ma khí nếu tới gần, khiến Lang thủ màu đen không thể tự mình đi giết lang hồn.","nguon":["@c1018"]},{"id":"than-thong-nguyen-hinh-cu-quy-cua-khue-dao-huu","name":"Thần thông nguyên hình cự quy của Khuê đạo hữu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu tu thần thông","hePhai":"Yêu tộc","soHuu":["Xú phụ","Khuê đạo hữu"],"blurb":"Thần thông hiện nguyên hình thành cự quy hai màu trắng đen để chống ảnh hưởng từ trường Kim Từ Linh Mộc.","detail":"Theo lời nhờ cậy của Ngân Sí Dạ Xoa, Xú phụ hiện nguyên hình thành cự quy hai màu trắng đen. Yêu thể này tỏa hắc bạch lưỡng sắc quang mang, giúp bản thân ít chịu ảnh hưởng hơn trong vùng cự lực của Kim Từ Linh Mộc và chở Ngân Sí Dạ Xoa cùng Sư cầm thú vượt qua khu vực nguy hiểm.","nguon":["@c1018"]},{"id":"ao-tran-trong-bac-cuc-nguyen-quang","name":"Ảo trận trong Bắc Cực Nguyên Quang","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Cổ tu","soHuu":["Cổ tu"],"blurb":"Ảo trận được bố trí bên trong Bắc Cực Nguyên Quang tại Côn Ngô Điện.","detail":"Ảo trận này được cổ tu giấu trong Bắc Cực Nguyên Quang để che lấp đường đi hoặc gây lạc hướng, nhưng bị Hàn Lập nhìn thấu nhờ Minh Thanh linh nhãn.","thuocTinh":"ảo trận","congNang":["Che giấu hoặc gây lạc hướng trong Bắc Cực Nguyên Quang @c1019"],"tabs":{"tienTrinh":[{"chuong":"@c1019","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Minh Thanh linh nhãn phát hiện","text":"Hàn Lập phát hiện trong Bắc Cực Nguyên Quang còn có một ảo trận do cổ tu bố trí.","anchor":"ở trong Bắc Cực Nguyên quang còn cố ý bố trí thêm một cái ảo trận"}]},"capNhatToi":"@c1019","nguon":["@c1019"]},{"id":"kim-sac-am-ba-cua-su-cam-thu","name":"Kim sắc âm ba của sư cầm thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông âm ba","phamCap":"không rõ","hePhai":"Sư cầm thú","soHuu":["Sư cầm thú"],"blurb":"Thần thông âm ba kim sắc của Sư cầm thú, có thể cắt đứt ngân ti trong Bắc Cực Nguyên Quang.","detail":"Sư cầm thú há miệng phun ra kim sắc âm ba vô thanh vô tức, nơi âm ba đi qua khiến ngân ti đứt thành từng đoạn, mở đường cho tam yêu vượt vào Côn Ngô Điện.","thuocTinh":"âm ba kim sắc","uyLuc":"Có thể cắt đứt ngân ti trong Bắc Cực Nguyên Quang.","congNang":["Cắt đứt ngân ti để mở đường trong Bắc Cực Nguyên Quang @c1019"],"nguoiTu":[{"ten":"Sư cầm thú","tuChuong":"@c1019","tangDatToi":"thi triển được trong Bắc Cực Nguyên Quang","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1019","loai":"thi triển","importance":"normal","giaiDoan":"Mở đường cho tam yêu","text":"Sư cầm thú phun kim sắc âm ba khiến ngân ti trong Bắc Cực Nguyên Quang đứt đoạn.","anchor":"những nơi nào nó đi qua, tất cả ngân ti trong nháy mắt bị đứt thành từng đoạn"}]},"capNhatToi":"@c1019","nguon":["@c1019"]},{"id":"thanh-sac-kinh-phong-cua-ngan-si-da-xoa","name":"Thanh sắc kình phong của Ngân Sí Dạ Xoa","cn":"","loai":"than-thong","loaiLabel":"Thần thông phong hệ","phamCap":"không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thần thông kình phong do Ngân Sí Dạ Xoa dùng đôi cánh quạt ra để phối hợp vượt ngân ti.","detail":"Ngân Sí Dạ Xoa dùng đôi cánh tạo thanh sắc kình phong, phối hợp với kim sắc âm ba của Sư cầm thú để thổi bay các đoạn ngân ti bị cắt đứt trong Bắc Cực Nguyên Quang.","thuocTinh":"phong hệ","congNang":["Thổi bay các đoạn ngân ti đã bị cắt đứt để dọn đường @c1019"],"nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c1019","tangDatToi":"thi triển được bằng đôi cánh","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1019","loai":"thi triển","importance":"normal","giaiDoan":"Phối hợp vượt ngân ti","text":"Ngân Sí Dạ Xoa quạt cánh tạo thanh sắc kình phong, thổi bay ngân ti đã bị kim sắc âm ba cắt đứt.","anchor":"phối hợp với kim sắc âm ba lập tức đem các đoạn Ngân ti bị đứt đoạn thổi bay đi"}]},"capNhatToi":"@c1019","nguon":["@c1019"]},{"id":"cam-che-cuoi-cung-trong-con-ngo-dien","name":"Cấm chế cuối cùng trong Côn Ngô Điện","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Côn Ngô tam lão","soHuu":["Côn Ngô tam lão"],"blurb":"Cấm chế cuối do Côn Ngô tam lão bố trí trong Côn Ngô Điện để phòng yêu tà đoạt bảo. Khi Mộc Khôi chạm tới bảo vật, cấm chế thông qua Tam nhân vọng nguyệt đồ và ba kiện bảo vật kích hoạt sát chiêu.","detail":"Cấm chế này ẩn trong bố trí của Côn Ngô Điện, liên hệ với Tam nhân vọng nguyệt đồ và các bảo vật trên bàn án. Nó hiện ra ba nhân ảnh một đạo, một nho, một tăng, rồi điều khiển tiểu kiếm, hàng ma trượng và thư cuốn hợp kích diệt Mộc Khôi.","congNang":["Phòng yêu tà đoạt bảo trong Côn Ngô Điện @c1020","Thông qua thần niệm và bảo vật trên bàn án phát động hợp kích @c1020"],"tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt trong cuộc đoạt bảo","text":"Cấm chế cuối trong Côn Ngô Điện được kích hoạt khi Mộc Khôi định đoạt bảo, hiện ba nhân ảnh Côn Ngô tam lão và điều khiển ba kiện bảo vật diệt yêu vật.","anchor":"mà cố ý trong Côn Ngô Điện bố trí một đạo cấm chế cuối cùng"}]},"nguon":["@c1020"]},{"id":"don-thuat-quy-di-cua-ba-dao-don-quang","name":"Độn thuật quỷ dị của ba đạo độn quang","cn":"","loai":"than-thong","loaiLabel":"Độn thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Huyết ảnh","Ngân sắc quang đoàn","Yêu ảnh trong đoàn tử vụ"],"blurb":"Độn thuật quỷ dị được ba đạo độn quang từ Bắc Cực Nguyên Quang sử dụng trong cuộc đoạt bảo. Có kẻ biến mất tại chỗ, có kẻ hóa thanh phong để áp sát bảo vật rất nhanh.","detail":"Thần thông này khiến huyết ảnh, ngân mang và tử vụ đồng thời tiếp cận khu bàn án trong lúc Hàn Lập đang tranh bảo. Cách biến hóa khác nhau làm cục diện đoạt bảo lập tức trở nên hỗn loạn.","congNang":["Tiếp cận bảo vật bằng biến hóa nhanh và khó lường @c1020"],"tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"thi triển","importance":"normal","giaiDoan":"Ba độn quang xông ra","text":"Ba đạo độn quang từ Bắc Cực Nguyên Quang cùng thi triển độn thuật quỷ dị để lao vào tranh bảo.","anchor":"Ba loại độn quang tựa hồ đều tinh thông một loại độn thuật quỉ dị nào đó"}]},"nguon":["@c1020"]},{"id":"lien-hoa-phat-quang-tu-thuoc-ngoc","name":"Liên hoa phật quang từ thước ngọc","cn":"","loai":"than-thong","loaiLabel":"Thần thông phật môn","phamCap":"Không rõ","hePhai":"Phật môn","soHuu":["Nữ tử dùng thước ngọc"],"blurb":"Thần thông phật môn phát ra từ thước ngọc màu trắng ngà. Nó hóa bạch liên, thất sắc cự liên và phật văn để bao trùm, áp chế nhiều đối tượng trong phạm vi.","detail":"Khi huyết ảnh định lấy Hóa Long Tỳ, nữ tử dùng thước ngọc gọi ra phật âm và vô số liên hoa. Uy năng này bao phủ huyết ảnh, ngân sắc quang đoàn và đoàn tử vụ, khiến các đối tượng loạng choạng không đứng vững.","congNang":["Khống chế phạm vi bằng phật âm, bạch liên và thất sắc cự liên @c1020","Áp chế huyết ảnh, ngân sắc quang đoàn và đoàn tử vụ @c1020"],"tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"thi triển","importance":"normal","giaiDoan":"Ngăn Hóa Long Tỳ bị đoạt","text":"Nữ tử dùng thước ngọc thi triển liên hoa phật quang để bao trùm huyết ảnh, ngân sắc quang đoàn và đoàn tử vụ.","anchor":"vô số đoá nhũ bạch sắc liên hoa, giống như thiếu nữ tán hoa"}]},"nguon":["@c1020"]},{"id":"bac-cuc-nguyen-quang-cam-che","name":"Bắc Cực Nguyên Quang","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/cấm chế ánh sáng","phamCap":"không rõ","hePhai":"Côn Ngô Sơn","soHuu":[],"blurb":"Một vùng ngân sắc quang ti nguy hiểm trong Côn Ngô Sơn, có thể hạn chế độn thuật và bào mòn phòng hộ.","detail":"Ở chương này, Bắc Cực Nguyên Quang bị Dương Hoàn trong tay Hàn Lập thao túng để phá côn ảnh của Huyền Nham Quy và hình thành sóng bạc vây công chiến giáp phòng hộ.","congNang":["Có thể hạn chế di chuyển và độn thuật của Huyền Nham Quy trong khu vực Nguyên Quang @c1021","Khi được Dương Hoàn điều động, ngân sắc quang ti có thể tụ lại phá côn ảnh và công kích địch nhân @c1021"],"tabs":{"tienTrinh":[{"chuong":"@c1021","loai":"thi triển","importance":"normal","giaiDoan":"Bị Dương Hoàn thao túng","text":"Ngân sắc quang ti trong Bắc Cực Nguyên Quang bị Dương Hoàn khống chế để phá côn ảnh và vây công Huyền Nham Quy.","anchor":"ngân sắc quang ti trong phạm vi hơn mười trượng đều chịu khống chế"}]},"nguon":["@c1021"]},{"id":"tu-tuong-xich-than-thong","name":"Tứ Tượng Xích","cn":"","aliases":["Bạch sắc ngọc thước"],"loai":"than-thong","loaiLabel":"Thần thông khốn địch","phamCap":"phỏng chế Thông Thiên Linh Bảo","hePhai":"Hóa Tiên Tông","soHuu":["Nữ tử tú lệ Hóa Tiên Tông"],"blurb":"Uy năng từ bạch sắc ngọc thước, thiên về khốn địch biến ảo bằng thải Liên và thất sắc phật quang.","detail":"Trong chương này, Tứ Tượng Xích khốn Kiền lão ma cùng hai yêu để phụ nhân Hóa Tiên Tông đoạt Hóa Long Ấn, nhưng uy năng phải thu lại khi nữ tử tú lệ cạn pháp lực.","congNang":["Khốn địch bằng thải Liên và thất sắc phật quang @c1021","Uy năng suy giảm khi người thúc giục cạn pháp lực @c1021"],"tabs":{"tienTrinh":[{"chuong":"@c1021","loai":"thi triển","importance":"normal","giaiDoan":"Khốn địch rồi suy giảm","text":"Tứ Tượng Xích vây khốn Kiền lão ma cùng hai yêu nhưng phải thu uy năng khi nữ tử tú lệ Hóa Tiên Tông hết pháp lực.","anchor":"làm cho uy năng của \"Tứ Tượng Xích\" phải thu lại"}]},"nguon":["@c1021"]},{"id":"phan-liet-nguyen-than","name":"Phân liệt nguyên thần","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Yêu thú","soHuu":["Khuê Linh"],"blurb":"Thủ đoạn nguyên thần được Khuê Linh dùng để giao một phần nguyên thần vào Mệnh nguyên bài.","detail":"Khuê Linh chủ động phân liệt gần nửa nguyên thần nhập vào Bổn mạng nguyên bài để Hàn Lập có thể cảm ứng và chế ước nàng nếu nàng sinh dị tâm.","thuocTinh":"Nguyên thần","congNang":["Đặt một phần nguyên thần vào mệnh bài để chịu chế ước @c1022"],"nguoiTu":[{"ten":"Khuê Linh","tuChuong":"@c1022","tangDatToi":"Không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1022","loai":"thi triển","importance":"normal","giaiDoan":"Giao nguyên thần vào mệnh bài","text":"Khuê Linh dùng Phân liệt nguyên thần để đặt gần nửa nguyên thần vào Bổn mạng nguyên bài, qua đó chứng minh quy phục trước Hàn Lập.","anchor":"Ta nguyện ý đem non nửa nguyên thần vào trên bổn mạng bài"}]},"capNhatToi":"@c1022","nguon":["@c1022"]},{"id":"bat-diet-than-the","name":"Bất diệt thân thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Yêu thú","soHuu":["Khuê Linh"],"blurb":"Thần thông tái sinh thân thể của Khuê Linh, khiến cánh tay bị mất mọc lại rất nhanh.","detail":"Sau khi dùng Vạn niên linh thủy hồi phục pháp lực, Khuê Linh vận hắc bạch linh quang khiến cánh tay cụt mọc lại trong vài hơi thở, làm Hàn Lập chấn động vì năng lực tái sinh mạnh mẽ này.","thuocTinh":"Tái sinh thân thể","uyLuc":"Cánh tay cụt mọc lại hoàn toàn trong vài hơi thở.","congNang":["Tái sinh phần thân thể bị tổn hại với tốc độ rất nhanh @c1022"],"nguoiTu":[{"ten":"Khuê Linh","tuChuong":"@c1022","tangDatToi":"Tái sinh cánh tay","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1022","loai":"thi triển","importance":"normal","giaiDoan":"Tái sinh cánh tay","text":"Khuê Linh vận hắc bạch linh quang, khiến cánh tay bị mất mọc lại hoàn toàn trong vài hơi thở.","anchor":"trong mấy cái hô hấp , toàn bộ cánh tay liền hoàn toàn dài ra"}]},"capNhatToi":"@c1022","nguon":["@c1022"]},{"id":"ma-cong-cua-kien-lao-ma","name":"Ma công của Kiền lão ma","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Kiền lão ma"],"blurb":"Ma công đặc dị của Kiền lão ma, được Khuê Linh nhận định là khó bị Bắc Cực Nguyên Quang khắc chế hoàn toàn.","detail":"Khuê Linh từng thấy Kiền lão ma thi triển ma công này và cho rằng nó có thể khiến lão không sợ Bắc Cực Nguyên Quang xuyên thủng thân thể, làm kế hoạch diệt sát lão trở nên khó khăn.","thuocTinh":"Ma khí","dacDiem":"Không sợ Bắc Cực Nguyên Quang xuyên thủng thân thể theo nhận định của Khuê Linh.","congNang":["Giúp Kiền lão ma chống chịu việc Bắc Cực Nguyên Quang xuyên thân @c1022"],"nguoiTu":[{"ten":"Kiền lão ma","tuChuong":"@c1022","tangDatToi":"Không rõ","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1022","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Khuê Linh đánh giá","text":"Khuê Linh nói Kiền lão ma từng thi triển ma công có thể không sợ Bắc Cực Nguyên Quang xuyên thủng thân thể.","anchor":"hắn thi triển ma công có thể không sợ Bắc Cực Nguyên Quang này xuyên thủng thân thể"}]},"capNhatToi":"@c1022","nguon":["@c1022"]},{"id":"giai-hon-chu-phap-quyet","name":"Giải hồn chú pháp quyết","cn":"","loai":"bi-thuat","loaiLabel":"Pháp quyết giải chú","phamCap":"không rõ","hePhai":"Âm La Tông","soHuu":["Âm La Tông"],"blurb":"Pháp quyết mà Hàn Lập chặn Kiền lão ma để yêu cầu phục chế. Kiền lão ma liên hệ pháp quyết này với Phong hồn chú và không chịu giao ra.","detail":"Đây là pháp quyết giải hồn chú của Âm La Tông, được Hàn Lập xem là mục tiêu đủ quan trọng để phục kích một đại trưởng lão thập đại tông môn. Công dụng được nêu là giải trừ hồn chú hoặc Phong hồn chú.","thuocTinh":"giải chú","congNang":["Giải trừ hồn chú hoặc Phong hồn chú @c1023"],"tabs":{"tienTrinh":[{"chuong":"@c1023","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập đòi pháp quyết","text":"Hàn Lập chặn Kiền lão ma và yêu cầu được phục chế pháp quyết giải hồn chú của Âm La Tông.","anchor":"pháp quyết giải hồn chú của quý tông"}]},"nguon":["@c1023"]},{"id":"huyet-anh-hoa-to-mau-tai-hop","name":"Huyết ảnh hóa tơ máu tái hợp","cn":"","loai":"than-thong","loaiLabel":"Thần thông thoát thân","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Kiền lão ma"],"blurb":"Thần thông giúp Kiền lão ma làm huyết ảnh nổ thành vô số tơ máu rồi tái hợp nguyên vẹn. Nhờ vậy lão thoát khỏi côn ảnh và võng Bắc cực nguyên quang.","detail":"Khi bị Hàn Lập và xú phụ hợp lực vây bắt, Kiền lão ma khiến huyết ảnh bành trướng rồi nổ thành vô số tơ máu, làm thế kìm giữ mất hiệu lực. Những tơ máu sau đó ngưng kết lại ngoài hơn mười trượng thành huyết ảnh nguyên vẹn.","thuocTinh":"huyết ảnh, thoát thân, tái hợp","congNang":["Thoát trói bằng cách phân tán huyết ảnh thành tơ máu rồi tái hợp @c1023"],"tabs":{"tienTrinh":[{"chuong":"@c1023","loai":"thi triển","importance":"normal","giaiDoan":"Thoát võng nguyên quang","text":"Kiền lão ma dùng thần thông khiến huyết ảnh nổ thành tơ máu để tránh thế hợp kích rồi tái hiện nguyên vẹn ngoài xa.","anchor":"cả thân thể như muốn nổ tung, vô số tơ máu bay ra bốn phía"}]},"nguon":["@c1023"]},{"id":"ma-cong-hoa-than-yeu-ma-gan-nhu-bat-tu","name":"Ma công hóa thân yêu ma gần như bất tử","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Kiền lão ma"],"blurb":"Ma công khiến thân thể Kiền lão ma tạm thời hóa thành hình thái yêu ma gần như bất tử, không phải quỷ phách chi thể.","detail":"Hàn Lập nhận định trạng thái gần như vô hình của Kiền lão ma không phải quỷ phách, mà là do ma công lợi hại tạm biến thân thể thành dạng yêu ma khó bị tiêu diệt trực diện.","thuocTinh":"ma đạo, hóa thân","uyLuc":"Tạo ra hình thái yêu ma gần như bất tử trong giao chiến.","dacDiem":"Không phải quỷ phách chi thể mà là biến hóa tạm thời của thân thể.","congNang":["Hóa thân thể thành hình thái yêu ma gần như bất tử trong thời gian giao chiến @c1024"],"nguoiTu":[{"ten":"Kiền lão ma","tuChuong":"@c1024","tangDatToi":"đã thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1024","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ bản chất ma công","text":"Hàn Lập nhận ra thân thể Kiền lão ma do ma công biến hóa thành hình thái yêu ma gần như bất tử.","anchor":"mà là ma công lợi hại đem thân thể tạm thời hóa thành loại hình thái yêu ma gần như bất tử"}]},"trangThai":"đang được Kiền lão ma sử dụng","capNhatToi":"@c1024","nguon":["@c1024"]},{"id":"lan-hoa-bich-diem-cua-ngu-tu-dong-tam-ma","name":"Lân hỏa bích diễm của Ngũ tử đồng tâm ma","cn":"","loai":"than-thong","loaiLabel":"Ma hỏa","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Ngũ tử đồng tâm ma"],"blurb":"Ma hỏa màu bích do năm bộ xương của Ngũ tử đồng tâm ma phun ra để chống lại linh hỏa và nguyên quang.","detail":"Khi vừa hiện thân, năm bộ xương phun lân hỏa bích diễm; hai cỗ dùng bích diễm giao đấu với Tử La Thiên Hỏa, ba cỗ còn lại hóa hỏa mạc cản Bắc Cực Nguyên Quang.","thuocTinh":"ma hỏa","uyLuc":"Có thể đối kháng trực diện Tử La Thiên Hỏa và cản Bắc Cực Nguyên Quang trong một đoạn giao chiến.","congNang":["Phun bích diễm để chống linh hỏa và tạo màn lửa cản nguyên quang @c1024"],"nguoiTu":[{"ten":"Ngũ tử đồng tâm ma","tuChuong":"@c1024","tangDatToi":"đã thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1024","loai":"thi triển","importance":"normal","giaiDoan":"Chặn hỏa quang","text":"Ngũ tử đồng tâm ma phun lân hỏa bích diễm, chia ra chống Tử La Thiên Hỏa và Bắc Cực Nguyên Quang.","anchor":"Năm bộ xương vừa hiện ra liền há mồm phun ra một cỗ lân hỏa bích diễm"}]},"trangThai":"đang được Ngũ tử đồng tâm ma sử dụng","capNhatToi":"@c1024","nguon":["@c1024"]},{"id":"cu-dai-thuat","name":"Cự đại thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông biến thân","phamCap":"đại thần thông","hePhai":"yêu tu","soHuu":["Khuê Linh"],"blurb":"Thần thông biến thân giúp Khuê Linh hóa thành cự nhân tám trượng mà không cần hiện nguyên hình.","detail":"Khuê Linh thi triển Cự đại thuật trong lúc dùng cự phủ bạc, thân hình hóa lớn thành người khổng lồ tám trượng; Hàn Lập nhận định bà không hiện nguyên hình vẫn dùng được loại đại thần thông này.","thuocTinh":"biến thân, yêu lực","uyLuc":"Giúp Khuê Linh hóa thành cự nhân tám trượng để phối hợp cự phủ bạc tấn công.","congNang":["Phóng đại thân thể thành cự nhân tám trượng khi giao chiến @c1024"],"nguoiTu":[{"ten":"Khuê Linh","tuChuong":"@c1024","tangDatToi":"đã thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1024","loai":"thi triển","importance":"normal","giaiDoan":"Hóa thành cự nhân","text":"Khuê Linh thi triển Cự đại thuật, hóa thành người khổng lồ cao tám trượng để vận dụng cự phủ bạc.","anchor":"Không nghĩ tới con yêu này không hiện nguyên hình cũng có thể thi triển đại thần thông loại này"}]},"trangThai":"đang được Khuê Linh sử dụng","capNhatToi":"@c1024","nguon":["@c1024","@c1042"]},{"id":"ue-am-ma-khi","name":"Uế âm ma khí","cn":"","loai":"than-thong","loaiLabel":"Ma khí","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Ngũ tử đồng tâm ma"],"blurb":"Ma khí do khô lâu hợp thể của Ngũ tử đồng tâm ma phun ra, có thể bám dính và hấp thu phủ mang bạc.","detail":"Sau khi ngũ ma hợp thể, khô lâu khổng lồ phun hôi hà bán trong suốt. Làn ma khí này giữ lại phủ mang bạc của Khuê Linh, khiến ánh bạc suy giảm rồi bị hấp thu; Khuê Linh nhận ra đó là Uế âm ma khí.","thuocTinh":"ma khí, ô uế âm hàn","uyLuc":"Có thể hấp thu phủ mang bạc cực mạnh của Khuê Linh.","dacDiem":"Khuê Linh cho rằng Ngũ tử đồng tâm ma có thần thông này rất bất thường.","congNang":["Bám dính, làm suy yếu và hấp thu phủ mang bạc @c1024"],"nguoiTu":[{"ten":"Ngũ tử đồng tâm ma","tuChuong":"@c1024","tangDatToi":"đã thi triển sau hợp thể","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1024","loai":"thi triển","importance":"normal","giaiDoan":"Hấp thu phủ mang","text":"Khô lâu hợp thể phun Uế âm ma khí, khiến phủ mang bạc của Khuê Linh từ sáng chuyển tối rồi bị hấp thu.","anchor":"Uế âm ma khí! Ngũ tử đồng tâm ma lại có thể có thần thông bậc này"}]},"trangThai":"đang được khô lâu hợp thể sử dụng","capNhatToi":"@c1024","nguon":["@c1024"]},{"id":"ngu-ma-hop-the","name":"Ngũ ma hợp thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông hợp thể","phamCap":"không rõ","hePhai":"ma đạo","soHuu":["Kiền lão ma","Ngũ tử đồng tâm ma"],"blurb":"Thần thông khiến năm bộ xương của Ngũ tử đồng tâm ma dung hợp thành một khô lâu khổng lồ có thể dùng Uế âm ma khí.","detail":"Kiền lão ma thúc năm bộ xương hợp làm một, biến thành khô lâu khổng lồ cao lớn không thua cự nhân Khuê Linh. Sau hợp thể, khô lâu chắn trước Kiền lão ma, phun Uế âm ma khí hấp thu phủ mang bạc và tiến về phía Khuê Linh.","thuocTinh":"hợp thể, ma đạo","uyLuc":"Tạo thành khô lâu khổng lồ đủ đối đầu trực diện cự nhân Khuê Linh và thi triển Uế âm ma khí.","dacDiem":"Là biến hóa then chốt của Ngũ tử đồng tâm ma trong trận chiến.","congNang":["Hợp năm bộ xương thành một khô lâu khổng lồ @c1024","Cho khô lâu hợp thể sử dụng Uế âm ma khí và trực tiếp tiến đánh @c1024"],"nguoiTu":[{"ten":"Kiền lão ma","tuChuong":"@c1024","tangDatToi":"đã thúc sử","trangThai":"dang-tu"},{"ten":"Ngũ tử đồng tâm ma","tuChuong":"@c1024","tangDatToi":"đã hợp thể","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1024","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Năm ma hợp nhất","text":"Năm bộ xương của Ngũ tử đồng tâm ma dung hợp thành khô lâu khổng lồ, mở ra hình thái chiến đấu mới và dùng Uế âm ma khí.","anchor":"vậy thì hãy lĩnh giáo uy lực của ngũ ma hợp thể rồi nói sau"}]},"trangThai":"đã thi triển","capNhatToi":"@c1024","nguon":["@c1024"]},{"id":"ho-phe","name":"Hổ phệ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Khuê Linh","soHuu":["Khuê Linh"],"blurb":"Chiêu thức do Khuê Linh thi triển thông qua ngân sắc cự phủ, kích phát khí linh Bạch hổ một sừng cắn nuốt mục tiêu.","detail":"Khi giao chiến với đại khô lâu, Khuê Linh hô Hổ phệ, khiến thú ảnh trên mặt phủ hiện ra và cắn nuốt đầu đại khô lâu. Chiêu này gắn trực tiếp với khí linh trong cự phủ.","congNang":["Triệu khí linh dạng Bạch hổ một sừng cắn nuốt mục tiêu @c1025"],"nguoiTu":[{"ten":"Khuê Linh","tuChuong":"@c1025","tangDatToi":"Thi triển trong giao chiến","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1025","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến đại khô lâu","text":"Khuê Linh dùng Hổ phệ kích phát khí linh trong cự phủ để cắn nuốt đầu đại khô lâu.","anchor":"trong miệng quát khẽ một tiếng “ Hổ phệ”"}]},"capNhatToi":"@c1025","nguon":["@c1025"]},{"id":"hoa-ma-vo-hinh","name":"Hoá ma vô hình","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma đạo","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Kiền lão ma","Ngũ tử đồng tâm ma"],"blurb":"Ma đạo thần thông khiến tử ma hóa thân bị phá nát vẫn có thể tái hiện và hợp nhất, rất khó bị tiêu diệt bằng công kích thường.","detail":"Kiền lão ma dùng Hoá ma vô hình để cứu Ngũ tử đồng tâm ma sau khi đại khô lâu bị Hổ phệ nuốt đầu, bị chém nát thân và bị hoàng sắc yêu diễm luyện hóa. Năm bộ bạch cốt tái hiện rồi hợp lại thành đại khô lâu, khiến Khuê Linh nhận ra mức độ nguy hiểm của thần thông này.","congNang":["Giúp tử ma hóa thân bị phá thân vẫn hóa lại thành bạch cốt và tái hợp @c1025"],"nguoiTu":[{"ten":"Kiền lão ma","tuChuong":"@c1025","tangDatToi":"Dùng để điều khiển Ngũ tử đồng tâm ma","trangThai":"dang-dung"},{"ten":"Ngũ tử đồng tâm ma","tuChuong":"@c1025","tangDatToi":"Tái hợp thân khô lâu","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1025","loai":"thi triển","importance":"major","giaiDoan":"Phục hồi đại khô lâu","text":"Kiền lão ma thi triển Hoá ma vô hình khiến Ngũ tử đồng tâm ma bị chém nát vẫn tái hợp thành đại khô lâu.","anchor":"Hoá ma vô hình! Không thể tưởng tượng được"}]},"capNhatToi":"@c1025","nguon":["@c1025"]},{"id":"me-hon-thuat-cua-nhan-hinh-khoi-loi","name":"Mê hồn thuật của nhân hình khôi lỗi","cn":"","loai":"than-thong","loaiLabel":"Thần thông tinh thần","phamCap":"không rõ","hePhai":"Nhân hình khôi lỗi của Hàn Lập","soHuu":["Nhân hình khôi lỗi của Hàn Lập"],"blurb":"Thần thông tinh thần do nhân hình khôi lỗi thi triển qua tử quang trong hai mắt, khiến nguyên anh Kiền lão ma suýt mê loạn.","detail":"Khi nguyên anh Kiền lão ma đổi hướng bỏ chạy, nhân hình khôi lỗi mở to hai mắt và phóng tử quang chói mắt. Lão ma lập tức nhận ra đây là mê hồn thuật, trong chớp mắt suýt mất ý chí hành động, nhưng nhờ thần thức mạnh nên tỉnh lại.","thuocTinh":"tinh thần","uyLuc":"Có thể khiến nguyên anh Kiền lão ma suýt buông bỏ hành động trong thoáng chốc.","dacDiem":"Thi triển qua tử quang phát ra từ hai mắt khôi lỗi.","congNang":["Mê hoặc tinh hồn đối thủ trong khoảnh khắc @c1026"],"nguoiTu":[{"ten":"Nhân hình khôi lỗi của Hàn Lập","tuChuong":"@c1026","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1026","loai":"thi triển","importance":"normal","giaiDoan":"Ngăn nguyên anh bỏ chạy","text":"Nhân hình khôi lỗi phóng tử quang từ hai mắt, khiến nguyên anh Kiền lão ma suýt bị mê hoặc trước khi kịp tỉnh lại.","anchor":"Không đúng, đây là mê hồn thuật!"}]},"capNhatToi":"@c1026","nguon":["@c1026"]},{"id":"thong-thien-bao-quyet-tang-thu-nhat","name":"Thông Thiên Bảo Quyết tầng thứ nhất","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp điều khiển bảo vật","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Khẩu quyết Hàn Lập dùng để điều khiển Hư Thiên Đỉnh, hiện mới luyện đến tầng thứ nhất.","detail":"Tầng thứ nhất của Thông Thiên Bảo Quyết chỉ giúp Hàn Lập phát ra một ít linh quang từ Hư Thiên Đỉnh. Muốn phát huy thêm uy năng của tiểu đỉnh, hắn phải chờ đến khi đạt Nguyên Anh hậu kỳ.","thuocTinh":"điều khiển bảo vật","dacDiem":"Giới hạn mức phát huy hiện tại của Hư Thiên Đỉnh.","cacTang":[{"ten":"Tầng thứ nhất","moTa":"Cho phép Hư Thiên Đỉnh phát ra một ít linh quang, nhưng chưa khai triển được uy năng sâu hơn.","chuong":"@c1027"}],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1027","tangDatToi":"Tầng thứ nhất","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1027","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Tầng thứ nhất","text":"Hàn Lập xác nhận mình chỉ mới luyện tầng thứ nhất nên Hư Thiên Đỉnh còn bị hạn chế uy năng.","anchor":"bởi vì chỉ vừa mới tu luyện tầng thứ nhất Thông Thiên Bảo Quyết"}]},"capNhatToi":"@c1027","nguon":["@c1027"]},{"id":"huyen-hoac-thuat-tu-huyen-quang-tinh","name":"Huyễn hoặc thuật từ Huyễn Quang tinh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Huyễn thuật","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Huyễn thuật Hàn Lập thi triển nhờ Huyễn Quang tinh để khiến Kiền lão ma thất thần.","detail":"Hàn Lập dùng Huyễn Quang tinh đã luyện chế để che mắt Kiền lão ma trong khoảnh khắc. Khoảng thất thần ngắn ngủi này tạo điều kiện cho Hư Thiên Đỉnh cấm chế nguyên anh lão ma.","thuocTinh":"huyễn hoặc","uyLuc":"Có thể khiến thần thức Kiền lão ma thất thần trong chốc lát khi phối hợp đúng thời cơ.","congNang":["Che mắt đối thủ và tạo khoảng thất thần ngắn để khống chế mục tiêu @c1027"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1027","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1027","loai":"thi triển","importance":"normal","giaiDoan":"Che mắt Kiền lão ma","text":"Hàn Lập dùng Huyễn Quang tinh thi triển huyễn hoặc thuật để làm Kiền lão ma thất thần trước khi dùng Hư Thiên Đỉnh cấm chế nguyên anh.","anchor":"Lại dùng Huyễn Quang tinh luyện chế thi triển huyễn hoặc thuật che mắt lão ma"}]},"capNhatToi":"@c1027","nguon":["@c1027"]},{"id":"than-thong-ma-nhan-hap-thu-huyet-nhuc-tinh-hon","name":"Thần thông ma nhận hấp thu huyết nhục tinh hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông ma đạo","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":[],"blurb":"Cơ chế ma đạo của loại ma nhận luyện từ Ma Tuỷ Toản, dùng huyết nhục và tinh hồn tu sĩ bị chém giết để tăng uy năng.","detail":"Thần thông này cho phép ma nhận hấp thu huyết nhục và tinh hồn của tu sĩ bị nó chém giết, rồi qua gia trì luyện hóa mà khiến uy lực bảo vật càng lúc càng mạnh.","congNang":["Hấp thu huyết nhục và tinh hồn tu sĩ bị chém giết để tăng uy lực @c1029"],"tabs":{"tienTrinh":[{"chuong":"@c1029","loai":"xuất hiện","importance":"normal","giaiDoan":"Cơ chế ma nhận được giải thích","text":"Chương nêu rõ loại ma nhận này có thể hấp thu huyết nhục và tinh hồn tu sĩ bị chém giết để gia tăng uy năng.","anchor":"có thể đem huyết nhục, tinh hồn của các tu sĩ mà nó chém giết hấp thu vào trong"}]},"capNhatToi":"@c1029","nguon":["@c1029"]},{"id":"ban-menh-phi-kiem","name":"Bản mệnh phi kiếm","cn":"","loai":"khac","loaiLabel":"Pháp khí bản mệnh","phamCap":"không rõ","hePhai":"Bạch Dao Di","soHuu":["Bạch Dao Di"],"blurb":"Thủ đoạn bản mệnh được Bạch Dao Di thả ra khi gặp cự địch trong Trấn Ma tháp.","detail":"Bạch Dao Di nói mình đã phải thả bản mệnh phi kiếm cùng huyền băng hàn khí khi gặp cự địch. Đây là thủ đoạn tự vệ trong lúc nàng bị trọng thương và bị đánh lén.","dinhDanh":"goc","congNang":["Tự vệ khi đối địch @c1031"],"nguoiTu":[{"ten":"Bạch Dao Di","tuChuong":"@c1031","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1031","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị buộc phải dùng khi gặp cự địch","text":"Bạch Dao Di kể nàng đã phải thả bản mệnh phi kiếm cùng huyền băng hàn khí khi gặp cự địch trong Trấn Ma tháp.","anchor":"đã phải mang bản mệnh phi kiếm cùng huyền băng hàn khí thả ra"}]},"capNhatToi":"@c1031","nguon":["@c1031"]},{"id":"huyen-bang-han-khi","name":"Huyền băng hàn khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Bạch Dao Di","soHuu":["Bạch Dao Di"],"blurb":"Hàn khí của Bạch Dao Di có thể hóa thành cự băng khó phá trong thời gian ngắn.","detail":"Huyền băng hàn khí từng biến thành cự băng bao phủ Bạch Dao Di sau khi nàng bị đánh lén. Theo lời nàng, nếu không phải tu sĩ hậu kỳ đích thân ra tay thì khó phá được trong thời gian ngắn, còn Hàn Lập lại phá ra rất dễ dàng.","thuocTinh":"hàn băng","congNang":["Đóng băng và tạo cự băng khó phá trong thời gian ngắn @c1031"],"nguoiTu":[{"ten":"Bạch Dao Di","tuChuong":"@c1031","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1031","loai":"nhắc tới","importance":"normal","giaiDoan":"Cự băng sau khi bị đánh lén","text":"Bạch Dao Di giải thích huyền băng hàn khí của nàng hóa thành cự băng sau biến cố bị đánh lén.","anchor":"Trừ phi là hậu kỳ tu sĩ tự mình ra tay phá đi"}]},"capNhatToi":"@c1031","nguon":["@c1031"]},{"id":"truyen-tong-tran-hac-bach-tang-bay","name":"Truyền tống trận hắc bạch tầng bảy","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Trấn Ma tháp","soHuu":[],"blurb":"Hai truyền tống trận đen trắng ở tầng bảy Trấn Ma tháp dẫn lên tầng tiếp theo.","detail":"Hai pháp trận hắc bạch là truyền tống trận cự ly ngắn. Ngân Nguyệt cảm thấy cả hai quen thuộc, nhưng trận trắng có cảm giác mạnh hơn, còn trận đen mang tà khí khiến nàng không thoải mái.","congNang":["Truyền tống cự ly ngắn lên tầng tiếp theo @c1031"],"dacDiem":"Một trận màu trắng cho cảm giác quen thuộc mạnh hơn, một trận màu đen có tà khí.","tabs":{"tienTrinh":[{"chuong":"@c1031","loai":"xuất hiện","importance":"normal","giaiDoan":"Lựa chọn lối lên tầng tám","text":"Hàn Lập theo cảm ứng của Ngân Nguyệt chọn truyền tống trận màu trắng trong hai trận hắc bạch ở tầng bảy.","anchor":"Hai truyền tống trận này đều là truyền tống trận cự ly ngắn"}]},"capNhatToi":"@c1031","nguon":["@c1031"]},{"id":"cam-che-cung-dien-tang-tam","name":"Cấm chế cung điện tầng tám","cn":"","loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Trấn Ma tháp","soHuu":[],"blurb":"Cấm chế quanh cung điện tầng tám phối hợp thạch khôi lỗi công kích các tu sĩ tranh bảo.","detail":"Cự trận cùng hơn mười tế đàn quanh cung điện tầng tám phối hợp các kim giáp thạch khôi lỗi. Chúng bổ ra từng đạo kim quang dài để công kích tu sĩ quanh cung điện.","congNang":["Phối hợp thạch khôi lỗi bổ kim quang công kích tu sĩ @c1031"],"tabs":{"tienTrinh":[{"chuong":"@c1031","loai":"xuất hiện","importance":"normal","giaiDoan":"Cục diện tầng tám","text":"Cấm chế cung điện tầng tám phối hợp thạch khôi lỗi tạo thành thế công khiến nhiều tu sĩ lâm vào hỗn loạn.","anchor":"Chúng phối hợp với cấm chế, bổ ra từng đạo kim quang dài"}]},"capNhatToi":"@c1031","nguon":["@c1031"]},{"id":"thuong-co-dai-tran-phap-tran-thach-khoi-loi","name":"Thượng cổ đại trận","aliases":["Pháp trận Thạch Khôi Lỗi"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng cổ đại trận","hePhai":"","soHuu":[],"blurb":"Đại trận bảo vệ tế đàn nơi các phe đang hợp lực phá giải để tranh đoạt Thông Thiên Linh Bảo.","detail":"Trận có thạch nhân bị đánh nát rồi tái ngưng tụ, tiếp tục phòng thủ và huy động kim nhận phản kích. Đây là chướng ngại trực tiếp ngăn các phe tiếp cận Bát Linh Thước.","congNang":["Tái tạo thạch nhân bị đánh nát và duy trì phòng thủ tế đàn @c1032"],"uyLuc":"Thạch nhân có thể tiếp tục huy động kim nhận chống lại cường công của nhiều tu sĩ.","tabs":{"tienTrinh":[{"chuong":"@c1032","loai":"xuất hiện","importance":"normal","giaiDoan":"Trước tế đàn","text":"Đại trận lộ khả năng phục hồi thạch nhân sau khi bị đánh nát và tiếp tục cản các phe phá trận.","anchor":"thạch nhân bị đánh nát kia chậm rãi ngưng tụ lại như lúc ban đầu"}]},"capNhatToi":"@c1032","nguon":["@c1032"]},{"id":"thach-khoi-loi","name":"Thạch Khôi Lỗi","loai":"khac","loaiLabel":"Khôi lỗi trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Nhóm thạch nhân phòng thủ dưới tế đàn trong pháp trận Thạch Khôi Lỗi.","detail":"Các khôi lỗi từ trạng thái bất động chuyển sang hoạt động khi pháp trận bị cường công, dùng kim nhận phản kích lên không trung.","congNang":["Dùng kim nhận phát đao quang phòng thủ tế đàn @c1032"],"uyLuc":"Khi hoạt động, chúng huy động kim nhận phản kích dày đặc trước các đợt công kích phá trận.","tabs":{"tienTrinh":[{"chuong":"@c1032","loai":"xuất hiện","importance":"normal","giaiDoan":"Phòng thủ tế đàn","text":"Thạch Khôi Lỗi dưới tế đàn hoạt động lại và dùng kim nhận chống trả đợt cường công của các tu sĩ.","anchor":"không chút yếu thế, huy động kim nhận đánh vào không trung"}]},"capNhatToi":"@c1032","nguon":["@c1032"]},{"id":"phap-tran-trong-cung-dien","name":"Pháp trận trong cung điện","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Pháp trận trong cung điện Côn Ngô Sơn đang bị các tu sĩ đồng loạt công kích. Mộc Phu Nhân nghi nó cùng Bát Linh Thước dùng để phong ấn cửa vào tầng thứ chín.","detail":"Pháp trận này nằm trong cung điện và có liên hệ với con đường đi sâu vào Phong Ma tháp. Theo suy đoán của Mộc Phu Nhân, nó có thể là lớp phong ấn cửa vào tầng thứ chín.","congNang":["Nghi dùng để phong ấn cửa vào tầng thứ chín @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị công kích","text":"Pháp trận trong cung điện bị mọi người công kích và được Mộc Phu Nhân nghi là thứ phong ấn cửa vào tầng thứ chín.","anchor":"Nay Bát Linh Thước cùng cái pháp trận này nói không chừng chính là dùng để phong ấn cửa vào tầng thứ chín"}]},"nguon":["@c1033"]},{"id":"cam-che-khong-che-con-ngo-son","name":"Cấm chế khống chế Côn Ngô Sơn","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Cấm chế then chốt khống chế cả Côn Ngô Sơn. Mộc Phu Nhân cho rằng đầu mối của nó nằm ở tầng chín Phong Ma tháp.","detail":"Muốn gia cố phong ấn trong Côn Ngô Sơn, người vào cuộc phải tới tầng thứ chín Phong Ma tháp, nơi có mắt trận hoặc đầu mối then chốt của cấm chế này.","congNang":["Khống chế cả tòa Côn Ngô Sơn @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ đầu mối","text":"Mộc Phu Nhân nói đầu mối then chốt của cấm chế khống chế Côn Ngô Sơn nằm ở tầng chín Phong Ma tháp.","anchor":"đầu mối then chốt của cấm chế, để khống chế cả toà Côn Ngô Sơn"}]},"nguon":["@c1033"]},{"id":"truyen-tong-tran-mau-trang","name":"Truyền tống trận màu trắng","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Truyền tống trận từng đưa hai nữ tu Hóa Tiên Tông vào mật thất. Sau đó trận ở mật thất đã mất hiệu lực.","detail":"Truyền tống trận màu trắng là đường đưa Mộc Phu Nhân và nữ tử tú lệ vào mật thất, nhưng khi câu chuyện diễn ra thì trận nơi đó đã không còn dùng được để quay lại kiểm tra.","congNang":["Đưa hai nữ tu Hóa Tiên Tông vào mật thất @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"nhắc tới","importance":"normal","giaiDoan":"Mất hiệu lực","text":"Hai nữ tu Hóa Tiên Tông từng truyền vào mật thất bằng truyền tống trận màu trắng, nhưng trận tại đó đã mất tác dụng.","anchor":"chúng ta từ cái truyền tống trận màu trắng truyền vào trong mật thất này"}]},"nguon":["@c1033"]},{"id":"truyen-tong-tran-mau-den","name":"Truyền tống trận màu đen","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Truyền tống trận màu đen nằm dưới chỗ cổ ma hai đầu bốn tay. Nó bị trận kỳ phủ hào quang xám bao lại để tạm ngừng hoạt động.","detail":"Nữ tử tú lệ chưa biết trận này dẫn tới đâu. Ở tuyến cổ ma, truyền tống trận màu đen đã bị cổ ma dùng trận kỳ tạm phong, nhằm ngăn tu sĩ khác xâm nhập vào không gian phong ấn.","trangThai":"bị tạm đình chỉ","congNang":["Có khả năng liên thông tới không gian phong ấn @c1033","Bị đình chỉ để ngăn người xâm nhập @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phong tạm","text":"Truyền tống trận màu đen nằm dưới thân cổ ma hai đầu bốn tay và bị trận kỳ phủ hào quang xám bao phủ để tạm ngừng hoạt động.","anchor":"Truyền Tống Trận màu đen đang bị một bộ trận kỳ phát ra một tầng hào quang màu xám bao phủ"}]},"nguon":["@c1033"]},{"id":"hac-sac-dien-quang-cua-hac-sac-lang-thu","name":"Hắc sắc điện quang của hắc sắc lang thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Cổ ma"],"blurb":"Thần thông hắc điện do hắc sắc lang thủ phóng ra từ lôi cầu trên sừng. Nó đánh xuống Đại Chu Thiên Tinh Thần Liên để đối kháng bạch diễm.","detail":"Hắc sắc lang thủ phóng lôi cầu từ sừng lên cao, lôi cầu nổ thành vô số hắc sắc điện quang rơi xuống tinh thần liên. Hắc điện cùng bạch diễm giằng co trong lúc phân hồn cổ ma phá cấm.","uyLuc":"Đối kháng bạch diễm trên Đại Chu Thiên Tinh Thần Liên.","congNang":["Đánh xuống tinh thần liên và giằng co với bạch diễm @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng bạch diễm","text":"Hắc sắc lang thủ phóng lôi cầu khiến vô số hắc sắc điện quang rơi xuống Đại Chu Thiên Tinh Thần Liên.","anchor":"Vô số đạo hắc sắc điện quang từ trên không trung rơi xuống"}]},"nguon":["@c1033"]},{"id":"tu-sac-ma-diem-cua-hac-sac-lang-thu","name":"Tử sắc ma diễm của hắc sắc lang thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma diễm","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Cổ ma"],"blurb":"Ma diễm màu tím trong ánh mắt hắc sắc lang thủ. Những phù chú bị ánh mắt này quét qua đều quỷ dị bốc cháy.","detail":"Trong quá trình phá cấm, hắc sắc lang thủ dùng tử sắc ma diễm từ ánh mắt thiêu hủy phù chú quanh thân, tạo điều kiện cho thân thể cự lang phình lớn và phá hoàng sắc quang trụ.","congNang":["Thiêu hủy phù chú quanh thân @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"thi triển","importance":"normal","giaiDoan":"Đốt phù chú","text":"Hắc sắc lang thủ dùng tử sắc ma diễm trong ánh mắt làm các phù chú quanh thân bốc cháy thành tro.","anchor":"những chiếc phù chú khi bị ánh mắt này nhìn lướt qua đều quỉ dị bốc cháy"}]},"nguon":["@c1033"]},{"id":"hac-sac-quang-ha","name":"Hắc sắc quang hà","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Cổ ma"],"blurb":"Quang hà màu đen do hắc sắc lang thủ phun ra sau khi niệm chú. Nó quét khắp bốn phía và thổi bay nhiều cấm chế dày đặc.","detail":"Sau khi dùng hắc sắc điện quang, hắc sắc lang thủ tiếp tục niệm chú rồi phun hắc sắc quang hà. Quang hà này càn quét xung quanh, khiến các cấm chế dày đặc bị thổi bay.","uyLuc":"Thổi bay nhiều cấm chế dày đặc quanh khu vực phong ấn.","congNang":["Quét bốn phía và phá cấm chế @c1033"],"tabs":{"tienTrinh":[{"chuong":"@c1033","loai":"thi triển","importance":"normal","giaiDoan":"Thổi bay cấm chế","text":"Hắc sắc lang thủ phun hắc sắc quang hà quét bốn phía, khiến nhiều cấm chế xung quanh bị thổi bay.","anchor":"làm cho các cấm chế dầy đặc ở xung quanh tất cả đều bị thổi bay"}]},"nguon":["@c1033"]},{"id":"phi-kiem-truyen-thu","name":"Phi Kiếm Truyền Thư","cn":"","loai":"than-thong","loaiLabel":"Thần thông truyền tin","phamCap":"Không rõ","hePhai":"","soHuu":["Phong lão quái","Hướng Chi Lễ"],"blurb":"Thần thông truyền tin khẩn cấp từ xa bằng phi kiếm. Phong lão quái dùng cách này báo cho Hô đạo hữu về biến cố của Hướng Chi Lễ.","detail":"Được dùng để truyền tin về tình trạng Hướng Chi Lễ trong Côn Ngô Sơn; trước đó Hướng Chi Lễ cũng từng dùng cách này báo tin cho Phong lão quái trước khi vào phong ấn.","congNang":["Truyền tin khẩn cấp từ xa giữa các tu sĩ cấp cao (@c1035)"],"nguoiTu":[{"ten":"Phong lão quái","tuChuong":"@c1035","tangDatToi":"","trangThai":"đã thi triển"},{"ten":"Hướng Chi Lễ","tuChuong":"@c1035","tangDatToi":"","trangThai":"được nhắc từng thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1035","loai":"thi triển","importance":"normal","giaiDoan":"Báo tin Hướng Chi Lễ gặp nạn","text":"Phong lão quái dùng Phi Kiếm Truyền Thư báo cho Hô đạo hữu rằng Hướng Chi Lễ gặp biến cố trong Côn Ngô Sơn.","anchor":"đây là do Phong lão dùng Phi Kiếm Truyền Thư tự mình nói cho ta biết"}]},"capNhatToi":"@c1035","nguon":["@c1035"]},{"id":"than-thong-luyen-hu-ky","name":"Thần thông luyện hư kỳ","cn":"","loai":"than-thong","loaiLabel":"Thần thông cảnh giới","phamCap":"Luyện Hư kỳ","hePhai":"","soHuu":[],"blurb":"Thần thông cấp Luyện Hư được Bạch đạo hữu nhắc khi bàn về ma vật cổ xưa. Ở Nhân giới hiện tại, loại thần thông này khó phát huy như thời thượng cổ.","detail":"Bạch đạo hữu cho rằng dù ma vật cổ xưa mạo hiểm thi triển thần thông Luyện Hư kỳ, trong hoàn cảnh thiên địa nguyên khí nhân giới đã biến đổi thì cũng không thể tùy ý đạt uy thế như trước.","uyLuc":"Bị hạn chế mạnh trong Nhân giới hiện tại do thiên địa nguyên khí biến đổi.","congNang":["Biểu thị cấp thần thông vượt trên Hóa Thần nhưng khó thi triển trọn vẹn tại Nhân giới hiện thời (@c1035)"],"tabs":{"tienTrinh":[{"chuong":"@c1035","loai":"nhắc tới","importance":"bridge","giaiDoan":"Bàn về ma vật cổ xưa","text":"Bạch đạo hữu nhắc tới khả năng ma vật thi triển thần thông Luyện Hư kỳ nhưng cho rằng uy lực sẽ bị Nhân giới hạn chế.","anchor":"Cho dù cam nguyện mạo hiểm thi triển ra thần thông luyện hư kỳ"}]},"capNhatToi":"@c1035","nguon":["@c1035"]},{"id":"bi-thuat-tam-thoi-lam-phap-luc-tang-len","name":"Bí thuật tạm thời làm pháp lực tăng lên","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Bí thuật được Hô đạo hữu nêu trong giả thuyết vượt Nghịch Linh Thông Đạo. Tác dụng là tạm thời tăng pháp lực để có thể tiến vào Linh giới.","detail":"Hô đạo hữu cho rằng nếu thật sự tìm được Nghịch Linh Thông Đạo, tu sĩ Nhân giới có thể dùng bí thuật tạm thời tăng pháp lực để thử vượt qua thông đạo tiến vào Linh giới.","congNang":["Tạm tăng pháp lực nhằm hỗ trợ vượt Nghịch Linh Thông Đạo vào Linh giới (@c1035)"],"tabs":{"tienTrinh":[{"chuong":"@c1035","loai":"nhắc tới","importance":"normal","giaiDoan":"Giả thuyết vượt thông đạo","text":"Hô đạo hữu nêu khả năng dùng bí thuật tạm thời làm pháp lực tăng lên để tiến vào Linh giới qua Nghịch Linh Thông Đạo.","anchor":"dùng bí thuật tạm thời làm pháp lực tăng lên tiến vào linh giới"}]},"capNhatToi":"@c1035","nguon":["@c1035"]},{"id":"dai-tran-thach-khoi-loi","name":"Đại trận thạch khôi lỗi","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đại trận ở tầng tám Trấn Ma Tháp phối hợp với các thạch khôi lỗi. Trận khiến khôi lỗi gần như có thân bất tử và dùng cấm chế cùng đao khí ngăn tu sĩ xâm nhập.","detail":"Pháp trận này giúp thạch khôi lỗi sau khi bị phá hủy vẫn có thể khôi phục nhiều lần, buộc các tu sĩ phải phá từng khôi lỗi tới giới hạn rồi mới bài trừ đại trận. Nó là chướng ngại chính trước cung điện tầng tám.","congNang":["Phối hợp với thạch khôi lỗi để phục hồi thân thể bị phá hủy (@c1035)","Dùng cấm chế và đao khí ngăn tu sĩ xâm nhập khu vực trước cung điện (@c1035)"],"tabs":{"tienTrinh":[{"chuong":"@c1035","loai":"xuất hiện","importance":"normal","giaiDoan":"Cản đường trước cung điện tầng tám","text":"Đại trận thạch khôi lỗi phối hợp với bạch ngọc thạch nhân khiến chúng liên tục khôi phục, buộc Hàn Lập và các tu sĩ phải lần lượt phá hủy chúng trước khi bài trừ trận.","anchor":"dưới sự phối hợp của pháp trận phảng phất như có được tấm thân bất tử"}]},"capNhatToi":"@c1035","nguon":["@c1035"]},{"id":"than-thong-diet-ma-cua-kim-nhan","name":"Thần thông diệt ma của kim nhận","cn":"","loai":"than-thong","loaiLabel":"Thần thông pháp khí","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch khôi lỗi"],"blurb":"Hiệu ứng thần thông đi kèm kim nhận của thạch khôi lỗi. Đao khí của kim nhận đặc biệt khắc chế tu sĩ tu luyện ma công.","detail":"Kim nhận trong tay thạch khôi lỗi không chỉ sắc bén mà còn phát ra đao khí diệt ma, khiến các tu sĩ ma công e ngại vì hộ thể ma khí có thể bị xuyên thủng.","congNang":["Phát ra đao khí khắc chế ma khí và uy hiếp tu sĩ tu luyện ma công (@c1035)"],"tabs":{"tienTrinh":[{"chuong":"@c1035","loai":"thi triển","importance":"normal","giaiDoan":"Thạch khôi lỗi cản đường","text":"Kim nhận của thạch khôi lỗi phát ra đao khí có thần thông diệt ma, khiến tu sĩ ma công không dám tùy tiện xông vào trận.","anchor":"trên kim nhận phát ra đao khí, làm cho vài tên tu sĩ tu luyện ma công"}]},"capNhatToi":"@c1035","nguon":["@c1035"]},{"id":"bi-thuat-vo-thuong-cua-ngan-nguyet-toc","name":"Bí thuật vô thượng của Ngân Nguyệt tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ngân Nguyệt tộc","soHuu":["Lung nhi","Lung Mộng","Ngân Nguyệt"],"blurb":"Bí thuật vô thượng của Ngân Nguyệt tộc từng được Lung nhi tu luyện để ứng phó thiên kiếp thứ hai. Do luyện sai, tinh hồn Lung nhi bị phân thành hai nguyên thần là Lung Mộng và Tuyết Linh.","detail":"Lung Mộng nói Lung nhi vì ứng phó thiên kiếp thứ hai buộc phải tu luyện bí thuật này. Sai lệch khi tu luyện khiến tinh hồn bị chia làm hai nguyên thần, tạo nên Lung Mộng và Tuyết Linh.","thuocTinh":"Nguyên thần","nguonGoc":"Ngân Nguyệt tộc","yeuCau":"Dùng trong bối cảnh ứng phó thiên kiếp thứ hai","dacDiem":"Luyện sai có thể khiến tinh hồn phân thành hai nguyên thần.","congNang":["Liên quan việc tách tinh hồn thành hai nguyên thần khi tu luyện sai @c1036."],"nguoiTu":[{"ten":"Lung nhi","tuChuong":"@c1036","tangDatToi":"Không rõ","trangThai":"luyện sai"}],"tabs":{"tienTrinh":[{"chuong":"@c1036","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ nguồn gốc phân tách nguyên thần","text":"Lung Mộng tiết lộ Lung nhi từng tu luyện bí thuật vô thượng của Ngân Nguyệt tộc để ứng phó thiên kiếp, nhưng luyện sai khiến tinh hồn phân thành hai nguyên thần.","anchor":"buộc phải tu luyện một bí thuật vô thượng của Ngân Nguyệt tộc chúng ta"}]},"capNhatToi":"@c1036","nguon":["@c1036"]},{"id":"phe-huyet-hon-an","name":"Phệ huyết hồn ấn","cn":"","loai":"bi-thuat","loaiLabel":"Hồn ấn","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Ngân Nguyệt","Lung Mộng"],"blurb":"Phệ huyết hồn ấn là ràng buộc sinh tử giữa hai nguyên thần Tuyết Linh và Lung Mộng. Ngân Nguyệt dùng ấn này để khẳng định Lung Mộng không thể giết nàng mà không bị liên lụy.","detail":"Khi Lung Mộng nói nguyên thần Tuyết Linh hiện suy yếu, Ngân Nguyệt nhắc đến Phệ huyết hồn ấn và nói nếu nàng hình thần câu diệt thì Lung Mộng cũng chẳng khá hơn. Điều này trở thành điểm kiềm chế Lung Mộng.","thuocTinh":"Hồn ấn","dacDiem":"Ràng buộc hậu quả sinh tử giữa hai nguyên thần.","congNang":["Khiến Lung Mộng không thể tùy tiện giết Tuyết Linh vì bản thân cũng sẽ bị liên lụy @c1036."],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c1036","tangDatToi":"Không rõ","trangThai":"bị ràng buộc"},{"ten":"Lung Mộng","tuChuong":"@c1036","tangDatToi":"Không rõ","trangThai":"bị ràng buộc"}],"tabs":{"tienTrinh":[{"chuong":"@c1036","loai":"xuất hiện","importance":"major","giaiDoan":"Ràng buộc hai nguyên thần","text":"Ngân Nguyệt nhắc Phệ huyết hồn ấn để chỉ ra Lung Mộng không thể diệt nàng mà vô sự.","anchor":"Nếu ta thật sự hình thần câu diệt, ngươi so với ta cũng chẳng tốt hơn đâu"}]},"capNhatToi":"@c1036","nguon":["@c1036"]},{"id":"bi-thuat-hoa-hoang-ha","name":"Bí thuật hóa hoàng hà","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật thoát thân","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Quái nhân đầu to"],"blurb":"Bí thuật hóa hoàng hà là thủ đoạn thoát thân của quái nhân đầu to Diệp gia. Khi bị Lung Mộng đánh trúng, hắn hóa thành hoàng hà tản ra bốn phía rồi ngưng tụ lại ở xa.","detail":"Quái nhân đầu to thi triển bí thuật này trong lúc bị Lung Mộng truy kích. Dù thoát khỏi đòn tiếp theo, hắn vẫn trọng thương và mất một cánh tay.","congNang":["Tán thân thành hoàng hà bay ra bốn phía để thoát khỏi truy kích @c1036."],"nguoiTu":[{"ten":"Quái nhân đầu to","tuChuong":"@c1036","tangDatToi":"Không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1036","loai":"thi triển","importance":"normal","giaiDoan":"Thoát thân khỏi Lung Mộng","text":"Quái nhân đầu to hóa thành hoàng hà tản ra bốn phía để thoát khỏi truy kích của Lung Mộng.","anchor":"hoá thành một cỗ hoàng hà bay ra bốn phía"}]},"capNhatToi":"@c1036","nguon":["@c1036"]},{"id":"quang-tru-cua-lung-mong","name":"Quang trụ của Lung Mộng","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lung Mộng"],"blurb":"Quang trụ của Lung Mộng là thần thông công kích được nàng thi triển trong thân xác Hoa Thiên Kỳ. Đòn này xuyên thủng bàn tay vàng do quái nhân đầu to hóa ra.","detail":"Lung Mộng phun ra quang trụ to bằng nắm tay, kèm tiếng như sấm. Quang trụ dễ dàng xuyên thủng hoàng quang cự thủ đang chộp về phía Bát Linh Xích.","uyLuc":"Xuyên thủng bàn tay vàng của quái nhân đầu to.","congNang":["Xuyên thủng hoàng quang cự thủ nhắm vào Bát Linh Xích @c1036."],"nguoiTu":[{"ten":"Lung Mộng","tuChuong":"@c1036","tangDatToi":"Không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1036","loai":"thi triển","importance":"normal","giaiDoan":"Phá hoàng quang cự thủ","text":"Lung Mộng phun quang trụ xuyên thủng bàn tay vàng của quái nhân đầu to.","anchor":"Bàn tay màu vàng kia đã dễ dàng bị quang trụ xuyên thủng"}]},"capNhatToi":"@c1036","nguon":["@c1036"]},{"id":"hu-khong-cu-luc-cua-hoa-thien-ky","name":"Hư không cự lực của Hoa Thiên Kỳ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hoa Thiên Kỳ"],"blurb":"Thần thông cách không trấn áp của Hoa Thiên Kỳ. Nàng dùng lực này phá Truyền Tống Trận và ép xuống Mộc phu nhân.","detail":"Hoa Thiên Kỳ chỉ cần cách không nhấn xuống đã làm Truyền Tống Trận màu trắng sụp đổ, sau đó lại tạo cự lực như xé rách hư không đánh thẳng xuống đỉnh đầu Mộc phu nhân.","congNang":["Cách không trấn áp, phá trận và ép đối thủ từ trên cao @c1037"],"uyLuc":"Có thể làm sụp Truyền Tống Trận và buộc Mộc phu nhân phải dùng Hóa Long Ấn chống đỡ.","tabs":{"tienTrinh":[{"chuong":"@c1037","loai":"thi triển","importance":"normal","giaiDoan":"Cách không trấn áp","text":"Hoa Thiên Kỳ dùng hư không cự lực phá đường lui của hai yêu và sau đó đánh xuống Mộc phu nhân.","anchor":"Một cỗ lực lớn dường như xé rách hư không trực tiếp hướng đỉnh đầu đối phương đè xuống."}]},"capNhatToi":"@c1037","nguon":["@c1037"]},{"id":"ngan-sac-quang-tru","name":"Ngân sắc quang trụ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hoa Thiên Kỳ"],"blurb":"Cột sáng bạc do Hoa Thiên Kỳ phóng ra để truy kích Nhật Nguyệt Toa. Đòn này bị ảo ảnh cự lộc trong đại trận nuốt mất.","detail":"Khi Mộc phu nhân và Nữ tử tú lệ dùng Nhật Nguyệt Toa rút đi, Hoa Thiên Kỳ há miệng phóng một dải cột sáng màu bạc truy kích linh toa. Cột sáng bị linh thú ảo ảnh của đại trận hóa giải.","congNang":["Truy kích linh toa bằng cột sáng bạc @c1037"],"tabs":{"tienTrinh":[{"chuong":"@c1037","loai":"thi triển","importance":"normal","giaiDoan":"Truy kích linh toa","text":"Hoa Thiên Kỳ phóng ngân sắc quang trụ đuổi theo Nhật Nguyệt Toa nhưng bị ảo ảnh cự lộc từ đại trận nuốt mất.","anchor":"Một dải cột sáng màu bạc hướng linh toa chợt lóe bắn lướt qua."}]},"capNhatToi":"@c1037","nguon":["@c1037"]},{"id":"ma-hoa-than-thong","name":"Ma Hóa Thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma đạo","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Nữ tử váy đen"],"blurb":"Thần thông ma đạo được nữ tử váy đen dùng để quán chú ma khí vào Hắc Phong kỳ. Nhờ đó, Thông Thiên Linh Bảo tạm thời nghe lệnh nàng dù nàng không tu luyện Thông Bảo quyết.","detail":"Nữ tử váy đen nói Hắc Phong kỳ sau khi được nàng tự mình quán chú ma khí bằng Ma Hóa Thần thông thì chỉ có thể tạm thời nghe lệnh. Công dụng đã thấy là ma hóa linh bảo để sai khiến trong thời gian ngắn.","thuocTinh":"ma đạo","uyLuc":"Có thể khiến Hắc Phong kỳ tạm thời nghe lệnh nữ tử váy đen.","dacDiem":"Tác dụng lên Thông Thiên Linh Bảo bằng cách quán chú ma khí.","congNang":["Ma hóa linh bảo để tạm thời sai khiến @c1038"],"nguoiTu":[{"ten":"Nữ tử váy đen","tuChuong":"@c1038","tangDatToi":"đã thi triển","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1038","loai":"thi triển","importance":"major","giaiDoan":"Ma hóa Hắc Phong kỳ","text":"Nữ tử váy đen dùng Ma Hóa Thần thông quán chú ma khí vào Hắc Phong kỳ, khiến linh bảo tạm thời nghe lệnh.","anchor":"sau khi bị ta tự mình quán chú ma khí một phen, cũng chỉ có thể tạm thời nghe lệnh ta"}]},"capNhatToi":"@c1038","nguon":["@c1038"]},{"id":"phong-don-than-thong-cua-ngan-si-da-xoa","name":"Phong độn thần thông của Ngân Sí Dạ Xoa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Ngân Sí Dạ Xoa","soHuu":["Ngân Sí Dạ Xoa"],"blurb":"Thần thông phong độn giúp Ngân Sí Dạ Xoa hành động linh hoạt trong ác phong dữ dội của Hắc Phong Kỳ.","detail":"Trong vùng ác phong khiến Hàn Lập bị hạn chế thần thức và phòng hộ, Ngân Sí Dạ Xoa vẫn huyền phù trên không như cá gặp nước nhờ phong độn quỷ dị.","thuocTinh":"Phong độn","uyLuc":"Có thể giúp người thi triển di chuyển an nhiên trong ác phong đang bao trùm khu vực giao chiến.","dacDiem":"Biểu hiện quỷ dị, nổi bật khi đối chiếu với tình trạng bị áp chế của các tu sĩ khác.","nguoiTu":[{"ten":"Ngân Sí Dạ Xoa","tuChuong":"@c1040","tangDatToi":"không rõ","trangThai":"đang dùng"}],"congNang":["Di chuyển trong ác phong của Hắc Phong Kỳ mà vẫn giữ được sự linh hoạt @c1040"],"tabs":{"tienTrinh":[{"chuong":"@c1040","loai":"thi triển","importance":"normal","giaiDoan":"Hiện thân trong ác phong","text":"Ngân Sí Dạ Xoa dựa vào phong độn quỷ dị để không bị ác phong ảnh hưởng như tu sĩ thông thường.","anchor":"Ngân Sí Quỷ Dạ Xoa phong độn thần thông thật là quỷ dị"}]},"capNhatToi":"@c1040","nguon":["@c1040"]},{"id":"ngu-sac-linh-quang","name":"Ngũ sắc linh quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông linh cầm","phamCap":"không rõ","hePhai":"Ngũ Sắc Khổng Tước","soHuu":["Ngũ Sắc Khổng Tước","Thanh niên họ Từ","Linh Tê Khổng Tước"],"blurb":"Thần thông do Ngũ Sắc Khổng Tước thi triển trong trận đối đầu cổ ma.","detail":"Ngũ Sắc Khổng Tước vung cánh phóng hà quang vạn đạo, dùng ngũ sắc linh quang chính diện đối kháng tử hoàn và ma khí của cổ ma.","congNang":["Phóng hà quang ngũ sắc để công kích và áp chế đối thủ trong giao chiến.","Phòng ngự bằng màn hào quang ngũ sắc quanh Linh Tê Khổng Tước @c1059","Có thể bị Ma Tượng luyện thành ngũ sắc linh châu sau khi thu lấy tinh hoa @c1059"],"tabs":{"tienTrinh":[{"chuong":"@c1041","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng cổ ma","text":"Ngũ Sắc Khổng Tước thi triển ngũ sắc linh quang để chống lại tử hoàn và ma khí của cổ ma.","anchor":"Chắc không? Vậy giờ hãy nếm thử một chút lợi hại của ngũ sắc linh quang rồi nói sao đi."},{"chuong":"@c1059","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá và luyện châu","text":"Linh Tê Khổng Tước dùng ngũ sắc linh quang phòng ngự nhưng bị Ma Tượng phá vỡ và thu lấy tinh hoa luyện thành châu.","anchor":"Ngũ sắc linh quang chói mắt, màn hào quang hóa thành một tầng"}]},"capNhatToi":"@c1041","nguon":["@c1041","@c1059"]},{"id":"ma-cong-phu-tro-cong-kich-cua-co-ma","name":"Ma công phụ trợ công kích của cổ ma","cn":"","loai":"bi-thuat","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Cổ ma hai đầu bốn tay"],"blurb":"Ma công cổ ma dùng để tăng uy lực bảo vật trong giao chiến.","detail":"Cổ ma bấm quyết, phóng tầng tầng hắc sắc ma khí quanh thân để phối hợp bảo vật công kích khi đối đầu Ngũ Sắc Khổng Tước và hai tu sĩ Thiên Lan.","congNang":["Phóng hắc sắc ma khí để phụ trợ công kích của bảo vật."],"tabs":{"tienTrinh":[{"chuong":"@c1041","loai":"thi triển","importance":"normal","giaiDoan":"Giao chiến tại truyền tống trận","text":"Cổ ma thi triển ma công phụ trợ công kích của bảo vật trong lúc đối kháng ngũ sắc linh quang.","anchor":"cả người xuất ra tầng tầng hắc sắc ma khí, dường như hắn đang thi triển một loại ma công phụ trợ công kích của bảo vật."}]},"capNhatToi":"@c1041","nguon":["@c1041"]},{"id":"that-than-thu","name":"Thất Thần Thứ","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật thần thức","phamCap":"","hePhai":"Đại Diễn Quyết","soHuu":["Hàn Lập"],"blurb":"Bí thuật công kích thần thức do Hàn Lập cải biến từ Kinh Thần Thứ, dùng để đánh bất ngờ vào thần thức đối thủ.","detail":"Hàn Lập tham ngộ Kinh Thần Thứ trong Đại Diễn Quyết nhưng chưa tu luyện Đại Diễn Quyết đến tận cùng, nên cải biến thành Thất Thần Thứ đơn giản hơn. Khi thi triển, bí thuật có thể khiến đối thủ không phòng bị bị ảnh hưởng mạnh trong khoảnh khắc, đủ tạo thời cơ cho sát chiêu phối hợp, nhưng sau một kích khiến thần thức Hàn Lập mê muội và khó dùng tiếp lần thứ hai.","nguon":["@c1042"]},{"id":"ma-cong-lan-giap-va-ma-diem-cua-co-ma","name":"Ma công lân giáp và ma diễm của Cổ Ma","cn":"","aliases":[],"loai":"khac","loaiLabel":"Ma công","phamCap":"","hePhai":"Ma công","soHuu":["Cổ Ma"],"blurb":"Ma công giúp Cổ Ma cường hóa thân thể, mọc lân phiến xanh đen, chữa lành thương thế bằng ma khí và phóng ma diễm tím đen.","detail":"Cổ Ma kết ấn khiến thân thể trở nên to lớn, da thịt phủ lân phiến xanh đen và thương thế được hắc khí che lấp rồi phục hồi. Sau đó lân phiến bừng hắc quang, ma diễm tím đen tỏa ra, biểu hiện hắn chuẩn bị thi triển bí thuật lợi hại hơn trong trận chiến.","nguon":["@c1042"]},{"id":"tu-sac-hoa-giao","name":"Tử sắc hỏa giao","cn":"","aliases":["tử sắc hỏa diễm"],"loai":"than-thong","loaiLabel":"Thần thông hỏa diễm","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông hỏa diễm màu tím do Hàn Lập thi triển để phong bế ma khí.","detail":"Hàn Lập kết pháp quyết gọi tử sắc hỏa giao, để tử diễm lan rộng phối hợp kim võng phong băng ma khí Cổ Ma.","congNang":["Phong bế và đóng băng ma khí @c1043"],"tabs":{"tienTrinh":[{"chuong":"@c1043","loai":"thi triển","importance":"normal","giaiDoan":"Phong băng ma khí","text":"Hàn Lập dùng tử sắc hỏa giao và tử diễm phối hợp kim võng để phong tỏa ma khí Cổ Ma.","anchor":"một con tử sắc hỏa giao nhanh chóng xuất hiện rồi bùng phát"}]},"nguon":["@c1043"]},{"id":"am-ba-vang-nhat-cua-su-cam-thu","name":"Âm ba vàng nhạt của Sư Cầm Thú","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông âm ba","phamCap":"không rõ","hePhai":"","soHuu":["Sư Cầm thú"],"blurb":"Âm ba công kích do Sư Cầm Thú phóng ra khi phá cấm chế truyền tống trận.","detail":"Sư Cầm Thú há miệng phóng âm ba vàng nhạt, khiến kết giới quanh truyền tống trận lõm sâu như sắp không chống nổi.","congNang":["Công kích và làm lõm sâu kết giới cấm chế @c1043"],"tabs":{"tienTrinh":[{"chuong":"@c1043","loai":"thi triển","importance":"normal","giaiDoan":"Phá quang tráo","text":"Sư Cầm Thú dùng âm ba vàng nhạt đánh vào quang tráo, tạo hiệu quả mạnh hơn lợi trảo trước đó.","anchor":"một đạo âm ba vàng nhạt từ trong miệng nó bay ra"}]},"nguon":["@c1043"]},{"id":"hon-don-khai-thien","name":"Hỗn độn khai thiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Hắc bào nữ tử"],"blurb":"Chiêu thức của Hắc bào nữ tử tạo quang trụ đen và chia cắt không gian phong ấn.","detail":"Khi Hắc bào nữ tử hô chiêu này, một quang trụ đen phá không xuất hiện, lấy cột sáng làm ranh giới chia không gian thành hai nửa sáng tối và phủ bóng đêm lên phía Hàn Lập.","congNang":["Chia cắt không gian thành hai nửa sáng tối @c1043"],"tabs":{"tienTrinh":[{"chuong":"@c1043","loai":"thi triển","importance":"major","giaiDoan":"Chia đôi không gian","text":"Hắc bào nữ tử phát động chiêu thức khiến cột sáng đen phá không và biến đổi toàn bộ không gian phong ấn.","anchor":"Cả không gian lấy cột sáng làm biên giới, phân chia ra làm hai nửa"}]},"nguon":["@c1043"]},{"id":"hac-phong-ky-khong-gian-than-thong","name":"Không gian thần thông của Hắc Phong kỳ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Nguyên Sát Thánh Tổ","soHuu":["Hắc bào nữ tử"],"blurb":"Thần thông mượn uy năng Hắc Phong kỳ để phong tỏa một mảnh không gian nhỏ.","detail":"Ở chương này, hắc bào nữ tử dùng thần thông này phong ấn lại mảnh không gian nơi nhóm Hàn Lập bị vây, khiến Truyền Tống Trận bị không gian chi lực phong trụ và không thể kích phát.","thuocTinh":"Không gian","uyLuc":"Có thể phong bế không gian nhỏ và ngăn truyền tống trong phạm vi bị ảnh hưởng.","dacDiem":"Khi thi triển, một phần uy năng của Hắc Phong kỳ bị chiếm dụng cho phong ấn không gian.","congNang":["Phong ấn một mảnh không gian nhỏ, khiến người bên trong không thể thoát bằng Truyền Tống Trận @c1044"],"nguoiTu":[{"ten":"Hắc bào nữ tử","tuChuong":"@c1044","tangDatToi":"Thi triển phong ấn không gian","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1044","loai":"thi triển","importance":"normal","giaiDoan":"Phong kín đường lui","text":"Hắc bào nữ tử dùng không gian thần thông của Hắc Phong kỳ phong ấn mảnh không gian nhỏ, làm Truyền Tống Trận mất hiệu lực.","anchor":"một lần nữa đem mảnh không gian nhỏ này phong ấn lại"}]},"capNhatToi":"@c1044","nguon":["@c1044"]},{"id":"cu-quyen-linh-luc-tu-cung-dien","name":"Cự quyền linh lực từ cung điện","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lung Mộng","soHuu":["Lung Mộng"],"blurb":"Thần thông tạo bàn tay khổng lồ rồi nắm thành quyền đánh xuống mục tiêu.","detail":"Lung Mộng từ trong cung điện ngưng tụ bàn tay khổng lồ hơn mười trượng, nắm thành quyền mang linh áp kinh người đánh xuống quái nhân đầu to để ngăn hắn tiếp cận Bát Linh Xích, nhưng bị hắc bào nữ tử hóa giải.","thuocTinh":"Linh lực","uyLuc":"Tạo cự quyền hơn mười trượng với linh áp mạnh, đủ buộc quái nhân đầu to phải đối mặt trực diện.","dacDiem":"Đòn đánh phát ra từ trong cung điện và nhằm ngăn hành động đoạt Bát Linh Xích.","congNang":["Ngưng tụ bàn tay khổng lồ hơn mười trượng để đánh xuống mục tiêu @c1044"],"nguoiTu":[{"ten":"Lung Mộng","tuChuong":"@c1044","tangDatToi":"Thi triển cự quyền","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1044","loai":"thi triển","importance":"normal","giaiDoan":"Ngăn quái nhân đầu to","text":"Lung Mộng tạo cự quyền linh lực từ trong cung điện để chặn quái nhân đầu to lấy Bát Linh Xích, nhưng đòn này bị hắc bào nữ tử đánh tan.","anchor":"một cái bàn tay khổng lồ hơn mười trượng kinh người hiện lên mà ra"}]},"capNhatToi":"@c1044","nguon":["@c1044"]},{"id":"nam-dao-mui-nhon-trong-suot","name":"Năm đạo mũi nhọn trong suốt","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Hắc bào nữ tử"],"blurb":"Thần thông công kích do Hắc bào nữ tử hư không trảo ra, tạo năm mũi nhọn trong suốt lao nhanh như thuấn di.","detail":"Năm đạo mũi nhọn trong suốt được Hắc bào nữ tử dùng để tập kích Bạch bào nho sinh, mỗi đạo lớn chừng nửa xích. Đòn này bị Lung Mộng tạo bàn tay trắng lớn bắt gọn và bóp tan.","congNang":["Công kích nhanh từ hư không nhằm xuyên phá đối thủ @c1045"],"tabs":{"tienTrinh":[{"chuong":"@c1045","loai":"thi triển","importance":"normal","giaiDoan":"Tập kích nho sinh","text":"Hắc bào nữ tử hư không trảo ra năm mũi nhọn trong suốt tấn công Bạch bào nho sinh nhưng bị Lung Mộng phá giải.","anchor":"Năm đạo mũi nhọn trong suốt, mỗi đạo lớn chừng nửa xích"}]},"nguon":["@c1045"]},{"id":"ban-tay-mau-trang-to-lon","name":"Bàn tay màu trắng to lớn","cn":"","loai":"than-thong","loaiLabel":"Thần thông phòng hộ","phamCap":"không rõ","hePhai":"Lung Mộng","soHuu":["Lung Mộng"],"blurb":"Thần thông của Lung Mộng tạo bàn tay trắng lớn để can thiệp và chặn công kích.","detail":"Bàn tay màu trắng to lớn xuất hiện trước Bạch bào nho sinh, bắt trọn năm đạo mũi nhọn trong suốt của Nguyên Sát rồi dùng lực làm chúng biến mất.","congNang":["Chặn và bóp tan công kích dạng mũi nhọn trong suốt @c1045"],"tabs":{"tienTrinh":[{"chuong":"@c1045","loai":"thi triển","importance":"normal","giaiDoan":"Cứu viện nho sinh","text":"Lung Mộng tạo bàn tay trắng lớn trước người Bạch bào nho sinh để phá đòn tập kích của Nguyên Sát.","anchor":"một bàn tay màu trắng to lớn chợt xuất hiện trước người bạch bào nho sinh"}]},"nguon":["@c1045"]},{"id":"hac-phong-nhan","name":"Hắc phong nhận","cn":"","loai":"than-thong","loaiLabel":"Thần thông từ linh bảo","phamCap":"không rõ","hePhai":"Hắc Phong Kỳ","soHuu":["Hắc bào nữ tử"],"blurb":"Phong nhận quỷ dị sinh ra từ hắc phong trụ của Hắc Phong Kỳ, có uy lực xuyên phá hộ tráo và phân thây tu sĩ Nguyên Anh.","detail":"Khi Hắc Phong Kỳ tạo cột gió đen, trong đó hiện vô số hắc sắc phong nhận quỷ dị xoay tròn. Chúng phá hoàng quang tráo từ cốt hoàn, làm cốt hoàn vỡ nát và chém nát cả thân thể lẫn kiếm quang của tu sĩ mặt chữ điền.","uyLuc":"Phá quang tráo, hủy cốt hoàn và phân thây tu sĩ mặt chữ điền Diệp gia.","congNang":["Tạo vô số phong nhận trong hắc phong trụ để phá phòng hộ và cắt nát mục tiêu @c1045"],"tabs":{"tienTrinh":[{"chuong":"@c1045","loai":"thi triển","importance":"normal","giaiDoan":"Diệt tu sĩ Diệp gia","text":"Hắc phong nhận từ Hắc Phong Kỳ phá pháp bảo hộ thân và phân thây tu sĩ mặt chữ điền khi hắn nhân kiếm hợp nhất bỏ chạy.","anchor":"hiện ra vô số hắc sắc phong nhận quỷ dị, kịch liệt xoay tròn"}]},"nguon":["@c1045"]},{"id":"thon-anh-huyet-ha","name":"Thôn Anh huyết hà","cn":"","loai":"ma-cong","loaiLabel":"Ma công thôn phệ","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Hắc bào nữ tử"],"blurb":"Ma công thôn phệ Nguyên Anh của Nguyên Sát, dùng huyết hà bao lấy và nuốt Nguyên Anh để tạm tăng pháp lực.","detail":"Hắc bào nữ tử phun huyết hà bao lấy ba quang cầu giam Nguyên Anh, ép chúng thu nhỏ rồi hút vào miệng nuốt xuống. Lung Mộng cho biết cách này chỉ tạm tăng pháp lực, đổi lại phải tiêu hao nhiều ma khí để luyện hóa trong thời gian ngắn.","congNang":["Nuốt Nguyên Anh để tăng pháp lực tạm thời nhưng khiến ma khí tiêu hao nhiều khi luyện hóa gấp @c1045"],"tabs":{"tienTrinh":[{"chuong":"@c1045","loai":"thi triển","importance":"normal","giaiDoan":"Thôn phệ ba Nguyên Anh","text":"Nguyên Sát dùng huyết hà bao lấy ba Nguyên Anh Diệp gia, ép nhỏ rồi nuốt để tăng pháp lực tạm thời.","anchor":"phun ra một phiến huyết hà đem quang cầu đang nhốt ba Nguyên Anh bao lại"}]},"nguon":["@c1045"]},{"id":"ngan-lang-yeu-the","name":"Ngân Lang Yêu Thể","cn":"","loai":"than-thong","loaiLabel":"Yêu thể biến hóa","phamCap":"Hóa Thần kỳ hậu kỳ","hePhai":"Ngân Nguyệt tộc","soHuu":["Lung Mộng","Hắc bào nữ tử"],"blurb":"Thân thể yêu lang Hóa Thần kỳ hậu kỳ của Lung Mộng bị Nguyên Sát vận dụng để hiện thành cự lang hai đầu.","detail":"Nguyên Sát xác nhận sẽ hao tổn ma khí để dựa vào yêu lang thân thể Hóa Thần kỳ hậu kỳ của Lung Mộng, nhanh chóng tiêu diệt đối thủ. Khi thi pháp, ngân quang bành trướng, sói tru vang lên, linh áp làm không gian chấn động và cuối cùng hiện hình Ngân lang hai đầu to như núi.","thuocTinh":"Yêu thể Ngân Lang hai đầu","uyLuc":"Linh áp khi hiện hình khiến không gian rung động và mặt đất nứt ra.","congNang":["Hiện thành cự lang hai đầu, phóng ra linh áp cực mạnh để áp chế chiến trường @c1045"],"nguoiTu":[{"ten":"Hắc bào nữ tử","tuChuong":"@c1045","tangDatToi":"mượn thân thể Hóa Thần kỳ hậu kỳ","trangThai":"đang vận dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c1045","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hiện yêu thể","text":"Nguyên Sát vận dụng thân thể Ngân Lang của Lung Mộng, hiện thành cự lang hai đầu to như núi để chuẩn bị tiêu diệt đối thủ.","anchor":"dựa vào yêu lang thân thể Hoá Thần Kỳ hậu kỳ mau chóng tiêu diệt hết các ngươi"}]},"nguon":["@c1045"]},{"id":"nhan-kiem-hop-nhat","name":"Nhân kiếm hợp nhất","cn":"","loai":"than-thong","loaiLabel":"Thần thông độn chiến","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Tu sĩ mặt chữ điền Diệp gia"],"blurb":"Thần thông hợp thân với phi kiếm để hóa thành kiếm hồng lao đi, được tu sĩ mặt chữ điền dùng khi liều mạng đào thoát.","detail":"Tu sĩ mặt chữ điền phun thanh sắc phi kiếm rồi nhân kiếm hợp nhất, hóa thành một đạo thanh hồng bắn nhanh ra khỏi hắc phong. Thần thông này thất bại vì hắc phong nhận chém nát cả kiếm quang lẫn thân thể.","congNang":["Hợp thân với phi kiếm để hóa thành kiếm hồng đào thoát hoặc xung kích @c1045"],"tabs":{"tienTrinh":[{"chuong":"@c1045","loai":"thi triển","importance":"normal","giaiDoan":"Liều mạng bỏ chạy","text":"Tu sĩ mặt chữ điền dùng nhân kiếm hợp nhất thoát khỏi hắc phong nhưng bị phong nhận phân thây.","anchor":"nhân kiếm hợp nhất, hoá thành một đạo thanh hồng bắn nhanh tới"}]},"nguon":["@c1045"]},{"id":"an-thuat-cua-tu-tan-chan-nhan","name":"Ẩn thuật của Tứ tán chân nhân","cn":"","loai":"bi-thuat","loaiLabel":"Ẩn thuật","phamCap":"không rõ","hePhai":"","soHuu":["Tứ tán chân nhân"],"blurb":"Ẩn thuật giúp Tứ tán chân nhân lén ẩn nấp gần Lâm Ngân Bình mà khó bị phát hiện.","detail":"Lâm Ngân Bình đánh giá ẩn thuật này thần diệu, vì nếu không nhờ ngũ sắc linh quang của Linh Tê Khổng Tước vừa quét tới thì nàng khó nhận ra Tứ tán chân nhân đang ẩn ở gần mình.","thuocTinh":"ẩn nấp","congNang":["Ẩn nấp gần tu sĩ cao giai, chỉ bị lộ khi gặp ngũ sắc linh quang quét tới @c1046"],"nguoiTu":[{"ten":"Tứ tán chân nhân","tuChuong":"@c1046","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1046","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Lâm Ngân Bình chỉ ra","text":"Ẩn thuật của Tứ tán chân nhân bị nhắc tới khi Lâm Ngân Bình nói hắn từng ẩn nấp gần nàng và chỉ bị phát hiện nhờ ngũ sắc linh quang.","anchor":"Ẩn thuật của đạo hữu quả là thần diệu"}]},"capNhatToi":"@c1046","nguon":["@c1046"]},{"id":"phong-viem-long-liet-tran","name":"Phong Viêm Long Liệt trận","cn":"","loai":"khac","loaiLabel":"Trận pháp công kích","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập","Thanh niên họ Từ"],"blurb":"Đại trận công kích do Hàn Lập và thanh niên họ Từ cùng bố trí trong lúc phá chướng bích.","detail":"Trận được đánh giá là đại trận công kích mạnh nhất trong hoàn cảnh hiện tại, đủ sức ngăn một tu sĩ Nguyên Anh hậu kỳ toàn lực công kích bằng pháp bảo.","congNang":["Tăng uy lực công phá khi phối hợp trận kỳ, trận bàn và người chủ trì."],"tabs":{"tienTrinh":[{"chuong":"@c1047","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí phá chướng bích","text":"Hàn Lập và thanh niên họ Từ cùng bố trí Phong Viêm Long Liệt trận để tập trung công phá chướng bích.","anchor":"cùng nhau bố trí một đại trận công kích có tên là Phong Viêm Long Liệt trận"}]},"nguon":["@c1047"]},{"id":"phong-hoa-giao","name":"Phong Hỏa Giao","cn":"","loai":"khac","loaiLabel":"Biến hóa trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập","Thanh niên họ Từ"],"blurb":"Biến hóa công kích do Thanh Phong Giao quấn lấy hỏa trụ mà thành trong lúc vận chuyển Phong Viêm Long Liệt trận.","detail":"Hơn mười Phong Hỏa Giao lấy gió làm thân, lấy lửa làm da, lao vào chướng bích khiến bức tường rung chuyển và biến dạng.","congNang":["Công kích tập trung vào chướng bích và làm bức tường rung chuyển."],"tabs":{"tienTrinh":[{"chuong":"@c1047","loai":"thi triển","importance":"normal","giaiDoan":"Công phá chướng bích","text":"Hàn Lập vận trận bàn tạo Thanh Phong Giao quấn hỏa trụ, hình thành hơn mười Phong Hỏa Giao lao vào chướng bích.","anchor":"hoá thành hơn mười con Phong Hoả Giao lấy gió làm thân lấy lửa làm da"}]},"nguon":["@c1047"]},{"id":"bi-quyet-chuyen-hoa-phe-kim-trung-thanh-thuc-the-sau-cung","name":"Bí quyết chuyển hóa Phệ Kim trùng thành thục thể sau cùng","aliases":["Bí quyết bồi dưỡng Phệ Kim Trùng","Bí quyết chuyển hóa Phệ Kim trùng thành thục thể sau cùng"],"cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật khu trùng","phamCap":"bí mật bất truyền của Thiên Lan thánh điện","hePhai":"Thiên Lan thánh điện","soHuu":["Thanh niên họ Từ","Thiên Lan thánh điện"],"blurb":"Bí quyết dùng để chuyển hóa Phệ Kim trùng tới thành thục thể sau cùng. Thanh niên họ Từ đem bí quyết này làm điều kiện cầu Hàn Lập ra tay cứu mạng.","detail":"Thanh niên họ Từ hứa giao bí quyết chuyển hóa Phệ Kim trùng thành thục thể sau cùng cho Hàn Lập, khiến Hàn Lập dao động. Lâm Ngân Bình phản đối vì đây là bí mật bất truyền của thánh điện, nhưng thanh niên họ Từ cho rằng trước sinh tử và hưng suy Đột Ngột nhân thì bí thuật này có thể đem ra trao đổi.","thuocTinh":"khu trùng","nguonGoc":"Thiên Lan thánh điện","congNang":["Chuyển hóa Phệ Kim trùng thành thành thục thể sau cùng @c1048"],"nguoiTu":[{"ten":"Thanh niên họ Từ","tuChuong":"@c1048","tangDatToi":"nắm bí quyết","trangThai":"đem làm điều kiện trao đổi"}],"tabs":{"tienTrinh":[{"chuong":"@c1048","loai":"xuất hiện","importance":"normal","giaiDoan":"Điều kiện cứu mạng","text":"Thanh niên họ Từ dùng bí quyết chuyển hóa Phệ Kim trùng thành thục thể sau cùng để đổi lấy sự trợ giúp của Hàn Lập.","anchor":"ta sẽ đem bí quyết biến thành thành thục thể sau cùng của Phệ Kim trùng tặng cho ngươi"}]},"capNhatToi":"@c1048","nguon":["@c1048"]},{"id":"kim-ba-cong-kich","name":"Kim ba công kích","aliases":[],"cn":"","loai":"than-thong","loaiLabel":"Thần thông kim ba","phamCap":"không rõ","hePhai":"Sư Cầm thú","soHuu":["Sư Cầm thú"],"blurb":"Kim ba là công kích lợi hại nhất được Sư Cầm thú dùng trong tử vụ. Trong chương này, kim ba bị ngũ sắc linh quang của Linh Tê Khổng Tước hóa giải.","detail":"Sư Cầm thú dùng kim ba công kích Linh Tê Khổng Tước, nhưng bất kể bao nhiêu kim ba đánh lên linh quang đều tan đi. Điều này khiến Sư Cầm thú tạm thời không thể áp chế đối thủ.","thuocTinh":"kim ba","uyLuc":"Được mô tả là công kích lợi hại nhất của Sư Cầm thú trong cảnh này.","congNang":["Tấn công bằng kim ba nhưng bị ngũ sắc linh quang khắc chế @c1048"],"nguoiTu":[{"ten":"Sư Cầm thú","tuChuong":"@c1048","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1048","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Linh Tê Khổng Tước","text":"Sư Cầm thú thi triển kim ba công kích nhưng bị ngũ sắc linh quang của Linh Tê Khổng Tước hóa giải.","anchor":"dù sao kim ba công kích lợi hại nhất của con hung cầm này"}]},"capNhatToi":"@c1048","nguon":["@c1048"]},{"id":"cong-phap-an-nac-cua-van-nam-thi-hung","name":"Công pháp ẩn nặc của Vạn Năm Thi Hùng","aliases":[],"cn":"","loai":"cong-phap","loaiLabel":"Công pháp ẩn nặc","phamCap":"thần diệu dị thường","hePhai":"Vạn Yêu Cốc","soHuu":["Vạn Năm Thi Hùng"],"blurb":"Công pháp giúp Vạn Năm Thi Hùng che giấu thân phận luyện thi khi hóa thân thành Tứ Tán chân nhân. Hàn Lập nhận xét công pháp này rất thần diệu nhưng có vẻ hạn chế tu vi khi ngụy trang.","detail":"Hàn Lập nhớ lại việc Vạn Năm Thi Hùng từng ngụy trang thành Tứ Tán chân nhân mà đến hắn cũng không nhìn ra thân phận luyện thi. Từ lần đối phương đánh lén hắc sam trưởng lão Âm La Tông nhưng không dùng hết tu vi, Hàn Lập suy đoán công pháp ẩn nặc này có đại giá hoặc hạn chế nhất định.","thuocTinh":"ẩn nặc","uyLuc":"Có thể che giấu thân phận luyện thi trước mắt Hàn Lập.","dacDiem":"Khi dùng để ngụy trang có vẻ khiến tu vi bị hạn chế.","congNang":["Ẩn giấu thân phận luyện thi khi hóa thân thành tu sĩ nhân loại @c1048"],"nguoiTu":[{"ten":"Vạn Năm Thi Hùng","tuChuong":"@c1048","tangDatToi":"thi triển thành công khi ngụy trang","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c1048","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Hàn Lập suy đoán","text":"Hàn Lập đánh giá công pháp ẩn nặc của Vạn Năm Thi Hùng thần diệu nhưng có thể hạn chế tu vi khi ngụy trang.","anchor":"Công pháp ẩn nặc vị này tu luyện thật đúng là thần diệu dị thường"}]},"capNhatToi":"@c1048","nguon":["@c1048"]},{"id":"kim-hinh-cung","name":"Kim hình cung","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập","Nhân hình khôi lỗi của Hàn Lập"],"blurb":"Đòn công kích dạng kim hình cung, dùng để phá mặt quỷ huyết quang và hắc khí đại thủ.","detail":"Trong chương 1049, kim hình cung xuất hiện hai lần trong mạch cứu thanh niên họ Từ và Nguyên Anh của hắn. Uy lực đã thấy là xuyên thủng đại thủ hắc khí và phá tan một phần mặt quỷ.","congNang":["Phá mặt quỷ huyết quang và xuyên thủng hắc khí đại thủ @c1049"],"uyLuc":"Phá được mặt quỷ và đại thủ hắc khí của Thi Hùng.","tabs":{"tienTrinh":[{"chuong":"@c1049","loai":"thi triển","importance":"normal","giaiDoan":"Cứu Nguyên Anh họ Từ","text":"Kim hình cung được dùng để xuyên thủng hắc khí đại thủ trong khoảnh khắc.","anchor":"Kim hình cung chợt hiện, đại thủ trong nháy mắt đã bị xuyên thủng một cái lỗ lớn"}]},"capNhatToi":"@c1049","nguon":["@c1049"]},{"id":"hac-khi-dai-thu","name":"Hắc khí đại thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vạn Yêu cốc","soHuu":["Vạn Năm Thi Hùng"],"blurb":"Thần thông hắc khí do Vạn Năm Thi Hùng thi triển để chụp bắt Nguyên Anh.","detail":"Thi Hùng hóa hắc khí trên đầu Nguyên Anh họ Từ thành đại thủ bao phủ hơn mười trượng. Thần thông này nhằm bắt giữ Nguyên Anh nhưng bị con rối của Hàn Lập phá tan.","congNang":["Tạo đại thủ hắc khí chụp bắt Nguyên Anh trong phạm vi lớn @c1049"],"uyLuc":"Bao phủ hơn mười trượng để truy bắt Nguyên Anh.","tabs":{"tienTrinh":[{"chuong":"@c1049","loai":"thi triển","importance":"normal","giaiDoan":"Truy bắt Nguyên Anh","text":"Thi Hùng hóa hắc khí thành đại thủ chộp Nguyên Anh họ Từ nhưng bị phá giải.","anchor":"hóa thành một cái đại thủ hướng nguyên anh chộp tới"}]},"capNhatToi":"@c1049","nguon":["@c1049"]},{"id":"ngu-sac-linh-quang-cua-linh-te-khong-tuoc","name":"Ngũ sắc linh quang của Linh Tê Khổng Tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông linh cầm","phamCap":"không rõ","hePhai":"","soHuu":["Linh Tê Khổng Tước"],"blurb":"Ngũ sắc quang hoa từ lông đuôi Linh Tê Khổng Tước, dùng phá tử vụ và mở đường thoát thân.","detail":"Linh Tê Khổng Tước dựng lông đuôi, phóng ngũ sắc linh quang khiến tử vụ bị chiếu tan thành lỗ hổng lớn. Nhờ đó linh cầm thoát khỏi sự áp chế của Sư Cầm thú.","congNang":["Phá tan tử vụ và mở lối thoát cho Linh Tê Khổng Tước @c1049"],"uyLuc":"Làm tử vụ tan ra thành lỗ hổng lớn.","tabs":{"tienTrinh":[{"chuong":"@c1049","loai":"thi triển","importance":"normal","giaiDoan":"Phá tử vụ","text":"Linh Tê Khổng Tước dùng ngũ sắc linh quang phá tử vụ để thoát khỏi Sư Cầm thú.","anchor":"Tử vụ nhất thời bị ngũ sắc linh quang chiếu xuống"}]},"capNhatToi":"@c1049","nguon":["@c1049"]},{"id":"huyet-quang-huyet-hai-hoa-nhan","name":"Huyết quang huyết hải hóa nhận","aliases":["Huyết quang","Huyết hải hóa nhận"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vạn Yêu cốc","soHuu":["Vạn Năm Thi Hùng"],"blurb":"Thần thông huyết quang của Thi Hùng, gom huyết hải thành huyết sắc cự nhận.","detail":"Vạn Năm Thi Hùng khiến huyết quang xoay tròn hóa thành huyết sắc cự nhận. Mặt quỷ trên nhận hút sạch huyết hải, chỉ còn khí huyết tinh nồng đậm.","congNang":["Thu huyết hải vào huyết sắc cự nhận @c1049"],"uyLuc":"Có thể gom và hút sạch huyết hải đang bao phủ khu vực.","tabs":{"tienTrinh":[{"chuong":"@c1049","loai":"thi triển","importance":"normal","giaiDoan":"Thu huyết hải","text":"Thi Hùng vận huyết quang hóa cự nhận và thu huyết hải trước khi rút lui.","anchor":"tất cả huyết quang sau khi xoay tròn trên không trung một cái"}]},"capNhatToi":"@c1049","nguon":["@c1049"]},{"id":"bi-quyet-boi-duong-phe-kim-trung","name":"Bí quyết bồi dưỡng Phệ Kim Trùng","aliases":["Bí quyết chuyển hóa Phệ Kim trùng thành thục thể sau cùng"],"cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật bồi dưỡng","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Hàn Lập","Thanh niên họ Từ","Thiên Lan thánh điện"],"blurb":"Bí quyết trùng thuật của Thiên Lan thánh điện dùng để thúc đẩy Phệ Kim Trùng tiến tới thành thục thể.","detail":"Pháp quyết mượn thiên địa chi lực, quán chú ngũ hành linh khí vào cơ thể linh trùng để rút ngắn thời gian thành thục. Theo thanh niên họ Từ, phương pháp này do một trưởng lão am hiểu trùng thuật của thánh điện nghiên cứu hơn một ngàn năm sau khi thánh điện có trứng Phệ Kim Trùng.","thuocTinh":"trùng thuật, ngũ hành linh khí","nguonGoc":"Thiên Lan thánh điện","congNang":["Rút ngắn quá trình Phệ Kim Trùng tiến hóa thành thục thể @c1050"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1050","tangDatToi":"đã đọc ngọc giản","trangThai":"đang nắm giữ bí quyết"}],"tabs":{"tienTrinh":[{"chuong":"@c1050","loai":"xuất hiện","importance":"normal","giaiDoan":"Trao đổi bí quyết","text":"Thanh niên họ Từ giao ngọc giản chứa bí quyết cho Hàn Lập, để hắn xem ra cốt lõi là quán chú ngũ hành linh khí vào linh trùng.","anchor":"mạnh mẽ hướng cơ thể linh trùng quán chú ngũ hành linh khí"}]},"dinhDanh":"goc","capNhatToi":"@c1050","nguon":["@c1050"]},{"id":"thanh-thu-chi-an","name":"Thánh thú chi ấn","aliases":[],"cn":"","loai":"bi-thuat","loaiLabel":"Ấn ký ràng buộc","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Thiên Lan thánh điện","Thanh niên họ Từ","Lâm Ngân Bình"],"blurb":"Ấn ký do thanh niên họ Từ đề xuất để hóa giải thù hận giữa Hàn Lập và Thiên Lan thánh điện.","detail":"Thánh thú chi ấn cần thánh nữ Thiên Lan thánh điện triệu hoán chân linh Thiên Lan thánh thú tham dự. Sau khi ký, các nhân vật trọng yếu của đôi bên không thể sinh sát tâm với nhau, nếu trái sẽ chịu thượng cổ nguyền rủa trớ chú.","thuocTinh":"ấn ký ràng buộc, nguyền rủa","nguonGoc":"Thiên Lan thánh điện","congNang":["Ràng buộc đôi bên không sinh sát tâm với nhau @c1050","Vi phạm sẽ chịu thượng cổ nguyền rủa trớ chú @c1050"],"tabs":{"tienTrinh":[{"chuong":"@c1050","loai":"xuất hiện","importance":"normal","giaiDoan":"Đề nghị hòa giải","text":"Nguyên anh họ Từ đề xuất để thánh nữ triệu hoán chân linh Thiên Lan thánh thú, ký Thánh thú chi ấn với Hàn Lập và mời hắn làm khách khanh trưởng lão.","anchor":"khiến cho không thể có sát tâm với nhau"}]},"dinhDanh":"goc","capNhatToi":"@c1050","nguon":["@c1050"]},{"id":"bi-thuat-trieu-hoan-chan-linh-thien-lan-thanh-thu","name":"Bí thuật triệu hoán chân linh Thiên Lan thánh thú","aliases":[],"cn":"","loai":"bi-thuat","loaiLabel":"Triệu hoán bí thuật","phamCap":"không rõ","hePhai":"Thiên Lan thánh điện","soHuu":["Lâm Ngân Bình","Thiên Lan thánh điện"],"blurb":"Bí thuật do thánh nữ Thiên Lan thánh điện thi triển để triệu hoán chân linh Thiên Lan thánh thú.","detail":"Bí thuật này được thanh niên họ Từ nhắc trong phương án ký Thánh thú chi ấn với Hàn Lập, dùng để mời chân linh Thiên Lan thánh thú tham dự ràng buộc.","thuocTinh":"triệu hoán","nguonGoc":"Thiên Lan thánh điện","congNang":["Triệu hoán chân linh Thiên Lan thánh thú để tham dự ký Thánh thú chi ấn @c1050"],"tabs":{"tienTrinh":[{"chuong":"@c1050","loai":"xuất hiện","importance":"normal","giaiDoan":"Điều kiện ký ấn","text":"Thanh niên họ Từ nói thánh nữ của thánh điện có thể dùng bí thuật này để triệu hoán chân linh Thiên Lan thánh thú.","anchor":"sử dụng bí thuật triệu hoán chân linh Thiên Lan thánh thú"}]},"dinhDanh":"goc","capNhatToi":"@c1050","nguon":["@c1050"]},{"id":"sat-niem-chan-loi","name":"Sất Niệm Chân Lôi","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật cấm chế thần niệm","phamCap":"Thượng cổ bí thuật","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật cấm chế do Hàn Lập vừa luyện xong, dùng để gieo vào Nguyên Anh đối phương. Nó do thần thức ngưng tụ, có đặc tính tụ tán vô hình và rất khó dò ra dấu vết.","detail":"Trong chương này, Hàn Lập dùng Sất Niệm Chân Lôi để ép thanh niên họ Từ và Lâm Ngân Bình chịu cấm chế vào Nguyên Anh. Thanh niên họ Từ sau khi bị gieo cấm chế dùng thần thức dò xét nhưng không tìm thấy dấu vết, càng sợ đặc tính tụ tán vô hình của bí thuật. Hàn Lập nói cấm chế này không nhằm khống chế lâu dài trong chuyến đi, nhưng hiệu lực có thể kéo dài ba bốn trăm năm.","thuocTinh":"Thần thức ngưng tụ","nguonGoc":"Thượng cổ bí thuật","yeuCau":"Người thi triển dùng thần thức kết thành cấm chế đưa vào Nguyên Anh mục tiêu","uyLuc":"Có thể cấm chế Nguyên Anh và khiến người bị hạ thuật khó dùng thần thức dò ra dấu vết.","dacDiem":"Tụ tán vô hình, không giống cấm thần thuật thông thường.","congNang":["Cấm chế Nguyên Anh của mục tiêu.","Ẩn trong Nguyên Anh sau khi nhập thể, khiến người bị hạ thuật khó phát hiện.","Hàn Lập nói hiệu lực có thể tự mất sau ba bốn trăm năm."],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1051","tangDatToi":"Vừa luyện thành và thi triển lên hai Nguyên Anh","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1051","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu dùng để cấm chế Nguyên Anh","text":"Hàn Lập dùng Sất Niệm Chân Lôi hạ cấm chế vào Nguyên Anh thanh niên họ Từ và Lâm Ngân Bình, khiến đối phương không dò ra dấu vết sau khi thuật nhập thể.","anchor":"Nghe đồn sất niệm chân lôi này là do thần thức tu sĩ ngưng tụ mà thành"}]},"dinhDanh":"goc","capNhatToi":"@c1051","nguon":["@c1051"]},{"id":"bi-thuat-bien-hinh-che-thi-khi-cua-thi-hung","name":"Bí thuật biến hình che thi khí của Thi hùng","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Vạn Yêu Cốc","soHuu":["Vạn Năm Thi Hùng"],"blurb":"Bí thuật giúp Thi hùng biến thành hình dáng tu sĩ và không lộ thi khí. Nhờ thủ đoạn này, Thi hùng ám toán được Thanh niên họ Từ.","detail":"Thi hùng dùng bí thuật này để biến thành hình dáng một gã tu hành, che giấu thi khí đến mức Thanh niên họ Từ không nhận ra. Khi đánh lén, Thi hùng mới hiện lại thân phận luyện thi.","thuocTinh":"biến hình, che giấu thi khí","uyLuc":"Đủ để qua mắt Thanh niên họ Từ và tạo điều kiện ám toán phá hủy thân thể ông.","dacDiem":"Che giấu thi khí dưới dáng vẻ tu sĩ.","congNang":["Biến thành hình dáng tu sĩ và che giấu thi khí khi hành động @c1052"],"nguoiTu":[{"ten":"Vạn Năm Thi Hùng","tuChuong":"@c1052","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1052","loai":"thi triển","importance":"normal","giaiDoan":"Ám toán Thanh niên họ Từ","text":"Thi hùng dùng bí thuật biến thành tu sĩ, che giấu thi khí và ám toán khiến Thanh niên họ Từ mất thân thể.","anchor":"không biết sử dụng loại bí thuật nào mà lại biến thành hình dáng của một gã tu hành"}]},"dinhDanh":"goc","capNhatToi":"@c1052","nguon":["@c1052"]},{"id":"thien-a-than-kiem","name":"Thiên A Thần Kiếm","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Thái Nhất môn","soHuu":["Huyền Thanh Tử","Thái Nhất môn"],"blurb":"Bí thuật bản môn của Thái Nhất môn. Huyền Thanh Tử nói cần phối hợp bí thuật này với Phá Giới Phù để phá chướng bích tầng tám.","detail":"Trong lời Huyền Thanh Tử, Phá Giới Phù của Thái Nhất môn vẫn phải phối hợp với bí thuật Thiên A Thần Kiếm mới phá được chướng bích tầng thứ tám và cưỡng ép tiến vào.","thuocTinh":"phá chướng bích không gian khi phối hợp phù lục","uyLuc":"Có thể phối hợp Phá Giới Phù để phá chướng bích tầng tám Côn Ngô Sơn.","dacDiem":"Bí thuật bản môn của Thái Nhất môn.","congNang":["Phối hợp Phá Giới Phù để phá chướng bích tầng thứ tám @c1052"],"nguoiTu":[{"ten":"Huyền Thanh Tử","tuChuong":"@c1052","tangDatToi":"không rõ","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1052","loai":"nhắc tới","importance":"normal","giaiDoan":"Phá chướng bích tầng tám","text":"Huyền Thanh Tử nói bí thuật Thiên A Thần Kiếm được dùng cùng Phá Giới Phù để phá chướng bích tầng tám.","anchor":"Còn phải phối hợp với bí thuật bản môn Thiên A thần kiếm"}]},"dinhDanh":"goc","capNhatToi":"@c1052","nguon":["@c1052"]},{"id":"phong-an-tang-thu-chin","name":"Phong ấn tầng thứ chín","cn":"","aliases":[],"loai":"khac","loaiLabel":"Phong ấn","phamCap":"không rõ","hePhai":"Trấn Ma Tháp","soHuu":["Nguyên Sát thánh tổ"],"blurb":"Phong ấn liên quan tầng thứ chín của Trấn Ma Tháp. Khi bị cổ ma thánh tổ mở ra, không gian tầng tám rung chuyển và nứt vỡ.","detail":"Thất Diệu chân nhân nhận ra dị biến không gian là dấu hiệu cổ ma thánh tổ đang mở phong ấn tầng thứ chín. Việc này khiến không gian tầng tám xuất hiện chấn động, mặt đất nứt và khe không gian lan ra.","thuocTinh":"phong ấn không gian","uyLuc":"Khi bị mở, tác động lan tới tầng tám và làm không gian toái liệt.","dacDiem":"Liên quan trực tiếp đến tầng thứ chín.","congNang":["Phong tỏa hoặc liên kết tầng thứ chín; khi bị mở gây dị biến không gian tầng tám @c1052"],"tabs":{"tienTrinh":[{"chuong":"@c1052","loai":"nhắc tới","importance":"major","giaiDoan":"Cổ ma mở phong ấn","text":"Thất Diệu chân nhân nhận ra cổ ma thánh tổ đang mở phong ấn tầng thứ chín khiến không gian tầng tám sụp vỡ.","anchor":"Cổ ma thánh tổ kia đang mở ra phong ấn của tầng thứ chín"}]},"dinhDanh":"goc","capNhatToi":"@c1052","nguon":["@c1052"]},{"id":"sieu-tran-quanh-te-dan","name":"Siêu trận quanh tế đàn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp quy mô lớn bằng các thạch trụ bao quanh tế đàn tầng thứ chín.","detail":"Các thạch trụ quanh tế đàn phát quang và hô ứng với bia đá có ấn tỳ, cho thấy trận này liên quan trực tiếp đến đầu mối phong ấn tại tầng thứ chín.","congNang":["Phong ấn hoặc trấn áp khu vực tế đàn tầng thứ chín @c1053"],"tabs":{"tienTrinh":[{"chuong":"@c1053","loai":"xuất hiện","importance":"normal","giaiDoan":"Tầng thứ chín","text":"Siêu trận quanh tế đàn phát quang qua các thạch trụ và hô ứng với bia đá có ấn tỳ.","anchor":"trên mỗi thạch trụ đều chứa đựng quang mang đại phóng"}]},"capNhatToi":"@c1053","nguon":["@c1053"]},{"id":"hac-ma-khi-cua-cu-lang","name":"Hắc ma khí của cự lang","cn":"","loai":"than-thong","loaiLabel":"Ma khí thần thông","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Nguyên Sát thánh tổ"],"blurb":"Ma khí đen đặc do cự lang hai đầu phun ra trong tầng thứ chín.","detail":"Hắc ma khí áp chế công kích của nhiều cường giả, nuốt kiếm khí và linh hà, đồng thời có thể khiến pháp bảo nhiễm phải bị ma hóa và mất thần thông.","thuocTinh":"ma khí","uyLuc":"Có thể áp chế pháp bảo và công kích của nhiều tu sĩ, yêu vật tại tầng thứ chín.","congNang":["Áp chế công kích quanh tế đàn @c1053","Ma hóa pháp bảo nếu bản thể nhiễm phải @c1053"],"nguoiTu":[{"ten":"Nguyên Sát thánh tổ","tuChuong":"@c1053","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1053","loai":"thi triển","importance":"normal","giaiDoan":"Tầng thứ chín","text":"Cự lang hai đầu phun hắc ma khí để áp chế phe vây công và uy hiếp pháp bảo của họ.","anchor":"bản thể của pháp bảo nếu như nhiễm phải, lập tức sẽ bị ma hóa"}]},"capNhatToi":"@c1053","nguon":["@c1053"]},{"id":"kim-ba-cua-su-cam-thu","name":"Kim ba của Sư Cầm thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Sư Cầm thú"],"blurb":"Sóng vàng do Sư Cầm thú phun ra khi đối kháng hắc ma khí.","detail":"Kim ba từ miệng Sư Cầm thú có tác dụng nhất định trước hắc ma khí của cự lang tại tầng thứ chín.","congNang":["Khắc chế một phần hắc ma khí @c1053"],"nguoiTu":[{"ten":"Sư Cầm thú","tuChuong":"@c1053","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1053","loai":"thi triển","importance":"normal","giaiDoan":"Tầng thứ chín","text":"Kim ba của Sư Cầm thú được ghi nhận có tác dụng nhất định trước hắc ma khí.","anchor":"kim ba phun ra từ miệng Sư Cầm thú"}]},"capNhatToi":"@c1053","nguon":["@c1053"]},{"id":"kiem-khi-co-kiem-cua-huyen-thanh-tu","name":"Kiếm khí cổ kiếm của Huyền Thanh Tử","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm thuật thần thông","phamCap":"không rõ","hePhai":"Thái Nhất Môn","soHuu":["Huyền Thanh Tử"],"blurb":"Kiếm khí do Huyền Thanh Tử dùng cổ kiếm và tinh huyết kích phát.","detail":"Huyền Thanh Tử dùng tinh huyết kích phát cổ kiếm, chém ra kiếm khí hơn mười trượng xuống cự lang nhưng bị hắc ma khí nuốt mất.","uyLuc":"Chém ra kiếm khí hơn mười trượng nhưng bị hắc ma khí áp chế tại tầng thứ chín.","congNang":["Chém rách không trung bằng kiếm khí lớn @c1053"],"nguoiTu":[{"ten":"Huyền Thanh Tử","tuChuong":"@c1053","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1053","loai":"thi triển","importance":"normal","giaiDoan":"Tầng thứ chín","text":"Huyền Thanh Tử phun tinh huyết lên cổ kiếm để kích phát kiếm khí lớn chém cự lang.","anchor":"Một đạo kiếm khí to lớn hơn mười trượng"}]},"capNhatToi":"@c1053","nguon":["@c1053"]},{"id":"ich-ta-loi","name":"Ích Tà Lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Lôi pháp của Hàn Lập dùng để khắc chế ma khí. Trong cục diện quanh tế đàn, hắn dùng nó tự vệ nhưng cố ý không bộc lộ hết uy lực.","detail":"Hàn Lập nhận ra Ích Tà Lôi có thể đối phó ma khí đen dị dạng quanh tế đàn, nhờ đó tạm tự bảo vệ. Tuy nhiên hắn không dốc toàn lực để tránh khiến Cổ Ma Thánh Tổ chú ý.","congNang":["Khắc chế ma khí và giúp Hàn Lập tự vệ trước hắc khí quanh tế đàn @c1054"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1054","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1054","loai":"thi triển","importance":"normal","giaiDoan":"Tự vệ trước ma khí","text":"Hàn Lập dùng Ích Tà Lôi để chống ma khí quanh tế đàn nhưng không phóng hết uy lực.","anchor":"Hàn Lập thấy Ích Tà Lôi có thể đối phó với ma khí"}]},"capNhatToi":"@c1054","nguon":["@c1054"]},{"id":"cam-ma-hoan","name":"Cấm Ma Hoàn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Trận khí trói ma","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Thất Diệu chân nhân"],"blurb":"Năm vòng xanh do Thất Diệu chân nhân thúc động để chế trụ cự lang ma hóa. Một vòng khóa cổ, bốn vòng khóa tứ chi khiến Nguyên Sát Thánh Tổ tạm thời mất khả năng điều khiển ma khí.","detail":"Cấm Ma Hoàn được Nguyên Sát Thánh Tổ nhận ra và kinh sợ. Khi Thất Diệu chân nhân thi pháp xong, năm vòng xanh khóa cự lang tại tế đàn, làm ma khí mất sự điều khiển trong một thời gian.","congNang":["Trói buộc cổ và tứ chi cự lang ma hóa, tạm thời cắt khả năng điều khiển ma khí @c1054"],"nguoiTu":[{"ten":"Thất Diệu chân nhân","tuChuong":"@c1054","tangDatToi":"thi triển năm vòng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1054","loai":"thi triển","importance":"major","giaiDoan":"Khóa cự lang","text":"Thất Diệu chân nhân thúc động Cấm Ma Hoàn, khóa cổ và tứ chi cự lang khiến nó ngã xuống tế đàn.","anchor":"Linh quang từ bốn chiếc hoàn chớp động xuống, đồng thời lại đè chặt"}]},"capNhatToi":"@c1054","nguon":["@c1054"]},{"id":"cam-che-te-dan","name":"Cấm chế tế đàn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Cấm chế trên tế đàn ngăn thần niệm dò xét. Khi Hàn Lập dùng thần niệm quét qua mặt ngoài tế đàn, thần niệm lập tức bị bắn ngược trở lại.","detail":"Cấm chế tế đàn bảo vệ khu vực phong ấn tầng thứ chín, khiến Hàn Lập không thể dò xét sâu bằng thần niệm. Đây là trở ngại trực tiếp khi hắn tìm cách hiểu kết cấu tế đàn trong lúc hỗn chiến.","congNang":["Chặn thần niệm dò xét và bắn ngược thần niệm của Hàn Lập @c1054"],"tabs":{"tienTrinh":[{"chuong":"@c1054","loai":"nhắc tới","importance":"normal","giaiDoan":"Ngăn dò xét","text":"Cấm chế tế đàn bắn ngược thần niệm của Hàn Lập khi hắn thử dò mặt ngoài tế đàn.","anchor":"Thần niệm vừa đảo qua bên mặt ngoài tế đàn"}]},"capNhatToi":"@c1054","nguon":["@c1054"]},{"id":"phong-an-te-dan-tang-thu-chin","name":"Phong ấn tế đàn tầng thứ chín","cn":"","aliases":["Phong ấn tế đàn"],"loai":"khac","loaiLabel":"Phong ấn trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Phong ấn dưới tế đàn tầng thứ chín chưa hoàn toàn mở, chỉ hé một khe hở. Khe hở này vẫn cung cấp ma khí tinh thuần cho Nguyên Sát Thánh Tổ.","detail":"Nguyên Sát Thánh Tổ dựa vào ma khí từ khe hở phong ấn tế đàn để hồi phục ma nguyên đang khô cạn. Vì phong ấn mới giải khai một phần nhỏ, nguồn ma khí vẫn đủ khiến cục diện quanh tế đàn rất nguy hiểm.","congNang":["Bổ sung ma khí tinh thuần cho Nguyên Sát Thánh Tổ qua khe hở phong ấn @c1054"],"tabs":{"tienTrinh":[{"chuong":"@c1054","loai":"nhắc tới","importance":"normal","giaiDoan":"Ma khí hé mở","text":"Phong ấn tế đàn tầng thứ chín chỉ hé một khe hở nhưng vẫn cung cấp ma khí tinh thuần cho cự lang.","anchor":"chỉ giải khai một chút khe hở mà thôi"}]},"capNhatToi":"@c1054","nguon":["@c1054"]},{"id":"gon-song-den-cua-cu-lang","name":"Gợn sóng đen của cự lang","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma đạo","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Vòng gợn sóng màu đen do cự lang phun ra, vô thanh vô tức nhưng có uy lực phá phong cấm mạnh.","detail":"Trong trận tế đàn, cự lang phun gợn sóng đen bao phủ Ngũ Thúy Hoàn, khiến năm vòng linh quang chớp động rồi tấc tấc vỡ vụn. Hàn Lập nhận ra chiêu này uy lực rất lợi hại nhưng tốc độ chậm và khó đi xa.","uyLuc":"Phá nát Ngũ Thúy Hoàn đang phong cấm cự lang.","dacDiem":"Vô thanh vô tức, tạo thành từng vòng gợn sóng đen.","congNang":["Bao phủ và phá vỡ pháp bảo phong cấm như Ngũ Thúy Hoàn @c1055"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c1055","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1055","loai":"thi triển","importance":"normal","giaiDoan":"Phá Cấm Ma Hoàn","text":"Cự lang phun gợn sóng đen làm Ngũ Thúy Hoàn tấc tấc vỡ vụn.","anchor":"sau đó linh quang lóe lên vài lần, vậy mà tấc tấc vỡ vụn"}]},"capNhatToi":"@c1055","nguon":["@c1055"]},{"id":"trao-mang-xuyen-hu-khong-cua-cu-lang","name":"Trảo mang xuyên hư không của cự lang","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Thần thông vung trảo vào hư không, khiến trảo mang biến mất rồi đột ngột xuất hiện cạnh mục tiêu.","detail":"Cự lang vung lang trảo, năm đạo trảo mang dài hơn trượng bắn ra rồi biến mất, sau đó xuất hiện bên cạnh Mộc phu nhân và chém thân bà thành nhiều đoạn. Đòn này xuyên qua hộ thân miên bố và hộ thể linh quang của bà.","uyLuc":"Đột kích xuyên vị trí, phá phòng hộ và hủy thân tu sĩ Nguyên Anh.","dacDiem":"Trảo mang rời trảo rồi biến mất trong hư không trước khi hiện ra cạnh mục tiêu.","congNang":["Đột kích từ khoảng cách bất ngờ và chém xuyên phòng hộ @c1055"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c1055","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1055","loai":"thi triển","importance":"normal","giaiDoan":"Hủy thân Mộc phu nhân","text":"Cự lang dùng trảo mang xuyên hư không chém Mộc phu nhân thành nhiều đoạn.","anchor":"năm đạo trảo mang dài hơn trượng bắn nhanh phóng ra"}]},"capNhatToi":"@c1055","nguon":["@c1055"]},{"id":"hac-sac-dai-thu-do-ma-khi-huyen-hoa","name":"Hắc sắc đại thủ do ma khí huyễn hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông ma khí","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Cổ ma"],"blurb":"Bàn tay đen do ma khí quanh mục tiêu huyễn hóa, chuyên chộp bắt Nguyên Anh.","detail":"Sau khi thân thể Mộc phu nhân bị hủy, ma khí quanh đó hóa thành hắc sắc đại thủ chộp lấy Nguyên Anh của bà. Cự lang còn dùng tiếng hống khiến pháp lực Nguyên Anh ngưng trệ, giúp ma khí kéo bà mất bóng.","uyLuc":"Bắt giữ Nguyên Anh và kéo vào ma khí.","dacDiem":"Do ma khí trực tiếp huyễn hóa thành bàn tay đen.","congNang":["Chộp bắt Nguyên Anh trong vùng ma khí @c1055"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c1055","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1055","loai":"thi triển","importance":"normal","giaiDoan":"Bắt Nguyên Anh","text":"Ma khí huyễn hóa thành bàn tay đen chộp Nguyên Anh Mộc phu nhân.","anchor":"bỗng nhiên huyễn hóa ra một cái hắc sắc đại thủ"}]},"capNhatToi":"@c1055","nguon":["@c1055"]},{"id":"dao-mang-den-cua-ma-vat-canh-ung","name":"Đao mang đen của ma vật cánh ưng","cn":"","loai":"than-thong","loaiLabel":"Ma đạo công kích","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hai ma vật cánh ưng"],"blurb":"Đòn công kích tầm xa bằng đại đao đen của hai ma vật cánh ưng.","detail":"Hai ma vật cánh ưng chưa đến gần Ngân Sí Dạ Xoa và Sư Cầm Thú đã vung hắc đao, liên tiếp phóng ra những luồng đao mang đen kịt hướng vào nhị yêu.","uyLuc":"Tấn công tầm xa bằng đao mang đen liên tiếp.","dacDiem":"Phát ra từ hắc đao trong tay hai ma vật cánh ưng.","congNang":["Phóng đao mang đen tấn công mục tiêu ở khoảng cách xa @c1055"],"nguoiTu":[{"ten":"Hai ma vật cánh ưng","tuChuong":"@c1055","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1055","loai":"thi triển","importance":"normal","giaiDoan":"Tập kích nhị yêu","text":"Hai ma vật cánh ưng vung hắc đao, phóng đao mang đen về phía Ngân Sí Dạ Xoa và Sư Cầm Thú.","anchor":"hắc đao trong tay hai ma vật này đã vung lên"}]},"capNhatToi":"@c1055","nguon":["@c1055"]},{"id":"bi-thuat-nhap-than-tranh-doat-khong-che-cua-lung-mong","name":"Bí thuật nhập thân tranh đoạt khống chế của Lung Mộng","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật thần hồn","phamCap":"","hePhai":"","soHuu":["Lung Mộng"],"blurb":"Bí thuật thần hồn mà Lung Mộng định dùng để chui vào thân thể ngân lang và tranh đoạt quyền khống chế với Ma Hồn.","detail":"Lung Mộng dự định mạo hiểm nhập vào thân thể ngân lang, cưỡng ép tranh đoạt quyền khống chế với Ma Hồn. Mục tiêu không phải lập tức đánh bại Ma Hồn, mà là khiến ngân lang tạm thời mất khống chế trong chốc lát để tạo cơ hội cho đồng minh hành động.","nguon":["@c1056"]},{"id":"ma-hoa-than-the-bang-ma-khi-te-dan","name":"Ma hóa thân thể bằng ma khí Tế Đàn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Ma công / quá trình ma hóa","phamCap":"","hePhai":"","soHuu":["Phân thần Nguyên Sát Thánh Tổ"],"blurb":"Quá trình Ma Hồn dùng ma khí tinh thuần trong Tế Đàn để tôi luyện và ma hóa thân thể ngân lang.","detail":"Ma Hồn trong ngân lang hấp thu ma khí tinh thuần bên trong Tế Đàn để tôi luyện thân thể. Nếu quá trình hoàn tất, Ma Hồn và thân thể sẽ hòa làm một, khiến Lung Mộng mất cơ hội thu hồi thân thể cũ và làm tình thế giao chiến trở nên cực kỳ bất lợi.","nguon":["@c1056"]},{"id":"thien-lang-toan","name":"Thiên Lang Toản","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Cự lang / phân thân Cổ Ma thánh tổ","Cổ ma hai đầu bốn tay","Ngân Lang"],"blurb":"Công kích quỷ dị của cự lang, vô hình hoặc cực nhanh, khiến Hàn Lập gần như không kịp phản ứng.","detail":"Thiên Lang Toản được cự lang phát động sau khi tam bảo hợp lực ép ngược hắc quang. Đòn đầu đánh trúng ngân sắc quang tráo khiến Hàn Lập bị đánh bay; đòn tiếp theo bị nhân hình khôi lỗi chắn lại, để lộ hai thanh đoản nhận quái dị găm sâu vào vùng ngực và đan điền của khôi lỗi.","nguon":["@c1057","@c1058"],"tabs":{"tienTrinh":[{"chuong":"@c1058","loai":"thi triển","importance":"normal","giaiDoan":"Dùng ba lang trảo bạc","text":"Thiên Lang Toản được phân thân Cổ Ma thánh tổ dùng ma khí thúc dục, xuyên phá nhiều tầng phòng hộ của Hàn Lập nhưng không giết được hắn.","anchor":"Mỗi một lần sử dụng, đều phải hủy đi tứ trảo ngân sắc, chính là lang trảo"}]},"congNang":["Xuyên phá phòng hộ nhiều tầng và gây sát thương trực tiếp vào thân thể @c1058"],"nguoiTu":[{"ten":"Cổ ma hai đầu bốn tay","tuChuong":"@c1058","tangDatToi":"dùng ma khí thúc dục","trangThai":"đã thi triển"}]},{"id":"ma-giap","name":"Ma giáp","cn":"","loai":"than-thong","loaiLabel":"Thần thông ngưng giáp","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Hắc bào nữ tử"],"blurb":"Ma giáp là chiến giáp do cổ ma có cơ thể ma hóa dùng chân ma khí ngưng kết. Nó vừa có sức phòng ngự mạnh vừa giúp tăng thần thông của người mặc.","detail":"Ngân Nguyệt giải thích rằng chỉ một phần cổ ma có cơ thể ma hóa mới có thể dùng chân ma khí ngưng kết ma giáp. Trong chiến tranh cổ đại, yêu tộc và tu sĩ nhân loại từng chịu nhiều đau khổ trước loại ma giáp này; hắc bào nữ tử ở chương này hiện ra hắc giáp dữ tợn có đầu quỷ hai sừng.","thuocTinh":"chân ma khí","nguonGoc":"thần thông của cổ ma có cơ thể ma hóa","uyLuc":"Tăng phòng ngự và thần thông của cổ ma.","dacDiem":"Ngưng kết thành chiến giáp đen dữ tợn từ chân ma khí.","congNang":["Tăng lực phòng ngự cho cơ thể ma hóa @c1058","Mượn ma khí hóa giáp để tăng thần thông @c1058"],"nguoiTu":[{"ten":"Hắc bào nữ tử","tuChuong":"@c1058","tangDatToi":"hiện ma giáp","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1058","loai":"xuất hiện","importance":"normal","giaiDoan":"Hắc bào nữ tử hiện giáp","text":"Hắc bào nữ tử hiện ra ma giáp đen dữ tợn và được Ngân Nguyệt giải thích lai lịch cùng công dụng.","anchor":"chẳng những lực phòng ngự rất mạnh, hơn nữa có thể mượn ma khí hóa thành ma giáp"}]},"capNhatToi":"@c1058","nguon":["@c1058"]},{"id":"khoa-khong-than-niem","name":"Khoa Không Thần Niệm","cn":"","loai":"than-thong","loaiLabel":"Thần niệm vượt giới","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Nguyên Sát thánh tổ"],"blurb":"Khoa Không Thần Niệm là thần niệm của Nguyên Sát thánh tổ hiện thân tại Nhân giới dưới dạng ma tượng. Sự xuất hiện này khiến các tu sĩ tại tế đàn kinh hãi.","detail":"Hoa Thiên Kỳ nhận ra ma tượng đen khổng lồ là Khoa Không Thần Niệm của Nguyên Sát thánh tổ. Thần niệm này được hắc giáp nữ tử mượn ma khí dưới tế đàn triệu hồi, sau đó phá thế áp chế của tam bảo, nghiền vỡ hai phỏng chế Thông Thiên Linh Bảo và ra tay khiến Sư cầm thú tự bạo.","thuocTinh":"thần niệm vượt giới","nguonGoc":"Nguyên Sát thánh tổ","uyLuc":"Có thể hiện thân thành ma tượng, phá bảo vật liên thủ và sát thương cường địch từ xa.","dacDiem":"Cần nguồn ma khí dưới tế đàn duy trì trong lần hiện thân này.","congNang":["Đưa thần niệm Nguyên Sát thánh tổ hiện thành ma tượng tại Nhân giới @c1058","Phá thế áp chế của tam bảo và can thiệp trực tiếp vào chiến trường @c1058"],"nguoiTu":[{"ten":"Nguyên Sát thánh tổ","tuChuong":"@c1058","tangDatToi":"hiện thân ma tượng","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1058","loai":"xuất hiện","importance":"major","giaiDoan":"Ma tượng hiện thân","text":"Khoa Không Thần Niệm của Nguyên Sát thánh tổ được nhận ra khi ma tượng đen hiện trên tế đàn và làm toàn bộ tu sĩ biến sắc.","anchor":"Khoa Không Thần Niệm, đây đích thực là thần niệm của nguyên sát thánh tổ!"}]},"capNhatToi":"@c1058","nguon":["@c1058"]},{"id":"ma-chi-cua-ma-tuong","name":"Ma chỉ của ma tượng","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Cổ ma","soHuu":["Nguyên Sát thánh tổ"],"blurb":"Ma chỉ của ma tượng là đòn búng tay của ma tượng Nguyên Sát thánh tổ. Một lần thi triển khiến Sư cầm thú tự bạo không rõ nguyên do.","detail":"Sau khi dùng mắt tím quét qua khiến mọi người cảnh giác lùi lại, ma tượng nâng tay búng ra một ma chỉ cực lớn. Vật gì đó chợt lóe biến mất, rồi Sư cầm thú đang cùng ma vật hình đại ưng run rẩy phát tiếng kêu thảm và tự bạo.","thuocTinh":"ma khí","uyLuc":"Khiến Sư cầm thú tự bạo chỉ sau một lần búng chỉ.","dacDiem":"Đòn công kích phát ra rất nhanh, dấu vết chỉ lóe lên rồi biến mất.","congNang":["Tác động từ xa khiến mục tiêu tự bạo @c1058"],"nguoiTu":[{"ten":"Nguyên Sát thánh tổ","tuChuong":"@c1058","tangDatToi":"búng ma chỉ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1058","loai":"thi triển","importance":"normal","giaiDoan":"Sư cầm thú tự bạo","text":"Ma tượng búng một ma chỉ cực lớn về phía đám người, sau đó Sư cầm thú kêu thảm và tự bạo.","anchor":"một tay liền được nhấc lên, xuất ra cái ma chỉ cực lớn"}]},"capNhatToi":"@c1058","nguon":["@c1058"]},{"id":"dung-hop-thanh-linh-lung","name":"Dung hợp thành Linh Lung","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật dung hợp nguyên thần","phamCap":"không rõ","hePhai":"Ngân Nguyệt tộc","soHuu":["Lung Mộng","Ngân Nguyệt"],"blurb":"Bí thuật dung hợp nguyên thần giữa Lung Mộng và Tuyết Linh để tái thành Linh Lung.","detail":"Lung Mộng thúc Hàn Lập thả Tuyết Linh để hai nguyên thần dung hợp thành Linh Lung, coi đây là cơ hội sống sót trước Ma Tượng trong tình thế tuyệt hiểm.","congNang":["Dung hợp nguyên thần Lung Mộng và Tuyết Linh để hình thành Linh Lung @c1059"],"nguoiTu":[{"ten":"Lung Mộng","tuChuong":"@c1059","tangDatToi":"chuẩn bị dung hợp","trangThai":"đang dùng"},{"ten":"Ngân Nguyệt","tuChuong":"@c1059","tangDatToi":"chuẩn bị dung hợp","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1059","loai":"xuất hiện","importance":"major","giaiDoan":"Đề nghị dung hợp","text":"Lung Mộng yêu cầu thả Tuyết Linh để hai người dung hợp thành Linh Lung, mở ra cơ hội chống lại Ma Tượng.","anchor":"Mau đem nàng phóng xuất cùng ta dung hợp thành Linh Lung"}]},"capNhatToi":"@c1059","nguon":["@c1059"]},{"id":"ma-mong-long","name":"Ma Mộng Long","cn":"","loai":"than-thong","loaiLabel":"Thần thông biến hóa","phamCap":"không rõ","hePhai":"Lung Mộng","soHuu":["Lung Mộng"],"blurb":"Thần thông hoặc trạng thái được Lung Mộng nhắc tới như hy vọng chống đỡ Ma Tượng sau khi dung hợp.","detail":"Trong tình thế Ma Tượng áp đảo toàn trường, Lung Mộng nói Ma Mộng Long có lẽ có năng lực ngăn cản Ma Tượng một trận nếu việc dung hợp được hoàn thành.","congNang":["Có thể chống đỡ Ma Tượng một trận theo nhận định của Lung Mộng @c1059"],"tabs":{"tienTrinh":[{"chuong":"@c1059","loai":"nhắc tới","importance":"normal","giaiDoan":"Hy vọng đối kháng","text":"Lung Mộng nhắc Ma Mộng Long như khả năng chặn Ma Tượng sau khi dung hợp.","anchor":"đối phó Ma Tượng này, Ma Mộng Long có lẽ có năng lực"}]},"capNhatToi":"@c1059","nguon":["@c1059"]},{"id":"kim-cuong-trao","name":"Kim Cương Tráo","aliases":["Ngũ tử ma Kim Cương Tráo"],"cn":"","loai":"than-thong","loaiLabel":"Phòng ngự thần thông","phamCap":"không rõ","hePhai":"Hàn Lập","soHuu":["Hàn Lập"],"blurb":"Tầng phòng ngự được Hàn Lập kích phát khi đối diện công kích của Ma Tượng.","detail":"Hàn Lập kích phát uy năng Ngũ tử ma Kim Cương Tráo để bảo hộ thân mình, nhưng tầng phòng ngự này vẫn bị công kích của Ma Tượng đánh vỡ.","congNang":["Tạo tầng phòng ngự bảo hộ Hàn Lập @c1059"],"tabs":{"tienTrinh":[{"chuong":"@c1059","loai":"thi triển","importance":"normal","giaiDoan":"Bị Ma Tượng phá","text":"Hàn Lập kích phát Kim Cương Tráo trong hệ thống phòng ngự nhưng bị Ma Tượng xuyên phá.","anchor":"lại đem cả ngũ tử ma Kim Cương Tráo uy năng cũng kích phát"}]},"capNhatToi":"@c1059","nguon":["@c1059"]},{"id":"thong-linh-bao-quyet","name":"Thông Linh bảo quyết tầng thứ nhất","cn":"","loai":"cong-phap","loaiLabel":"Pháp quyết ngự bảo","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp quyết ngự bảo mà Hàn Lập dùng để thúc giục Hư Thiên Đỉnh.","detail":"Ở chương này Hàn Lập mới chỉ phóng ra được tầng thứ nhất của Thông Linh bảo quyết nên Hư Thiên Đỉnh chưa phát huy đủ uy năng trước ma chưởng của Nguyên Sát.","nguon":["@c1060"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1060","tangDatToi":"tầng thứ nhất","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1060","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"tầng thứ nhất","text":"Hàn Lập chỉ mới thi triển được tầng thứ nhất nên chưa phát huy đủ uy năng của Hư Thiên Đỉnh.","anchor":"chỉ mới phóng ra được bí quyết tầng thứ nhất của Thông Linh bảo"}]},"capNhatToi":"@c1060"},{"id":"khieu-nguyet-yeu-cong","name":"Khiếu Nguyệt yêu công","cn":"","loai":"cong-phap","loaiLabel":"Yêu công","phamCap":"không rõ","hePhai":"Yêu Tộc","soHuu":["Ngao Khiếu lão tổ"],"blurb":"Yêu công nổi danh của Ngao Khiếu yêu vương.","detail":"Nguyên Sát Thánh Tổ nói từng bội phục Khiếu Nguyệt yêu công của Ngao Khiếu trong hai lần viễn chinh đánh Linh giới, cho thấy công pháp này gắn với uy danh khiến Nguyên Sát kiêng kị.","nguon":["@c1060"],"nguoiTu":[{"ten":"Ngao Khiếu lão tổ","tuChuong":"@c1060","tangDatToi":"không rõ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1060","loai":"nhắc tới","importance":"normal","giaiDoan":"uy danh","text":"Nguyên Sát nhắc từng bội phục Khiếu Nguyệt yêu công của Ngao Khiếu trong chiến sự Linh giới.","anchor":"đối với Khiếu Nguyệt yêu công của lão lang kia"}]},"capNhatToi":"@c1060"},{"id":"than-niem-nguyen-sat","name":"Thần niệm Nguyên Sát Thánh Tổ","cn":"","loai":"than-thong","loaiLabel":"Thần niệm công kích","phamCap":"không rõ","hePhai":"Cổ Ma giới","soHuu":["Nguyên Sát Thánh Tổ"],"blurb":"Thần niệm công kích của Nguyên Sát Thánh Tổ, có thể áp súc thành vật chất để phá phòng ngự.","detail":"Trong chương này thần niệm được áp súc thành viên châu nhũ trắng, phá kim quang tráo và hỏa thuẫn của Tam Diễm Phiến, sau đó tiếp tục hóa thành tinh mang công kích Linh Lung.","nguon":["@c1060"],"congNang":["Áp súc thành viên châu nhũ trắng để xuyên phá phòng ngự.","Hóa thành vô số tinh mang công kích mục tiêu."],"tabs":{"tienTrinh":[{"chuong":"@c1060","loai":"thi triển","importance":"normal","giaiDoan":"áp súc thành vật chất","text":"Nguyên Sát áp súc thần niệm thành viên châu nhũ trắng phá phòng ngự của Hàn Lập.","anchor":"do thần niệm của Nguyên Sát Thánh Tổ áp súc ngưng tụ"}]},"capNhatToi":"@c1060"},{"id":"tran-phap-te-dan-co-ma","name":"Trận pháp tế đàn Cổ Ma","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Cổ Ma","soHuu":["Phân thân Nguyên Sát Thánh Tổ"],"blurb":"Trận pháp lớn quanh tế đàn cung cấp hắc ma khí cho thần niệm Nguyên Sát. Dù hơn mười cột đá bị Phệ Kim Trùng phá khiến nó tạm dừng, nữ tử giáp đen vẫn có thể tái khởi qua Hóa Long Tỳ trên bia đá.","detail":"Trận pháp này vận hành bằng các cột đá và trận cơ quanh tế đàn, có tác dụng cung cấp hắc ma khí và duy trì cục diện phong ấn hoặc triệu hồi tại nơi này. Khi các cột đá tắt linh quang, nguồn hắc ma khí bị cắt làm thần niệm Nguyên Sát tan biến; sau đó phân thân Nguyên Sát đặt tay lên Hóa Long Tỳ khiến trận pháp hoạt động trở lại.","congNang":["Cung cấp hắc ma khí cho ma tượng thần niệm Nguyên Sát @c1061","Có thể được tái khởi qua Hóa Long Tỳ trên bia đá sau khi một số cột đá bị phá @c1061"],"trangThai":"đang vận hành lại @c1061","capNhatToi":"@c1061","tabs":{"tienTrinh":[{"chuong":"@c1061","loai":"xuất hiện","importance":"normal","giaiDoan":"Tạm dừng rồi tái khởi","text":"Trận pháp bị ngừng khi hơn mười cột đá mất linh quang, sau đó được phân thân Nguyên Sát tái khởi qua Hóa Long Tỳ trên bia đá.","anchor":"trận pháp cực lớn vốn vẫn đang được kích phát bỗng nhiên dừng lại"}]},"nguon":["@c1061"]},{"id":"tinh-tru-than-niem-cua-nguyen-sat","name":"Tinh trụ thần niệm của Nguyên Sát","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cổ Ma","soHuu":["Nguyên Sát thánh tổ"],"blurb":"Đòn tinh quang do thần niệm Nguyên Sát ngưng tụ khi hóa thành người khổng lồ trong suốt. Dù bị gián đoạn vì nguồn hắc ma khí bị cắt, nửa đoạn tinh trụ vẫn xuyên qua phòng hộ của Linh Lung.","detail":"Tinh trụ là công kích thần niệm cực mạnh của Nguyên Sát trong lúc đối đầu Linh Lung. Nghịch Tinh Bàn hút được một phần uy lực nhưng không hóa giải hết, khiến đòn còn lại xuyên thủng bụng dưới Linh Lung.","uyLuc":"Xuyên thủng thân thể thần niệm của Linh Lung dù đã bị Nghịch Tinh Bàn triệt tiêu một phần @c1061","congNang":["Ngưng tinh quang thần niệm thành trụ công kích trực tiếp thân thể thần niệm đối phương @c1061"],"trangThai":"đã thi triển @c1061","capNhatToi":"@c1061","tabs":{"tienTrinh":[{"chuong":"@c1061","loai":"thi triển","importance":"normal","giaiDoan":"Đả thương Linh Lung","text":"Nguyên Sát tung tinh trụ thần niệm, khiến nửa đoạn công kích còn lại xuyên thủng bụng dưới Linh Lung.","anchor":"hung hăng đánh lên phần bụng dưới của Linh Lung"}]},"nguon":["@c1061"]},{"id":"thien-luan-hoa-ma-dai-phap","name":"Thiên Luân Hóa Ma đại pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật hóa ma","phamCap":"không rõ","hePhai":"Cổ Ma","soHuu":["Nguyên Sát Thánh Tổ"],"blurb":"Bí pháp hóa ma do Nguyên Sát Thánh Tổ nêu tên khi giải thích bố cục tạo chiến ma ba đầu. Pháp này phối hợp Chân Ma Khí, ma giáp và hóa thân để thúc đẩy dung hợp ma hóa.","detail":"Nguyên Sát dùng Thiên Luân Hóa Ma đại pháp để đưa quái nhân đầu to vào vòng phong ấn, truyền Chân Ma Khí, mặc ma giáp và dung hợp với hóa thân của mình. Hình thái tạo ra chưa hoàn chỉnh nhưng một kích toàn lực vẫn không kém tu sĩ Hóa Thần kỳ.","thuocTinh":"ma công","uyLuc":"Có thể tạo chiến ma chưa hoàn chỉnh nhưng một kích toàn lực không kém tu sĩ Hóa Thần kỳ.","dacDiem":"Cần Chân Ma Khí, ma giáp và hóa thân phối hợp để hình thành chiến ma dung hợp.","congNang":["Đưa đối tượng vào vòng phong ấn và thúc đẩy hóa ma bằng Chân Ma Khí.","Dung hợp người bị hóa ma với hóa thân để tạo hình thái chiến ma ba đầu."],"nguoiTu":[{"ten":"Nguyên Sát Thánh Tổ","tuChuong":"@c1062","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1062","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ bí pháp","text":"Nguyên Sát Thánh Tổ nêu tên Thiên Luân Hóa Ma đại pháp và giải thích nó là nền tảng tạo ra Già Luân Chiến Ma chưa hoàn chỉnh.","anchor":"Thiên Luân Hóa Ma đại pháp của bản Thánh tổ cũng không tệ lắm"}]},"trangThai":"đang dùng","capNhatToi":"@c1062","nguon":["@c1062"]},{"id":"gia-luan-chien-ma","name":"Già Luân Chiến Ma","cn":"","loai":"than-thong","loaiLabel":"Hình thái chiến ma","phamCap":"không rõ","hePhai":"Cổ Ma","soHuu":["Nguyên Sát Thánh Tổ","Quái nhân đầu to","Hai ma vật mình người cánh ưng"],"blurb":"Hình thái chiến ma ba đầu do Thiên Luân Hóa Ma đại pháp tạo ra. Bản trong chương này chưa hoàn chỉnh nhưng vẫn có uy lực cực lớn.","detail":"Già Luân Chiến Ma trong chương này được tạo từ quái nhân đầu to, hai ma vật mình người cánh ưng, Chân Ma Khí, ma giáp và hóa thân của Nguyên Sát. Do thời gian truyền Chân Ma Khí quá ngắn nên chưa chân chính hoàn thành, nhưng một kích toàn lực đủ giết Huyền Thanh Tử và uy hiếp toàn cục.","thuocTinh":"ma hóa chiến đấu","uyLuc":"Một kích toàn lực không kém tu sĩ Hóa Thần kỳ khi phối hợp ma giáp và hóa thân.","dacDiem":"Có ba đầu, sáu tay, chiến giáp đen và sáu binh khí đen khi hình thái dung hợp ổn định hơn.","congNang":["Hóa thành chiến ma ba đầu để phát ra một kích cực mạnh.","Dung hợp ba ma vào một thân thể chiến đấu có sáu tay và nhiều binh khí."],"tabs":{"tienTrinh":[{"chuong":"@c1062","loai":"xuất hiện","importance":"major","giaiDoan":"Chiến ma chưa hoàn chỉnh","text":"Nguyên Sát thừa nhận hình thái này chưa chân chính hóa thành Già Luân Chiến Ma ba đầu vì thời gian truyền Chân Ma Khí quá ngắn.","anchor":"không thể chân chính hóa thành hình dạng ba đầu Già Luân Chiến Ma"}]},"trangThai":"đang hiện hình","capNhatToi":"@c1062","nguon":["@c1062"]},{"id":"khong-gian-huyen-dieu","name":"Không gian huyền diệu","cn":"","aliases":["Khốn Tiên Lung","Mộng Yểm Các"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thượng cổ","hePhai":"","soHuu":[],"blurb":"Bí thuật thượng cổ đã thất truyền ở Nhân Giới, bản chất nhốt người vào khe không gian tạm thời do linh lực tạo ra.","detail":"Yêu cầu tối thiểu Hóa Thần trung kỳ mới thi triển. Khe không gian không tồn tại lâu, người thi triển không tự vào được. Tu sĩ cùng cấp khó nhốt chính xác, tu sĩ cấp cao có nhiều thần thông tiện hơn nên dần thất truyền. Linh hồn mới (cổ ma) tu vi gần Luyện Hư sơ kỳ đã dùng nhốt Hướng Chi Lễ; Linh Lung mượn lực Nghịch Tinh Bàn giải phóng.","thuocTinh":"Không gian","nguonGoc":"Bí thuật thượng cổ, thất truyền ở Nhân Giới","yeuCau":"Tối thiểu Hóa Thần trung kỳ","uyLuc":"Nhốt người vào khe không gian tạm thời, tu sĩ cùng cấp khó thoát","dacDiem":"Khe không gian tự biến mất sau thời gian, người thi triển không tự vào được, thực dụng thấp do tu sĩ cấp cao có nhiều thần thông tiện hơn","congNang":["Nhốt người vào khe không gian tạm thời do linh lực tạo ra"],"nguoiTu":[{"ten":"Cổ ma","tuChuong":"@c1064","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1064","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lộ bản chất bí thuật","text":"Được giải thích rõ bản chất: nhốt người vào khe không gian tạm thời do linh lực tạo ra, có nhiều tên gọi (Khốn Tiên Lung, Mộng Yểm Các), yêu cầu tối thiểu Hóa Thần trung kỳ, đã thất truyền ở Nhân Giới. Cổ ma (linh hồn mới) tu vi gần Luyện Hư sơ kỳ đã dùng nhốt Hướng Chi Lễ, Linh Lung mượn lực Nghịch Tinh Bàn giải phóng.","anchor":"đem một người tới nhốt ở một khe không gian tạm thời do một lượng lớn linh lực tạo ra mà thôi"}]},"nguon":["@c1064"]},{"id":"dung-linh-dai-phap","name":"Dung Linh Đại Pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":[],"blurb":"Bí thuật dung hợp hai linh hồn thành một thực thể mới mạnh hơn nhiều lần.","detail":"Ma hồn và Linh Lung dùng Dung Linh Đại Pháp tạo linh hồn mới, tu vi gần Luyện Hư sơ kỳ.","congNang":["Dung hợp hai linh hồn thành một thực thể mới mạnh hơn nhiều lần"],"nguoiTu":[{"ten":"Ma hồn","tuChuong":"@c1064","trangThai":"da-dung"},{"ten":"Linh Lung","tuChuong":"@c1064","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1064","loai":"nhắc tới","importance":"bridge","giaiDoan":"Nhắc lại trong hồi ức","text":"Được nhắc lại: trước đó ma hồn và Linh Lung dùng Dung Linh Đại Pháp tạo linh hồn mới tu vi gần Luyện Hư sơ kỳ.","anchor":"sử dụng Dung Linh Đại Pháp tạo thành linh hồn mới"}]},"nguon":["@c1064"]},{"id":"nghich-linh-thong-dao","name":"Nghịch Linh Thông Đạo","cn":"逆灵通道","loai":"khac","loaiLabel":"Thông đạo / Trận pháp","phamCap":"Không rõ","hePhai":"Linh giới","soHuu":[],"blurb":"Thông đạo nối Nhân giới và Linh giới, không phải thực thể cố định mà do Linh giới dùng Thiên lực nhất thời mở ra, dùng xong biến mất.","detail":"Nghịch Linh Thông Đạo do Linh giới nhờ vào Thiên lực nhất thời mở ra, dùng xong biến mất. Muốn mở lại cần đốt Truyền Giới Hương và tiêu hao lượng Cao giai Linh Thạch cực lớn. Xưa kia tu sĩ thượng cổ Nhân giới đốt Truyền Giới Hương để cầu viện, Linh giới mở thông đạo đáp ứng. Linh Lung có ấn ký Nghịch Tinh Bàn trên chân thân và thần niệm, có thể kích phát pháp trận riêng do trưởng lão Ngân Nguyệt Lang Tộc thiết lập để mở thông đạo nhỏ chỉ cho một mình nàng.","congNang":["Thông đạo nối Nhân giới–Linh giới, cho phép tu sĩ di chuyển giữa hai giới @c1066"],"nguon":["@c1066"],"tabs":{"tienTrinh":[{"chuong":"@c1066","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Linh Lung tiết lộ bản chất","text":"Linh Lung cho biết Nghịch Linh Thông Đạo không phải thực thể cố định, do Linh giới dùng Thiên lực nhất thời mở, dùng xong biến mất. Muốn mở lại cần đốt Truyền Giới Hương và lượng Cao giai Linh Thạch cực lớn.","anchor":"Nghịch Linh Thông Đạo, chẳng qua là do Linh giới chúng ta nhờ vào Thiên lực nhất thời mở ra thông đạo mà thôi"}]}},{"id":"thien-phu-than-thong-ngan-toc","name":"Thiên phú thần thông Ngân tộc","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ngân Nguyệt Lang Tộc","soHuu":["Linh Lung"],"blurb":"Thiên phú thần thông của Ngân Nguyệt Lang Tộc, Linh Lung coi đây là vũ khí chính để đoạt hồi chân thân từ Ma vật.","detail":"Linh Lung nhắc tới thiên phú thần thông của Ngân tộc như phương tiện chính để đoạt lại thân thể từ Ma vật, cần chuẩn bị kỹ trước khi tiếp cận. Nàng tự tin có trên 50% cơ hội thành công nhờ thần thông này.","congNang":["Hỗ trợ đoạt hồi chân thân từ thực thể chiếm cứ @c1066"],"nguon":["@c1066"],"tabs":{"tienTrinh":[{"chuong":"@c1066","loai":"xuat-hien","importance":"normal","giaiDoan":"Linh Lung nhắc tới khi lập kế hoạch đoạt thân","text":"Linh Lung nói sẽ chuẩn bị thiên phú thần thông Ngân tộc để đoạt hồi chân thân, tự tin có trên 50% cơ hội.","anchor":"Trước tiên ta sẽ chuẩn bị tốt thiên phú thần thông của Ngân tộc chúng ta"}]}},{"id":"phap-tran-rieng-ngan-nguyet-lang-toc","name":"Pháp trận riêng của Ngân Nguyệt Lang Tộc","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Ngân Nguyệt Lang Tộc","soHuu":["Linh Lung"],"blurb":"Pháp trận do trưởng lão Ngân Nguyệt Lang Tộc thiết lập riêng cho Linh Lung, kích phát ấn ký Nghịch Tinh Bàn sẽ mở thông đạo nhỏ chỉ cho một mình nàng.","detail":"Trưởng lão trong tộc Linh Lung đã thiết lập pháp trận chuyên môn, khi nàng kích phát ấn ký Nghịch Tinh Bàn trên chân thân và thần niệm sẽ mở Nghịch Linh Thông Đạo nhỏ chỉ cho một mình nàng đi qua. Người khác tiến vào sẽ bị nghiền nát.","congNang":["Mở thông đạo nhỏ riêng cho Linh Lung trở về Linh giới, xác minh ấn ký, người khác bị nghiền nát @c1066"],"nguon":["@c1066"],"tabs":{"tienTrinh":[{"chuong":"@c1066","loai":"xuat-hien","importance":"normal","giaiDoan":"Linh Lung tiết lộ","text":"Linh Lung cho biết trưởng lão trong tộc đã thiết lập pháp trận chuyên môn cho nàng dùng, kích phát ấn ký Nghịch Tinh Bàn sẽ mở thông đạo nhỏ.","anchor":"Trưởng lão trong tộc ta đã thiết lập một cái pháp trận chuyên môn cho ta dùng"}]}},{"id":"phap-tran-du-phong-con-ngo-son","name":"Pháp trận dự phòng Côn Ngô Sơn","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Cổ tu sĩ","soHuu":[],"blurb":"Pháp trận dự phòng do các Cổ tu sĩ thiết lập, cần Khiếu Thiên Tinh Bi để kích hoạt, thay thế pháp trận chính dùng Hóa Long Tỳ.","detail":"Ngoài pháp trận chính dùng Hóa Long Tỳ, các Cổ tu sĩ đã chuẩn bị pháp trận dự phòng cần pháp khí Khiếu Thiên Tinh Bi để kích hoạt, nhằm khống chế cấm chế của Côn Ngô Sơn.","congNang":["Thay thế pháp trận chính khi Hóa Long Tỳ không dùng được, khống chế cấm chế Côn Ngô Sơn @c1066"],"nguon":["@c1066"],"tabs":{"tienTrinh":[{"chuong":"@c1066","loai":"xuat-hien","importance":"normal","giaiDoan":"Hướng Chi Lễ tiết lộ","text":"Hướng Chi Lễ cho biết các Cổ tu sĩ đã chuẩn bị pháp khí Khiếu Thiên Tinh Bi làm dự phòng cho pháp trận Côn Ngô Sơn.","anchor":"Năm đó để khống chế cấm chế của Côn Ngô Sơn các Cổ tu sĩ đã chuẩn bị một kiện pháp khí khác để dự phòng"}]}},{"id":"phong-linh-dai-phap","name":"Phong Linh Đại Pháp","cn":"封灵大法","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Bí thuật phong ấn bí mật, cần sự phối hợp của đối tượng. Phong ấn thành công thì kể cả bên thứ ba chiếm quyền khống chế cũng vô pháp cởi bỏ.","detail":"Hàn Lập thi triển lên Ngân Nguyệt để phong ấn bí mật về tiểu bình. Phong ấn vĩnh viễn trừ phi một trong hai người chết hoặc chính thức giải trừ thân phận khí linh, kể cả ở Linh Giới cũng không sợ bị phát hiện. Khi thi triển, Hàn Lập hai tay bắt pháp quyết niệm chú, thanh quang từ trong người phát ra bao phủ hai người.","congNang":["Phong ấn ký ức/bí mật về bảo vật, ngăn bên thứ ba dù chiếm quyền khống chế thân thể cũng không thể cởi bỏ"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1067","tangDatToi":"Thành công","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1067","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển thành công","text":"Hàn Lập bắt pháp quyết niệm chú, thanh quang bao phủ hai người, phối hợp cùng Ngân Nguyệt phong ấn bí mật tiểu bình thành công. Linh Lung dù chiếm lại quyền cũng vô pháp cởi bỏ.","anchor":"bí thuật thực hiện thành công. Cho dù Lung linh một lần nữa chiếm quyền điều khiển cũng vô pháp cởi bỏ phong ấn này"}]},"nguon":["@c1067"]},{"id":"linh-hon-thon-phe","name":"Linh Hồn Thôn Phệ","cn":"灵魂吞噬","aliases":["linh hồn cắn nuốt","thần thông thôn phệ linh hồn"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Ngân Nguyệt","Linh Lung"],"blurb":"Thần thông cường ngạnh thôn phệ linh hồn đối phương, có thể dùng để đoạt lại thân thể hoặc nuốt phân thần kẻ khác.","detail":"Ngân Nguyệt dự định dùng để thôn phệ trở lại thân thể ban đầu và thôn phệ phân thần Nguyên Sát Thánh Tổ trong đệ cửu tầng không gian. Chưa thi triển trong chương 1067.","congNang":["Cường ngạnh thôn phệ linh hồn đối phương","Đoạt lại thân thể bị chiếm"],"nguoiTu":[{"ten":"Ngân Nguyệt","tuChuong":"@c1067","tangDatToi":"Chưa thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1067","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Ngân Nguyệt tiết lộ kế hoạch sử dụng","text":"Ngân Nguyệt bày kế dùng thần thông thôn phệ linh hồn cường ngạnh thôn phệ trở lại thân thể ban đầu và nuốt phân thần Nguyên Sát Thánh Tổ.","anchor":"ta sẽ dùng thần thông thôn phệ linh hồn cường ngạnh thôn phệ trở lại trong thân thể ban đầu"}]},"nguon":["@c1067"]},{"id":"phap-tran-phong-an-thien-tinh-bi","name":"Pháp trận phong ấn (Thiên Tinh Bi)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp cổ đại được kích hoạt bởi Thiên Tinh Bi nhấn vào thạch bia sá linh nhuyễn ngọc, hơn mười thạch trụ mọc lên hút sạch ma khí, linh đoàn nhũ bạch khổng lồ phong ấn hoàn toàn hắc động và tái tạo chướng bích.","detail":"Khi Thiên Tinh Bi được nhấn vào thạch bia, thạch bia tự cắm xuống đất phát ông minh, hơn mười đạo quang trụ từ mặt đất mọc lên hóa thành cự đại thạch trụ, đỉnh mỗi trụ có linh hoàn đa sắc quay cuồng hút sạch ma khí trong không gian. Phía trên hắc động xuất hiện vô số quang tia như mạng nhện, hình thành linh đoàn nhũ bạch sắc cự đại đủ sức ngăn cả tiểu sơn, áp xuống phong ấn hắc động hoàn toàn, chướng bích tái lập.","congNang":["Hút sạch ma khí trong không gian phong ấn","Tái tạo chướng bích phong ấn hắc động"],"tabs":{"tienTrinh":[{"chuong":"@c1068","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt lần đầu","text":"Hàn Lập nhấn Thiên Tinh Bi vào thạch bia, kích hoạt trận pháp. Hơn mười thạch trụ mọc lên hút ma khí, linh đoàn nhũ bạch phong ấn hắc động hoàn toàn.","anchor":"từ mặt đất hơn mười đạo quang trụ phát ra tiếng nổ vang kinh nhân mọc lên, hoá thành các cự đại thạch trụ"}]},"nguon":["@c1068"]},{"id":"lien-linh-thong-dao-dai-tran","name":"Liên Linh Thông Đạo đại trận","cn":"连灵通道大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ (cấp linh giới)","hePhai":"Linh giới","soHuu":[],"blurb":"Đại trận cực kỳ thần diệu do tu sĩ linh giới dùng để mở nghịch linh thông đạo, cần số lượng khổng lồ linh thạch đỉnh giai, không thích hợp nhân giới sử dụng.","detail":"Phương pháp bố trí đại trận mở nghịch linh thông đạo, nguồn gốc từ tu sĩ linh giới. Yêu cầu linh thạch đỉnh giai với số lượng khổng lồ khiến Hàn Lập kinh hãi. Không thích hợp cho nhân giới nhưng có giá trị nghiên cứu. Tư liệu nằm trong ngọc giản trắng mà Hàn Lập thu được.","thuocTinh":"Không gian","nguonGoc":"Tu sĩ linh giới","yeuCau":"Linh thạch đỉnh giai số lượng khổng lồ","uyLuc":"Mở được nghịch linh thông đạo nối nhân giới và linh giới","dacDiem":"Cực kỳ thần diệu, quy mô quá lớn cho nhân giới","congNang":["Mở nghịch linh thông đạo"],"trangThai":"Tư liệu đã được Hàn Lập sở hữu, chưa thi triển","tabs":{"tienTrinh":[{"chuong":"@c1071","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện tư liệu","text":"Hàn Lập nghiên cứu ngọc giản trắng, phát hiện phương pháp bố trí đại trận Liên Linh Thông Đạo do tu sĩ linh giới dùng mở nghịch linh thông đạo, cần linh thạch đỉnh giai khổng lồ, không hợp nhân giới nhưng có giá trị nghiên cứu.","anchor":"một loại phương pháp bố trí đại trận cực kỳ thần diệu được tu sĩ linh giới dùng để mở nghịch linh thông đạo"}]},"capNhatToi":"@c1071","nguon":["@c1071"]},{"id":"ao-tran-suong-mu-can-lao-ma","name":"Ảo trận sương mù (trận bàn Càn lão ma)","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Cao giai","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bộ trận kỳ trận bàn lấy từ túi trữ vật Càn lão ma, tạo ảo trận sương mù bao phủ cả tòa linh sơn, đủ cầm chân Kết Đan kỳ tu sĩ.","detail":"Thuộc loại cao giai khí cụ bày trận, lấy được từ túi trữ vật của Càn lão ma. Triển khai tạo sương mù bao phủ toàn bộ Tuyết Liên sơn. Tu sĩ Kết Đan kỳ lầm vào sẽ đại phí trắc trở mới thoát thân. Kết hợp mười hai con Lục Dực Sương Công ẩn trong sương mù, tạo hai lớp phòng ngự khiến ngay cả Nguyên Anh sơ kỳ cũng khó xâm nhập.","nguonGoc":"Túi trữ vật của Càn lão ma","congNang":["Tạo ảo trận sương mù bao phủ toàn sơn, cầm chân Kết Đan kỳ tu sĩ"],"uyLuc":"Kết Đan kỳ lầm vào đại phí trắc trở thoát thân; kết hợp Lục Dực Sương Công chặn được Nguyên Anh sơ kỳ","tabs":{"tienTrinh":[{"chuong":"@c1072","loai":"thi triển","importance":"major","giaiDoan":"Triển khai phòng hộ Tuyết Liên sơn","text":"Hàn Lập triển khai bộ trận kỳ trận bàn từ túi trữ vật Càn lão ma, tạo ảo trận sương mù bao phủ toàn Tuyết Liên sơn, kết hợp mười hai con Lục Dực Sương Công ẩn bên trong canh giữ.","anchor":"bộ pháp trận này là hắn lấy được từ trong túi trữ vật của Càn lão ma, xem ra là một phần của cao giai khí cụ bày trận"}]},"nguon":["@c1072"]},{"id":"bat-linh-xich-thong-bao-quyet","name":"Bát Linh xích thông bảo quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Phật môn","soHuu":["Hàn Lập"],"blurb":"Khẩu quyết kích hoạt Bát Linh xích, ẩn bên trong linh bảo dưới dạng văn tự phật quang, chỉ hiển lộ khi rót phật quang vào.","detail":"Khẩu quyết hiển lộ dưới dạng văn tự phật quang khi dùng phật quang rót vào Bát Linh xích. Tầng thứ nhất cần khoảng một năm sơ thành. Khác biệt với thông bảo quyết Hư Thiên đỉnh. Phải dùng phật quang (từ Kim Cương tráo) mới tu luyện được, linh lực thường hoàn toàn vô dụng.","thuocTinh":"Phật quang","nguonGoc":"Ẩn trong Bát Linh xích","yeuCau":"Phật quang (Hàn Lập dùng Kim Cương tráo thay thế)","cacTang":[{"ten":"Tầng thứ nhất","moTa":"Cần một năm công phu sơ thành","chuong":"@c1073"}],"trangThai":"dang-tu","capNhatToi":"@c1073","congNang":["Kích hoạt và khu sử Bát Linh xích (Thông Thiên Linh Bảo phật môn)"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1073","tangDatToi":"Tầng 1 (đang tu)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1073","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và ghi nhớ khẩu quyết","text":"Hàn Lập dùng phật quang từ Kim Cương tráo rót vào Bát Linh xích, xích phát thanh quang hiển lộ thông bảo quyết bằng văn tự phật quang. Ghi nhớ khẩu quyết tầng thứ nhất, cần một năm sơ thành.","anchor":"Tầng thứ nhất chỉ cần một năm công phu là có thể sơ thành"}]},"nguon":["@c1073"]},{"id":"dai-nguyen-kiem-tran","name":"Đại Nguyên kiếm trận","cn":"大元剑阵","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp phối hợp bộ Thanh Trúc Phong Vân kiếm, uy lực giảm mạnh khi phi kiếm bị ma hóa.","detail":"Trận pháp triển khai bằng bộ Thanh Trúc Phong Vân kiếm. Khi hai thanh kiếm bị Cổ Ma ma hóa, uy lực trận giảm mạnh, là lý do Hàn Lập phải tế luyện lại phi kiếm.","congNang":["Phối hợp bộ Thanh Trúc Phong Vân kiếm tạo kiếm trận uy lực lớn"],"trangThai":"hoat-dong","capNhatToi":"@c1073","tabs":{"tienTrinh":[{"chuong":"@c1073","loai":"nhắc tới","importance":"bridge","giaiDoan":"Nhắc uy lực giảm khi kiếm bị ma hóa","text":"Hai thanh Thanh Trúc Phong Vân kiếm bị ma hóa nên tạo Đại Nguyên kiếm trận uy lực giảm mạnh.","anchor":"Nhưng nếu là tạo thành Đại Nguyên kiếm trận tựa hồ uy lực giảm mạnh"}]},"nguon":["@c1073"]},{"id":"khong-ma-bi-thuat","name":"Khống ma bí thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Hàn Lập"],"blurb":"Phương pháp thay thế trong ma kinh vô danh, dùng cấm chế đặc thù kết hợp máu huyết tự thân và pháp quyết đặc thù để khống chế ngũ ma mà không cần tế luyện tinh hồn chung với nguyên anh bản thân.","detail":"Hạ nhiều loại cấm chế đặc thù lên người ngũ ma, rồi dùng máu huyết tự thân thường xuyên dưỡng ma, kết hợp pháp quyết đặc thù để khống chế. Ưu điểm: không cần tế luyện tinh hồn ngũ ma cùng nguyên anh bản thân, dù bị phản phệ vẫn có thể tránh đi an toàn. Nhược điểm: không thể thao túng ngũ ma linh hoạt, nếu tu vi suy yếu hoặc cung cấp máu tươi không đủ thì ngũ ma sẽ phản phệ tàn khốc. Người sáng lập bí thuật là một luyện đan đại sư ma đạo.","thuocTinh":"Âm","nguonGoc":"Ma kinh vô danh từ túi trữ vật Càn lão ma","yeuCau":"Cần là luyện đan đại sư hoặc có đủ đan dược bổ sung huyết khí, phải định kỳ cung cấp máu huyết tự thân","congNang":["Khống chế ngũ ma Nguyên Anh sơ kỳ bằng cấm chế + máu huyết + pháp quyết đặc thù @c1074","Phản phệ vẫn có thể thoát thân an toàn @c1074"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1074","tangDatToi":"Sơ thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1074","loai":"thi triển","importance":"major","giaiDoan":"Hàn Lập sơ thành thu phục ngũ ma","text":"Hàn Lập dùng bí thuật khống ma thay thế thu phục thành công Ngũ tử đồng tâm ma: phun huyết châu, đóng tế châm, phóng tiểu nhân thanh khí cùng pháp khí cương ngân, gắn dược hoàn bạc trấn áp.","anchor":"dùng máu huyết trên thân thường xuyên dưỡng ma"}]},"capNhatToi":"@c1074","nguon":["@c1074"]},{"id":"dai-tran-than-lau-thach","name":"Đại trận Thận Lâu Thạch","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ (ảnh hưởng cả Nguyên Anh kỳ)","hePhai":"Tiểu Cực cung","soHuu":["Tiểu Cực cung"],"blurb":"Đại trận hộ sơn của Tiểu Cực cung, dùng Thận Lâu Thạch làm mắt trận, có thể làm lệch thần niệm tu sĩ khiến không tìm được Tiểu Cực cung, đồng thời cấm đê giai tu sĩ phi hành.","detail":"Cấm chế bảo vệ Tiểu Cực cung, dùng Thận Lâu Thạch nổi tiếng tu tiên giới làm mắt trận, phạm vi mười vạn lý cực hàn. Có thể làm lệch thần niệm tu sĩ khỏi quỹ đạo thực tế, khiến người không biết vĩnh viễn không tìm được Tiểu Cực cung. Đê giai tu sĩ trong phạm vi trận không thể ngự khí phi hành. Ngay cả Nguyên Anh tu sĩ như Hàn Lập cũng bị lệch thần niệm phương hướng. Muốn đi qua phải dùng Định Nguyên bài do Tiểu Cực cung bán ra.","congNang":["Làm lệch thần niệm tu sĩ, khiến không tìm được Tiểu Cực cung","Cấm đê giai tu sĩ phi hành trong phạm vi trận"],"uyLuc":"Ảnh hưởng cả Nguyên Anh kỳ tu sĩ","dacDiem":"Phạm vi mười vạn lý cực hàn, dùng Thận Lâu Thạch làm mắt trận","tabs":{"tienTrinh":[{"chuong":"@c1075","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu giới thiệu","text":"Lần đầu tiết lộ đại trận hộ sơn Tiểu Cực cung dùng Thận Lâu Thạch làm mắt trận, phạm vi mười vạn lý. Hàn Lập (Nguyên Anh kỳ) bị lệch thần niệm, không tìm được Tiểu Cực cung.","anchor":"Đại trận này chính là dùng Thận Lâu Thạch tiếng tăm lừng lẫy trong tu tiên giới làm mắt trận"}]},"nguon":["@c1075"]},{"id":"cam-che-noi-cung-tieu-cuc-cung","name":"Cấm chế nội cung Tiểu Cực cung","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Cấp tông sư (Hàn Lập suy đoán)","hePhai":"Tiểu Cực cung","soHuu":["Tiểu Cực cung"],"blurb":"Hệ thống cấm chế bố trí dọc sườn cự sơn nội cung Tiểu Cực cung, ít nhất ba bốn chỗ cực kỳ lợi hại khiến ngay cả Hàn Lập cũng phải run sợ trong lòng.","detail":"Hàn Lập dùng trận pháp tạo nghệ phát hiện ít nhất ba bốn chỗ cấm chế lợi hại trên đường lên sườn cự sơn, suy đoán Tiểu Cực cung có trận pháp đại sư cấp tông sư và muốn tìm giao lưu.","congNang":["Phòng thủ nội cung, sức mạnh đủ khiến tu sĩ Kết Đan kỳ kiêng dè"],"tabs":{"tienTrinh":[{"chuong":"@c1077","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập lần đầu phát hiện","text":"Hàn Lập dùng trận pháp tạo nghệ phát hiện ít nhất ba bốn chỗ cấm chế lợi hại trên sườn cự sơn nội cung, suy đoán có trận pháp đại sư cấp tông sư.","anchor":"phát hiện ít nhất ba bốn chỗ xuất hiện cấm chế lợi hại đến ngay cả hắn cũng phải run sợ trong lòng"}]},"nguon":["@c1077"]},{"id":"cong-phap-bang-han-tieu-cuc-cung","name":"Công pháp băng hàn Tiểu Cực Cung","loai":"cong-phap","loaiLabel":"Công pháp","hePhai":"Tiểu Cực Cung","soHuu":["Tiểu Cực Cung"],"blurb":"Hệ công pháp chủ tính băng hàn đỉnh cao của Tiểu Cực Cung, được coi là một mạch riêng biệt của Đại Tấn.","detail":"Hàn Lập nhận định đây là một mạch riêng biệt và đỉnh cao của tu giới Đại Tấn, bày tỏ hứng thú dù bản thân không chủ tu băng hàn thuộc tính.","thuocTinh":"Băng hàn","nguon":["@c1079"],"tabs":{"tienTrinh":[{"chuong":"@c1079","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập bày tỏ hứng thú","text":"Hàn Lập nhận định công pháp băng hàn Tiểu Cực Cung là một mạch riêng biệt đỉnh cao của Đại Tấn, muốn tham khảo.","anchor":"công pháp này chủ yếu có tính băng hàn, mà nghe nói Tiểu Cực Cung có vài loại công pháp đỉnh cao được coi là một mạch riêng biệt của Đại Tấn"}]}},{"id":"phuong-phap-tinh-luyen-han-diem","name":"Phương pháp tinh luyện hàn diễm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Băng hàn","soHuu":["Hàn Ly thượng nhân"],"blurb":"Bí thuật đặc thù dùng để tinh luyện hàn băng chi diễm cho thuần khiết, tăng uy lực từng bước.","detail":"Hàn Ly thượng nhân giải thích mọi hàn băng chi diễm đều có thể dùng đặc thù bí thuật tinh luyện cho thuần khiết để tăng uy lực. Kiền lam băng diễm nếu tinh luyện tận cùng uy lực có thể tăng gấp mấy lần. Phương pháp khác với cách dùng pháp lực áp súc thông thường vốn tổn hao lớn và chỉ tinh luyện được ít tinh thuần chi hỏa.","congNang":["Tinh luyện hàn diễm thành thuần khiết, tăng uy lực từng bước"],"nguon":["@c1080"],"tabs":{"tienTrinh":[{"chuong":"@c1080","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hàn Ly tiết lộ cho Hàn Lập","text":"Hàn Ly giải thích mọi hàn diễm đều có thể tinh luyện bằng bí thuật đặc thù, khác với cách dùng pháp lực áp súc vốn tổn hao lớn.","anchor":"có thể sử dụng đặc thù bí thuật để tinh luyện cho thuần khiết"}]}},{"id":"phuong-phap-dot-pha-hoa-than-ngu-han-diem","name":"Phương pháp đột phá hóa thần bằng ngũ hàn diễm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật thượng cổ","phamCap":"","hePhai":"Băng hàn","soHuu":["Hàn Ly thượng nhân"],"blurb":"Phương pháp đột phá từ nguyên anh hậu kỳ đỉnh phong sang hóa thần kỳ, cần năm nguyên anh tu sĩ tu luyện hàn diễm khác nhau cùng kích thích cực hàn.","detail":"Hàn Ly tìm được từ thượng cổ điển tịch. Phương pháp yêu cầu năm nguyên anh tu sĩ tu luyện các loại hàn diễm khác nhau cùng trợ giúp kích thích cực hàn, có ba thành nắm chắc đột phá bình cảnh tiến vào hóa thần kỳ. Hàn Ly đã chuẩn bị bốn người (hai trong Tiểu Cực Cung, hai tán tu bên ngoài), Hàn Lập là người thứ năm cuối cùng sau hơn mười năm tìm kiếm.","nguonGoc":"Thượng cổ điển tịch","yeuCau":"Năm nguyên anh tu sĩ tu luyện các loại hàn diễm khác nhau","congNang":["Kích thích cực hàn đột phá bình cảnh từ nguyên anh hậu kỳ đỉnh phong sang hóa thần kỳ, ba thành nắm chắc"],"nguon":["@c1080"],"tabs":{"tienTrinh":[{"chuong":"@c1080","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Ly tiết lộ kế hoạch, Hàn Lập là người thứ năm","text":"Hàn Ly tiết lộ phương pháp từ thượng cổ điển tịch, cần năm nguyên anh tu sĩ hàn diễm kích thích cực hàn. Đã có bốn người, Hàn Lập là người cuối cùng sau hơn mười năm tìm kiếm.","anchor":"tại hạ phải cần tới năm nguyên anh tu sĩ tu luyện các loại hàn diễm khác nhau trợ giúp mới có khả năng thành công"}]}},{"id":"tinh-luyen-han-diem-bi-thuat","name":"Tinh luyện hàn diễm bí thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Hàn Lập"],"blurb":"Bí thuật do Hàn Ly thượng nhân phục chế, dùng tinh luyện tăng uy năng hàn diễm. Hàn Lập muốn dùng để tăng uy năng tử la cực hỏa.","detail":"Hàn Ly trao cho Hàn Lập dưới dạng ngọc giản. Tác dụng tinh luyện hàn diễm tăng uy lực, Hàn Lập hy vọng dùng tăng uy năng tử la cực hỏa.","thuocTinh":"Băng hàn","nguonGoc":"Hàn Ly thượng nhân phục chế","congNang":["Tinh luyện tăng uy năng hàn diễm"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c1081","tangDatToi":"","trangThai":"mới nhận"}],"tabs":{"tienTrinh":[{"chuong":"@c1081","loai":"xuất hiện","importance":"major","giaiDoan":"Trao cho Hàn Lập","text":"Hàn Ly phục chế bí thuật tinh luyện hàn diễm và trao ngọc giản cho Hàn Lập như một trong các điều kiện đàm phán.","anchor":"Hy vọng có thể dùng nó để tăng uy năng tử la cực hỏa lên"}]},"nguon":["@c1081"]},{"id":"phuong-phap-kich-thich-dot-pha","name":"Phương pháp kích thích đột phá cảnh giới","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Hàn Ly thượng nhân"],"blurb":"Phương pháp do Hàn Ly tự nghiên cứu, cần tập hợp năm loại cực hàn chi diễm, chỉ tác dụng với nguyên anh hậu kỳ sĩ, người tham gia bị hao tổn nguyên khí.","detail":"Hàn Ly thượng nhân tự nghiên cứu ra. Yêu cầu năm loại cực hàn chi diễm, chỉ có tác dụng với tu sĩ tu luyện băng thuộc tính công pháp ở nguyên anh hậu kỳ. Người phụ trợ sẽ bị hao tổn nguyên khí. Chỉ Tiểu Cực Cung mới đủ khả năng hội tụ đủ người và điều kiện.","thuocTinh":"Băng hàn","nguonGoc":"Hàn Ly thượng nhân tự nghiên cứu","yeuCau":"5 loại cực hàn chi diễm, nguyên anh hậu kỳ","congNang":["Kích thích đột phá cảnh giới từ Nguyên Anh hậu kỳ"],"dacDiem":"Người phụ trợ bị hao tổn nguyên khí, chỉ tác dụng với nguyên anh hậu kỳ sĩ tu luyện băng thuộc tính","tabs":{"tienTrinh":[{"chuong":"@c1081","loai":"xuất hiện","importance":"major","giaiDoan":"Tiết lộ và trao ngọc giản","text":"Hàn Ly tiết lộ phương pháp kích thích đột phá do mình nghiên cứu và trao ngọc giản cho Hàn Lập.","anchor":"Trong một quả ngọc giản chính là phương pháp kích thích cảnh giới do lão phu nghiên cứu ra"}]},"nguon":["@c1081"]},{"id":"hac-thuy-bang-diem","name":"Hắc Thủy băng diễm","cn":"黑水冰焰","loai":"cong-phap","loaiLabel":"Hàn diễm","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Thanh sam trung niên"],"blurb":"Một trong tam đại hàn diễm của Tiểu Cực Cung, do thanh sam trung niên nhân đang tinh luyện. Cần hàn tủy phụ trợ tu luyện.","detail":"Thuộc tam đại hàn diễm cốt lõi của Tiểu Cực Cung. Cần hàn tủy phụ trợ mới tu luyện được, hầu hết không ai luyện nổi nếu không có hàn tủy.","congNang":["Hàn diễm cực mạnh dùng trong đột phá cảnh giới"],"nguoiTu":[{"ten":"Thanh sam trung niên","tuChuong":"@c1081","tangDatToi":"","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1081","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc tên","text":"Hàn Ly ban hàn tủy cho thanh sam trung niên tu luyện Hắc Thủy băng diễm, một trong tam đại hàn diễm.","anchor":"Hai người các ngươi tinh luyện Hắc thủy băng diễm cùng Phong ly băng diễm"}]},"nguon":["@c1081"]},{"id":"phong-ly-bang-diem","name":"Phong Ly băng diễm","cn":"凤离冰焰","loai":"cong-phap","loaiLabel":"Hàn diễm","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":["Đường tỷ"],"blurb":"Một trong tam đại hàn diễm của Tiểu Cực Cung, do bạch sam nữ tử đang tinh luyện. Cần hàn tủy phụ trợ tu luyện.","detail":"Thuộc tam đại hàn diễm cốt lõi của Tiểu Cực Cung. Cần hàn tủy phụ trợ mới tu luyện được.","congNang":["Hàn diễm cực mạnh dùng trong đột phá cảnh giới"],"nguoiTu":[{"ten":"Đường tỷ","tuChuong":"@c1081","tangDatToi":"","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1081","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc tên","text":"Hàn Ly ban hàn tủy cho bạch sam nữ tử tu luyện Phong Ly băng diễm, một trong tam đại hàn diễm.","anchor":"Hai người các ngươi tinh luyện Hắc thủy băng diễm cùng Phong ly băng diễm"}]},"nguon":["@c1081"]},{"id":"kien-lam-bang-diem-technique","name":"Kiền Lam băng diễm","cn":"乾蓝冰焰","loai":"cong-phap","loaiLabel":"Hàn diễm","phamCap":"Không rõ","hePhai":"Băng thuộc tính","soHuu":[],"blurb":"Một trong tam đại hàn diễm của Tiểu Cực Cung, uy lực không nhỏ. Hàn Ly nhận ra bóng dáng của nó trong hàn diễm hỗn tạp trên người Hàn Lập.","detail":"Thuộc tam đại hàn diễm cốt lõi của Tiểu Cực Cung. Hàn Ly nhận xét hàn diễm hỗn tạp của Hàn Lập có bóng dáng kiền lam băng diễm, uy lực không nhỏ.","congNang":["Hàn diễm cực mạnh, uy lực không nhỏ"],"tabs":{"tienTrinh":[{"chuong":"@c1081","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Ly nhận ra bóng dáng trong hàn diễm Hàn Lập","text":"Hàn Ly nhận xét hàn diễm hỗn tạp trên người Hàn Lập có bóng dáng kiền lam băng diễm.","anchor":"tựa hồ bên trong lại có bóng dáng của kiền lam băng diễm"}]},"nguon":["@c1081"]},{"id":"tu-sac-han-diem","name":"Tử sắc hàn diễm","cn":"紫色寒焰","aliases":["Cực hàn chi diễm"],"loai":"khac","loaiLabel":"Dị hỏa","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Loại cực hàn chi diễm tử sắc mà Hàn Lập sở hữu, được Đại trưởng lão Hàn Ly thượng nhân của Tiểu Cực Cung đặc biệt chú ý tìm kiếm.","detail":"Đường tỷ tiết lộ Đại trưởng lão Hàn Ly quan tâm Hàn Lập chính vì hắn thân mang loại cực hàn chi diễm này. Đường tỷ yêu cầu Bạch Dao Di tìm hiểu uy lực chân chính của tử sắc hàn diễm.","congNang":["Được Tiểu Cực Cung chú ý tìm kiếm, Đại trưởng lão Hàn Ly muốn tìm người sở hữu loại hàn diễm này"],"tabs":{"tienTrinh":[{"chuong":"@c1082","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Tiểu Cực Cung chú ý","text":"Đường tỷ tiết lộ Đại trưởng lão Hàn Ly quan tâm Hàn Lập vì hắn mang cực hàn chi diễm, yêu cầu Bạch Dao Di tìm hiểu uy lực chân chính.","anchor":"người này thân mang một loại cực hàn chi diễm, đúng là người mà Hàn Ly sư huynh muốn tìm kiếm"}]},"nguon":["@c1082"]},{"id":"phong-ly-bang-diem-technique","name":"Phong Ly Băng Diễm","cn":"凤沥冰焰","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực Hàn Chi Diễm","hePhai":"Băng hàn","soHuu":["Bạch Mộng Hinh"],"blurb":"Một trong tam đại hàn diễm của Tiểu Cực Cung, bạch sắc băng diễm nhạt như khói nhẹ, có thể biến hình thành tiểu bạch xà công kích nhưng uy lực thua Tử La cực hỏa.","detail":"Bạch Mộng Hinh thi triển Phong Ly Băng Diễm biến thành tiểu bạch xà tấn công Hàn Lập để thử sức, bị Tử La cực hỏa hóa hỏa điểu nuốt trọn hoàn toàn.","congNang":["Hàn diễm công kích, có thể biến hình thành tiểu bạch xà"],"nguoiTu":[{"ten":"Bạch Mộng Hinh","tuChuong":"@c1086","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1086","loai":"thi triển","importance":"normal","giaiDoan":"Thử sức với Tử La cực hỏa","text":"Bạch Mộng Hinh biến Phong Ly Băng Diễm thành tiểu bạch xà tấn công Hàn Lập, bị Tử La cực hỏa hóa hỏa điểu nuốt trọn hoàn toàn.","anchor":"một luồng băng diễm bạch sắc hiện lên"}]},"nguon":["@c1086"]},{"id":"bi-thuat-dot-pha-hoa-than-han-ly","name":"Bí thuật đột phá Hóa Thần (Hàn Ly)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Băng hàn","soHuu":["Hàn Ly thượng nhân"],"blurb":"Bí thuật đột phá bình cảnh tiến lên Hóa Thần do Hàn Ly thượng nhân nghiên cứu mấy trăm năm, cần năm tu sĩ Cực Hàn Chi Diễm tương trợ, xác suất thành công chỉ ba thành.","detail":"Phương thức đột phá bình cảnh Nguyên Anh hậu kỳ tiến lên Hóa Thần, yêu cầu năm đồng đạo sở hữu Cực Hàn Chi Diễm hỗ trợ. Phần bí thuật Hàn Ly đưa cho Hàn Lập chỉ là một phần, chưa đầy đủ. Tỷ lệ thành công chỉ ba thành nhưng Hàn Ly quyết mạo hiểm vì thọ nguyên sắp hết.","congNang":["Đột phá Nguyên Anh hậu kỳ (bình cảnh) tiến lên Hóa Thần"],"yeuCau":"Năm tu sĩ sở hữu Cực Hàn Chi Diễm tương trợ","nguoiTu":[{"ten":"Hàn Ly thượng nhân","tuChuong":"@c1086","tangDatToi":"","trangThai":"chua-thi-hanh"}],"tabs":{"tienTrinh":[{"chuong":"@c1086","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Công bố bí thuật, hội tụ đủ năm người","text":"Hàn Ly công bố bí thuật đột phá Hóa Thần nghiên cứu mấy trăm năm, tỷ lệ chỉ ba thành, cần năm tu sĩ Cực Hàn Chi Diễm. Hội tụ đủ năm đồng đạo, quyết định bắt đầu sớm.","anchor":"theo suy đoán của ta, thành công công chỉ được có ba thành"}]},"nguon":["@c1086"]},{"id":"cong-phap-bao-tri-thanh-am-lieu-thuy","name":"Công pháp bảo trì thanh âm Liễu Thúy phái","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Long phu nhân"],"blurb":"Công pháp đặc thù của Liễu Thúy phái, cho phép nữ tu bảo trì thanh âm lúc trẻ dù ngoại hình đã già.","detail":"Long phu nhân tu luyện công pháp này, ngoại hình lão ẩu tóc bạc nhưng thanh âm vẫn dịu dàng như thiếu nữ.","nguon":["@c1086"]},{"id":"bang-phach-han-liet-tran","name":"Băng Phách Hàn Liệt trận","cn":"冰魄寒裂陣","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Thượng cổ trận pháp","hePhai":"Băng hàn","soHuu":["Tiểu Cực Cung"],"blurb":"Trận pháp thượng cổ nổi danh gồm 1008 cây vạn năm huyền băng trụ do tu sĩ thượng cổ tỉ mỉ luyện chế, phong bế cấm cung Linh Hư Điện. Kẻ xâm nhập không có pháp khí kiềm giữ sẽ bị đóng băng vĩnh viễn.","detail":"Trận pháp gồm 1008 cây vạn năm huyền băng trụ, mỗi cây to cần hai người ôm, bề mặt bóng loáng với ký hiệu ẩn hiện bên dưới, phần trên ẩn trong hàn vụ trắng, tỏa khí lạnh cực lớn. Phong bế ngàn năm tự sinh ra băng hàn khí hình thành gió lạnh dữ dội. Không có pháp khí chuyên dụng kiềm giữ mà tiến vào sẽ bị đóng băng vĩnh viễn, ngay cả năm người sở hữu Cực Hàn Chi Diễm cũng chưa chắc sống sót. Cần trận bàn chuyên dụng để mở thông đạo đi qua.","nguonGoc":"Tu sĩ thượng cổ luyện chế","thuocTinh":"Băng hàn","dacDiem":"1008 vạn năm huyền băng trụ tạo mê cung, tự sinh băng hàn khí sau ngàn năm phong bế","congNang":["Phong bế cấm địa, đóng băng vĩnh viễn kẻ xâm nhập không có pháp khí kiềm giữ"],"uyLuc":"Năm người có Cực Hàn Chi Diễm chưa chắc sống sót nếu không có pháp khí dẫn đường","tabs":{"tienTrinh":[{"chuong":"@c1088","loai":"xuất hiện","importance":"major","giaiDoan":"Đoàn Hàn Ly vượt qua trận pháp","text":"Hàn Ly thượng nhân dùng trận bàn trắng noãn dẫn đường, đưa năm người đi qua 1008 huyền băng trụ, mất khoảng một chung trà. Trận pháp này nổi danh thời thượng cổ, do tu sĩ thượng cổ tỉ mỉ luyện chế.","anchor":"Băng Phách Hàn Liệt trận nổi danh thời thượng cổ"}]},"capNhatToi":"@c1088","nguon":["@c1088"]},{"id":"tran-phap-dot-pha-binh-canh","name":"Trận pháp đột phá bình cảnh (Huyền Ngọc động)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Băng hàn","soHuu":["Hàn Ly thượng nhân"],"blurb":"Trận pháp do Hàn Ly thượng nhân bố trí quanh Huyền Ngọc động, lấy đống loạn thạch làm trung tâm, phóng ra năm quang trụ ngũ sắc bằng linh lực tinh thuần, có công hiệu gia tăng uy lực hàn diễm nhưng tăng tiêu hao pháp lực.","detail":"Trận pháp được dựng bằng trận kỳ và trận bàn luyện chế sẵn, phóng ra năm quang trụ ngũ sắc (tím, hồng, bạch, hắc, hoàng) liên kết bằng hà quang. Mỗi tu sĩ ngồi trong quang trụ, dưới chân hiện quang liên. Bên ngoài phủ quang mạc ngũ sắc cùng cuồng phong lốc trắng che khuất. Có tác dụng ổn định hàn khí, gia tăng uy lực hàn diễm ngoài ý muốn nhưng pháp lực tiêu hao gấp bội.","congNang":["Gia tăng uy lực hàn diễm của tu sĩ ngồi trong trận","Ổn định hàn khí xung quanh, tạo quang liên hỗ trợ đột phá","Tạo quang mạc ngũ sắc + cuồng phong lốc trắng che khuất bên trong"],"tabs":{"tienTrinh":[{"chuong":"@c1091","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí và kích hoạt","text":"Hàn Ly thượng nhân cùng Bạch Mộng Hinh, thanh sam trung niên bố trí trận pháp ngũ sắc quang trụ quanh Huyền Ngọc động, năm tu sĩ tiến vào quang trụ bắt đầu đột phá bình cảnh.","anchor":"mười ngón tay đồng thời búng ra"}]},"nguon":["@c1091"]},{"id":"tran-cung-dai-tran","name":"Trấn cung đại trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Tiểu Cực cung","soHuu":["Tiểu Cực cung"],"blurb":"Trận phòng thủ chính của Tiểu Cực cung, phạm vi phía trước mịt mờ hàn vụ, cung chủ lệnh mở toàn bộ cấm chế để đối phó yêu thú phát cuồng sau khi dùng Trấn Hải Chung.","detail":"Đại trận phòng thủ bao trùm khu vực Tiểu Cực cung trên Bắc Minh Đảo. Cung chủ Liễu Ngọc ra lệnh mở toàn bộ cấm chế đại trận khi chuẩn bị kích hoạt Trấn Hải Chung, dự phòng cao giai yêu thú phát cuồng sau đó.","congNang":["Phòng thủ diện rộng khu vực Tiểu Cực cung, ngăn chặn yêu thú xâm nhập"],"tabs":{"tienTrinh":[{"chuong":"@c1092","loai":"thi triển","importance":"normal","giaiDoan":"Mở toàn bộ cấm chế","text":"Cung chủ Liễu Ngọc lệnh Đinh sư đệ mở toàn bộ cấm chế đại trận để đối phó yêu thú phát cuồng sau khi dùng Trấn Hải Chung.","anchor":"Đinh sư đệ, đem cấm chế đại trận toàn bộ mở ra"}]},"nguon":["@c1092"]}]};
